def resource_path(relative_path):
    """ Ermittelt den absoluten Pfad zu einer Ressource, funktioniert für .py und .exe. """
    try:
        base_path = sys._MEIPASS
    except Exception:
        base_path = os.path.dirname(os.path.abspath(__file__))
    return os.path.join(base_path, relative_path)

def get_app_data_path(filename):
    if hasattr(sys, '_MEIPASS'):
        base_path = os.path.dirname(sys.executable)
    else:
        base_path = os.path.dirname(os.path.abspath(__file__))
    return os.path.join(base_path, filename)

def hex_to_rgb(hex_color):
    hex_color = hex_color.lstrip('#')
    if len(hex_color) not in [6, 8]: return (0, 0, 0)
    if len(hex_color) == 8: hex_color = hex_color[:6]
    try:
        return tuple(int(hex_color[i:i+2], 16) for i in (0, 2, 4))
    except ValueError:
        return (0, 0, 0)

class SafeToplevel(tk.Toplevel):
    """
    Eine Basisklasse für Toplevel-Fenster, die `after()`-Jobs sicher verwaltet.
    Alle geplanten Jobs werden beim Schließen des Fensters automatisch abgebrochen.
    """
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self._after_jobs = []

    def register_after_job(self, job_id):
        """Registriert eine `after()`-Job-ID zur späteren Bereinigung."""
        if job_id:
            self._after_jobs.append(job_id)
        return job_id

    def destroy(self):
        """Bricht alle registrierten `after()`-Jobs ab, bevor das Fenster zerstört wird."""
        for job_id in self._after_jobs:
            try:
                self.after_cancel(job_id)
            except (tk.TclError, ValueError):
                pass
        self._after_jobs = []
        if self.winfo_exists():
            super().destroy()

class TreeViewCellNavigation:
    """
    Implementiert eine zellbasierte Pfeiltasten-Navigation für ein ttk.Treeview,
    inklusive eines visuellen Cursors zur Anzeige der aktiven Zelle.
    """
    def __init__(self, tree, edit_command_func=None):
        self.tree = tree
        self.edit_command_func = edit_command_func
        
        self.tree._columns = ["#0"] + list(self.tree["columns"])
        self.tree._cur_col_index = 0
        
        self.tree._cursor = tk.Frame(self.tree, highlightbackground="#007bff", highlightcolor="#007bff", highlightthickness=2)

        self.tree.bind("<Up>", self._handle_key_press)
        self.tree.bind("<Down>", self._handle_key_press)
        self.tree.bind("<Left>", self._handle_key_press)
        self.tree.bind("<Right>", self._handle_key_press)
        
        if self.edit_command_func:
            self.tree.bind("<Return>", self._handle_key_press)
        
        self.tree.bind("<Button-1>", self._on_click, add="+")
        self.tree.bind("<<TreeviewSelect>>", self._show_cell_cursor)
        self.tree.bind("<FocusOut>", self._cleanup_cursor)
        self.tree.bind("<FocusIn>", self._show_cell_cursor)
        self.tree.bind("<Destroy>", self._cleanup_cursor)

    def _cleanup_cursor(self, event=None):
        if hasattr(self.tree, '_cursor') and self.tree._cursor and self.tree._cursor.winfo_exists():
            self.tree._cursor.place_forget()

    def _show_cell_cursor(self, event=None):
        self._cleanup_cursor()
        item = self.tree.focus()
        if not item: return

        if self.tree._cur_col_index >= len(self.tree._columns):
            self.tree._cur_col_index = 0

        col_id = self.tree._columns[self.tree._cur_col_index]
        bbox = self.tree.bbox(item, column=col_id)
        if not bbox:
            self.tree.after(20, self._show_cell_cursor)
            return
        
        x, y, w, h = bbox
        self.tree._cursor.place(x=x, y=y, width=w, height=h)
        self.tree._cursor.lift()

    def _move_row(self, delta):
        items = self.tree.get_children("")
        if not items: return "break"

        cur_item = self.tree.focus()
        if not cur_item: cur_item = items[0]
        
        try:
            idx = items.index(cur_item)
            new_idx = max(0, min(idx + delta, len(items) - 1))
            new_item = items[new_idx]
            
            self.tree.selection_set(new_item)
            self.tree.focus(new_item)
            self.tree.see(new_item)
            self._show_cell_cursor()
        except ValueError:
            pass 
        
        return "break"

    def _move_col(self, delta):
        new_idx = max(0, min(self.tree._cur_col_index + delta, len(self.tree._columns) - 1))
        self.tree._cur_col_index = new_idx
        self._show_cell_cursor()
        return "break"

    def _on_click(self, event):
        region = self.tree.identify("region", event.x, event.y)
        if region in ("cell", "heading"):
            col_id = self.tree.identify_column(event.x)
            try:
                self.tree._cur_col_index = self.tree._columns.index(col_id)
            except ValueError:
                pass
        
        item = self.tree.identify_row(event.y)
        if item:
            self.tree.focus(item)
            self.tree.selection_set(item)

        self._show_cell_cursor()

    def _start_edit(self, event=None):
        if self.edit_command_func and callable(self.edit_command_func):
            try:
                self.edit_command_func()
            except TypeError:
                self.edit_command_func(event)
        return "break"
        
    def _handle_key_press(self, event):
        if event.keysym == "Up":
            return self._move_row(-1)
        elif event.keysym == "Down":
            return self._move_row(1)
        elif event.keysym == "Left":
            return self._move_col(-1)
        elif event.keysym == "Right":
            return self._move_col(1)
        elif event.keysym == "Return":
            return self._start_edit(event)



class BulkAddNamenslisteDialog(tk.Toplevel):
    """
    Ein Dialogfenster, das ein großes Textfeld zum Einfügen 
    mehrerer Namen auf einmal bereitstellt.
    """
    def __init__(self, parent, app_ref):
        super().__init__(parent)
        self.transient(parent)
        self.grab_set()
        self.parent_app = app_ref
        self.result = None
        self.title("Mehrere Namen einfügen")

        main_frame = ttk.Frame(self, padding=15)
        main_frame.pack(expand=True, fill="both")
        main_frame.rowconfigure(1, weight=1)
        main_frame.columnconfigure(0, weight=1)

        ttk.Label(main_frame, text="Fügen Sie hier die Namen ein (ein Name pro Zeile):", wraplength=400).grid(row=0, column=0, sticky="w", padx=5, pady=(0, 5))

        self.text_area = tk.Text(main_frame, wrap="word", height=15, width=60, undo=True)
        self.text_area.grid(row=1, column=0, sticky="nsew", padx=5, pady=5)
        self.text_area.focus_set()

        button_frame = ttk.Frame(main_frame)
        button_frame.grid(row=2, column=0, pady=(10, 0), sticky="ew")
        button_frame.columnconfigure((0, 1), weight=1)
        
        ipady = self.parent_app.current_settings.get('dialog_button_ipady', 5)
        save_button = ttk.Button(button_frame, text="Übernehmen", command=self.on_save)
        self.parent_app._configure_dialog_button(save_button, 'Dialog_Save', 'Übernehmen')
        save_button.grid(row=0, column=0, padx=5, ipady=ipady, sticky="ew")

        cancel_button = ttk.Button(button_frame, text="Abbrechen", command=self.on_cancel)
        self.parent_app._configure_dialog_button(cancel_button, 'Dialog_Cancel', 'Abbrechen')
        cancel_button.grid(row=0, column=1, padx=5, ipady=ipady, sticky="ew")
        
        self.protocol("WM_DELETE_WINDOW", self.on_cancel)

    def on_save(self):
        content = self.text_area.get("1.0", tk.END).strip()
        if not content:
            self.result = []
            self.destroy()
            return
        
        lines = content.splitlines()
        
        # Leere Zeilen aus der Liste entfernen
        names_list = [line.strip() for line in lines if line.strip()]
        
        # Eine Liste von Dictionaries erstellen, die dem Datenformat der Namensliste entspricht
        self.result = [
            {
                "id": uuid.uuid4().hex,
                "name": name,
                "nationality": "",
                "contact": "",
                "car": "",
            } for name in names_list
        ]
        self.destroy()

    def on_cancel(self):
        self.result = None
        self.destroy()

    def show(self):
        self.wait_window(self)
        return self.result

