def _get_pdf_logo_path(settings, key):
    """Gibt den konfigurierten Logo-Pfad für ein PDF-Dokument zurück.
    Fällt auf das Standard-Logo zurück, wenn kein Pfad konfiguriert oder die Datei nicht vorhanden ist."""
    path = settings.get('pdf_logo_paths', {}).get(key, '')
    if path and os.path.exists(path):
        return path
    return resource_path("icons/bwp_logo.png")


class OffeneRechnungenPDF(FPDF):
    """
    Erstellt eine PDF-Datei für die Liste der offenen Rechnungen.
    """
    def __init__(self, logo_path=None, datum_str=""):
        super().__init__(orientation='L', unit='mm', format='A4')
        self.logo_path = logo_path
        self.datum_str = datum_str if datum_str else datetime.date.today().strftime("%d.%m.%Y")
        self.font_family = "Helvetica"
        try:
            font_dir = resource_path('fonts')
            dejavu_sans_path = os.path.join(font_dir, "DejaVuSans.ttf")
            dejavu_sans_bold_path = os.path.join(font_dir, "DejaVuSans-Bold.ttf")
            if os.path.exists(dejavu_sans_path) and os.path.exists(dejavu_sans_bold_path):
                # Wichtig: uni=True aktivieren, damit Unicode (Umlaute, Sonderzeichen) funktioniert
                self.add_font("DejaVuSans", "", dejavu_sans_path, uni=True)
                self.add_font("DejaVuSans", "B", dejavu_sans_bold_path, uni=True)
                self.font_family = "DejaVuSans"
        except Exception as e:
            print(f"PDF Font Warning (Offene Rechnungen): {e}")

    def header(self):
        if self.logo_path and os.path.exists(self.logo_path):
            self.image(self.logo_path, x=10, y=8, w=30)
        self.set_font(self.font_family, 'B', 16)
        self.cell(0, 10, "Übersicht: Offene Rechnungen", 0, new_x=XPos.LMARGIN, new_y=YPos.NEXT, align='C')
        self.set_font(self.font_family, '', 10)
        self.cell(0, 7, f"Stand: {self.datum_str}", 0, new_x=XPos.LMARGIN, new_y=YPos.NEXT, align='R')
        self.ln(5)

    def footer(self):
        self.set_y(-15)
        self.set_font(self.font_family, '', 8)
        self.cell(0, 10, f'Seite {self.page_no()}', 0, align='C')

    def draw_table(self, title, data, col_configs):
        self.set_font(self.font_family, 'B', 12)
        self.cell(0, 10, title, 0, new_x=XPos.LMARGIN, new_y=YPos.NEXT, align='L')
        
        # Header
        self.set_font(self.font_family, 'B', 8)
        self.set_fill_color(220, 220, 220)
        page_width = self.w - 2 * self.l_margin
        for col_id, config in col_configs.items():
            self.cell(page_width * config['width_pct'], 7, config['text'], 1, align='C', fill=1)
        self.ln()

        # Data
        self.set_font(self.font_family, '', 7)
        for row_data in data:
            if self.get_y() > (self.h - self.b_margin - 12): self.add_page()

            for col_id, config in col_configs.items():
                col_w = page_width * config['width_pct']
                text = str(row_data.get(col_id, ''))
                # Text abschneiden, falls er breiter als die Zelle ist
                while text and self.get_string_width(text) > col_w - 1:
                    text = text[:-1]
                self.cell(col_w, 6, text, 1, align=config.get('align', 'L'))
            self.ln()
        self.ln(8)

class CalendarPopup(tk.Toplevel):
    """Kalender-Popup zur Datumsauswahl. Schreibt das gewählte Datum (TT.MM.JJJJ) in target_var."""

    MONTH_NAMES = ["Januar", "Februar", "März", "April", "Mai", "Juni",
                   "Juli", "August", "September", "Oktober", "November", "Dezember"]
    DAY_HEADERS = ["Mo", "Di", "Mi", "Do", "Fr", "Sa", "So"]

    def __init__(self, parent, target_var, max_date=None):
        super().__init__(parent)
        self.transient(parent)
        self.grab_set()
        self.title("Datum auswählen")
        self.resizable(False, False)
        self.target_var = target_var
        self.max_date = max_date

        today = datetime.date.today()
        pre_selected = None
        initial = target_var.get().strip()
        if initial:
            for fmt in ("%d.%m.%Y", "%d.%m.%y"):
                try:
                    pre_selected = datetime.datetime.strptime(initial, fmt).date()
                    break
                except (ValueError, TypeError):
                    pass

        self.selected = pre_selected or today
        self.view_year = self.selected.year
        self.view_month = self.selected.month

        self._build()
        self._center(parent)

    def _center(self, parent):
        self.update_idletasks()
        px, py = parent.winfo_rootx(), parent.winfo_rooty()
        pw, ph = parent.winfo_width(), parent.winfo_height()
        w, h = self.winfo_reqwidth(), self.winfo_reqheight()
        self.geometry(f"+{px + (pw - w) // 2}+{py + (ph - h) // 2}")

    def _build(self):
        for w in self.winfo_children():
            w.destroy()

        frm = ttk.Frame(self, padding=12)
        frm.pack()

        # Navigations-Header
        hdr = ttk.Frame(frm)
        hdr.grid(row=0, column=0, columnspan=7, sticky='ew', pady=(0, 8))
        hdr.columnconfigure(1, weight=1)
        ttk.Button(hdr, text="◀", width=3, command=self._prev_month).grid(row=0, column=0)
        ttk.Label(hdr, text=f"{self.MONTH_NAMES[self.view_month - 1]} {self.view_year}",
                  font=("Segoe UI", 13, "bold"), anchor='center').grid(row=0, column=1, sticky='ew', padx=10)
        ttk.Button(hdr, text="▶", width=3, command=self._next_month).grid(row=0, column=2)

        # Wochentag-Kopfzeile
        for col, name in enumerate(self.DAY_HEADERS):
            fg = '#CC0000' if col >= 5 else '#333333'
            tk.Label(frm, text=name, font=("Segoe UI", 10, "bold"),
                     width=4, fg=fg, anchor='center').grid(row=1, column=col, padx=2, pady=(0, 4))

        # Tage
        today = datetime.date.today()
        weeks = calendar.monthcalendar(self.view_year, self.view_month)
        for r, week in enumerate(weeks):
            for c, day in enumerate(week):
                if day == 0:
                    tk.Label(frm, text="", width=4).grid(row=r + 2, column=c, padx=2, pady=2)
                    continue
                d = datetime.date(self.view_year, self.view_month, day)
                is_sel = (d == self.selected)
                is_today = (d == today)
                is_weekend = (c >= 5)
                if is_sel:
                    bg, fg, fw = '#0078D4', 'white', 'bold'
                elif is_today:
                    bg, fg, fw = '#CCE4F7', '#0078D4', 'bold'
                elif is_weekend:
                    bg, fg, fw = 'SystemButtonFace', '#CC0000', 'normal'
                else:
                    bg, fg, fw = 'SystemButtonFace', '#111111', 'normal'
                tk.Button(frm, text=str(day), width=4,
                          font=("Segoe UI", 10, fw), bg=bg, fg=fg,
                          relief='flat', cursor='hand2',
                          command=lambda d=d: self._pick(d)).grid(row=r + 2, column=c, padx=2, pady=2, sticky='nsew')

        # Heute & Abbrechen
        ttk.Button(frm, text="Heute", command=lambda: self._pick(datetime.date.today())).grid(
            row=len(weeks) + 2, column=0, columnspan=7, pady=(10, 3), sticky='ew')
        ttk.Button(frm, text="Abbrechen", command=self.destroy).grid(
            row=len(weeks) + 3, column=0, columnspan=7, pady=(3, 0), sticky='ew')

    def _prev_month(self):
        if self.view_month == 1:
            self.view_month, self.view_year = 12, self.view_year - 1
        else:
            self.view_month -= 1
        self._build()

    def _next_month(self):
        if self.view_month == 12:
            self.view_month, self.view_year = 1, self.view_year + 1
        else:
            self.view_month += 1
        self._build()

    def _pick(self, date_obj):
        if self.max_date and date_obj > self.max_date:
            antwort = messagebox.askyesno(
                "Ungültiges Datum",
                f"Das gewählte Datum ({date_obj.strftime('%d.%m.%Y')}) überschreitet das erlaubte Datum!\n"
                f"Erlaubt bis: {self.max_date.strftime('%d.%m.%Y')}\n\n"
                "Möchten Sie dieses Datum trotzdem verwenden?",
                icon='warning',
                parent=self
            )
            if not antwort:
                return
        self.target_var.set(date_obj.strftime("%d.%m.%Y"))
        self.destroy()


class CleanupPreviewDialog(tk.Toplevel):
    """
    Zeigt eine elegante Vorschau aller Einträge, die beim Aufräumen
    gelöscht werden würden, und lässt den Mitarbeiter bestätigen oder abbrechen.
    """
    def __init__(self, parent, entries):
        super().__init__(parent)
        self.transient(parent)
        self.grab_set()
        self.confirmed = False

        self.title("Aufräumen – Vorschau")
        self.resizable(True, True)

        # ── Farben ──────────────────────────────────────────────────
        BG        = "#1e1e2e"
        CARD_BG   = "#2a2a3e"
        HDR_BG    = "#c0392b"
        HDR_FG    = "#ffffff"
        ROW_EVEN  = "#2a2a3e"
        ROW_ODD   = "#252535"
        ROW_SEL   = "#e74c3c"
        FG        = "#ecf0f1"
        MUTED     = "#95a5a6"
        BTN_DEL   = "#c0392b"
        BTN_DEL_H = "#e74c3c"
        BTN_CNL   = "#34495e"
        BTN_CNL_H = "#4a6278"

        self.configure(bg=BG)

        # ── Hauptrahmen ──────────────────────────────────────────────
        outer = tk.Frame(self, bg=BG, padx=20, pady=20)
        outer.pack(fill='both', expand=True)

        # ── Kopfzeile ───────────────────────────────────────────────
        header = tk.Frame(outer, bg=HDR_BG, padx=16, pady=12)
        header.pack(fill='x', pady=(0, 14))

        tk.Label(
            header, text="⚠  Einträge zum Löschen",
            bg=HDR_BG, fg=HDR_FG,
            font=("Segoe UI", 14, "bold")
        ).pack(side='left')

        count_badge = tk.Label(
            header,
            text=f"  {len(entries)} Einträge  ",
            bg="#e74c3c", fg=HDR_FG,
            font=("Segoe UI", 10, "bold"),
            padx=6, pady=2, relief='flat'
        )
        count_badge.pack(side='right', padx=(0, 4))

        # ── Info-Text ────────────────────────────────────────────────
        tk.Label(
            outer,
            text="Die folgenden Einträge haben das Final-Datum vor mehr als 7 Tagen\n"
                 "und werden bei Bestätigung unwiderruflich gelöscht.",
            bg=BG, fg=MUTED,
            font=("Segoe UI", 9),
            justify='left'
        ).pack(anchor='w', pady=(0, 10))

        # ── Treeview-Rahmen ──────────────────────────────────────────
        tree_frame = tk.Frame(outer, bg=CARD_BG, padx=2, pady=2)
        tree_frame.pack(fill='both', expand=True)

        cols = ("bk_ref", "gruppenname", "anreise", "abreise", "final_datum")
        self.tree = ttk.Treeview(tree_frame, columns=cols, show="headings", height=12)

        style = ttk.Style(self)
        style.theme_use(style.theme_use())  # Keep current theme
        style.configure("Cleanup.Treeview",
                        background=ROW_EVEN, foreground=FG,
                        fieldbackground=ROW_EVEN,
                        rowheight=26, font=("Segoe UI", 9),
                        borderwidth=0)
        style.configure("Cleanup.Treeview.Heading",
                        background=CARD_BG, foreground=MUTED,
                        font=("Segoe UI", 9, "bold"),
                        relief='flat')
        style.map("Cleanup.Treeview",
                  background=[("selected", ROW_SEL)],
                  foreground=[("selected", HDR_FG)])
        self.tree.configure(style="Cleanup.Treeview")

        col_cfg = [
            ("bk_ref",      "BK-Referenz",    110, 'center'),
            ("gruppenname", "Gruppenname",     260, 'w'),
            ("anreise",     "Anreise",          90, 'center'),
            ("abreise",     "Abreise",          90, 'center'),
            ("final_datum", "Final versendet",  110, 'center'),
        ]
        for cid, lbl, w, anchor in col_cfg:
            self.tree.heading(cid, text=lbl)
            self.tree.column(cid, width=w, anchor=anchor, stretch=(cid == "gruppenname"))

        self.tree.tag_configure("even", background=ROW_EVEN)
        self.tree.tag_configure("odd",  background=ROW_ODD)

        vsb = ttk.Scrollbar(tree_frame, orient="vertical",   command=self.tree.yview)
        hsb = ttk.Scrollbar(tree_frame, orient="horizontal", command=self.tree.xview)
        self.tree.configure(yscrollcommand=vsb.set, xscrollcommand=hsb.set)

        self.tree.grid(row=0, column=0, sticky='nsew')
        vsb.grid(row=0, column=1, sticky='ns')
        hsb.grid(row=1, column=0, sticky='ew')
        tree_frame.rowconfigure(0, weight=1)
        tree_frame.columnconfigure(0, weight=1)

        for i, entry in enumerate(entries):
            tag = "even" if i % 2 == 0 else "odd"
            self.tree.insert("", "end", tags=(tag,), values=(
                entry.get('bk_ref', ''),
                entry.get('gruppenname', ''),
                entry.get('anreise', ''),
                entry.get('abreise', ''),
                entry.get('final_datum', ''),
            ))

        # ── Trennlinie ───────────────────────────────────────────────
        tk.Frame(outer, bg="#3d3d55", height=1).pack(fill='x', pady=(14, 10))

        # ── Button-Leiste ────────────────────────────────────────────
        btn_bar = tk.Frame(outer, bg=BG)
        btn_bar.pack(fill='x')

        def _on_enter_del(e):  del_btn.configure(bg=BTN_DEL_H)
        def _on_leave_del(e):  del_btn.configure(bg=BTN_DEL)
        def _on_enter_cnl(e):  cnl_btn.configure(bg=BTN_CNL_H)
        def _on_leave_cnl(e):  cnl_btn.configure(bg=BTN_CNL)

        cnl_btn = tk.Button(
            btn_bar, text="Abbrechen",
            bg=BTN_CNL, fg=FG, activebackground=BTN_CNL_H, activeforeground=FG,
            font=("Segoe UI", 10), relief='flat', padx=20, pady=8, cursor='hand2',
            command=self.destroy
        )
        cnl_btn.pack(side='right', padx=(8, 0))
        cnl_btn.bind("<Enter>", _on_enter_cnl)
        cnl_btn.bind("<Leave>", _on_leave_cnl)

        del_btn = tk.Button(
            btn_bar, text="🗑  Alle löschen",
            bg=BTN_DEL, fg=HDR_FG, activebackground=BTN_DEL_H, activeforeground=HDR_FG,
            font=("Segoe UI", 10, "bold"), relief='flat', padx=20, pady=8, cursor='hand2',
            command=self._confirm
        )
        del_btn.pack(side='right')
        del_btn.bind("<Enter>", _on_enter_del)
        del_btn.bind("<Leave>", _on_leave_del)

        # ── Fenster-Größe und Zentrierung ────────────────────────────
        self.update_idletasks()
        w, h = 720, 520
        px = parent.winfo_rootx() + (parent.winfo_width()  - w) // 2
        py = parent.winfo_rooty() + (parent.winfo_height() - h) // 2
        self.geometry(f"{w}x{h}+{px}+{py}")
        self.minsize(600, 400)

        self.bind("<Escape>", lambda e: self.destroy())
        self.wait_window(self)

    def _confirm(self):
        self.confirmed = True
        self.destroy()


class OffeneRechnungEntryDialog(tk.Toplevel):
    """ Dialog zum Hinzufügen oder Bearbeiten eines Eintrags für offene Rechnungen. """
    def __init__(self, parent, app_ref, entry_data=None):
        super().__init__(parent)
        self.transient(parent)
        self.grab_set()
        self.parent_app = app_ref
        self.result = None
        self.is_editing = entry_data is not None
        # NEU: Die ursprünglichen Daten werden gespeichert, um Änderungen zu erkennen
        self.initial_data = entry_data.copy() if self.is_editing else {}
        self.title("Eintrag bearbeiten" if self.is_editing else "Neuer Eintrag")

         # Initialisierung von Attributen, die in der destroy-Methode verwendet werden
        self.is_destroyed = False
        self.periodic_check_job = None
        self.app = app_ref # Stellt sicher, dass self.app existiert


        main_frame = ttk.Frame(self, padding=15)
        main_frame.pack(expand=True, fill="both")
        main_frame.columnconfigure(1, weight=1)

        try:
            base_font_family = tkFont.Font(font=self.parent_app.style.lookup('TLabel', 'font')).actual('family')
        except (tk.TclError, AttributeError):
            base_font_family = "Segoe UI"
        
        dialog_font = tkFont.Font(family=base_font_family, size=14)
        entry_ipady = 8

        self.data_vars = {
            'id': tk.StringVar(), 'bk_ref': tk.StringVar(), 'gruppenname': tk.StringVar(),
            'anreise': tk.StringVar(), 'abreise': tk.StringVar(),
            'info_sent': tk.StringVar(value="Nein"), 'info_kuerzel': tk.StringVar(), 'info_datum': tk.StringVar(),
            'erneut_sent': tk.StringVar(value="Nein"), 'erneut_kuerzel': tk.StringVar(), 'erneut_datum': tk.StringVar(),
            'final_sent': tk.StringVar(value="Nein"), 'final_kuerzel': tk.StringVar(), 'final_datum': tk.StringVar()
        }

        if self.is_editing and entry_data:
            for key, var in self.data_vars.items():
                var.set(entry_data.get(key, ''))
        else:
            self.data_vars['id'].set(uuid.uuid4().hex)

        kuerzel_options = ['', 'MZ', 'SS', 'JH']
        # Die leere Option ('') ist wichtig, damit die Logik eine unvollständige Eingabe erkennen kann.
        status_options = ['','Ja', 'Nein', 'in Bearbeitung', 'an Bankett übergeben', 'noch offen']

        row = 0
        ttk.Label(main_frame, text="BK-Referenz:", font=dialog_font).grid(row=row, column=0, sticky='w', padx=5, pady=3)
        ttk.Entry(main_frame, textvariable=self.data_vars['bk_ref'], font=dialog_font).grid(row=row, column=1, columnspan=3, sticky='ew', padx=5, pady=3, ipady=entry_ipady); row+=1
        
        ttk.Label(main_frame, text="Gruppenname:", font=dialog_font).grid(row=row, column=0, sticky='w', padx=5, pady=3)
        ttk.Entry(main_frame, textvariable=self.data_vars['gruppenname'], font=dialog_font).grid(row=row, column=1, columnspan=3, sticky='ew', padx=5, pady=3, ipady=entry_ipady); row+=1
        
        ttk.Label(main_frame, text="Anreise:", font=dialog_font).grid(row=row, column=0, sticky='w', padx=5, pady=3)
        self._make_date_field(main_frame, self.data_vars['anreise'], dialog_font, entry_ipady, max_date=datetime.date.today() - datetime.timedelta(days=1)).grid(row=row, column=1, columnspan=3, sticky='ew', padx=5, pady=3); row+=1

        ttk.Label(main_frame, text="Abreise:", font=dialog_font).grid(row=row, column=0, sticky='w', padx=5, pady=3)
        self._make_date_field(main_frame, self.data_vars['abreise'], dialog_font, entry_ipady).grid(row=row, column=1, columnspan=3, sticky='ew', padx=5, pady=3); row+=1

        sections = [
            ('Info versendet:', 'info_sent', 'info_kuerzel', 'info_datum'),
            ('Erneut versendet:', 'erneut_sent', 'erneut_kuerzel', 'erneut_datum'),
            ('Final versendet:', 'final_sent', 'final_kuerzel', 'final_datum')
        ]
        
        for i, (label, status_key, kuerzel_key, datum_key) in enumerate(sections):
            ttk.Separator(main_frame, orient='horizontal').grid(row=row, column=0, columnspan=4, sticky='ew', pady=8); row+=1
            ttk.Label(main_frame, text=label, font=dialog_font).grid(row=row, column=0, sticky='w', padx=5, pady=3)
            ttk.Combobox(main_frame, textvariable=self.data_vars[status_key], values=status_options, state='readonly', width=22, font=dialog_font).grid(row=row, column=1, sticky='w', padx=5)
            ttk.Label(main_frame, text="Kürzel:", font=dialog_font).grid(row=row, column=2, sticky='e', padx=5)
            ttk.Combobox(main_frame, textvariable=self.data_vars[kuerzel_key], values=kuerzel_options, state='readonly', width=7, font=dialog_font).grid(row=row, column=3, sticky='w', padx=5); row+=1
            ttk.Label(main_frame, text="Datum:", font=dialog_font).grid(row=row, column=0, sticky='w', padx=5, pady=3)
            self._make_date_field(main_frame, self.data_vars[datum_key], dialog_font, entry_ipady, max_date=datetime.date.today()).grid(row=row, column=1, columnspan=3, sticky='ew', padx=5, pady=3); row+=1
        
        button_frame = ttk.Frame(main_frame)
        button_frame.grid(row=row, column=0, columnspan=4, pady=15, sticky="ew")
        button_frame.columnconfigure((0, 1), weight=1)
        
        save_button = ttk.Button(button_frame, text="Speichern", command=self.on_save)
        self.parent_app._configure_dialog_button(save_button, 'Dialog_Save', 'Speichern')
        save_button.grid(row=0, column=0, padx=5, ipady=5, sticky="ew")

        cancel_button = ttk.Button(button_frame, text="Abbrechen", command=self.on_cancel)
        self.parent_app._configure_dialog_button(cancel_button, 'Dialog_Cancel', 'Abbrechen')
        cancel_button.grid(row=0, column=1, padx=5, ipady=5, sticky="ew")
        
        self.protocol("WM_DELETE_WINDOW", self.on_cancel)

    def _make_date_field(self, parent, var, font, entry_ipady, max_date=None):
        """Erstellt ein Datumsfeld: schreibgeschütztes Entry + 📅 Kalender-Button."""
        frame = ttk.Frame(parent)
        entry = ttk.Entry(frame, textvariable=var, font=font, state='readonly')
        entry.pack(side='left', fill='x', expand=True, ipady=entry_ipady)

        def open_calendar():
            CalendarPopup(self, var, max_date=max_date)

        def on_key(event):
            ignored = {'Tab', 'Shift_L', 'Shift_R', 'Control_L', 'Control_R',
                       'Alt_L', 'Alt_R', 'Left', 'Right', 'Up', 'Down', 'Escape'}
            if event.keysym not in ignored:
                messagebox.showwarning(
                    "Eingabe nicht erlaubt",
                    "Das Datum kann nur über den Kalender eingetragen werden.\n"
                    "Bitte den 📅-Button verwenden.",
                    parent=self
                )

        entry.bind('<Key>', on_key)
        entry.bind('<Button-1>', lambda e: open_calendar())
        ttk.Button(frame, text="📅", width=3, command=open_calendar).pack(side='left', padx=(4, 0))
        return frame

    def on_save(self):
        import re
        # BK-Referenz validieren (Format: BK gefolgt von Ziffern, optional /Ziffern, z.B. BK009514 oder BK123456/1)
        bk_ref = self.data_vars['bk_ref'].get().strip()
        if not re.match(r'^BK\d+(/\d+)?$', bk_ref):
            messagebox.showerror(
                "Ungültige BK-Referenz",
                "Die BK-Referenz muss das Format BK + Ziffern haben (z.B. BK009514 oder BK123456/1).",
                parent=self
            )
            return

        # Grundlegende Validierung für den Gruppennamen
        if not self.data_vars['gruppenname'].get().strip():
            messagebox.showerror("Fehler", "Der Gruppenname darf nicht leer sein.", parent=self)
            return

        # Datumsvalidierung: Anreise muss in der Vergangenheit liegen, Abreise maximal heute
        def parse_date(s):
            for fmt in ("%d.%m.%Y", "%d.%m.%y"):
                try:
                    return datetime.datetime.strptime(s.strip(), fmt).date()
                except (ValueError, AttributeError):
                    pass
            return None

        today = datetime.date.today()
        anreise_date = parse_date(self.data_vars['anreise'].get())
        abreise_date = parse_date(self.data_vars['abreise'].get())

        if anreise_date and anreise_date >= today:
            messagebox.showerror(
                "Ungültiges Anreisedatum",
                f"Das Anreisedatum ({self.data_vars['anreise'].get()}) darf nicht heute oder in der Zukunft liegen.\n\n"
                "Die Anreise muss in der Vergangenheit liegen.",
                parent=self
            )
            return


        # Definition der zu prüfenden Sektionen
        sections_to_validate = [
            {'label': 'Info versendet', 'keys': ('info_sent', 'info_kuerzel', 'info_datum')},
            {'label': 'Erneut versendet', 'keys': ('erneut_sent', 'erneut_kuerzel', 'erneut_datum')},
            {'label': 'Final versendet', 'keys': ('final_sent', 'final_kuerzel', 'final_datum')}
        ]

        # Prüfung jeder Sektion auf Vollständigkeit, falls sie bearbeitet wurde
        for section in sections_to_validate:
            status_key, kuerzel_key, datum_key = section['keys']

            # Aktuelle Werte aus den UI-Elementen holen
            current_status = self.data_vars[status_key].get()
            current_kuerzel = self.data_vars[kuerzel_key].get()
            current_datum = self.data_vars[datum_key].get().strip()

            # Ursprüngliche Werte aus den beim Öffnen gespeicherten Daten holen
            initial_status = self.initial_data.get(status_key, "Nein")
            initial_kuerzel = self.initial_data.get(kuerzel_key, "")
            initial_datum = self.initial_data.get(datum_key, "")

            # Prüfen, ob irgendein Feld in dieser Sektion geändert wurde
            was_edited = (
                current_status != initial_status or
                current_kuerzel != initial_kuerzel or
                current_datum != initial_datum
            )

            # Wenn eine Änderung stattgefunden hat, muss die Sektion vollständig sein
            if was_edited:
                # Vollständigkeit prüfen: Alle drei Felder müssen einen Wert haben (nicht leer sein)
                is_complete = all([
                    current_status,  # Prüft, ob der String nicht leer ist ('')
                    current_kuerzel, # Prüft, ob der String nicht leer ist ('')
                    current_datum    # Prüft, ob der String nach dem Strippen nicht leer ist
                ])

                if not is_complete:
                    messagebox.showerror(
                        "Unvollständige Eingabe",
                        f"Im Bereich '{section['label']}' wurde eine Änderung vorgenommen. "
                        f"Bitte füllen Sie alle drei Felder (Status, Kürzel und Datum) vollständig aus.",
                        parent=self
                    )
                    return # Verhindert das Schließen des Fensters

        # Wenn alle Prüfungen bestanden wurden, Daten speichern und Dialog schließen
        self.result = {key: var.get() for key, var in self.data_vars.items()}
        self.destroy()

    def on_cancel(self):
        # Diese Methode ist unverändert, aber notwendig.
        self.result = None
        self.destroy()

    def show(self):
        # Diese Methode ist unverändert, aber notwendig.
        self.wait_window(self)
        return self.result

    def destroy(self):
        # Setzt ein Flag, um laufende Prozesse zu informieren
        self.is_destroyed = True 
        
        # Ruft die ursprüngliche destroy-Methode der Elternklasse auf, 
        # um das Fenster korrekt zu schließen.
        super().destroy()

