            recipient = "andreas.triebsch@kronsberg.bestwestern.de"
            subject = f"Übersicht Offene Rechnungen - Stand: {datetime.date.today().strftime('%d.%m.%Y')}"
            body_text = (
                "Guten Tag Herr Triebsch,\n\n"
                "anbei senden wir Ihnen die offenen Rechnungen für Gruppen und Einzelpersonen.\n\n"
                "Herzliche Grüße\n"
                "Empfangsteam"
            )

            email_callback = None
