        frm.grid(row=0, column=0, sticky="ew", padx=6, pady=6)
        frm.columnconfigure((0, 1), weight=1)
        
        entry_ipady = 5

        ttk.Label(frm, text="Zimmerpreis (Gesamt) €:").grid(row=0, column=0, sticky="w")
        zimmerpreis_entry = ttk.Entry(frm, textvariable=self.zimmerpreis_var, width=12, font=self.dialog_font)
        zimmerpreis_entry.grid(row=0, column=1, sticky="w", ipady=entry_ipady)
        self.parent_app._bind_dialog_navigation(zimmerpreis_entry)
        
        ttk.Label(frm, text="Erwachsene (steuerpflichtig):").grid(row=1, column=0, sticky="w")
        erwachsene_spinbox = ttk.Spinbox(frm, from_=1, to=20, textvariable=self.erwachsene_var, width=6, font=self.dialog_font)
        erwachsene_spinbox.grid(row=1, column=1, sticky="w", ipady=entry_ipady)
        self.parent_app._bind_dialog_navigation(erwachsene_spinbox)
        
        ttk.Label(frm, text="Kinder (steuerfrei):").grid(row=2, column=0, sticky="w")
