class LayoverApp:
    """
    Verwaltet die UI und die Berechnungslogik für die Layover-Übersicht.
    Daten werden manuell eingegeben und in einer JSON-Datei gespeichert.
    """
    def __init__(self, parent, app_ref):
        self.parent_frame = parent
        self.app = app_ref
        self.data = {}
        self.layover_buttons = {}
        self.ui_labels = {}

        # vvvvv HIER IST DIE KORREKTUR vvvvv
        # Die Logik wird angepasst, um das Laden zu verzögern.
        self._build_ui()
        # Die load_data Methode ruft update_display intern auf.
        self.app.master.after_idle(self.load_data)
        # ^^^^^ ENDE DER KORREKTUR ^^^^^

    def load_data(self):
        """Lädt die Layover-Daten aus der JSON-Datei."""
        if os.path.exists(self.app.layover_data_file):
            try:
                with open(self.app.layover_data_file, 'r', encoding='utf-8') as f:
                    self.data = json.load(f)
            except (json.JSONDecodeError, IOError):
                self._initialize_default_data()
        else:
            self._initialize_default_data()

    def _initialize_default_data(self):
        """Setzt die Daten auf einen leeren Standardwert."""
        self.data = {
            'single': {'total': 0, 'oos': 0},
            'double': {'total': 0, 'oos': 0},
            'special_rooms': {
                '3 Bettzimmer': [],
                '4 Bettzimmer': [],
                'Babybett-Zimmer': []
            }
        }

    def save_data(self, action=None):
        """Speichert die aktuellen Layover-Daten und optional einen Verlaufseintrag."""
        try:
            with open(self.app.layover_data_file, 'w', encoding='utf-8') as f:
                json.dump(self.data, f, indent=4)
            if action:
                self._save_history_snapshot(action)
        except Exception as e:
            print(f"Fehler beim Speichern der Layover-Daten: {e}")

    def _open_edit_dialog(self):
        """Öffnet den Dialog zur Bearbeitung."""
        dialog = LayoverEntryDialog(self.app.master, self.app, initial_data=self.data)
        new_data = dialog.show()
        
        if new_data == "DELETE":
            self._delete_all_layover_data()
        elif new_data:
            self.data = new_data
            self.save_data(action="Daten bearbeitet")
            self.update_display()
            SuccessToast(self.app.master, title="Gespeichert", message="Die Layover-Daten wurden erfolgreich aktualisiert.", toast_type='success', colors=self.app.current_settings.get('toast_colors'))

    def _calculate_data(self):
        """Führt alle Berechnungen basierend auf den aktuellen Daten durch."""
        results = {}
        pax_per_room = {'single': 1, 'double': 2}
        total_rooms = 0
        total_oos = 0
        
        for key in ['single', 'double']:
            total = self.data.get(key, {}).get('total', 0)
            oos = self.data.get(key, {}).get('oos', 0)
            clean = total - oos
            pax = clean * pax_per_room[key]
            
            results[key] = {'total': total, 'oos': oos, 'clean': clean, 'pax': pax, 'label': key.capitalize() + 'zimmer'}
            total_rooms += total
            total_oos += oos
            
        results['total'] = {
            'total': total_rooms,
            'oos': total_oos,
            'clean': results['single']['clean'] + results['double']['clean'],
            'pax': results['single']['pax'] + results['double']['pax'],
            'label': 'Gesamt'
        }
        return results

    def update_display(self):
        """Aktualisiert alle Labels in der UI mit den neu berechneten Daten."""
        calculated_data = self._calculate_data()
        
        for key in ['single', 'double', 'total']:
            for col in ['total', 'oos', 'clean', 'pax']:
                if f"table_{key}_{col}" in self.ui_labels:
                    self.ui_labels[f"table_{key}_{col}"].config(text=calculated_data[key][col])

        self.ui_labels['result_clean_single'].config(text=calculated_data['single']['clean'])
        self.ui_labels['result_clean_double'].config(text=calculated_data['double']['clean'])
        self.ui_labels['result_total_pax'].config(text=calculated_data['total']['pax'])

        special_rooms_data = self.data.get('special_rooms', {})
        for label, rooms_list in special_rooms_data.items():
            if label in self.ui_labels:
                container = self.ui_labels[label]
                for widget in container.winfo_children():
                    if isinstance(widget, ttk.Label) and " (Zimmernummer)" not in widget.cget("text"):
                        widget.destroy()
                
                for room_num in rooms_list:
                    ttk.Label(container, text=room_num, font=("Segoe UI", 12)).pack(anchor='w', pady=1)

    def _save_layover_as_pdf(self):
        """Speichert die aktuelle Layover-Übersicht als PDF-Datei."""
        save_path = filedialog.asksaveasfilename(
            defaultextension=".pdf",
            filetypes=[("PDF-Dateien", "*.pdf")],
            title="Layover-Übersicht als PDF speichern",
            initialfile=f"Layover_Uebersicht_{datetime.date.today().strftime('%Y-%m-%d')}.pdf"
        )
        if not save_path:
            return

        try:
            calculated_data = self._calculate_data()
            logo_path = _get_pdf_logo_path(self.app.current_settings, 'layover')
            pdf = LayoverPDF(logo_path=logo_path, datum_str=self.app.date_display_var.get())
            pdf.add_page()
            pdf.create_overview(self.data, calculated_data)
            pdf.output(save_path)
            
            self.save_data(action="PDF exportiert")

            # KORRIGIERT: self.app.master und self.app.current_settings verwenden
            SuccessToast(self.app.master, title="Erfolg",
                         message="Layover-Übersicht erfolgreich als PDF gespeichert.",
                         toast_type='success',
                         colors=self.app.current_settings.get('toast_colors'))
            
            # KORRIGIERT: parent=self.app.master verwenden
            if messagebox.askyesno("Ordner öffnen?", "Möchten Sie den Speicherort öffnen?", parent=self.app.master):
                self.app._open_folder(os.path.dirname(save_path))
        
        except Exception as e:
            # KORRIGIERT: parent=self.app.master verwenden
            messagebox.showerror("Fehler beim PDF-Export", f"Ein Fehler ist aufgetreten:\n{e}", parent=self.app.master)
        finally:
            if 'pdf' in locals() and hasattr(pdf, 'close'):
                pdf.close()
    def _delete_all_layover_data(self):
        """Löscht alle aktuellen Layover-Daten nach Bestätigung."""
        if messagebox.askyesno("Bestätigung", "Möchten Sie wirklich alle Layover-Daten unwiderruflich löschen?", parent=self.app.master):
            self._initialize_default_data()
            self.save_data(action="Alle Daten gelöscht")
            self.update_display()
            SuccessToast(self.app.master, title="Gelöscht", message="Alle Layover-Daten wurden entfernt.", toast_type='success', colors=self.app.current_settings.get('toast_colors'))
            
    def _save_history_snapshot(self, action):
        """Speichert einen Snapshot der aktuellen Daten in der Verlaufsdatei."""
        history_file = self.app.layover_history_file
        history_data = []
        if os.path.exists(history_file):
            try:
                with open(history_file, 'r', encoding='utf-8') as f:
                    history_data = json.load(f)
            except (json.JSONDecodeError, IOError):
                pass
        
        snapshot = {
            "timestamp": datetime.datetime.now().isoformat(),
            "action": action,
            "data": json.loads(json.dumps(self.data))
        }
        
        history_data.insert(0, snapshot)
        history_data = history_data[:self.app.max_history_entries]

        try:
            os.makedirs(os.path.dirname(history_file), exist_ok=True)
            with open(history_file, 'w', encoding='utf-8') as f:
                json.dump(history_data, f, indent=2, ensure_ascii=False)
        except Exception as e:
            print(f"Fehler beim Speichern des Layover-Verlaufs: {e}")

    def _show_layover_history(self):
        """Öffnet den Dialog zur Anzeige des Layover-Verlaufs."""
        self.app._open_generic_list_history_dialog(
            "Layover-Übersicht",
            self.app.layover_history_file,
            self._get_layover_history_summary_line,
            self._restore_from_history
        )
        
    def _get_layover_history_summary_line(self, snapshot):
        """Erstellt eine Zusammenfassungszeile für einen Layover-Verlaufseintrag."""
        action = snapshot.get('action', 'Unbekannt')
        data = snapshot.get('data', {})
        
        pax_per_room = {'single': 1, 'double': 2}
        total_clean = 0
        total_pax = 0
        for key in ['single', 'double']:
            total = data.get(key, {}).get('total', 0)
            oos = data.get(key, {}).get('oos', 0)
            clean = total - oos
            pax = clean * pax_per_room[key]
            total_clean += clean
            total_pax += pax
            
        return f"[{action}] - Saubere Zimmer: {total_clean}, Personen: {total_pax}"

    def _restore_from_history(self, history_dialog):
        """Stellt einen Zustand aus dem Layover-Verlauf wieder her."""
        # --- START DER KORREKTUR ---
        listbox = history_dialog.listbox_widget
        all_snapshots = history_dialog.displayed_snapshots
        selected_indices = listbox.curselection()

        if not selected_indices or len(selected_indices) > 1:
            messagebox.showwarning("Auswahl", "Bitte genau einen Eintrag zum Wiederherstellen auswählen.", parent=history_dialog)
            return
        
        snapshot_data = all_snapshots[selected_indices[0]]
        # --- ENDE DER KORREKTUR ---

        data_to_restore = snapshot_data.get('data')
        if not data_to_restore:
            messagebox.showerror("Fehler", "Keine gültigen Daten zum Wiederherstellen.", parent=history_dialog)
            return
            
        if messagebox.askyesno("Wiederherstellen", "Diesen Zustand wiederherstellen? Aktuelle, nicht gespeicherte Änderungen gehen verloren.", parent=history_dialog):
            self.data = data_to_restore
            self.save_data(action="Wiederhergestellt aus Verlauf")
            self.update_display()
            history_dialog.destroy()
            SuccessToast(self.app.master, title="Erfolg", message="Der Zustand wurde wiederhergestellt.", toast_type='success', colors=self.app.current_settings.get('toast_colors'))

    def _build_ui(self):
        """Erstellt die Benutzeroberfläche für die Layover-Seite."""
        for widget in self.parent_frame.winfo_children():
            widget.destroy()

        self.parent_frame.grid_rowconfigure(1, weight=1)
        self.parent_frame.grid_columnconfigure(0, weight=1)
        
        header = ttk.Frame(self.parent_frame, style='AppBackground.TFrame', height=60)
        header.grid(row=0, column=0, sticky='ew')
        header.columnconfigure(1, weight=1)
        self.app._create_home_button(header).grid(row=0, column=0, sticky='w', padx=10, pady=10)
        ttk.Label(header, text="Layover Übersicht", font=("Segoe UI", 20, "bold")).grid(row=0, column=1, sticky='w', padx=20, pady=10)
        
        content_canvas = tk.Canvas(self.parent_frame, borderwidth=0, highlightthickness=0, bg=self.app.style.lookup('AppBackground.TFrame', 'background'))
        vsb = ttk.Scrollbar(self.parent_frame, orient="vertical", command=content_canvas.yview)
        content_canvas.configure(yscrollcommand=vsb.set)
        content_canvas.grid(row=1, column=0, sticky='nsew', padx=15, pady=10)
        vsb.grid(row=1, column=1, sticky='ns', pady=10)
        scrollable_frame = ttk.Frame(content_canvas, style='AppBackground.TFrame', padding=25)
        canvas_window = content_canvas.create_window((0, 0), window=scrollable_frame, anchor="nw")

        def configure_scroll_region(event): content_canvas.configure(scrollregion=content_canvas.bbox("all"))
        def configure_canvas_window(event): content_canvas.itemconfig(canvas_window, width=event.width)
        scrollable_frame.bind("<Configure>", configure_scroll_region)
        content_canvas.bind("<Configure>", configure_canvas_window)

        title_font = ("Segoe UI", 16, "bold")
        header_font = ("Segoe UI", 16, "bold")
        data_font = ("Segoe UI", 16)
        
        # --- Button-Leiste ---
        button_frame = ttk.Frame(scrollable_frame, style='AppBackground.TFrame')
        button_frame.pack(fill='x', pady=(0, 20), padx=20)
        
        design_cfg = self.app.current_settings.get('list_views_button_style', {})
        ipady = design_cfg.get('ipady', 8)
        
        button_defs = {
            'Layover_Edit': {'text': 'Daten bearbeiten...', 'command': self._open_edit_dialog},
            'Layover_SavePDF': {'text': 'Als PDF speichern', 'command': self._save_layover_as_pdf},
            'Layover_History': {'text': 'Verlauf', 'command': self._show_layover_history},
            'Layover_Delete': {'text': 'Alle Daten löschen', 'command': self._delete_all_layover_data}
        }
        
        self.layover_buttons = {}
        button_frame.columnconfigure(tuple(range(len(button_defs))), weight=1)
        
        col = 0
        for key, props in button_defs.items():
            btn = ttk.Button(button_frame, command=props['command'])
            btn.grid(row=0, column=col, sticky='ew', padx=5, ipady=ipady)
            # HIER WIRD DIE NEUE KONFIGURATIONS-LOGIK AUFGERUFEN
            self._configure_layover_button(btn, key, props['text'])
            self.layover_buttons[key] = btn
            col += 1
            
        # --- Datentabelle (unverändert) ---
        table_frame = ttk.Frame(scrollable_frame, style='AppBackground.TFrame')
        table_frame.pack(fill='x', expand=True, pady=(0, 20))
        
        headers = ["", "Anzahl Zimmer", "Out Of Service", "Anzahl saubere Zimmer", "Anzahl Personen"]
        for i, text in enumerate(headers):
            ttk.Label(table_frame, text=text, font=header_font, anchor='w', padding=(15, 10)).grid(row=0, column=i, sticky='w')

        row_idx = 1
        labels_map = {'single': 'Einzelzimmer', 'double': 'Doppelzimmer', 'total': 'Gesamt'}
        for key in ['single', 'double', 'total']:
            font_style = header_font if key == 'total' else data_font
            ttk.Label(table_frame, text=labels_map[key], font=font_style, anchor='w', padding=(15, 8)).grid(row=row_idx, column=0, sticky='w')
            for i, col_name in enumerate(['total', 'oos', 'clean', 'pax']):
                lbl = ttk.Label(table_frame, text="0", font=font_style, anchor='center', padding=(15, 8))
                lbl.grid(row=row_idx, column=i + 1, sticky='w')
                self.ui_labels[f"table_{key}_{col_name}"] = lbl
            row_idx += 1
        
        ttk.Separator(scrollable_frame, orient='horizontal').pack(fill='x', pady=25)

        # ... (Rest der UI-Erstellung bleibt unverändert) ...
        ergebnis_frame = ttk.Frame(scrollable_frame, style='AppBackground.TFrame')
        ergebnis_frame.pack(fill='x', expand=True, pady=(0, 20))
        ttk.Label(ergebnis_frame, text="Ergebnis:", font=title_font, anchor='w').pack(fill='x', pady=(0, 15))
        
        result_items = [("Anzahl saubere Einzelzimmer", "result_clean_single"),
                        ("Anzahl saubere Doppelzimmer", "result_clean_double"),
                        ("Anzahl Personen", "result_total_pax")]
        
        for label, key in result_items:
            row_frame = ttk.Frame(ergebnis_frame, style='AppBackground.TFrame')
            row_frame.pack(fill='x', pady=2)
            ttk.Label(row_frame, text=label, font=data_font, width=35, anchor='w').pack(side='left', padx=5)
            lbl = ttk.Label(row_frame, text="0", font=header_font, anchor='w')
            lbl.pack(side='left', padx=5)
            self.ui_labels[key] = lbl

        ttk.Separator(scrollable_frame, orient='horizontal').pack(fill='x', pady=25)
        
        special_rooms_frame = ttk.Frame(scrollable_frame, style='AppBackground.TFrame')
        special_rooms_frame.pack(fill='x', expand=True)
        
        col_idx = 0
        for label in ['3 Bettzimmer', '4 Bettzimmer', 'Babybett-Zimmer']:
            col_frame = ttk.Frame(special_rooms_frame, style='AppBackground.TFrame')
            col_frame.grid(row=0, column=col_idx, sticky='nw', padx=40)
            ttk.Label(col_frame, text=f"{label} (Zimmernummer)", font=header_font).pack(anchor='w', pady=(0, 8))
            self.ui_labels[label] = col_frame
            col_idx += 1

    # vvvvv HIER DIE NEUE HELPER-METHODE EINFÜGEN vvvvv
    def _configure_layover_button(self, button_widget, config_key, default_text):
        """Konfiguriert einen Button der Layover-Ansicht basierend auf den Einstellungen."""
        layover_configs = self.app.current_settings.get('layover_button_configs', {})
        
        # Nutzt die bereits existierende, generische Konfigurationsmethode der Haupt-App
        self.app._configure_list_tab_button(
            button_widget, 
            config_key, 
            default_text, 
            button_config_source=layover_configs
        )

    def destroy(self):
        """Leere Methode für einen sauberen Neustart-Prozess."""
        pass



class LayoverPDF(FPDF):
    """ Erstellt eine PDF-Datei für die Layover-Übersicht. """
    def __init__(self, logo_path=None, datum_str=""):
        super().__init__(orientation='P', unit='mm', format='A4')
        self.logo_path = logo_path
        self.datum_str = datum_str if datum_str else datetime.date.today().strftime("%d.%m.%Y")
        self.font_family = "Helvetica"
        try:
            # Versucht, eine Unicode-kompatible Schriftart zu laden
            font_dir = resource_path('fonts')
            dejavu_sans_path = os.path.join(font_dir, "DejaVuSans.ttf")
            dejavu_sans_bold_path = os.path.join(font_dir, "DejaVuSans-Bold.ttf")
            if os.path.exists(dejavu_sans_path) and os.path.exists(dejavu_sans_bold_path):
                self.add_font("DejaVuSans", "", dejavu_sans_path)
                self.add_font("DejaVuSans", "B", dejavu_sans_bold_path)
                self.font_family = "DejaVuSans"
        except Exception as e:
            print(f"PDF Font Warning (Layover): {e}")

    def header(self):
        if self.logo_path and os.path.exists(self.logo_path):
            self.image(self.logo_path, x=10, y=8, w=30)
        self.set_font(self.font_family, 'B', 18)
        self.cell(0, 10, "Layover Übersicht", 0, new_x=XPos.LMARGIN, new_y=YPos.NEXT, align='C')
        self.set_font(self.font_family, '', 11)
        self.cell(0, 8, f"Stand: {self.datum_str}", 0, new_x=XPos.LMARGIN, new_y=YPos.NEXT, align='R')
        self.ln(8)

    def footer(self):
        self.set_y(-15)
        self.set_font(self.font_family, '', 8)
        self.cell(0, 10, f'Seite {self.page_no()}', 0, align='C')

    def create_overview(self, data, calculated_data):
        # Tabelle zeichnen
        self.set_font(self.font_family, 'B', 11)
        self.set_fill_color(220, 220, 220)
        page_width = self.w - 2 * self.l_margin
        col_widths = [page_width * 0.25, page_width * 0.18, page_width * 0.18, page_width * 0.21, page_width * 0.18]
        
        headers = ["", "Anzahl Zimmer", "Out Of Service", "Saubere Zimmer", "Personen"]
        for i, header_text in enumerate(headers):
            self.cell(col_widths[i], 8, header_text, 1, align='C', fill=1)
        self.ln()
        
        self.set_font(self.font_family, '', 10)
        row_labels = {'single': 'Einzelzimmer', 'double': 'Doppelzimmer', 'total': 'Gesamt'}
        for key in ['single', 'double', 'total']:
            if key == 'total':
                self.set_font(self.font_family, 'B', 10)
            
            self.cell(col_widths[0], 7, row_labels[key], 1)
            self.cell(col_widths[1], 7, str(calculated_data[key]['total']), 1, align='C')
            self.cell(col_widths[2], 7, str(calculated_data[key]['oos']), 1, align='C')
            self.cell(col_widths[3], 7, str(calculated_data[key]['clean']), 1, align='C')
            self.cell(col_widths[4], 7, str(calculated_data[key]['pax']), 1, align='C')
            self.ln()
        
        self.set_font(self.font_family, '', 10)
        self.ln(12)

        # Ergebnis-Sektion
        self.set_font(self.font_family, 'B', 14)
        self.cell(0, 10, "Ergebnis:", 0, new_x=XPos.LMARGIN, new_y=YPos.NEXT)
        self.set_font(self.font_family, '', 11)
        result_items = [
            ("Anzahl saubere Einzelzimmer", calculated_data['single']['clean']),
            ("Anzahl saubere Doppelzimmer", calculated_data['double']['clean']),
            ("Anzahl Personen", calculated_data['total']['pax'])
        ]
        for label, value in result_items:
            self.cell(page_width * 0.6, 7, label)
            self.cell(page_width * 0.4, 7, str(value), new_x=XPos.LMARGIN, new_y=YPos.NEXT, align='L')
        self.ln(12)

        # Sonderzimmer-Sektion
        special_rooms_data = data.get('special_rooms', {})
        if any(special_rooms_data.values()):
            self.set_font(self.font_family, 'B', 14)
            self.cell(0, 10, "Sonderzimmer:", 0, new_x=XPos.LMARGIN, new_y=YPos.NEXT)
            self.set_font(self.font_family, '', 10)
            
            for room_type, room_list in special_rooms_data.items():
                if room_list:
                    self.set_font(self.font_family, 'B', 10)
                    self.cell(page_width * 0.4, 7, f"{room_type}:")
                    self.set_font(self.font_family, '', 10)
                    # Umbruch bei langen Listen
                    room_text = ', '.join(room_list)
                    self.multi_cell(page_width * 0.6, 7, room_text, new_x=XPos.LMARGIN, new_y=YPos.NEXT)
            self.ln(5)
            # ^^^ HIER ENDET DER NEUE CODE ^^



# HIER IST DIE PERFEKTE STELLE, UM DEN NEUEN CODE EINZUFÜGEN

class NamenslistePDF(FPDF):
    """
    Erstellt eine PDF-Datei für die Namensliste und verarbeitet das Logo intern,
    um Transparenzprobleme zu beheben.
    """
    def __init__(self, orientation='L', unit='mm', format='A4', firmenname="", extra_infos="", logo_path=None, datum_str=""):
        super().__init__(orientation, unit, format)
        self.firmenname = firmenname
        self.extra_infos = extra_infos
        self.datum_str = datum_str if datum_str else datetime.date.today().strftime("%d.%m.%Y")
        
        self.processed_logo_path = None
        self.temp_logo_to_delete = None
        self.logo_render_h = 0  # Gerenderete Logo-Höhe in mm bei w=40

        # --- Interne Logo-Verarbeitung ---
        source_logo_path = logo_path
        if not source_logo_path or not os.path.exists(source_logo_path):
            try:
                default_logo = resource_path("icons/bwp_logo.png")
                if os.path.exists(default_logo):
                    source_logo_path = default_logo
            except Exception:
                source_logo_path = None

        if source_logo_path and 'Image' in globals() and Image:
            try:
                with tempfile.NamedTemporaryFile(suffix=".png", delete=False) as temp_file:
                    self.temp_logo_to_delete = temp_file.name

                img = Image.open(source_logo_path).convert("RGBA")
                iw, ih = img.size
                if iw > 0:
                    self.logo_render_h = 40 * ih / iw  # proportionale Höhe bei w=40mm
                background = Image.new("RGBA", img.size, (255, 255, 255))
                background.paste(img, (0, 0), img)
                background.convert("RGB").save(self.temp_logo_to_delete, "PNG")

                self.processed_logo_path = self.temp_logo_to_delete
            except Exception as e:
                print(f"Fehler bei der Logo-Verarbeitung für PDF: {e}")
                self.close()

        # --- Schriftarten-Setup ---
        self.font_family = "Helvetica"
        try:
            font_dir = resource_path('fonts')
            dejavu_sans_path = os.path.join(font_dir, "DejaVuSans.ttf")
            dejavu_sans_bold_path = os.path.join(font_dir, "DejaVuSans-Bold.ttf")
            if os.path.exists(dejavu_sans_path) and os.path.exists(dejavu_sans_bold_path):
                self.add_font("DejaVuSans", "", dejavu_sans_path)
                self.add_font("DejaVuSans", "B", dejavu_sans_bold_path)
                self.font_family = "DejaVuSans"
        except Exception as e:
            print(f"PDF Font Warning (Namensliste): {e}")

    def header(self):
        logo_w = 40
        if self.processed_logo_path and os.path.exists(self.processed_logo_path):
            x_center = (self.w - logo_w) / 2
            self.image(self.processed_logo_path, x=x_center, y=8, w=logo_w)

        self.set_font(self.font_family, '', 12)
        self.cell(0, 10, self.datum_str, new_x=XPos.LMARGIN, new_y=YPos.NEXT, align='R')

        # Y-Cursor sicherstellen: Text beginnt UNTER dem Logo
        min_y = 8 + self.logo_render_h + 3
        if self.get_y() < min_y:
            self.set_y(min_y)
        else:
            self.ln(3)

        self.set_font(self.font_family, 'B', 11)
        self.cell(0, 7, f"Firmenname: {self.firmenname}", new_x=XPos.LMARGIN, new_y=YPos.NEXT, align='L')
        self.set_font(self.font_family, '', 11)
        self.cell(0, 7, f"Extra-Infos: {self.extra_infos}", new_x=XPos.LMARGIN, new_y=YPos.NEXT, align='L')
        self.ln(5)

    def close(self):
        """
        Eine benutzerdefinierte close-Methode, die aufgerufen wird, um die
        temporäre Logo-Datei sicher zu löschen.
        """
        # KORREKTUR: Die folgende Zeile wurde entfernt, da die Elternklasse FPDF
        # keine 'close'-Methode hat, die so aufgerufen werden muss.
        # super().close() 
        
        if self.temp_logo_to_delete and os.path.exists(self.temp_logo_to_delete):
            # KORREKTUR: Fehler abfangen, falls die Datei gesperrt ist.
            try:
                os.remove(self.temp_logo_to_delete)
            except OSError as e:
                print(f"Fehler beim Löschen der temporären Logo-Datei: {e}")
        self.temp_logo_to_delete = None

    def __del__(self):
        """
        Destruktor, der sicherstellt, dass die temporäre Datei auch dann
        gelöscht wird, wenn die Instanz zerstört wird.
        """
        self.close()

    def footer(self):
        self.set_y(-15)
        self.set_font(self.font_family, '', 8)
        self.cell(0, 10, f'Seite {self.page_no()}', 0, align='C')

    def create_table(self, data, num_empty_rows=15, col_widths=None):
        DEFAULTS = {"name": 50, "nationality": 25, "contact": 125, "car": 35, "signature": 42}
        cw = {k: int(col_widths.get(k, DEFAULTS[k])) if col_widths else DEFAULTS[k] for k in DEFAULTS}

        def _draw_header():
            self.set_font(self.font_family, 'B', 10)
            self.set_fill_color(220, 220, 220)
            self.cell(cw["name"],        8, "Nachname, Vorname", 1, new_x=XPos.RIGHT, new_y=YPos.TOP, align='C', fill=1)
            self.cell(cw["nationality"], 8, "Nationalität",      1, new_x=XPos.RIGHT, new_y=YPos.TOP, align='C', fill=1)
            self.cell(cw["contact"],     8, "E-Mail / Telefon",  1, new_x=XPos.RIGHT, new_y=YPos.TOP, align='C', fill=1)
            self.cell(cw["car"],         8, "PKW",               1, new_x=XPos.RIGHT, new_y=YPos.TOP, align='C', fill=1)
            self.cell(cw["signature"],   8, "Unterschrift",      1, new_x=XPos.LMARGIN, new_y=YPos.NEXT, align='C', fill=1)

        _draw_header()
        self.set_font(self.font_family, '', 10)
        fill = False
        all_rows = data + ([{}] * num_empty_rows)

        for row in all_rows:
            if self.get_y() > (self.h - self.b_margin - 15):
                self.add_page()
                _draw_header()
                self.set_font(self.font_family, '', 10)

            self.set_fill_color(245, 245, 245) if fill else self.set_fill_color(255, 255, 255)
            self.cell(cw["name"],        10, row.get('name', ''),        1, new_x=XPos.RIGHT,  new_y=YPos.TOP,  align='L', fill=1)
            self.cell(cw["nationality"], 10, row.get('nationality', ''), 1, new_x=XPos.RIGHT,  new_y=YPos.TOP,  align='L', fill=1)
            self.cell(cw["contact"],     10, row.get('contact', ''),     1, new_x=XPos.RIGHT,  new_y=YPos.TOP,  align='L', fill=1)
            self.cell(cw["car"],         10, row.get('car', ''),         1, new_x=XPos.RIGHT,  new_y=YPos.TOP,  align='L', fill=1)
            self.cell(cw["signature"],   10, '',                         1, new_x=XPos.LMARGIN, new_y=YPos.NEXT, align='L', fill=1)
            fill = not fill


class NameSplitDialog(tk.Toplevel):
    """
    Dialog zum manuellen Festlegen des Trennpunkts zwischen Vorname und Nachname
    bei mehrteiligen Namen (z.B. "Anna Maria Müller Schmidt").
    """
    def __init__(self, parent, app_ref, name_words):
        super().__init__(parent)
        self.transient(parent)
        self.grab_set()
        self.parent_app = app_ref
        self.result = None  # None = überspringen, (nachname, vorname) = Ergebnis
        self.name_words = name_words
        self.title("Name aufteilen")

        full_name = " ".join(name_words)

        main_frame = ttk.Frame(self, padding=15)
        main_frame.pack(expand=True, fill="both")
        main_frame.columnconfigure(0, weight=1)

        dialog_font = ("Segoe UI", 12)

        ttk.Label(main_frame, text="Mehrteiligen Namen aufteilen",
                  font=("Segoe UI", 13, "bold")).grid(row=0, column=0, sticky="w", pady=(0, 5))
        ttk.Label(main_frame, text=f'Name: "{full_name}"',
                  font=dialog_font).grid(row=1, column=0, sticky="w", pady=(0, 10))
        ttk.Label(main_frame,
                  text="Wo ist der Trennpunkt? (linke Wörter = Vorname, rechte = Nachname)",
                  font=dialog_font).grid(row=2, column=0, sticky="w", pady=(0, 8))

        # split_var = Anzahl der Wörter von LINKS, die zum Vornamen gehören
        self.split_var = tk.IntVar(value=1)

        options_frame = ttk.Frame(main_frame)
        options_frame.grid(row=3, column=0, sticky="ew", pady=(0, 8))
        options_frame.columnconfigure(0, weight=1)

        for n in range(1, len(name_words)):
            vorname_part = " ".join(name_words[:n])
            nachname_part = " ".join(name_words[n:])
            label_text = f"Vorname: \"{vorname_part}\"  |  Nachname: \"{nachname_part}\""
            rb = ttk.Radiobutton(options_frame, text=label_text,
                                 variable=self.split_var, value=n)
            rb.grid(row=n - 1, column=0, sticky="w", pady=2)

        preview_frame = ttk.LabelFrame(main_frame, text="Ergebnis-Vorschau", padding=8)
        preview_frame.grid(row=4, column=0, sticky="ew", pady=(4, 12))
        preview_frame.columnconfigure(0, weight=1)

        self.preview_var = tk.StringVar()
        self._update_preview()
        self.split_var.trace_add('write', lambda *_: self._update_preview())
        ttk.Label(preview_frame, textvariable=self.preview_var,
                  font=("Segoe UI", 12, "bold")).grid(row=0, column=0, sticky="w")

        button_frame = ttk.Frame(main_frame)
        button_frame.grid(row=5, column=0, sticky="ew")
        button_frame.columnconfigure((0, 1), weight=1)

        ipady = self.parent_app.current_settings.get('dialog_button_ipady', 5)

        confirm_btn = ttk.Button(button_frame, text="Bestätigen", command=self.on_confirm)
        self.parent_app._configure_dialog_button(confirm_btn, 'Dialog_Save', 'Bestätigen')
        confirm_btn.grid(row=0, column=0, padx=5, ipady=ipady, sticky="ew")

        skip_btn = ttk.Button(button_frame, text="Überspringen", command=self.on_skip)
        self.parent_app._configure_dialog_button(skip_btn, 'Dialog_Cancel', 'Überspringen')
        skip_btn.grid(row=0, column=1, padx=5, ipady=ipady, sticky="ew")

        self.protocol("WM_DELETE_WINDOW", self.on_skip)

    def _update_preview(self):
        n = self.split_var.get()
        if 1 <= n < len(self.name_words):
            vorname_part = " ".join(self.name_words[:n])
            nachname_part = " ".join(self.name_words[n:])
            self.preview_var.set(f"{nachname_part}, {vorname_part}")

    def on_confirm(self):
        n = self.split_var.get()
        if 1 <= n < len(self.name_words):
            vorname_part = " ".join(self.name_words[:n])
            nachname_part = " ".join(self.name_words[n:])
            self.result = (nachname_part, vorname_part)
        self.destroy()

    def on_skip(self):
        self.result = None
        self.destroy()

    def show(self):
        self.wait_window(self)
        return self.result


class NamenslisteEntryDialog(tk.Toplevel):
    """
    Dialogfenster zum Hinzufügen oder Bearbeiten eines Eintrags in der Namensliste.
    """
    def __init__(self, parent, app_ref, entry_data=None):
        super().__init__(parent)
        self.transient(parent)
        self.grab_set()
        self.parent_app = app_ref
        self.result = None
        self.is_editing = entry_data is not None
        self.title("Eintrag bearbeiten" if self.is_editing else "Neuer Eintrag")

        main_frame = ttk.Frame(self, padding=15)
        main_frame.pack(expand=True, fill="both")
        main_frame.columnconfigure(1, weight=1)

        self.id_var = tk.StringVar()
        self.name_var = tk.StringVar()
        self.nationality_var = tk.StringVar()
        self.contact_var = tk.StringVar()
        self.car_var = tk.StringVar()

        if self.is_editing and entry_data:
            self.id_var.set(entry_data.get('id', ''))
            self.name_var.set(entry_data.get('name', ''))
            self.nationality_var.set(entry_data.get('nationality', ''))
            self.contact_var.set(entry_data.get('contact', ''))
            self.car_var.set(entry_data.get('car', ''))
        else:
            self.id_var.set(uuid.uuid4().hex)

        fields = [
            ("Name (Nachname, Vorname):", self.name_var),
            ("Nationalität:", self.nationality_var),
            ("E-Mail / Telefon:", self.contact_var),
            ("PKW:", self.car_var),
        ]

        dialog_font = ("Segoe UI", 12)
        entry_ipady = 5

        for i, (label_text, var) in enumerate(fields):
            ttk.Label(main_frame, text=label_text, font=dialog_font).grid(row=i, column=0, sticky="w", padx=5, pady=4)
            entry = ttk.Entry(main_frame, textvariable=var, font=dialog_font, width=40)
            entry.grid(row=i, column=1, sticky="ew", padx=5, pady=4, ipady=entry_ipady)
            self.parent_app._bind_dialog_navigation(entry) # HIER WIRD DIE NAVIGATION HINZUGEFÜGT
            if i == 0:
                entry.focus_set()

        button_frame = ttk.Frame(main_frame)
        button_frame.grid(row=len(fields), column=0, columnspan=2, pady=(15, 0), sticky="ew")
        button_frame.columnconfigure((0, 1), weight=1)

        ipady = self.parent_app.current_settings.get('dialog_button_ipady', 5)
        
        save_button = ttk.Button(button_frame, text="Speichern", command=self.on_save)
        self.parent_app._configure_dialog_button(save_button, 'Dialog_Save', 'Speichern')
        save_button.grid(row=0, column=0, padx=5, ipady=ipady, sticky="ew")

        cancel_button = ttk.Button(button_frame, text="Abbrechen", command=self.on_cancel)
        self.parent_app._configure_dialog_button(cancel_button, 'Dialog_Cancel', 'Abbrechen')
        cancel_button.grid(row=0, column=1, padx=5, ipady=ipady, sticky="ew")
        
        self.protocol("WM_DELETE_WINDOW", self.on_cancel)
    def on_save(self):
        name = self.name_var.get().strip()
        if not name:
            messagebox.showerror("Fehler", "Der Name darf nicht leer sein.", parent=self)
            return

        self.result = {
            "id": self.id_var.get(),
            "name": name,
            "nationality": self.nationality_var.get().strip(),
            "contact": self.contact_var.get().strip(),
            "car": self.car_var.get().strip(),
        }
        self.destroy()

    def on_cancel(self):
        self.result = None
        self.destroy()

    def show(self):
        self.wait_window(self)
        return self.result
    
    
class UrlaubsantragPDF(FPDF):
    """
    Erstellt eine PDF-Datei für den Urlaubsantrag mit einem Layout,
    das exakt dem gewünschten Muster entspricht.
    """
    def __init__(self, data, logo_path=None):
        super().__init__('P', 'mm', 'A4')
        self.data = data
        self.logo_path = logo_path
        self.font_family = "Helvetica"
        try:
            font_dir = resource_path('fonts')
            dejavu_sans_path = os.path.join(font_dir, "DejaVuSans.ttf")
            dejavu_sans_bold_path = os.path.join(font_dir, "DejaVuSans-Bold.ttf")
            if os.path.exists(dejavu_sans_path) and os.path.exists(dejavu_sans_bold_path):
                self.add_font("DejaVuSans", "", dejavu_sans_path)
                self.add_font("DejaVuSans", "B", dejavu_sans_bold_path)
                self.font_family = "DejaVuSans"
        except Exception as e:
            print(f"PDF Font Warning (Urlaubsantrag): {e}")

    def create_form(self):
        self.add_page()

        # --- KOPFZEILE: LOGO ZENTRIERT, INFO-FELDER RECHTS ---
        if self.logo_path and os.path.exists(self.logo_path):
            self.image(self.logo_path, x=65, y=0, w=80)

        self.set_font(self.font_family, 'B', 8)
        rx = 135
        self.set_xy(rx, 15)
        self.cell(0, 5, "*Auszufüllen von der Personalabteilung", align='L')
        
        self.set_font(self.font_family, '', 9)
        self.set_xy(rx, 23)
        self.cell(0, 5, "*Resturlaub:")
        self.set_xy(rx, 31)
        self.cell(0, 5, "*Überschneidungen:")
        self.set_xy(rx, 39)
        self.cell(0, 5, "*Guestline:")

        # --- TITEL ---
        self.set_y(65)
        self.set_font(self.font_family, 'BU', 16)
        self.cell(0, 10, "Urlaubsantrag", new_x=XPos.LMARGIN, new_y=YPos.NEXT, align='C')
        self.ln(8)

        # --- OBERE FELDER ---
        lbl_w = 55
        val_x = 15 + lbl_w
        line_w = 100

        self.set_x(15)
        self.set_font(self.font_family, 'B', 11)
        self.cell(lbl_w, 8, "Name des Mitarbeiters:")
        self.set_font(self.font_family, '', 11)
        self.cell(line_w, 8, self.data.get('name', ''), border='B', new_x=XPos.LMARGIN, new_y=YPos.NEXT)
        self.ln(3)

        self.set_x(15)
        self.set_font(self.font_family, 'B', 11)
        self.cell(lbl_w, 8, "Abteilung:")
        self.set_font(self.font_family, '', 11)
        self.cell(line_w, 8, self.data.get('abteilung', ''), border='B', new_x=XPos.LMARGIN, new_y=YPos.NEXT)
        self.ln(3)

        self.set_x(15)
        self.set_font(self.font_family, 'B', 11)
        self.cell(lbl_w, 8, "Position:")
        self.set_font(self.font_family, '', 11)
        self.cell(line_w, 8, self.data.get('position', ''), border='B', new_x=XPos.LMARGIN, new_y=YPos.NEXT)

        self.set_font(self.font_family, '', 8)
        self.set_x(val_x)
        self.write(5, "(Änderungen sind unbedingt ")
        self.set_font(self.font_family, 'B', 8)
        self.write(5, "schriftlich")
        self.set_font(self.font_family, '', 8)
        self.write(5, " mitzuteilen)")
        self.ln(8)

        # --- TRENNLINIE 1 ---
        self.set_line_width(0.8)
        self.line(10, self.get_y(), 200, self.get_y())
        self.ln(8)

        # --- DATUMS-FELDER ---
        def thick_date_field(label, value):
            self.set_x(15)
            self.set_font(self.font_family, 'B', 10)
            self.cell(100, 10, label)
            
            start_x = 130
            end_x = 175
            y_line = self.get_y() + 7
            
            self.set_line_width(1.2)
            self.line(start_x, y_line, end_x, y_line)
            
            if value:
                self.set_font(self.font_family, '', 11)
                self.set_xy(start_x, self.get_y())
                self.cell(end_x - start_x, 7, str(value), align='C')
            
            self.set_xy(15, self.get_y() + 11)

        thick_date_field("erster tatsächlicher Urlaubstag:", self.data.get('erster_tag', ''))
        thick_date_field("letzter tatsächlicher Urlaubstag:", self.data.get('letzter_tag', ''))
        thick_date_field("reguläre freie Arbeitstage:", self.data.get('regulaere_freie_tage', ''))
        thick_date_field("Gesamtanzahl der tatsächlichen Urlaubstage:", self.data.get('gesamtzahl', '0'))
        thick_date_field("Unterschrift des Mitarbeiters:", "")

        self.ln(2)

        # --- TRENNLINIE 2 ---
        self.set_line_width(0.8)
        self.line(10, self.get_y(), 200, self.get_y())
        self.ln(6)

        # --- FÜR DEN ABTEILUNGSLEITER ---
        self.set_x(15)
        self.set_font(self.font_family, 'BU', 10)
        self.cell(0, 6, "Für den Abteilungsleiter:", new_x=XPos.LMARGIN, new_y=YPos.NEXT)
        self.ln(1)
        self.set_font(self.font_family, '', 9)
        self.set_x(15)
        self.cell(0, 5, "Dieser Urlaubsantrag ist erst verbindlich, wenn die Direktion ihn genehmigt hat.", new_x=XPos.LMARGIN, new_y=YPos.NEXT)
        self.ln(12)

        col1 = 15
        col2 = 110
        w1 = 60
        w2 = 80
        
        y_line = self.get_y()
        self.set_line_width(0.3)
        self.line(col1, y_line, col1 + w1, y_line)
        self.line(col2, y_line, col2 + w2, y_line)
        
        self.set_y(y_line + 1)
        self.set_font(self.font_family, 'B', 10)
        self.set_x(col1)
        self.cell(w1, 5, "Datum")
        self.set_x(col2)
        self.cell(w2, 5, "Unterschrift des Abteilungsleiters", new_x=XPos.LMARGIN, new_y=YPos.NEXT)
        self.ln(10)

        # --- TRENNLINIE 3 ---
        self.set_line_width(0.8)
        self.line(10, self.get_y(), 200, self.get_y())
        self.ln(8)

        # --- FUSSBEREICH ---
        self.set_font(self.font_family, '', 10)
        self.set_x(10)
        self.cell(60, 8, "Unterschrift Direktion:")
        y_line = self.get_y() + 6
        self.set_line_width(1.2)
        self.line(75, y_line, 125, y_line)
        self.ln(10)

        self.set_x(10)
        self.cell(60, 8, "eingetragen vom Personalbüro:")
        y_line = self.get_y() + 6
        self.line(75, y_line, 125, y_line)
        self.ln(8)

        # CHECKBOXES
        self.set_x(10)
        self.set_font(self.font_family, '', 10)
        box_y = self.get_y() + 1
        self.set_line_width(0.8)
        
        for ch in ["D", "G", "K", "S"]:
            self.cell(5, 6, ch)
            self.rect(self.get_x(), box_y, 4, 4)
            self.set_x(self.get_x() + 7)
            
        self.ln(12)

        # VERLAUF
        self.set_x(10)
        self.set_font(self.font_family, '', 7)
        self.cell(0, 5, "Verlauf: Auszufüllen durch AN -> Personalabteilung -> Abteilungsleiter -> Personalabteilung", align='L')


class UrlaubsantragEntryDialog(tk.Toplevel):
    """
    Dialogfenster zur Erfassung oder Bearbeitung eines Urlaubsantrags.
    Gibt die Daten als Dictionary zurück. Inklusive Kalender-Auswahl.
    """
    def __init__(self, parent, app_ref, entry_data=None):
        super().__init__(parent)
        self.transient(parent)
        self.grab_set()
        self.parent_app = app_ref
        self.result = None
        self.is_editing = entry_data is not None
        self.title("Urlaubsantrag Bearbeiten" if self.is_editing else "Neuer Urlaubsantrag")

        main_frame = ttk.Frame(self, padding=15)
        main_frame.pack(expand=True, fill="both")
        main_frame.columnconfigure(1, weight=1)
        
        try:
            base_font_family = tkFont.Font(font=self.parent_app.style.lookup('TLabel', 'font')).actual('family')
        except (tk.TclError, AttributeError):
            base_font_family = "Segoe UI"
        dialog_font = tkFont.Font(family=base_font_family, size=14)

        self.id_var = tk.StringVar()
        self.name_var = tk.StringVar()
        self.abteilung_var = tk.StringVar()
        self.position_var = tk.StringVar()
        self.erster_tag_var = tk.StringVar()
        self.letzter_tag_var = tk.StringVar()
        self.regulaere_freie_tage_var = tk.StringVar(value="")
        self.gesamtzahl_var = tk.StringVar(value="0")

        if self.is_editing and entry_data:
            self.id_var.set(entry_data.get('id', ''))
            self.name_var.set(entry_data.get('name', ''))
            self.abteilung_var.set(entry_data.get('abteilung', ''))
            self.position_var.set(entry_data.get('position', ''))
            self.erster_tag_var.set(entry_data.get('erster_tag', ''))
            self.letzter_tag_var.set(entry_data.get('letzter_tag', ''))
            self.regulaere_freie_tage_var.set(entry_data.get('regulaere_freie_tage', ''))
            self.gesamtzahl_var.set(str(entry_data.get('gesamtzahl', '0')))
        else:
            self.id_var.set(uuid.uuid4().hex)

        # Traces hinzufügen, damit sich die Summe LIVE automatisch berechnet
        self.erster_tag_var.trace_add("write", lambda *args: self._calculate_days())
        self.letzter_tag_var.trace_add("write", lambda *args: self._calculate_days())
        self.regulaere_freie_tage_var.trace_add("write", lambda *args: self._calculate_days())

        # Felder Definition mit Typ-Angabe (text, date oder number)
        fields =[
            ("Name d. Mitarbeiters:", self.name_var, "text"), 
            ("Abteilung:", self.abteilung_var, "text"), 
            ("Position:", self.position_var, "text"),
            None,
            ("Erster Tag (TT.MM.JJJJ):", self.erster_tag_var, "date"), 
            ("Letzter Tag (TT.MM.JJJJ):", self.letzter_tag_var, "date"),
            ("Reguläre freie Arbeitstage:", self.regulaere_freie_tage_var, "number")
        ]

        row = 0
        for item in fields:
            if item is None:
                ttk.Separator(main_frame, orient='horizontal').grid(row=row, column=0, columnspan=2, sticky='ew', pady=10)
                row += 1
                continue

            label_text, var, field_type = item
            ttk.Label(main_frame, text=label_text).grid(row=row, column=0, sticky="w", padx=5, pady=3)
            
            if field_type == "date":
                # Container für Eingabefeld + Kalender-Button
                date_frame = ttk.Frame(main_frame)
                date_frame.grid(row=row, column=1, sticky="ew", padx=5, pady=3)
                
                # Eingabefeld auf readonly setzen (nur Klick erlaubt)
                entry = ttk.Entry(date_frame, textvariable=var, font=dialog_font, state='readonly')
                entry.pack(side='left', fill='x', expand=True, ipady=8)
                
                def open_calendar(v=var):
                    CalendarPopup(self, v)
                    
                entry.bind('<Button-1>', lambda e, v=var: open_calendar(v))
                btn_cal = ttk.Button(date_frame, text="📅", width=4, command=lambda v=var: open_calendar(v))
                btn_cal.pack(side='left', padx=(4, 0))
                
                self.parent_app._bind_dialog_navigation(entry)
            else:
                entry = ttk.Entry(main_frame, textvariable=var, width=40, font=dialog_font)
                entry.grid(row=row, column=1, sticky="ew", padx=5, pady=3, ipady=8)
                self.parent_app._bind_dialog_navigation(entry)

            if row == 0: entry.focus_set()
            row += 1

        ttk.Label(main_frame, text="Gesamtanzahl der Tage:").grid(row=row, column=0, sticky="w", padx=5, pady=3)
        ttk.Label(main_frame, textvariable=self.gesamtzahl_var, relief="sunken", anchor="w", padding=(10, 8), font=dialog_font).grid(row=row, column=1, sticky="ew", padx=5, pady=3)
        row += 1

        button_frame = ttk.Frame(main_frame)
        button_frame.grid(row=row, column=0, columnspan=2, pady=(20, 0), sticky="ew")
        button_frame.columnconfigure((0, 1), weight=1)
        ipady = self.parent_app.current_settings.get('dialog_button_ipady', 5)
        
        save_button = ttk.Button(button_frame, text="Übernehmen", command=self.on_save)
        self.parent_app._configure_dialog_button(save_button, 'Dialog_Save', 'Übernehmen')
        save_button.grid(row=0, column=0, padx=5, ipady=ipady, sticky="ew")

        cancel_button = ttk.Button(button_frame, text="Abbrechen", command=self.on_cancel)
        self.parent_app._configure_dialog_button(cancel_button, 'Dialog_Cancel', 'Abbrechen')
        cancel_button.grid(row=0, column=1, padx=5, ipady=ipady, sticky="ew")
        self.protocol("WM_DELETE_WINDOW", self.on_cancel)

    def _calculate_days(self, event=None):
        try:
            start_str = self.erster_tag_var.get()
            end_str = self.letzter_tag_var.get()

            if not start_str or not end_str:
                self.gesamtzahl_var.set("0")
                return

            start_date = datetime.datetime.strptime(start_str, "%d.%m.%Y").date()
            end_date = datetime.datetime.strptime(end_str, "%d.%m.%Y").date()

            if end_date < start_date:
                self.gesamtzahl_var.set("0")
                return

            # Für die Hotellerie zählen wir ALLE Kalendertage (Mo-So)
            total_days_in_period = (end_date - start_date).days + 1

            try:
                # Prüft sicher, ob das Feld leer ist (wichtig beim Live-Tippen)
                reg_free_str = self.regulaere_freie_tage_var.get().strip()
                reg_free = int(reg_free_str) if reg_free_str else 0
            except ValueError:
                reg_free = 0

            # Zieht die regulär freien Tage von der Gesamtzeit ab
            final_vacation_days = total_days_in_period - reg_free
            if final_vacation_days < 0:
                final_vacation_days = 0
                
            self.gesamtzahl_var.set(str(final_vacation_days))

        except (ValueError, TypeError):
            self.gesamtzahl_var.set("Ungültiges Datum")

    def on_save(self):
        name = self.name_var.get().strip()
        if not name:
            messagebox.showerror("Fehler", "Der Name des Mitarbeiters darf nicht leer sein.", parent=self)
            return

        try:
            datetime.datetime.strptime(self.erster_tag_var.get(), "%d.%m.%Y")
            datetime.datetime.strptime(self.letzter_tag_var.get(), "%d.%m.%Y")
        except ValueError:
            messagebox.showerror("Fehler", "Bitte wählen Sie ein gültiges Datum aus.", parent=self)
            return

        self.result = {
            "id": self.id_var.get(),
            "name": name,
            "abteilung": self.abteilung_var.get().strip(),
            "position": self.position_var.get().strip(),
            "erster_tag": self.erster_tag_var.get().strip(),
            "letzter_tag": self.letzter_tag_var.get().strip(),
            "regulaere_freie_tage": self.regulaere_freie_tage_var.get().strip(),
            "gesamtzahl": self.gesamtzahl_var.get(),
        }
        self.destroy()

    def on_cancel(self):
        self.result = None
        self.destroy()

    def show(self):
        self.wait_window(self)
        return self.result
    
    
    




class UeberstundenantragPDF(FPDF):
    """
    Erstellt eine PDF-Datei für den Überstundenantrag.
    Basiert auf UrlaubsantragPDF mit geändertem Titel.
    """
    def __init__(self, data, logo_path=None):
        super().__init__('P', 'mm', 'A4')
        self.data = data
        self.logo_path = logo_path
        self.font_family = "Helvetica"
        try:
            font_dir = resource_path('fonts')
            dejavu_sans_path = os.path.join(font_dir, "DejaVuSans.ttf")
            dejavu_sans_bold_path = os.path.join(font_dir, "DejaVuSans-Bold.ttf")
            if os.path.exists(dejavu_sans_path) and os.path.exists(dejavu_sans_bold_path):
                self.add_font("DejaVuSans", "", dejavu_sans_path)
                self.add_font("DejaVuSans", "B", dejavu_sans_bold_path)
                self.font_family = "DejaVuSans"
        except Exception as e:
            print(f"PDF Font Warning (Ueberstundenantrag): {e}")

    def create_form(self):
        self.add_page()
        if self.logo_path and os.path.exists(self.logo_path):
            self.image(self.logo_path, x=10, y=8, w=40)
        self.set_y(20)
        self.set_font(self.font_family, 'B', 18)
        # Geänderter Titel
        self.cell(0, 10, "Überstundenantrag", new_x=XPos.LMARGIN, new_y=YPos.NEXT, align='C')
        self.ln(15)
        self.set_font(self.font_family, '', 11)
        x_label, x_value, y_pos, line_height = 20, 70, self.get_y(), 12
        self.set_y(y_pos); self.set_x(x_label)
        self.cell(50, 8, "Name des Mitarbeiters:")
        self.set_x(x_value); self.cell(0, 8, self.data.get('name', ''))
        y_pos += line_height
        self.set_y(y_pos); self.set_x(x_label)
        self.cell(50, 8, "Abteilung:")
        self.set_x(x_value); self.cell(0, 8, self.data.get('abteilung', ''))
        y_pos += line_height
        self.set_y(y_pos); self.set_x(x_label)
        self.cell(50, 8, "Position:")
        self.set_x(x_value); self.cell(0, 8, self.data.get('position', ''))
        y_pos += 8
        self.set_y(y_pos); self.set_x(x_value)
        self.set_font(self.font_family, '', 9)
        self.cell(0, 6, "(Änderungen sind unbedingt schriftlich mitzuteilen)")
        y_pos += 20
        self.set_font(self.font_family, '', 11)
        self.set_y(y_pos); self.set_x(x_label)
        self.cell(50, 8, "erster Tag:")
        self.set_x(x_value); self.cell(0, 8, self.data.get('erster_tag', ''))
        y_pos += line_height
        self.set_y(y_pos); self.set_x(x_label)
        self.cell(50, 8, "letzter Tag:")
        self.set_x(x_value); self.cell(0, 8, self.data.get('letzter_tag', ''))
        y_pos += line_height
        self.set_y(y_pos); self.set_x(x_label)
        self.cell(50, 8, "Gesamtanzahl der Tage:")
        self.set_x(x_value); self.cell(0, 8, str(self.data.get('gesamtzahl', '0')))
        y_pos += 25
        line_len, x_unterschrift_start = 75, 115
        y_pos_m_unterschrift = y_pos
        self.set_y(y_pos_m_unterschrift)
        self.line(x_label, self.get_y(), x_label + line_len, self.get_y())
        self.line(x_unterschrift_start, self.get_y(), x_unterschrift_start + line_len, self.get_y())
        self.set_y(y_pos_m_unterschrift + 1)
        self.set_x(x_label); self.cell(line_len, 8, "Datum", align='C')
        self.set_x(x_unterschrift_start); self.cell(line_len, 8, "Unterschrift des Mitarbeiters", align='C')
        y_pos_abt = y_pos_m_unterschrift + 25
        self.set_y(y_pos_abt); self.set_x(x_label)
        self.set_font(self.font_family, 'B', 11)
        self.cell(0, 8, "Für den Abteilungsleiter:", new_x=XPos.LMARGIN, new_y=YPos.NEXT)
        self.set_font(self.font_family, '', 11)
        # Geänderter Hinweistext
        self.set_x(x_label); self.cell(0, 8, "Dieser Überstundenantrag ist erst verbindlich, wenn die Direktion ihn genehmigt hat.", new_x=XPos.LMARGIN, new_y=YPos.NEXT)
        self.ln(8)
        y_pos_abt_unterschrift = self.get_y()
        self.set_y(y_pos_abt_unterschrift)
        self.line(x_label, self.get_y(), x_label + line_len, self.get_y())
        self.line(x_unterschrift_start, self.get_y(), x_unterschrift_start + line_len, self.get_y())
        self.set_y(y_pos_abt_unterschrift + 1)
        self.set_x(x_label); self.cell(line_len, 8, "Datum", align='C')
        self.set_x(x_unterschrift_start); self.cell(line_len, 8, "Unterschrift des Abteilungsleiters", align='C')
        y_pos_final = y_pos_abt_unterschrift + 30
        line_len_final = 170
        x_start_line_final = 20
        self.set_y(y_pos_final)
        self.line(x_start_line_final, self.get_y(), x_start_line_final + line_len_final, self.get_y())
        self.set_y(y_pos_final + 1)
        self.set_x(x_start_line_final)
        self.cell(line_len_final, 8, "Unterschrift Direktion", align='C')
        y_pos_personalbuero = y_pos_final + 20
        self.set_y(y_pos_personalbuero)
        self.line(x_start_line_final, self.get_y(), x_start_line_final + line_len_final, self.get_y())
        self.set_y(y_pos_personalbuero + 1)
        self.set_x(x_start_line_final)
        self.cell(line_len_final, 8, "eingetragen vom Personalbüro", align='C')


