class SafeToplevel(tk.Toplevel):
    """
    Eine Basisklasse für Toplevel-Fenster, die `after()`-Jobs sicher verwaltet.
    Alle geplanten Jobs werden beim Schließen des Fensters automatisch abgebrochen.
    """
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self._after_jobs = []

    def register_after_job(self, job_id):
        """Registriert eine `after()`-Job-ID zur späteren Bereinigung."""
        if job_id:
            self._after_jobs.append(job_id)
        return job_id

    def destroy(self):
        """Bricht alle registrierten `after()`-Jobs ab, bevor das Fenster zerstört wird."""
        for job_id in self._after_jobs:
            try:
                self.after_cancel(job_id)
            except (tk.TclError, ValueError):
                # Ignoriert Fehler, falls der Job bereits beendet wurde oder ungültig ist
                pass
        self._after_jobs = []
        super().destroy()
    

class CustomButtonDialog(tk.Toplevel):
    def __init__(self, parent, item=None, current_defs=None, temp_settings_ref=None, system_button_keys=None):
        super().__init__(parent)
        self.transient(parent)
        self.grab_set()
        self.parent = parent
        self.result = None
        self.item_to_edit = item
        self.is_editing = item is not None
        self.current_defs_for_validation = current_defs or []
        self.temp_settings_ref = temp_settings_ref
        self.system_button_keys = system_button_keys or []


        self.title("Eigenen Button Konfigurieren")

        main_frame = ttk.Frame(self, padding=15)
        main_frame.pack(expand=True, fill="both")

        self.key_var = tk.StringVar()
        self.label_var = tk.StringVar()
        self.type_var = tk.StringVar(value="symbol")
        self.symbol_value_var = tk.StringVar()
        self.image_path_var = tk.StringVar()
        self.command_placeholder_var = tk.StringVar()
        self.is_active_var = tk.BooleanVar(value=True)

        if self.is_editing and self.item_to_edit:
            self.key_var.set(self.item_to_edit.get('key', ''))
            self.label_var.set(self.item_to_edit.get('label', ''))
            self.type_var.set(self.item_to_edit.get('type', 'symbol'))
            self.symbol_value_var.set(self.item_to_edit.get('value', '') if self.item_to_edit.get('type') == 'symbol' else '✨')
            self.image_path_var.set(self.item_to_edit.get('value', '') if self.item_to_edit.get('type') == 'image' else '')
            self.command_placeholder_var.set(self.item_to_edit.get('command_placeholder', ''))
            self.is_active_var.set(self.item_to_edit.get('is_active', True))
        else:
            i = 1
            all_custom_buttons_in_temp = []
            if self.temp_settings_ref and 'custom_buttons' in self.temp_settings_ref:
                 all_custom_buttons_in_temp = self.temp_settings_ref['custom_buttons']
            while any(d.get('key') == f"CUSTOM_BTN_{i}" for d in all_custom_buttons_in_temp) or f"CUSTOM_BTN_{i}" in self.system_button_keys :
                i += 1
            self.key_var.set(f"CUSTOM_BTN_{i}")
            self.label_var.set("Neuer Button")
            self.symbol_value_var.set("✨")
            self.is_active_var.set(True)
            self.command_placeholder_var.set("Aktion ausführen...")


        row_idx = 0
        ttk.Label(main_frame, text="Key (intern, eindeutig):").grid(row=row_idx, column=0, sticky="w", padx=5, pady=3)
        self.key_entry = ttk.Entry(main_frame, textvariable=self.key_var, width=40)
        self.key_entry.grid(row=row_idx, column=1, columnspan=2, sticky="ew", padx=5, pady=3)
        row_idx += 1

        ttk.Label(main_frame, text="Anzeige-Label:").grid(row=row_idx, column=0, sticky="w", padx=5, pady=3)
        self.label_entry = ttk.Entry(main_frame, textvariable=self.label_var, width=40)
        self.label_entry.grid(row=row_idx, column=1, columnspan=2, sticky="ew", padx=5, pady=3)
        row_idx += 1

        ttk.Label(main_frame, text="Typ:").grid(row=row_idx, column=0, sticky="w", padx=5, pady=3)
        type_frame = ttk.Frame(main_frame)
        type_frame.grid(row=row_idx, column=1, columnspan=2, sticky="w", padx=5, pady=3)
        self.symbol_radio = ttk.Radiobutton(type_frame, text="Symbol", variable=self.type_var, value="symbol", command=self.toggle_type_fields)
        self.symbol_radio.pack(side="left", padx=(0,10))
        self.image_radio = ttk.Radiobutton(type_frame, text="Bild", variable=self.type_var, value="image", command=self.toggle_type_fields)
        self.image_radio.pack(side="left")
        row_idx += 1

        self.symbol_label = ttk.Label(main_frame, text="Symbol-Wert:")
        self.symbol_label.grid(row=row_idx, column=0, sticky="w", padx=5, pady=3)
        self.symbol_value_entry = ttk.Entry(main_frame, textvariable=self.symbol_value_var, width=10)
        self.symbol_value_entry.grid(row=row_idx, column=1, sticky="w", padx=5, pady=3)

        self.image_label = ttk.Label(main_frame, text="Bildpfad:")
        self.image_label.grid(row=row_idx, column=0, sticky="w", padx=5, pady=3)
        self.image_path_display = ttk.Label(main_frame, textvariable=self.image_path_var, relief="sunken", width=30, anchor="w")
        self.image_path_display.grid(row=row_idx, column=1, sticky="ew", padx=5, pady=3)
        self.browse_button = ttk.Button(main_frame, text="...", width=3, command=self.browse_image)
        self.browse_button.grid(row=row_idx, column=2, sticky="w", padx=5, pady=5)
        row_idx += 1


        ttk.Label(main_frame, text="Aktions-Platzhaltertext:").grid(row=row_idx, column=0, sticky="w", padx=5, pady=3)
        self.command_placeholder_entry = ttk.Entry(main_frame, textvariable=self.command_placeholder_var, width=40)
        self.command_placeholder_entry.grid(row=row_idx, column=1, columnspan=2, sticky="ew", padx=5, pady=3)
        row_idx += 1

        self.is_active_check = ttk.Checkbutton(main_frame, text="Button ist aktiv", variable=self.is_active_var)
        self.is_active_check.grid(row=row_idx, column=0, columnspan=3, sticky="w", padx=5, pady=10)
        row_idx += 1

        button_frame = ttk.Frame(main_frame)
        button_frame.grid(row=row_idx, column=0, columnspan=3, pady=10, sticky="ew")
        button_frame.columnconfigure(0, weight=1)
        button_frame.columnconfigure(1, weight=1)

        save_button = ttk.Button(button_frame, text="Speichern", command=self.on_save)
        save_button.grid(row=0, column=0, padx=5, sticky="ew")
        cancel_button = ttk.Button(button_frame, text="Abbrechen", command=self.on_cancel)
        cancel_button.grid(row=0, column=1, padx=5, sticky="ew")

        self.toggle_type_fields()
        self.protocol("WM_DELETE_WINDOW", self.on_cancel)
        self.key_entry.focus_set()


    def toggle_type_fields(self):
        if self.type_var.get() == "symbol":
            self.symbol_label.grid()
            self.symbol_value_entry.grid()
            self.image_label.grid_remove()
            self.image_path_display.grid_remove()
            self.browse_button.grid_remove()
        else:
            self.symbol_label.grid_remove()
            self.symbol_value_entry.grid_remove()
            self.image_label.grid()
            self.image_path_display.grid()
            self.browse_button.grid()

    def browse_image(self):
        initial_dir = ""
        current_path = self.image_path_var.get()
        if current_path and os.path.isfile(current_path):
            initial_dir = os.path.dirname(current_path)

        fpath = filedialog.askopenfilename(title="Bilddatei auswählen",
                                           initialdir=initial_dir if initial_dir else None,
                                           filetypes=[("Bilddateien", "*.png *.gif *.jpg *.jpeg"), ("Alle Dateien", "*.*")],
                                           parent=self)
        if fpath:
            self.image_path_var.set(fpath)

    def on_save(self):
        key = self.key_var.get().strip()
        label = self.label_var.get().strip()

        if not key or not label:
            messagebox.showerror("Fehler", "Key und Label dürfen nicht leer sein.", parent=self)
            return

        if " " in key:
            messagebox.showerror("Fehler", "Der Key darf keine Leerzeichen enthalten.", parent=self)
            return
        
        if key.upper() in [k.upper() for k in self.system_button_keys]:
            if not self.is_editing or (self.is_editing and self.item_to_edit.get('key').upper() != key.upper()):
                 messagebox.showerror("Fehler", f"Der Key '{key}' ist für einen System-Button reserviert.", parent=self)
                 return

        all_custom_buttons_in_temp = []
        if self.temp_settings_ref and 'custom_buttons' in self.temp_settings_ref:
            all_custom_buttons_in_temp = self.temp_settings_ref['custom_buttons']

        for button_def in all_custom_buttons_in_temp:
            if button_def.get('key').upper() == key.upper():
                if self.is_editing and self.item_to_edit and self.item_to_edit.get('key').upper() == key.upper():
                    continue
                else:
                    messagebox.showerror("Fehler", f"Der Key '{key}' wird bereits von einem anderen benutzerdefinierten Button verwendet.", parent=self)
                    return


        self.result = {
            'key': key,
            'label': label,
            'type': self.type_var.get(),
            'value': self.symbol_value_var.get() if self.type_var.get() == 'symbol' else self.image_path_var.get(),
            'command_placeholder': self.command_placeholder_var.get(),
            'is_active': self.is_active_var.get()
        }
        self.destroy()

    def on_cancel(self):
        self.result = None
        self.destroy()

    def show(self):
        self.parent.wait_window(self)
        return self.result

class TrinkgeldEntryDialog(tk.Toplevel):
    def __init__(self, parent, app_ref, entry_data=None, previous_day_total=None, selected_date_str=None):
        super().__init__(parent)
        self.transient(parent)
        self.grab_set()
        self.parent_widget = parent
        self.parent_app = app_ref

        self.result = None
        self.entry_data = entry_data
        self.is_editing = entry_data is not None

        self.title("Trinkgeld Eintrag Bearbeiten" if self.is_editing else "Neuer Trinkgeld Eintrag")
        
        main_frame = ttk.Frame(self, padding=15)
        main_frame.pack(expand=True, fill="both")

        self.datum_var = tk.StringVar()
        self.bestand_var = tk.StringVar(value="0,00 €")
        self.einnahme_f_var = tk.StringVar(value="0,00 €")
        self.entnahme_f_var = tk.StringVar(value="0,00 €")
        self.kuerzel_f_var = tk.StringVar()
        self.einnahme_s_var = tk.StringVar(value="0,00 €")
        self.entnahme_s_var = tk.StringVar(value="0,00 €")
        self.kuerzel_s_var = tk.StringVar()
        self.gesamt_display_var = tk.StringVar(value="0,00 €")

        if self.is_editing:
            self.datum_var.set(datetime.datetime.strptime(entry_data['datum'], "%Y-%m-%d").strftime("%d.%m.%Y"))
            self.bestand_var.set(self.parent_app._format_decimal_for_display(decimal.Decimal(str(entry_data.get('bestand', 0.0)))))
            self.einnahme_f_var.set(self.parent_app._format_decimal_for_display(decimal.Decimal(str(entry_data.get('einnahme_frueh', 0.0)))))
            self.entnahme_f_var.set(self.parent_app._format_decimal_for_display(decimal.Decimal(str(entry_data.get('entnahme_frueh', 0.0)))))
            self.kuerzel_f_var.set(entry_data.get('kuerzel_frueh', ''))
            self.einnahme_s_var.set(self.parent_app._format_decimal_for_display(decimal.Decimal(str(entry_data.get('einnahme_spaet', 0.0)))))
            self.entnahme_s_var.set(self.parent_app._format_decimal_for_display(decimal.Decimal(str(entry_data.get('entnahme_spaet', 0.0)))))
            self.kuerzel_s_var.set(entry_data.get('kuerzel_spaet', ''))
        else:
            self.datum_var.set(datetime.date.today().strftime("%d.%m.%Y"))
            if previous_day_total is not None:
                self.bestand_var.set(self.parent_app._format_decimal_for_display(decimal.Decimal(str(previous_day_total))))

        self._calculate_gesamt()


        size_settings = self.parent_app.current_settings.get('configurable_sizes', {})
        trinkgeld_config = size_settings.get('trinkgeldliste', {'font_size': 11, 'entry_width': 20})
        font_size = trinkgeld_config.get('font_size', 11)
        entry_width = trinkgeld_config.get('entry_width', 20)
        
        try:
            base_font_family = tkFont.Font(font=self.parent_app.style.lookup('TLabel', 'font')).actual('family')
        except (tk.TclError, AttributeError):
            base_font_family = "Segoe UI"
        dialog_font = tkFont.Font(family=base_font_family, size=font_size)
        sum_font = tkFont.Font(family=base_font_family, size=font_size, weight="bold")
        
        fields = [
            ("Datum (TT.MM.JJJJ):", self.datum_var, False),
            ("Bestand:", self.bestand_var, True),
            ("Einnahme Frühdienst:", self.einnahme_f_var, True),
            ("Entnahme Frühdienst:", self.entnahme_f_var, True),
            ("Kürzel Frühdienst:", self.kuerzel_f_var, False),
            ("Einnahme Spätdienst:", self.einnahme_s_var, True),
            ("Entnahme Spätdienst:", self.entnahme_s_var, True),
            ("Kürzel Spätdienst:", self.kuerzel_s_var, False),
            ("Gesamt:", self.gesamt_display_var, False)
        ]
        
        for i, (label_text, var, is_numeric) in enumerate(fields):
            ttk.Label(main_frame, text=label_text, font=dialog_font).grid(row=i, column=0, sticky="w", padx=5, pady=3)
            if label_text == "Gesamt:":
                entry = ttk.Label(main_frame, textvariable=var, style="BoldNumberDisplay.TLabel")
                entry.configure(font=sum_font)
            else:
                entry = ttk.Entry(main_frame, textvariable=var, width=entry_width, style="NumberInput.TEntry" if is_numeric else "TEntry")
                entry.configure(font=dialog_font)
                if is_numeric:
                    entry.bind("<FocusOut>", lambda e, v=var: self._format_and_recalculate_currency(e, v))
                    entry.bind("<Return>", lambda e, v=var: self._format_and_recalculate_currency(e, v))
                if label_text == "Datum (TT.MM.JJJJ):" and self.is_editing:
                    entry.config(state='readonly')

                # HIER WIRD DIE NAVIGATION HINZUGEFÜGT
                self.parent_app._bind_dialog_navigation(entry)

            entry.grid(row=i, column=1, sticky="ew", padx=5, pady=3)
        
        main_frame.columnconfigure(1, weight=1)

        button_frame = ttk.Frame(main_frame)
        button_frame.grid(row=len(fields), column=0, columnspan=2, pady=10, sticky="ew")
        button_frame.columnconfigure(0, weight=1)
        button_frame.columnconfigure(1, weight=1)
        button_frame.columnconfigure(2, weight=1)

        ipady = self.parent_app.current_settings.get('dialog_button_ipady', 5)

        update_button = ttk.Button(button_frame, command=self._update_date, style='TButton')
        self.parent_app._configure_dialog_button(update_button, 'Dialog_Update', 'Aktualisieren')
        update_button.grid(row=0, column=0, padx=5, ipady=ipady, sticky="ew")
        if self.is_editing:
            update_button.config(state="disabled")
        
        save_button = ttk.Button(button_frame, command=self.on_save, style='TButton')
        self.parent_app._configure_dialog_button(save_button, 'Dialog_Save', 'Speichern')
        save_button.grid(row=0, column=1, padx=5, ipady=ipady, sticky="ew")

        cancel_button = ttk.Button(button_frame, command=self.on_cancel, style='TButton')
        self.parent_app._configure_dialog_button(cancel_button, 'Dialog_Cancel', 'Abbrechen')
        cancel_button.grid(row=0, column=2, padx=5, ipady=ipady, sticky="ew")
        
        self.protocol("WM_DELETE_WINDOW", self.on_cancel)
        if main_frame.winfo_children():
             for child in main_frame.winfo_children():
                 if isinstance(child, ttk.Entry) and child.cget('textvariable') == str(self.kuerzel_f_var):
                     child.focus_set()
                     break

    def _format_and_recalculate_currency(self, event, string_var):
        self.parent_app._format_on_focus_out(event, string_var, is_count=False)
        self._calculate_gesamt()

    def _calculate_gesamt(self):
        try:
            bestand = self.parent_app._parse_input_string(self.bestand_var.get()) or decimal.Decimal('0')
            e_f = self.parent_app._parse_input_string(self.einnahme_f_var.get()) or decimal.Decimal('0')
            ent_f = self.parent_app._parse_input_string(self.entnahme_f_var.get()) or decimal.Decimal('0')
            e_s = self.parent_app._parse_input_string(self.einnahme_s_var.get()) or decimal.Decimal('0')
            ent_s = self.parent_app._parse_input_string(self.entnahme_s_var.get()) or decimal.Decimal('0')
            gesamt = bestand + e_f - abs(ent_f) + e_s - abs(ent_s)
            self.gesamt_display_var.set(self.parent_app._format_decimal_for_display(gesamt))
        except Exception:
            self.gesamt_display_var.set(self.parent_app._format_decimal_for_display(decimal.Decimal('0')))

    def _update_date(self):
        self.datum_var.set(datetime.date.today().strftime("%d.%m.%Y"))

    def on_save(self):
        # Button deaktivieren, um Doppelklicks zu verhindern
        try:
            # Versucht, den Speichern-Button zu finden (er ist das 3. Kind im btn_frame oder wir navigieren über die GUI-Struktur)
            # Da wir keine direkte Referenz auf den Button als self.variable haben, iterieren wir kurz:
            for widget in self.winfo_children():
                if isinstance(widget, ttk.Frame): # Button Frame
                    for btn in widget.winfo_children():
                        if isinstance(btn, ttk.Button) and btn.cget('text') == "Speichern":
                            btn.config(state='disabled')
        except Exception:
            pass # Ignorieren, falls Button nicht gefunden, UI-Logik soll nicht crashen

        try:
            datum_str_display = self.datum_var.get()
            datum_obj = datetime.datetime.strptime(datum_str_display, "%d.%m.%Y").date()
            datum_iso = datum_obj.isoformat()
        except ValueError:
            messagebox.showerror("Fehler", "Ungültiges Datumsformat. Bitte TT.MM.JJJJ verwenden.", parent=self)
            # Button wieder aktivieren bei Fehler
            self._reenable_save_button()
            return

        # Validierung der Entnahmen
        try:
            entnahme_f = self.parent_app._parse_input_string(self.entnahme_f_var.get()) or decimal.Decimal('0')
            entnahme_s = self.parent_app._parse_input_string(self.entnahme_s_var.get()) or decimal.Decimal('0')

            if entnahme_f < 0 or entnahme_s < 0:
                messagebox.showerror("Ungültige Eingabe", "Entnahmen müssen als positive Beträge erfasst werden.", parent=self)
                self._reenable_save_button()
                return
        except (ValueError, TypeError, decimal.InvalidOperation):
            messagebox.showerror("Fehler", "Ungültiges Zahlenformat in einem der Entnahmefelder.", parent=self)
            self._reenable_save_button()
            return

        kuerzel_f = self.kuerzel_f_var.get().strip()
        kuerzel_s = self.kuerzel_s_var.get().strip()

        if not kuerzel_f:
            messagebox.showerror("Pflichtfeld fehlt", "Das Kürzel für den Frühdienst muss ausgefüllt werden.", parent=self)
            self._reenable_save_button()
            return
        if not kuerzel_s:
            messagebox.showerror("Pflichtfeld fehlt", "Das Kürzel für den Spätdienst muss ausgefüllt werden.", parent=self)
            self._reenable_save_button()
            return

        allowed_kuerzel_list = self.parent_app.current_settings.get('trinkgeld_kuerzel_list', [])
        allowed_kuerzel = {k.upper() for k in allowed_kuerzel_list}
        
        if kuerzel_f.upper() not in allowed_kuerzel:
            messagebox.showerror("Ungültiges Kürzel", f"Kürzel '{kuerzel_f}' ist nicht zulässig.", parent=self)
            self._reenable_save_button()
            return

        if kuerzel_s.upper() not in allowed_kuerzel:
            messagebox.showerror("Ungültiges Kürzel", f"Kürzel '{kuerzel_s}' ist nicht zulässig.", parent=self)
            self._reenable_save_button()
            return

        self._calculate_gesamt()

        self.result = {
            "datum": datum_iso,
            "bestand": float(self.parent_app._parse_input_string(self.bestand_var.get()) or 0.0),
            "einnahme_frueh": float(self.parent_app._parse_input_string(self.einnahme_f_var.get()) or 0.0),
            "entnahme_frueh": float(self.parent_app._parse_input_string(self.entnahme_f_var.get()) or 0.0),
            "kuerzel_frueh": kuerzel_f.upper(),
            "einnahme_spaet": float(self.parent_app._parse_input_string(self.einnahme_s_var.get()) or 0.0),
            "entnahme_spaet": float(self.parent_app._parse_input_string(self.entnahme_s_var.get()) or 0.0),
            "kuerzel_spaet": kuerzel_s.upper(),
            "gesamt": float(self.parent_app._parse_input_string(self.gesamt_display_var.get()) or 0.0)
        }
        self.destroy()
        
    def _reenable_save_button(self):
        """Hilfsmethode, um den Button bei Validierungsfehlern wieder zu aktivieren."""
        try:
            for widget in self.winfo_children():
                if isinstance(widget, ttk.Frame):
                    for btn in widget.winfo_children():
                        if isinstance(btn, ttk.Button) and btn.cget('text') == "Speichern":
                            btn.config(state='normal')
        except Exception: pass
        
    # vvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvv
    # HIER BEGINNT DIE FEHLENDE METHODE
    # vvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvv
    def on_cancel(self):
        self.result = None
        self.destroy()
    # ^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^
    # HIER ENDET DIE FEHLENDE METHODE
    # ^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^

    def show(self):
        self.parent_widget.wait_window(self) 
        return self.result



