class MinibarEntryDialog(tk.Toplevel):
    def __init__(self, parent, app_ref, entry_data=None, selected_date_str=None, minibar_items_definitions=None):
        super().__init__(parent)
        self.transient(parent)
        self.grab_set()
        self.parent_widget = parent
        self.parent_app = app_ref
        self.result_action = None
        self.is_editing = entry_data is not None
        self.minibar_items_definitions = minibar_items_definitions if minibar_items_definitions else []

        self.title("Minibar Eintrag Bearbeiten" if self.is_editing else "Neue Minibar Einträge")
        
        main_frame = ttk.Frame(self, padding=15)
        main_frame.pack(expand=True, fill="both")

        # HIER IST DIE ANPASSUNG: LÄDT DIE GRÖSSEN AUS DEN EINSTELLUNGEN
        size_settings = self.parent_app.current_settings.get('configurable_sizes', {})
        minibar_config = size_settings.get('minibarliste', {'font_size': 14, 'entry_width': 25})
        font_size = minibar_config.get('font_size', 14)
        
        try:
            base_font_family = tkFont.Font(font=self.parent_app.style.lookup('TLabel', 'font')).actual('family')
        except (tk.TclError, AttributeError):
            base_font_family = "Segoe UI"
        
        dialog_font = tkFont.Font(family=base_font_family, size=font_size)
        sum_font = tkFont.Font(family=base_font_family, size=font_size, weight="bold")
        
        entry_ipady = 8 
        
        self.id_var = tk.StringVar()
        self.datum_var = tk.StringVar()
        self.artikel_name_var = tk.StringVar()
        self.menge_var = tk.StringVar(value="1")
        self.verlust_anzahl_var = tk.StringVar(value="0")
        self.preis_pro_stueck_var = tk.StringVar(value="0,00 €")
        self.gesamt_umsatz_display_var = tk.StringVar(value="0,00 €")

        active_item_names = [item['name'] for item in self.minibar_items_definitions if item.get('is_active', True)]
        active_item_names.sort()

        if self.is_editing and entry_data:
            self.id_var.set(entry_data.get('id', ''))
            self.datum_var.set(datetime.datetime.strptime(entry_data['datum'], "%Y-%m-%d").strftime("%d.%m.%Y"))
            self.artikel_name_var.set(entry_data.get('artikel_name', ''))
            self.menge_var.set(str(entry_data.get('menge', 1)))
            self.verlust_anzahl_var.set(str(entry_data.get('verlust_anzahl', 0)))
            self.preis_pro_stueck_var.set(self.parent_app._format_decimal_for_display(decimal.Decimal(str(entry_data.get('preis_pro_stueck', 0.0)))))
        else:
            self.id_var.set(uuid.uuid4().hex)
            self.datum_var.set(selected_date_str if selected_date_str else datetime.date.today().strftime("%d.%m.%Y"))
            if active_item_names:
                self.artikel_name_var.set(active_item_names[0])
                self._update_price_from_selected_item()

        self._calculate_gesamt_umsatz()

        row_idx = 0
        ttk.Label(main_frame, text="Datum (TT.MM.JJJJ):", font=dialog_font).grid(row=row_idx, column=0, sticky="w", padx=5, pady=3)
        self.datum_entry = ttk.Entry(main_frame, textvariable=self.datum_var, font=dialog_font, width=25)
        self.datum_entry.grid(row=row_idx, column=1, sticky="ew", padx=5, pady=3, ipady=entry_ipady)
        if self.is_editing:
            self.datum_entry.config(state='readonly')
        self.parent_app._bind_dialog_navigation(self.datum_entry)
        row_idx += 1
        
        ttk.Label(main_frame, text="Artikel:", font=dialog_font).grid(row=row_idx, column=0, sticky="w", padx=5, pady=3)
        self.artikel_combo = ttk.Combobox(main_frame, textvariable=self.artikel_name_var, values=active_item_names, font=dialog_font, width=23, state="readonly")
        self.artikel_combo.grid(row=row_idx, column=1, sticky="ew", padx=5, pady=3, ipady=entry_ipady)
        self.artikel_combo.bind("<<ComboboxSelected>>", self._on_artikel_selected)
        self.parent_app._bind_dialog_navigation(self.artikel_combo)
        row_idx += 1

        ttk.Label(main_frame, text="Menge:", font=dialog_font).grid(row=row_idx, column=0, sticky="w", padx=5, pady=3)
        self.menge_entry = ttk.Entry(main_frame, textvariable=self.menge_var, font=dialog_font, width=25, style="NumberInput.TEntry")
        self.menge_entry.grid(row=row_idx, column=1, sticky="ew", padx=5, pady=3, ipady=entry_ipady)
        self.menge_entry.bind("<FocusOut>", lambda e, v=self.menge_var: self._format_and_recalculate_numeric(e, v, is_count=True))
        self.menge_entry.bind("<Return>", lambda e, v=self.menge_var: self._format_and_recalculate_numeric(e, v, is_count=True))
        self.parent_app._bind_dialog_navigation(self.menge_entry)
        row_idx += 1

        ttk.Label(main_frame, text="Verlustanzahl:", font=dialog_font).grid(row=row_idx, column=0, sticky="w", padx=5, pady=3)
        self.verlust_entry = ttk.Entry(main_frame, textvariable=self.verlust_anzahl_var, font=dialog_font, width=25, style="NumberInput.TEntry")
        self.verlust_entry.grid(row=row_idx, column=1, sticky="ew", padx=5, pady=3, ipady=entry_ipady)
        self.verlust_entry.bind("<FocusOut>", lambda e, v=self.verlust_anzahl_var: self._format_and_recalculate_numeric(e, v, is_count=True))
        self.verlust_entry.bind("<Return>", lambda e, v=self.verlust_anzahl_var: self._format_and_recalculate_numeric(e, v, is_count=True))
        self.parent_app._bind_dialog_navigation(self.verlust_entry)
        row_idx += 1

        ttk.Label(main_frame, text="Preis/Stück:", font=dialog_font).grid(row=row_idx, column=0, sticky="w", padx=5, pady=3)
        self.preis_entry = ttk.Entry(main_frame, textvariable=self.preis_pro_stueck_var, font=dialog_font, width=25, style="NumberInput.TEntry")
        self.preis_entry.grid(row=row_idx, column=1, sticky="ew", padx=5, pady=3, ipady=entry_ipady)
        self.preis_entry.bind("<FocusOut>", lambda e, v=self.preis_pro_stueck_var: self._format_and_recalculate_numeric(e, v))
        self.preis_entry.bind("<Return>", lambda e, v=self.preis_pro_stueck_var: self._format_and_recalculate_numeric(e, v))
        self.parent_app._bind_dialog_navigation(self.preis_entry)
        row_idx += 1

        ttk.Label(main_frame, text="Gesamtumsatz:", font=dialog_font).grid(row=row_idx, column=0, sticky="w", padx=5, pady=3)
        ttk.Label(main_frame, textvariable=self.gesamt_umsatz_display_var, font=sum_font, style="BoldNumberDisplay.TLabel").grid(row=row_idx, column=1, sticky="ew", padx=5, pady=3)
        row_idx += 1
        
        main_frame.columnconfigure(1, weight=1)

        button_frame = ttk.Frame(main_frame)
        button_frame.grid(row=row_idx, column=0, columnspan=2, pady=10, sticky="ew")
        button_frame.columnconfigure((0, 1, 2), weight=1)

        ipady = self.parent_app.current_settings.get('dialog_button_ipady', 5)
        button_configs = self.parent_app.current_settings.get('minibar_dialog_button_configs', {})

        add_button = ttk.Button(button_frame, text="Hinzufügen", command=self.on_add_and_continue)
        self.parent_app._configure_list_tab_button(add_button, 'Minibar_SaveCont', 'Hinzufügen', button_config_source=button_configs)
        add_button.grid(row=0, column=0, padx=5, ipady=ipady, sticky="ew")
        
        close_button = ttk.Button(button_frame, text="Fertig", command=self.on_close)
        self.parent_app._configure_list_tab_button(close_button, 'Minibar_SaveClose', 'Fertig', button_config_source=button_configs)
        close_button.grid(row=0, column=1, padx=5, ipady=ipady, sticky="ew")

        save_and_close_button = ttk.Button(button_frame, text="Speichern & Schließen", command=self.on_save_and_close)
        self.parent_app._configure_list_tab_button(save_and_close_button, 'Minibar_SaveClose', 'Speichern & Schließen', button_config_source=button_configs)

        if self.is_editing:
            add_button.grid_remove()
            close_button.grid_remove()
            save_and_close_button.grid(row=0, column=0, columnspan=2, padx=5, ipady=ipady, sticky="ew")
        
        self.protocol("WM_DELETE_WINDOW", self.on_close)
        self.artikel_combo.focus_set()

    def _get_data_from_fields(self):
        try:
            datum_obj = datetime.datetime.strptime(self.datum_var.get(), "%d.%m.%Y").date()
        except ValueError:
            messagebox.showerror("Fehler", "Ungültiges Datumsformat. Bitte TT.MM.JJJJ verwenden.", parent=self)
            return None

        artikel_name = self.artikel_name_var.get()
        if not artikel_name:
            messagebox.showerror("Fehler", "Bitte einen Artikel auswählen.", parent=self)
            return None
        
        try:
            menge = int(self.menge_var.get())
            verlust = int(self.verlust_anzahl_var.get())
            if menge < 0 or verlust < 0 or verlust > menge:
                messagebox.showerror("Fehler", "Menge und Verlust müssen gültige, positive Zahlen sein, wobei der Verlust nicht größer als die Menge sein darf.", parent=self)
                return None
        except ValueError:
            messagebox.showerror("Fehler", "Menge und Verlust müssen ganze Zahlen sein.", parent=self)
            return None
        
        preis_pro_stk = self.parent_app._parse_input_string(self.preis_pro_stueck_var.get())
        if preis_pro_stk is None or preis_pro_stk < 0:
            messagebox.showerror("Fehler", "Ungültiger Preis pro Stück.", parent=self)
            return None

        self._calculate_gesamt_umsatz()
        
        return {
            "id": self.id_var.get(), "datum": datum_obj.isoformat(),
            "artikel_name": artikel_name, "menge": menge, "verlust_anzahl": verlust,
            "preis_pro_stueck": float(preis_pro_stk),
            "gesamt_umsatz": float(self.parent_app._parse_input_string(self.gesamt_umsatz_display_var.get()) or 0.0)
        }

    def on_save_and_close(self):
        data = self._get_data_from_fields()
        if data:
            self._process_data_in_main_app(data, is_editing=True)
            self.destroy()

    def on_add_and_continue(self):
        data = self._get_data_from_fields()
        if data:
            self._process_data_in_main_app(data, is_editing=False)
            SuccessToast(self, title="Gespeichert", message=f"{data['artikel_name']} wurde hinzugefügt.", toast_type='success', colors=self.parent_app.current_settings.get('toast_colors'), duration=2000)
            self._reset_for_next_entry()

# In der Klasse MinibarEntryDialog
    def _process_data_in_main_app(self, data, is_editing):
        period_key = data['datum'][:7]
        
        if is_editing:
            # (Logic zum Finden und Ersetzen...)
            for i, entry in enumerate(self.parent_app.minibar_data_cache.get(period_key, [])):
                if entry.get("id") == data["id"]:
                    self.parent_app.minibar_data_cache[period_key][i] = data
                    self.parent_app._save_list_entry_to_history(data, "Bearbeitet", "Minibar")
                    break
        else:
            self.parent_app.minibar_data_cache.setdefault(period_key, []).append(data)
            self.parent_app._save_list_entry_to_history(data, "Hinzugefügt", "Minibar")
        
        self.parent_app._save_minibar_data()
        
        # AUTOMATISCHES BACKUP (ask_confirmation=False erzwingen)
        self.parent_app._perform_manual_backup_minibar(ask_confirmation=False)
        
        self.parent_app._load_and_display_minibar_for_period()

    def _reset_for_next_entry(self):
        self.id_var.set(uuid.uuid4().hex)
        self.menge_var.set("1")
        self.verlust_anzahl_var.set("0")
        self.artikel_combo.focus_set()
        self._calculate_gesamt_umsatz()

    def on_close(self):
        """
        Asks for confirmation before closing the dialog. If the user wants to
        continue adding items, the window remains open.
        """
        if messagebox.askyesno("Weitere Einträge?",
                               "Möchten Sie noch weitere Artikel hinzufügen?",
                               icon='question', parent=self):
            # User clicked "Ja" -> do nothing, just keep the window open
            self.artikel_combo.focus_set() # Set focus back to a useful field
        else:
            # User clicked "Nein" -> close the window
            self.destroy()

    def on_cancel(self):
        """
        When "Abbrechen" is clicked, it now triggers the same confirmation logic
        as closing the window via the 'X' button or 'Fertig'.
        """
        self.on_close()

    def show(self):
        self.wait_window(self)
    
    def _on_artikel_selected(self, event=None):
        self._update_price_from_selected_item()
        self._calculate_gesamt_umsatz()

    def _update_price_from_selected_item(self):
        selected_name = self.artikel_name_var.get()
        for item_def in self.minibar_items_definitions:
            if item_def.get('name') == selected_name:
                price = decimal.Decimal(str(item_def.get('price', 0.0)))
                self.preis_pro_stueck_var.set(self.parent_app._format_decimal_for_display(price))
                return
        self.preis_pro_stueck_var.set(self.parent_app._format_decimal_for_display(decimal.Decimal('0.0')))

    def _format_and_recalculate_numeric(self, event, string_var, is_count=False):
        self.parent_app._format_on_focus_out(event, string_var, is_count=is_count)
        self._calculate_gesamt_umsatz()

    def _calculate_gesamt_umsatz(self):
        try:
            menge_str = self.menge_var.get()
            menge = int("".join(filter(str.isdigit, menge_str)) or '0')
            
            verlust_str = self.verlust_anzahl_var.get()
            verlust = int("".join(filter(str.isdigit, verlust_str)) or '0')

            menge_netto = max(0, menge - verlust)

            preis_str = self.preis_pro_stueck_var.get()
            preis = self.parent_app._parse_input_string(preis_str) or decimal.Decimal('0')
            
            gesamt = decimal.Decimal(menge_netto) * preis
            self.gesamt_umsatz_display_var.set(self.parent_app._format_decimal_for_display(gesamt))
        except Exception:
            self.gesamt_umsatz_display_var.set(self.parent_app._format_decimal_for_display(decimal.Decimal('0')))

class WeckrufEntryDialog(tk.Toplevel):
    def __init__(self, parent, app_ref, entry_data=None):
        super().__init__(parent)
        self.transient(parent)
        self.grab_set()
        self.parent_app = app_ref

        self.result = None
        self.is_editing = entry_data is not None
        self.title("Weckruf bearbeiten" if self.is_editing else "Neuer Weckruf")

        main_frame = ttk.Frame(self, padding=15)
        main_frame.pack(expand=True, fill="both")

        self.id_var = tk.StringVar()
        self.datum_var = tk.StringVar()
        self.zeit_var = tk.StringVar()
        self.zimmer_var = tk.StringVar()
        self.gastname_var = tk.StringVar()
        self.kuerzel_var = tk.StringVar()

        if self.is_editing and entry_data:
            self.id_var.set(entry_data.get('id', ''))
            self.datum_var.set(datetime.datetime.strptime(entry_data.get('datum', ''), "%Y-%m-%d").strftime("%d.%m.%Y"))
            self.zeit_var.set(entry_data.get('zeit', '08:00')[:5])
            self.zimmer_var.set(entry_data.get('zimmer', ''))
            self.gastname_var.set(entry_data.get('gastname', ''))
            self.kuerzel_var.set(entry_data.get('kuerzel', ''))
        else:
            self.id_var.set(uuid.uuid4().hex)
            self.datum_var.set(datetime.date.today().strftime("%d.%m.%Y"))
            self.zeit_var.set("08:00")

        fields = [
            ("Datum (TT.MM.JJJJ):", self.datum_var),
            ("Weckzeit (HH:MM):", self.zeit_var),
            ("Zimmer:", self.zimmer_var),
            ("Gastname(n):", self.gastname_var),
            ("Kürzel:", self.kuerzel_var),
        ]

        size_settings = self.parent_app.current_settings.get('configurable_sizes', {})
        weckruf_config = size_settings.get('weckrufliste', {'font_size': 11, 'entry_width': 30})
        
        font_size = weckruf_config.get('font_size', 11)
        entry_width = weckruf_config.get('entry_width', 30)

        try:
            base_font_family = tkFont.Font(font=self.parent_app.style.lookup('TLabel', 'font')).actual('family')
        except (tk.TclError, AttributeError):
            base_font_family = "Segoe UI"
        dialog_font = tkFont.Font(family=base_font_family, size=font_size)

        for i, (label_text, var) in enumerate(fields):
            label = ttk.Label(main_frame, text=label_text, font=dialog_font)
            label.grid(row=i, column=0, sticky="w", padx=5, pady=3)
            
            entry = ttk.Entry(main_frame, textvariable=var, width=entry_width, font=dialog_font)
            entry.grid(row=i, column=1, sticky="ew", padx=5, pady=3)
            if label_text == "Zimmer:":
                entry.focus_set()
            
            # HIER WIRD DIE NAVIGATION HINZUGEFÜGT
            self.parent_app._bind_dialog_navigation(entry)

        main_frame.columnconfigure(1, weight=1)

        button_frame = ttk.Frame(main_frame)
        button_frame.grid(row=len(fields), column=0, columnspan=2, pady=10, sticky="ew")
        button_frame.columnconfigure(0, weight=1)
        button_frame.columnconfigure(1, weight=1)

        ipady = self.parent_app.current_settings.get('dialog_button_ipady', 5)
        save_button = ttk.Button(button_frame, command=self.on_save)
        self.parent_app._configure_dialog_button(save_button, 'Dialog_Save', 'Speichern')
        save_button.grid(row=0, column=0, padx=5, ipady=ipady, sticky="ew")

        cancel_button = ttk.Button(button_frame, command=self.on_cancel)
        self.parent_app._configure_dialog_button(cancel_button, 'Dialog_Cancel', 'Abbrechen')
        cancel_button.grid(row=0, column=1, padx=5, ipady=ipady, sticky="ew")

        self.protocol("WM_DELETE_WINDOW", self.on_cancel)
    def on_save(self):
        try:
            datum_obj = datetime.datetime.strptime(self.datum_var.get(), "%d.%m.%Y").date()
        except ValueError:
            messagebox.showerror("Fehler", "Ungültiges Datumsformat. Bitte TT.MM.JJJJ verwenden.", parent=self)
            return
            
        try:
            time.strptime(self.zeit_var.get(), '%H:%M')
        except ValueError:
            messagebox.showerror("Fehler", "Ungültiges Zeitformat. Bitte HH:MM verwenden.", parent=self)
            return

        zimmer = self.zimmer_var.get().strip()
        gastname = self.gastname_var.get().strip()
        kuerzel = self.kuerzel_var.get().strip()

        if not zimmer or not gastname or not kuerzel:
            messagebox.showerror("Fehler", "Zimmer, Gastname und Kürzel dürfen nicht leer sein.", parent=self)
            return

        self.result = {
            "id": self.id_var.get(),
            "datum": datum_obj.isoformat(),
            "zeit": self.zeit_var.get(),
            "zimmer": zimmer,
            "gastname": gastname,
            "kuerzel": kuerzel.upper()
        }
        self.destroy()

    def on_cancel(self):
        self.result = None
        self.destroy()

    def show(self):
        self.wait_window(self)
        return self.result
    

class ShuttleEntryDialog(tk.Toplevel):
    def __init__(self, parent, app_ref, entry_data=None, booking_type='Hinfahrt', save_callback=None):
        super().__init__(parent)
        self.transient(parent)
        self.grab_set()
        self.parent_app = app_ref
        self.save_callback = save_callback

        self.result = None
        self.is_editing = entry_data is not None
        self.entry_data = entry_data
        self.booking_type = booking_type
        self.title(f"Shuttle {self.booking_type} {'bearbeiten' if self.is_editing else 'buchen'}")

        main_frame = ttk.Frame(self, padding=15)
        main_frame.pack(expand=True, fill="both")

        self.id_var = tk.StringVar()
        self.datum_var = tk.StringVar()
        self.zeit_var = tk.StringVar()
        self.zimmer_var = tk.StringVar()
        self.gastname_var = tk.StringVar()
        self.personen_var = tk.StringVar()

        # --- Zeitlogik ---
        if self.booking_type == 'Hinfahrt':
            start_time = datetime.time(7, 0)
            end_time = datetime.time(10, 30)
        else:
            start_time = datetime.time(17, 0)
            end_time = datetime.time(20, 0)

        alle_zeiten = []
        current_time = datetime.datetime.combine(datetime.date.today(), start_time)
        end_datetime = datetime.datetime.combine(datetime.date.today(), end_time)
        while current_time <= end_datetime:
            alle_zeiten.append(current_time.strftime("%H:%M"))
            current_time += datetime.timedelta(minutes=30)

        kapazitaetsgrenze = 5
        buchungszaehler = {}

        for buchung in self.parent_app.shuttle_data_cache:
            if buchung.get('type') == self.booking_type:
                uhrzeit = buchung.get('zeit')
                if uhrzeit:
                    buchungszaehler[uhrzeit] = buchungszaehler.get(uhrzeit, 0) + 1

        verfuegbare_zeiten = []
        for uhrzeit in alle_zeiten:
            anzahl_buchungen = buchungszaehler.get(uhrzeit, 0)
            
            if anzahl_buchungen < kapazitaetsgrenze:
                verfuegbare_zeiten.append(uhrzeit)
            elif self.is_editing and self.entry_data.get('zeit') == uhrzeit:
                verfuegbare_zeiten.append(uhrzeit)

        # --- Initialisierung der Felder ---
        if self.is_editing and entry_data:
            self.id_var.set(entry_data.get('id', ''))
            self.datum_var.set(entry_data.get('datum', datetime.date.today().strftime("%d.%m.%Y")))
            if entry_data.get('zeit') not in verfuegbare_zeiten:
                verfuegbare_zeiten.append(entry_data.get('zeit'))
                verfuegbare_zeiten.sort()
            self.zeit_var.set(entry_data.get('zeit'))
            self.zimmer_var.set(entry_data.get('zimmer', ''))
            self.gastname_var.set(entry_data.get('gastname', ''))
            self.personen_var.set(str(entry_data.get('personen', '1')))
        else:
            self.id_var.set(uuid.uuid4().hex)
            self.datum_var.set(datetime.date.today().strftime("%d.%m.%Y"))
            if verfuegbare_zeiten:
                self.zeit_var.set(verfuegbare_zeiten[0])
            self.personen_var.set("1")

        fields = [
            ("Datum (TT.MM.JJJJ):", self.datum_var),
            ("Uhrzeit:", self.zeit_var),
            ("Zimmer:", self.zimmer_var),
            ("Gastname(n):", self.gastname_var),
            ("Anzahl der Personen:", self.personen_var),
        ]

        size_settings = self.parent_app.current_settings.get('configurable_sizes', {})
        shuttle_config = size_settings.get('shuttle_service', {'font_size': 11, 'entry_width': 30})
        font_size = shuttle_config.get('font_size', 11)
        entry_width = shuttle_config.get('entry_width', 30)
        
        try:
            base_font_family = tkFont.Font(font=self.parent_app.style.lookup('TLabel', 'font')).actual('family')
        except (tk.TclError, AttributeError):
            base_font_family = "Segoe UI"
        dialog_font = tkFont.Font(family=base_font_family, size=font_size)

        for i, (label_text, var) in enumerate(fields):
            label = ttk.Label(main_frame, text=label_text, font=dialog_font)
            label.grid(row=i, column=0, sticky="w", padx=5, pady=3)

            if label_text == "Uhrzeit:":
                entry = ttk.Combobox(main_frame, textvariable=var, values=verfuegbare_zeiten, width=entry_width - 2, font=dialog_font)
            else:
                entry = ttk.Entry(main_frame, textvariable=var, width=entry_width, font=dialog_font)
            
            entry.grid(row=i, column=1, sticky="ew", padx=5, pady=3)
            if label_text == "Zimmer:":
                entry.focus_set()
                self.first_input_field = entry 

            self.parent_app._bind_dialog_navigation(entry)
            
        main_frame.columnconfigure(1, weight=1)

        # --- Button-Bereich ---
        button_frame = ttk.Frame(main_frame)
        button_frame.grid(row=len(fields), column=0, columnspan=2, pady=15, sticky="ew")
        
        ipady = self.parent_app.current_settings.get('dialog_button_ipady', 5)

        if self.is_editing:
            # Modus: Bearbeiten (Klassisches Verhalten, hier bleibt Speichern sinnvoll)
            button_frame.columnconfigure(0, weight=1)
            button_frame.columnconfigure(1, weight=1)

            save_button = ttk.Button(button_frame, command=self.on_save_and_close)
            self.parent_app._configure_dialog_button(save_button, 'Dialog_Save', 'Speichern')
            save_button.grid(row=0, column=0, padx=5, ipady=ipady, sticky="ew")

            cancel_button = ttk.Button(button_frame, command=self.on_cancel)
            self.parent_app._configure_dialog_button(cancel_button, 'Dialog_Cancel', 'Abbrechen')
            cancel_button.grid(row=0, column=1, padx=5, ipady=ipady, sticky="ew")

        else:
            # Modus: Neu (Optimierter Workflow)
            # Wir brauchen nur noch 2 Spalten
            button_frame.columnconfigure(0, weight=1)
            button_frame.columnconfigure(1, weight=1)

            # Button 1: Hinzufügen (nutzt Shuttle_Add_Next Icon)
            add_button = ttk.Button(button_frame, command=self.on_add_next)
            self.parent_app._configure_shuttle_button(add_button, 'Shuttle_Add_Next', 'Hinzufügen')
            add_button.grid(row=0, column=0, padx=5, ipady=ipady, sticky="ew")

            # Button 2: Fertig (nutzt Shuttle_Dialog_Done Icon)
            done_button = ttk.Button(button_frame, command=self.on_cancel)
            self.parent_app._configure_shuttle_button(done_button, 'Shuttle_Dialog_Done', 'Fertig')
            done_button.grid(row=0, column=1, padx=5, ipady=ipady, sticky="ew")

            # Der dritte Button "Speichern & Schließen" wurde hier entfernt.

        self.protocol("WM_DELETE_WINDOW", self.on_cancel)

    def _validate_and_get_data(self):
        """Validiert die Eingaben und gibt das Daten-Dictionary zurück oder None bei Fehler."""
        datum_str = self.datum_var.get().strip()
        try:
            datetime.datetime.strptime(datum_str, "%d.%m.%Y")
        except ValueError:
            messagebox.showerror("Ungültiges Datum", "Bitte geben Sie das Datum im Format TT.MM.JJJJ ein.", parent=self)
            return None
            
        zimmer = self.zimmer_var.get().strip()
        gastname = self.gastname_var.get().strip()
        personen_str = self.personen_var.get().strip()

        if not zimmer or not gastname or not personen_str:
            messagebox.showerror("Fehler", "Zimmer, Gastname und Personenanzahl dürfen nicht leer sein.", parent=self)
            return None

        try:
            personen = int(personen_str)
            if personen <= 0:
                messagebox.showerror("Fehler", "Die Personenanzahl muss eine positive Zahl sein.", parent=self)
                return None
        except ValueError:
            messagebox.showerror("Fehler", "Ungültige Personenanzahl. Bitte eine ganze Zahl eingeben.", parent=self)
            return None

        uhrzeit = self.zeit_var.get().strip()
        try:
            time.strptime(uhrzeit, '%H:%M')
        except ValueError:
            messagebox.showerror("Ungültiges Zeitformat", "Bitte geben Sie die Uhrzeit im Format HH:MM ein.", parent=self)
            return None

        kapazitaetsgrenze = 5
        bereits_gebucht = 0

        for buchung in self.parent_app.shuttle_data_cache:
            if buchung.get('type') == self.booking_type and buchung.get('zeit') == uhrzeit:
                if self.is_editing and buchung.get('id') == self.id_var.get():
                    continue
                bereits_gebucht += 1
        
        if bereits_gebucht >= kapazitaetsgrenze:
            messagebox.showwarning(
                "Kapazitätsgrenze erreicht",
                f"Für die Uhrzeit {uhrzeit} sind bereits alle {kapazitaetsgrenze} Plätze im Shuttle belegt.\nBitte wählen Sie eine andere Uhrzeit.",
                parent=self
            )
            return None

        return {
            "id": self.id_var.get(),
            "type": self.booking_type,
            "datum": datum_str,
            "zeit": uhrzeit,
            "zimmer": zimmer,
            "gastname": gastname,
            "personen": personen,
        }

    def on_add_next(self):
        """Speichert den aktuellen Eintrag und leert die Felder für den nächsten."""
        data = self._validate_and_get_data()
        if data:
            if self.save_callback:
                self.save_callback(data)
            
            self.id_var.set(uuid.uuid4().hex)
            self.zimmer_var.set("")
            self.gastname_var.set("")
            self.personen_var.set("1")
            
            if hasattr(self, 'first_input_field'):
                self.first_input_field.focus_set()

    def on_save_and_close(self):
        """Speichert den Eintrag und schließt das Fenster."""
        data = self._validate_and_get_data()
        if data:
            if self.save_callback:
                self.save_callback(data)
            else:
                self.result = data
            self.destroy()

    def on_cancel(self):
        """
        Wird aufgerufen, wenn der Benutzer auf 'Fertig' oder das 'X' klickt.
        Fragt nach, ob weitere Einträge hinzugefügt werden sollen.
        """
        if messagebox.askyesno("Weitere Einträge?",
                               "Möchten Sie noch weitere Buchungen hinzufügen?",
                               icon='question', parent=self):
            # Benutzer wählt "Ja": Fenster bleibt offen, Fokus auf erstes Feld
            if hasattr(self, 'first_input_field'):
                self.first_input_field.focus_set()
            return
        else:
            # Benutzer wählt "Nein": Fenster schließen
            self.result = None
            self.destroy()

    def show(self):
        self.wait_window(self)
        return self.result

    
class ShuttleOverlayWindow(SafeToplevel):
    """
    Ein kleines, immer sichtbares Overlay-Fenster zur Anzeige der heutigen Shuttle-Services.
    Erbt von SafeToplevel, um Hintergrundprozesse sicher zu verwalten.
    """
    def __init__(self, parent, app_ref):
        super().__init__(parent)
        self.app_ref = app_ref
        self._offset_x = 0
        self._offset_y = 0
        self.update_job_id = None

        self.overrideredirect(True)
        self.wm_attributes("-topmost", True)
        self.geometry("+50+50")

        colors = self.app_ref.current_settings.get('shuttle_overlay_colors', {
            'title_bar_bg': '#434C5E',
            'title_bar_fg': '#FFFFFF'
        })
        title_bg = colors.get('title_bar_bg', '#434C5E')
        title_fg = colors.get('title_bar_fg', '#FFFFFF')

        style = ttk.Style()
        title_bar_style_name = f"ShuttleOverlayTitle.{id(self)}.TFrame"
        title_label_style_name = f"ShuttleOverlayTitle.{id(self)}.TLabel"
        
        style.configure(title_bar_style_name, background=title_bg)
        style.configure(title_label_style_name, background=title_bg, foreground=title_fg, font=("Segoe UI", 10, "bold"))

        main_frame = ttk.Frame(self, style='Card.TFrame', borderwidth=1, relief="raised")
        main_frame.pack(expand=True, fill='both', padx=2, pady=2)

        title_bar = ttk.Frame(main_frame, style=title_bar_style_name, cursor="fleur")
        title_bar.pack(fill='x')
        
        ttk.Label(title_bar, text="Shuttle Info (Heute)", style=title_label_style_name).pack(side='left', padx=10, pady=4)
        
        close_button = ttk.Button(title_bar, text="X", command=self.destroy, width=3)
        close_button.pack(side='right', padx=(0, 4), pady=4)
        
        minimize_button = ttk.Button(title_bar, text="—", command=self._minimize, width=3)
        minimize_button.pack(side='right', padx=4, pady=4)
        
        title_bar.bind("<ButtonPress-1>", self._start_move)
        title_bar.bind("<ButtonRelease-1>", self._stop_move)
        title_bar.bind("<B1-Motion>", self._do_move)

        self.content_frame = ttk.Frame(main_frame, padding=10)
        self.content_frame.pack(expand=True, fill='both')

        self.hinfahrt_frame = ttk.LabelFrame(self.content_frame, text="Hinfahrt")
        self.hinfahrt_frame.pack(fill='x', pady=(0, 10))
        
        self.rueckfahrt_frame = ttk.LabelFrame(self.content_frame, text="Rückfahrt")
        self.rueckfahrt_frame.pack(fill='x')

        self.update_display()

    def _minimize(self):
        """Minimiert oder maximiert den Inhaltsbereich des Fensters."""
        if self.content_frame.winfo_viewable():
            self.content_frame.pack_forget()
            self.update_idletasks()
        else:
            self.content_frame.pack(expand=True, fill='both')
            self.update_display()

    def _start_move(self, event):
        self._offset_x = event.x
        self._offset_y = event.y

    def _stop_move(self, event):
        self._offset_x = None
        self._offset_y = None

    def _do_move(self, event):
        x = self.winfo_pointerx() - self._offset_x
        y = self.winfo_pointery() - self._offset_y
        self.geometry(f"+{x}+{y}")

    def update_display(self):
        """Aktualisiert die angezeigten Shuttle-Services und fasst sie pro Uhrzeit zusammen."""
        if not self.winfo_exists():
            return

        today_str = datetime.date.today().strftime("%d.%m.%Y")
        
        for widget in self.hinfahrt_frame.winfo_children():
            widget.destroy()
        
        hinfahrten_today = [e for e in self.app_ref.shuttle_data_cache if e.get('type') == 'Hinfahrt' and e.get('datum') == today_str]
        
        if not hinfahrten_today:
            ttk.Label(self.hinfahrt_frame, text="(Keine Hinfahrten für heute)").pack(padx=5, pady=5)
        else:
            time_counts = {}
            for entry in hinfahrten_today:
                zeit = entry.get('zeit', 'Unbekannt')
                time_counts[zeit] = time_counts.get(zeit, 0) + 1
            
            for uhrzeit in sorted(time_counts.keys()):
                count = time_counts[uhrzeit]
                plural = "s" if count > 1 else ""
                label_text = f"{uhrzeit} Uhr → {count} Shuttle{plural}"
                ttk.Label(self.hinfahrt_frame, text=label_text).pack(anchor='w', padx=5)

        for widget in self.rueckfahrt_frame.winfo_children():
            widget.destroy()
            
        rueckfahrten_today = [e for e in self.app_ref.shuttle_data_cache if e.get('type') == 'Rückfahrt' and e.get('datum') == today_str]

        if not rueckfahrten_today:
            ttk.Label(self.rueckfahrt_frame, text="(Keine Rückfahrten für heute)").pack(padx=5, pady=5)
        else:
            time_counts = {}
            for entry in rueckfahrten_today:
                zeit = entry.get('zeit', 'Unbekannt')
                time_counts[zeit] = time_counts.get(zeit, 0) + 1
            
            for uhrzeit in sorted(time_counts.keys()):
                count = time_counts[uhrzeit]
                plural = "s" if count > 1 else ""
                label_text = f"{uhrzeit} Uhr → {count} Shuttle{plural}"
                ttk.Label(self.rueckfahrt_frame, text=label_text).pack(anchor='w', padx=5)

        # KORREKTUR: Der Job wird über die SafeToplevel-Klasse registriert.
        self.update_job_id = self.register_after_job(self.after(60000, self.update_display))

    def destroy(self):
        # KORREKTUR: Die manuelle Bereinigung des Timers ist nicht mehr nötig.
        if self.app_ref:
            self.app_ref.shuttle_overlay_window = None
        super().destroy()
    
    
class TaxiOverlayWindow(SafeToplevel):
    """
    Ein kleines, immer sichtbares Overlay-Fenster zur Anzeige der heutigen Taxibestellungen.
    Erbt von SafeToplevel, um Hintergrundprozesse sicher zu verwalten.
    """
    def __init__(self, parent, app_ref):
        super().__init__(parent)
        self.app_ref = app_ref
        self._offset_x = 0
        self._offset_y = 0
        self.update_job_id = None

        self.overrideredirect(True)
        self.wm_attributes("-topmost", True)
        self.geometry("+100+100")

        colors = self.app_ref.current_settings.get('shuttle_overlay_colors', {
            'title_bar_bg': '#434C5E', 'title_bar_fg': '#FFFFFF'
        })
        title_bg = colors.get('title_bar_bg', '#434C5E')
        title_fg = colors.get('title_bar_fg', '#FFFFFF')

        style = ttk.Style()
        title_bar_style_name = f"TaxiOverlayTitle.{id(self)}.TFrame"
        title_label_style_name = f"TaxiOverlayTitle.{id(self)}.TLabel"
        
        style.configure(title_bar_style_name, background=title_bg)
        style.configure(title_label_style_name, background=title_bg, foreground=title_fg, font=("Segoe UI", 10, "bold"))

        main_frame = ttk.Frame(self, style='Card.TFrame', borderwidth=1, relief="raised")
        main_frame.pack(expand=True, fill='both', padx=2, pady=2)

        title_bar = ttk.Frame(main_frame, style=title_bar_style_name, cursor="fleur")
        title_bar.pack(fill='x')
        
        ttk.Label(title_bar, text="Offene Taxis (Heute)", style=title_label_style_name).pack(side='left', padx=10, pady=4)
        
        close_button = ttk.Button(title_bar, text="X", command=self.destroy, width=3)
        close_button.pack(side='right', padx=(0, 4), pady=4)
        
        minimize_button = ttk.Button(title_bar, text="—", command=self._minimize, width=3)
        minimize_button.pack(side='right', padx=4, pady=4)
        
        title_bar.bind("<ButtonPress-1>", self._start_move)
        title_bar.bind("<ButtonRelease-1>", self._stop_move)
        title_bar.bind("<B1-Motion>", self._do_move)

        self.content_frame = ttk.Frame(main_frame, padding=10)
        self.content_frame.pack(expand=True, fill='both')

        self.update_display()

    def _minimize(self):
        if self.content_frame.winfo_viewable():
            self.content_frame.pack_forget()
            self.update_idletasks()
        else:
            self.content_frame.pack(expand=True, fill='both')
            self.update_display()

    def _start_move(self, event): self._offset_x = event.x; self._offset_y = event.y
    def _stop_move(self, event): self._offset_x = None; self._offset_y = None
    def _do_move(self, event): self.geometry(f"+{self.winfo_pointerx() - self._offset_x}+{self.winfo_pointery() - self._offset_y}")

    def update_display(self):
        if not self.winfo_exists(): return

        for widget in self.content_frame.winfo_children(): widget.destroy()

        today_iso = datetime.date.today().isoformat()
        
        offene_taxis = [e for e in self.app_ref.taxi_data_cache if e.get('datum') == today_iso]
        offene_taxis.sort(key=lambda x: x.get('uhrzeit', ''))

        if not offene_taxis:
            ttk.Label(self.content_frame, text="(Keine offenen Bestellungen für heute)").pack(padx=5, pady=5)
        else:
            for entry in offene_taxis:
                uhrzeit = entry.get('uhrzeit', '??:??')
                name_zimmer = entry.get('name_zimmer', 'N/A')
                zielort = entry.get('zielort', 'N/A')
                label_text = f"● {uhrzeit} | {name_zimmer} → {zielort}"
                ttk.Label(self.content_frame, text=label_text, wraplength=280).pack(anchor='w', padx=5, pady=2)

        # KORREKTUR: Der Job wird jetzt bei der Basisklasse registriert.
        self.update_job_id = self.register_after_job(self.after(60000, self.update_display))

    def destroy(self):
        # KORREKTUR: Die manuelle Bereinigung des Timers ist nicht mehr nötig.
        if self.app_ref: self.app_ref.taxi_overlay_window = None
        super().destroy()
        
        
class WeckrufPDF(FPDF):
    """ Erstellt eine PDF-Datei für die Weckrufliste. """
    def __init__(self, data, title="Weckrufliste", logo_path=None):
        super().__init__(orientation='P', unit='mm', format='A4')
        self.data = data
        self.title_text = title
        self.logo_path = logo_path
        self.font_family = "Helvetica"
        try:
            font_dir = resource_path('fonts')
            dejavu_sans_path = os.path.join(font_dir, "DejaVuSans.ttf")
            dejavu_sans_bold_path = os.path.join(font_dir, "DejaVuSans-Bold.ttf")
            if os.path.exists(dejavu_sans_path) and os.path.exists(dejavu_sans_bold_path):
                self.add_font("DejaVuSans", "", dejavu_sans_path)
                self.add_font("DejaVuSans", "B", dejavu_sans_bold_path)
                self.font_family = "DejaVuSans"
        except Exception as e:
            print(f"PDF Font Warning (Weckruf): {e}")

    def header(self):
        if self.logo_path and os.path.exists(self.logo_path):
            self.image(self.logo_path, x=10, y=8, w=30)
        self.set_font(self.font_family, 'B', 16)
        # KORREKTUR: Veralteten ln-Parameter ersetzt
        self.cell(0, 10, self.title_text, 0, new_x=XPos.LMARGIN, new_y=YPos.NEXT, align='C')
        self.set_font(self.font_family, '', 10)
        # KORREKTUR: Veralteten ln-Parameter ersetzt
        self.cell(0, 7, f"Stand: {datetime.datetime.now().strftime('%d.%m.%Y %H:%M')}", 0, new_x=XPos.LMARGIN, new_y=YPos.NEXT, align='C')
        self.ln(8)

    def footer(self):
        self.set_y(-15)
        self.set_font(self.font_family, '', 8)
        # KORREKTUR: Veralteten ln-Parameter entfernt
        self.cell(0, 10, f'Seite {self.page_no()}', 0, align='C')

    def create_table(self):
        self.set_font(self.font_family, 'B', 10)
        self.set_fill_color(220, 220, 220)
        page_width = self.w - 2 * self.l_margin
        col_widths = [page_width * 0.15, page_width * 0.15, page_width * 0.15, page_width * 0.40, page_width * 0.15]
        headers = ["Datum", "Weckzeit", "Zimmer", "Gastname(n)", "Benutzer"]
        for i, h in enumerate(headers):
            # KORREKTUR: Veralteten ln-Parameter ersetzt
            self.cell(col_widths[i], 7, h, 1, new_x=XPos.RIGHT, new_y=YPos.TOP, align='C', fill=1)
        self.ln()

        self.set_font(self.font_family, '', 9)
        sorted_data = sorted(self.data, key=lambda x: (x.get('datum', ''), x.get('zeit', '')))
        for entry in sorted_data:
            if self.get_y() > (self.h - self.b_margin - 12): self.add_page()
            try: display_datum = datetime.datetime.strptime(entry.get('datum', ''), "%Y-%m-%d").strftime("%d.%m.%Y")
            except ValueError: display_datum = entry.get('datum', '')
            
            self.cell(col_widths[0], 6, display_datum, 1)
            self.cell(col_widths[1], 6, entry.get('zeit', ''), 1, align='C')
            self.cell(col_widths[2], 6, entry.get('zimmer', ''), 1, align='C')
            self.cell(col_widths[3], 6, entry.get('gastname', ''), 1)
            self.cell(col_widths[4], 6, entry.get('kuerzel', ''), 1, align='C')
            self.ln()

