class TaxiEntryDialog(tk.Toplevel):
    def __init__(self, parent, app_ref, entry_data=None):
        super().__init__(parent)
        self.transient(parent)
        self.grab_set()
        self.parent_app = app_ref

        self.result = None
        self.is_editing = entry_data is not None
        self.title("Taxibestellung bearbeiten" if self.is_editing else "Neue Taxibestellung")

        main_frame = ttk.Frame(self, padding=15)
        main_frame.pack(expand=True, fill="both")

        self.id_var = tk.StringVar()
        self.datum_var = tk.StringVar()
        self.uhrzeit_var = tk.StringVar()
        self.name_zimmer_var = tk.StringVar()
        self.zielort_var = tk.StringVar()
        self.personen_var = tk.StringVar()
        self.kuerzel_var = tk.StringVar()

        if self.is_editing and entry_data:
            self.id_var.set(entry_data.get('id', ''))
            self.datum_var.set(datetime.datetime.strptime(entry_data.get('datum', ''), "%Y-%m-%d").strftime("%d.%m.%Y"))
            self.uhrzeit_var.set(entry_data.get('uhrzeit', '12:00'))
            self.name_zimmer_var.set(entry_data.get('name_zimmer', ''))
            self.zielort_var.set(entry_data.get('zielort', ''))
            self.personen_var.set(str(entry_data.get('personen', '1')))
            self.kuerzel_var.set(entry_data.get('kuerzel', ''))
        else:
            self.id_var.set(uuid.uuid4().hex)
            self.datum_var.set(datetime.date.today().strftime("%d.%m.%Y"))
            self.uhrzeit_var.set("12:00")
            self.personen_var.set("1")

        fields = [
            ("Datum (TT.MM.JJJJ):", self.datum_var),
            ("Uhrzeit (HH:MM):", self.uhrzeit_var),
            ("Name / Zimmer:", self.name_zimmer_var),
            ("Zielort:", self.zielort_var),
            ("Personenanzahl:", self.personen_var),
            ("Kürzel:", self.kuerzel_var),
        ]
        
        size_settings = self.parent_app.current_settings.get('configurable_sizes', {})
        taxi_config = size_settings.get('taxibestellung', {'font_size': 11, 'entry_width': 30})
        
        font_size = taxi_config.get('font_size', 11)
        entry_width = taxi_config.get('entry_width', 30)

        try:
            base_font_family = tkFont.Font(font=self.parent_app.style.lookup('TLabel', 'font')).actual('family')
        except (tk.TclError, AttributeError):
            base_font_family = "Segoe UI"
        dialog_font = tkFont.Font(family=base_font_family, size=font_size)

        for i, (label_text, var) in enumerate(fields):
            label = ttk.Label(main_frame, text=label_text, font=dialog_font)
            label.grid(row=i, column=0, sticky="w", padx=5, pady=3)
            
            entry = ttk.Entry(main_frame, textvariable=var, width=entry_width, font=dialog_font)
            entry.grid(row=i, column=1, sticky="ew", padx=5, pady=3)
            if label_text == "Name / Zimmer:":
                entry.focus_set()
            
            # HIER WIRD DIE NAVIGATION HINZUGEFÜGT
            self.parent_app._bind_dialog_navigation(entry)

        main_frame.columnconfigure(1, weight=1)

        button_frame = ttk.Frame(main_frame)
        button_frame.grid(row=len(fields), column=0, columnspan=2, pady=10, sticky="ew")
        button_frame.columnconfigure(0, weight=1)
        button_frame.columnconfigure(1, weight=1)

        ipady = self.parent_app.current_settings.get('dialog_button_ipady', 5)
        save_button = ttk.Button(button_frame, command=self.on_save)
        self.parent_app._configure_dialog_button(save_button, 'Dialog_Save', 'Speichern')
        save_button.grid(row=0, column=0, padx=5, ipady=ipady, sticky="ew")

        cancel_button = ttk.Button(button_frame, command=self.on_cancel)
        self.parent_app._configure_dialog_button(cancel_button, 'Dialog_Cancel', 'Abbrechen')
        cancel_button.grid(row=0, column=1, padx=5, ipady=ipady, sticky="ew")

        self.protocol("WM_DELETE_WINDOW", self.on_cancel)
    def on_save(self):
        try:
            datum_obj = datetime.datetime.strptime(self.datum_var.get(), "%d.%m.%Y").date()
        except ValueError:
            messagebox.showerror("Fehler", "Ungültiges Datumsformat. Bitte TT.MM.JJJJ verwenden.", parent=self)
            return

        try:
            time.strptime(self.uhrzeit_var.get(), '%H:%M')
        except ValueError:
            messagebox.showerror("Fehler", "Ungültiges Zeitformat. Bitte HH:MM verwenden.", parent=self)
            return
            
        try:
            personen = int(self.personen_var.get())
            if personen <= 0:
                messagebox.showerror("Fehler", "Personenanzahl muss eine positive Zahl sein.", parent=self)
                return
        except ValueError:
            messagebox.showerror("Fehler", "Ungültige Personenanzahl.", parent=self)
            return

        name_zimmer = self.name_zimmer_var.get().strip()
        zielort = self.zielort_var.get().strip()
        kuerzel = self.kuerzel_var.get().strip()

        if not name_zimmer or not zielort or not kuerzel:
            messagebox.showerror("Fehler", "Name/Zimmer, Zielort und Kürzel dürfen nicht leer sein.", parent=self)
            return

        self.result = {
            "id": self.id_var.get(),
            "datum": datum_obj.isoformat(),
            "uhrzeit": self.uhrzeit_var.get(),
            "name_zimmer": name_zimmer,
            "zielort": zielort,
            "personen": personen,
            "kuerzel": kuerzel.upper()
        }
        self.destroy()

    def on_cancel(self):
        self.result = None
        self.destroy()

    def show(self):
        self.wait_window(self)
        return self.result

class PDFPreviewDialog(tk.Toplevel):
    def __init__(self, parent, app_ref, pdf_path, email_callback, recipient, subject, body_text, cc="", success_title="E-Mail versendet", success_message="E-Mail wurde erfolgreich versendet."):
        super().__init__(parent)
        self.transient(parent)
        self.grab_set()
        
        self.parent_app = app_ref
        self.pdf_path = pdf_path
        self.email_callback = email_callback
        
        # Empfänger verarbeiten (Liste oder String)
        processed_recipient = ""
        if isinstance(recipient, list):
            unique_recipients = sorted(list(set(addr.strip() for addr in recipient if addr and addr.strip())))
            processed_recipient = "; ".join(unique_recipients)
        else:
            processed_recipient = str(recipient)

        self.recipient_var = tk.StringVar(value=processed_recipient)
        
        # CC-Variable initialisieren
        self.cc_var = tk.StringVar(value=cc)
        
        self.subject_var = tk.StringVar(value=subject)
        
        self.body_text = body_text
        self.success_title = success_title
        self.success_message = success_message
        self.doc = None
        self.photo_images = []

        self.title("E-Mail Vorschau & Versand")
        self.geometry("800x900")

        main_frame = ttk.Frame(self)
        main_frame.pack(fill=tk.BOTH, expand=True, padx=10, pady=10)
        main_frame.rowconfigure(2, weight=1)
        main_frame.columnconfigure(0, weight=1)

        # --- Header-Frame ---
        header_frame = ttk.Frame(main_frame)
        header_frame.grid(row=0, column=0, columnspan=2, sticky='ew', pady=(0, 10))
        header_frame.columnconfigure(1, weight=1)

        # Zeile 0: Empfänger
        ttk.Label(header_frame, text="Empfänger:").grid(row=0, column=0, sticky='w', padx=5, pady=2)
        ttk.Entry(header_frame, textvariable=self.recipient_var).grid(row=0, column=1, sticky='ew', padx=5, pady=2, ipady=4)
        
        # Zeile 1: CC-Feld
        ttk.Label(header_frame, text="CC:").grid(row=1, column=0, sticky='w', padx=5, pady=2)
        ttk.Entry(header_frame, textvariable=self.cc_var).grid(row=1, column=1, sticky='ew', padx=5, pady=2, ipady=4)
        
        # Zeile 2: Betreff
        ttk.Label(header_frame, text="Betreff:").grid(row=2, column=0, sticky='w', padx=5, pady=2)
        ttk.Entry(header_frame, textvariable=self.subject_var).grid(row=2, column=1, sticky='ew', padx=5, pady=2, ipady=4)
        
        # --- E-Mail-Text Frame ---
        email_text_frame = ttk.Frame(main_frame, style='Card.TFrame')
        email_text_frame.grid(row=1, column=0, columnspan=2, sticky='ew', pady=(0, 15))
        email_text_frame.columnconfigure(0, weight=1)

        ttk.Label(email_text_frame, text="E-Mail-Text:", font=("Segoe UI", 10, "bold")).pack(anchor='w', padx=10, pady=(8, 2))
        self.body_text_widget = tk.Text(
            email_text_frame, height=8, wrap=tk.WORD, font=("Segoe UI", 10),
            relief="sunken", bg=self.parent_app.style.lookup('TEntry', 'background') or '#f9f9f9',
            padx=10, pady=5
        )
        self.body_text_widget.insert('1.0', self.body_text)
        self.body_text_widget.pack(fill='both', expand=True, padx=10, pady=(0, 8))

        # Trennlinie und Canvas
        ttk.Label(main_frame, text="Anhang-Vorschau", font=("Segoe UI", 10, "italic")).grid(row=2, column=0, columnspan=2, sticky='w', padx=5, pady=(5, 2))

        self.canvas = tk.Canvas(main_frame, bg="gray")
        self.canvas.grid(row=2, column=0, sticky="nsew")

        vsb = ttk.Scrollbar(main_frame, orient="vertical", command=self.canvas.yview)
        vsb.grid(row=2, column=1, sticky="ns")
        self.canvas.configure(yscrollcommand=vsb.set)

        self.pages_frame = ttk.Frame(self.canvas)
        self.canvas.create_window((0, 0), window=self.pages_frame, anchor="nw")

        button_frame = ttk.Frame(self, padding=10)
        button_frame.pack(fill=tk.X)
        button_frame.columnconfigure(0, weight=1)
        button_frame.columnconfigure(1, weight=1)
        
        self.send_button = ttk.Button(button_frame, text="Senden", command=self._on_send)
        self.send_button.grid(row=0, column=0, padx=5, sticky="ew")
        self.cancel_button = ttk.Button(button_frame, text="Abbrechen", command=self._on_cancel)
        self.cancel_button.grid(row=0, column=1, padx=5, sticky="ew")

        # Event-Binding für das Scrollen (Dies fehlte vorher und verursachte den Fehler)
        self.pages_frame.bind("<Configure>", self._on_frame_configure)
        self.protocol("WM_DELETE_WINDOW", self._on_cancel)

        if not pymupdf_available:
            ttk.Label(self.pages_frame, text="PDF-Vorschau nicht verfügbar.\nBitte PyMuPDF installieren (pip install PyMuPDF).").pack(pady=20)
            self.send_button.config(state="disabled")
        else:
            self._load_pdf_pages()

    def _load_pdf_pages(self):
        """Lädt die Seiten der PDF als Bilder in den Canvas."""
        try:
            self.doc = fitz.open(self.pdf_path)
            for page_num in range(len(self.doc)):
                page = self.doc.load_page(page_num)
                pix = page.get_pixmap()
                img_data = pix.tobytes("ppm")
                photo = tk.PhotoImage(data=img_data)
                self.photo_images.append(photo)

                label = ttk.Label(self.pages_frame, image=photo)
                label.pack(pady=5)
        except Exception as e:
            ttk.Label(self.pages_frame, text=f"Fehler beim Laden der PDF-Vorschau:\n{e}").pack(pady=20)
            self.send_button.config(state="disabled")

    def _on_frame_configure(self, event):
        """Passt die Scrollregion an die Größe des Inhalts an."""
        self.canvas.configure(scrollregion=self.canvas.bbox("all"))

    def _on_send(self):
        self.send_button.config(state="disabled")
        self.cancel_button.config(state="disabled")
        self.update_idletasks()

        current_recipient_str = self.recipient_var.get()
        current_cc_str = self.cc_var.get()
        current_subject = self.subject_var.get()

        # Hilfsfunktion zum Parsen von Listen (Komma oder Semikolon)
        def parse_emails(text):
            return [addr.strip() for addr in re.split(r'[;,]', text) if addr.strip()]

        unique_recipients = sorted(list(set(parse_emails(current_recipient_str))))
        unique_cc = sorted(list(set(parse_emails(current_cc_str))))

        if not unique_recipients:
             messagebox.showerror("Kein Empfänger", "Das Empfängerfeld darf nicht leer sein.", parent=self)
             self.send_button.config(state="normal"); self.cancel_button.config(state="normal")
             return

        # Callback aufrufen und CC übergeben
        try:
            success, message = self.email_callback(
                pdf_path=self.pdf_path,
                recipient=unique_recipients,
                subject=current_subject,
                body=self.body_text_widget.get("1.0", tk.END).strip(),
                cc=unique_cc
            )
        except TypeError:
             # Fallback für Callbacks, die CC noch nicht unterstützen
             success, message = self.email_callback(
                pdf_path=self.pdf_path,
                recipient=unique_recipients,
                subject=current_subject,
                body=self.body_text_widget.get("1.0", tk.END).strip()
            )

        if success:
            SuccessToast(self, 
                         title=self.success_title, 
                         message=self.success_message, 
                         toast_type='success', 
                         colors=self.parent_app.current_settings.get('toast_colors'))
            self.after(1500, lambda: (self._cleanup(), self.destroy()))
        else:
            SuccessToast(self, 
                         title="Fehler beim Senden", 
                         message=message,
                         toast_type='error',
                         colors=self.parent_app.current_settings.get('toast_colors'),
                         duration=5000)
            self.send_button.config(state="normal")
            self.cancel_button.config(state="normal")

    def _on_cancel(self):
        self._cleanup()
        self.destroy()

    def _cleanup(self):
        if self.doc:
            self.doc.close()
        # Nur temporäre Dateien löschen
        if self.pdf_path and os.path.exists(self.pdf_path):
             try:
                 os.remove(self.pdf_path)
             except OSError as e:
                 print(f"Error removing temporary PDF file '{self.pdf_path}': {e}")

    def show(self):
        self.master.wait_window(self)
        
        
