class EmailPreviewDialog(tk.Toplevel):
    """
    Ein Dialogfenster zur Vorschau und zum Versand von E-Mails.
    Nimmt Rohdaten entgegen, erstellt eine formatierte Text-Vorschau
    und generiert beim Senden den finalen HTML-Body.
    """
    def __init__(self, parent, app_ref, recipient, subject, entry_data, email_callback):
        super().__init__(parent)
        self.transient(parent)
        self.grab_set()
        self.parent_app = app_ref
        self.entry_data = entry_data
        self.email_callback = email_callback

        self.title("E-Mail Vorschau & Versand")
        self.geometry("800x600")
        self.minsize(600, 400)

        self.columnconfigure(0, weight=1)
        self.rowconfigure(0, weight=1)

        container_frame = ttk.Frame(self, padding=10)
        container_frame.grid(row=0, column=0, sticky="nsew")
        container_frame.columnconfigure(1, weight=1)
        container_frame.rowconfigure(2, weight=1)

        # Empfänger und Betreff
        ttk.Label(container_frame, text="Empfänger:").grid(row=0, column=0, sticky='w', padx=5, pady=3)
        self.recipient_var = tk.StringVar(value=recipient)
        ttk.Entry(container_frame, textvariable=self.recipient_var).grid(row=0, column=1, sticky='ew', padx=5, pady=3)

        ttk.Label(container_frame, text="Betreff:").grid(row=1, column=0, sticky='w', padx=5, pady=3)
        self.subject_var = tk.StringVar(value=subject)
        ttk.Entry(container_frame, textvariable=self.subject_var).grid(row=1, column=1, sticky='ew', padx=5, pady=3)

        # Vorschau des Inhalts
        preview_frame = ttk.LabelFrame(container_frame, text="Vorschau", padding=10)
        preview_frame.grid(row=2, column=0, columnspan=2, sticky='nsew', pady=(10, 0))
        preview_frame.rowconfigure(0, weight=1)
        preview_frame.columnconfigure(0, weight=1)
        
        try:
            bg_color = self.parent_app.style.lookup('TFrame', 'background')
        except tk.TclError:
            bg_color = "SystemButtonFace"
        
        self.text_preview = tk.Text(preview_frame, wrap="word", font=("Segoe UI", 11), relief="flat", spacing1=5, spacing3=5, background=bg_color)
        self.text_preview.grid(row=0, column=0, sticky='nsew')
        
        self.text_preview.tag_configure("bold", font=("Segoe UI", 11, "bold"))
        self.text_preview.tag_configure("heading", font=("Segoe UI", 16, "bold"), spacing1=15, spacing3=8)
        self.text_preview.tag_configure("separator", foreground="gray")
        self.text_preview.config(tabs=("120p", "280p", "380p"))

        self.text_preview.insert("end", "Anruf\n", "heading")
        self.text_preview.insert("end", "Für/Abteilung:\t", "bold"); self.text_preview.insert("end", f"{self.entry_data.get('fuer_abteilung', '')}\t")
        self.text_preview.insert("end", "Datum:\t", "bold"); self.text_preview.insert("end", f"{self.entry_data.get('datum', '')}\n")
        self.text_preview.insert("end", "Anrufer:\t", "bold"); self.text_preview.insert("end", f"{self.entry_data.get('anrufer', '')}\t")
        self.text_preview.insert("end", "Firma:\t", "bold"); self.text_preview.insert("end", f"{self.entry_data.get('firma', '')}\n")
        self.text_preview.insert("end", "Telefonnummer:\t", "bold"); self.text_preview.insert("end", f"{self.entry_data.get('telefonnummer', '')}\t")
        self.text_preview.insert("end", "Uhrzeit:\t", "bold"); self.text_preview.insert("end", f"{self.entry_data.get('uhrzeit', '')}\n\n")
        rueckruf_char = "☑" if self.entry_data.get('bitte_um_rueckruf') else "☐"
        info_char = "☑" if self.entry_data.get('zur_info') else "☐"
        self.text_preview.insert("end", f"{rueckruf_char} Bitte um Rückruf\t\t{info_char} Zur Info\n")
        self.text_preview.insert("end", "Nachricht:", "heading")
        self.text_preview.insert("end", "----------------------------------------------------------------------------------------------------------------------\n", "separator")
        self.text_preview.insert("end", f"{self.entry_data.get('nachricht', '')}\n\n")
        self.text_preview.insert("end", "----------------------------------------------------------------------------------------------------------------------\n", "separator")
        self.text_preview.insert("end", "----------------------------------------------------------------------------------------------------------------------\n", "separator")
        self.text_preview.insert("end", "----------------------------------------------------------------------------------------------------------------------\n\n", "separator")
        self.text_preview.insert("end", "angenommen von: ", "bold")
        self.text_preview.insert("end", f"{self.entry_data.get('angenommen_von', '')}")
        self.text_preview.config(state="disabled")

        button_frame = ttk.Frame(container_frame, padding=(0, 10, 0, 0))
        button_frame.grid(row=3, column=0, columnspan=2, sticky='sew')
        button_frame.columnconfigure((0, 1), weight=1)
        
        self.send_button = ttk.Button(button_frame, text="Senden", command=self._on_send)
        self.send_button.grid(row=0, column=0, padx=5, ipady=5, sticky="ew")
        
        self.cancel_button = ttk.Button(button_frame, text="Abbrechen", command=self.destroy)
        self.cancel_button.grid(row=0, column=1, padx=5, ipady=5, sticky="ew")
        
        self.protocol("WM_DELETE_WINDOW", self.destroy)

    def _on_send(self):
        recipient = self.recipient_var.get().strip()
        subject = self.subject_var.get().strip()

        if not recipient or not subject:
            messagebox.showerror("Fehler", "Empfänger und Betreff dürfen nicht leer sein.", parent=self)
            return

        self.send_button.config(state="disabled")
        self.cancel_button.config(state="disabled")
        self.update_idletasks()

        rueckruf_text = "<b>Ja</b>" if self.entry_data.get('bitte_um_rueckruf') else "Nein"
        info_text = "<b>Ja</b>" if self.entry_data.get('zur_info') else "Nein"

        body_html = f"""
        <html><head><style>
            body {{ font-family: Segoe UI, Arial, sans-serif; font-size: 11pt; }}
            table {{ border-collapse: collapse; width: 100%; margin-bottom: 15px; }}
            th, td {{ border: 1px solid #dddddd; text-align: left; padding: 8px; }}
            th {{ background-color: #f2f2f2; width: 140px; font-weight: bold; }}
            .message-box {{ border: 1px solid #dddddd; padding: 12px; margin-top: 10px; background-color: #f9f9f9; }}
        </style></head><body>
            <p>Neue Anrufnotiz:</p>
            <table>
                <tr><th>Für/Abteilung</th><td>{self.entry_data.get('fuer_abteilung', '')}</td></tr>
                <tr><th>Datum</th><td>{self.entry_data.get('datum', '')}</td></tr>
                <tr><th>Uhrzeit</th><td>{self.entry_data.get('uhrzeit', '')}</td></tr>
                <tr><th>Anrufer</th><td>{self.entry_data.get('anrufer', '')}</td></tr>
                <tr><th>Firma</th><td>{self.entry_data.get('firma', '')}</td></tr>
                <tr><th>Telefonnummer</th><td>{self.entry_data.get('telefonnummer', '')}</td></tr>
            </table>
            <div class="message-box">
                <b>Nachricht:</b><br>
                <p style="white-space: pre-wrap; margin: 5px 0 0 0;">{self.entry_data.get('nachricht', '')}</p>
            </div>
            <table>
                <tr><th>Bitte um Rückruf</th><td>{rueckruf_text}</td></tr>
                <tr><th>Zur Info</th><td>{info_text}</td></tr>
                <tr><th>Angenommen von</th><td>{self.entry_data.get('angenommen_von', '')}</td></tr>
            </table>
        </body></html>
        """

        success, message = self.email_callback(
            recipient=recipient,
            subject=subject,
            body=body_html
        )
        
        if success:
            SuccessToast(self, title="E-Mail erfolgreich versendet", message="Die Daten wurden versendet.", toast_type='success', colors=self.parent_app.current_settings.get('toast_colors'))
            self.after(1500, self.destroy)
        else:
            SuccessToast(self, title="Fehler beim Senden", message=message, toast_type='error', colors=self.parent_app.current_settings.get('toast_colors'), duration=5000)
            self.send_button.config(state="normal")
            self.cancel_button.config(state="normal")
            
    # vvvvv HIER IST DIE KORREKTUR vvvvv
    # Diese Methode hat gefehlt.
    def show(self):
        """Zeigt das Dialogfenster an und wartet, bis es geschlossen wird."""
        self.wait_window(self)
