class ZimmerreservierungForm(tk.Toplevel): # Geändert von tk.Tk zu tk.Toplevel
    def __init__(self, parent): # "parent" als Argument hinzugefügt
        super().__init__(parent) # "parent" hier übergeben
        self.transient(parent) # Sorgt dafür, dass das Fenster über dem Hauptfenster bleibt
        self.grab_set() # Blockiert die Interaktion mit dem Hauptfenster
        self.title("Zimmerreservierung")
        self.geometry("850x800")

        # --- Schriftarten definieren ---
        self.title_font = tkFont.Font(family="Helvetica", size=18, weight="bold", underline=True)
        self.label_font = tkFont.Font(family="Helvetica", size=11, weight="bold")
        self.header_font = tkFont.Font(family="Helvetica", size=10, weight="bold")

        # --- Haupt-Container ---
        main_frame = ttk.Frame(self, padding="15 15 15 15")
        main_frame.pack(fill=tk.BOTH, expand=True)

        # --- Titel und Anreise/Abreise ---
        self._create_header_section(main_frame)

        # --- Zimmer-Tabelle ---
        self._create_room_table(main_frame)

        # --- Gästedaten ---
        self._create_guest_details_section(main_frame)
        
        # --- Checkbox-Optionen ---
        self._create_options_section(main_frame)

        # --- Untere Felder ---
        self._create_footer_section(main_frame)

    def _create_header_section(self, parent):
        frame = ttk.Frame(parent)
        frame.pack(fill=tk.X, pady=(0, 15))
        frame.columnconfigure(2, weight=1)

        ttk.Label(frame, text="Zimmerreservierung", font=self.title_font).grid(row=0, column=0, columnspan=4, pady=(0, 10))

        ttk.Label(frame, text="Anreise:", font=self.label_font).grid(row=1, column=0, sticky="w", padx=(0, 5))
        ttk.Entry(frame).grid(row=1, column=1, sticky="ew")
        
        ttk.Label(frame, text="Abreise:", font=self.label_font).grid(row=1, column=2, sticky="e", padx=(20, 5))
        ttk.Entry(frame).grid(row=1, column=3, sticky="ew")

    def _create_room_table(self, parent):
        frame = ttk.Frame(parent)
        frame.pack(fill=tk.X, pady=(10, 15))
        
        headers = ["Zimmer", "Anzahl", "Kategorie", "Preis", "Besonderheiten"]
        col_widths = [10, 10, 20, 20, 40]

        for i, header in enumerate(headers):
            frame.columnconfigure(i, weight=col_widths[i])
            lbl = ttk.Label(frame, text=header, font=self.header_font, relief=tk.RIDGE, padding=5, anchor="center")
            lbl.grid(row=0, column=i, sticky="nsew")

        room_types = ["EZ", "DZ", "Suite"]
        for row_idx, room in enumerate(room_types, start=1):
            ttk.Label(frame, text=room, relief=tk.RIDGE, padding=5).grid(row=row_idx, column=0, sticky="nsew")
            for col_idx in range(1, len(headers)):
                ttk.Entry(frame).grid(row=row_idx, column=col_idx, sticky="nsew")

