        self.parent_app._configure_dialog_button(save_button, 'Dialog_Save', 'Speichern')
        save_button.grid(row=0, column=0, padx=5, ipady=5, sticky="ew")

        cancel_button = ttk.Button(button_frame, text="Abbrechen", command=self.on_cancel)
