class MODChecklisteEmailDialog(tk.Toplevel):
    """Dialog zur Auswahl eines Empfängers für den E-Mail-Versand der MOD-Checkliste.
    Analog zu AnrufnotizEmailDialog."""
    
    def __init__(self, parent, app_ref):
        super().__init__(parent)
        self.transient(parent)
        self.grab_set()
        self.parent_app = app_ref
        self.result = None
        self.title("E-Mail an Abteilung senden")
        
        main_frame = ttk.Frame(self, padding=15)
        main_frame.pack(expand=True, fill="both")
        main_frame.columnconfigure(0, weight=1)
        
        ttk.Label(main_frame, text="Wählen Sie die Zielabteilung aus:").grid(
            row=0, column=0, sticky="w", padx=5, pady=(0, 10))
        
        self.recipient_var = tk.StringVar()
        
        # Empfänger aus den Einstellungen laden
        recipients_config = self.parent_app.current_settings.get('mod_checkliste_email_recipients', {})
        self.recipient_map = recipients_config
        department_names = sorted(list(recipients_config.keys()))
        
        self.recipient_combo = ttk.Combobox(
            main_frame, 
            textvariable=self.recipient_var, 
            values=department_names,
            state="readonly",
            font=("Segoe UI", 10)
        )
        self.recipient_combo.grid(row=1, column=0, sticky="ew", padx=5, pady=5)
        
        if department_names:
            self.recipient_combo.set(department_names[0])
        
        # Button-Frame
        button_frame = ttk.Frame(main_frame)
        button_frame.grid(row=2, column=0, pady=(15, 0))
        
        ttk.Button(button_frame, text="OK", command=self.on_ok, width=10).pack(side='left', padx=5)
        ttk.Button(button_frame, text="Abbrechen", command=self.on_cancel, width=10).pack(side='left', padx=5)
        
        # Fenster zentrieren
        self.update_idletasks()
        width = self.winfo_width()
        height = self.winfo_height()
        x = (self.winfo_screenwidth() // 2) - (width // 2)
        y = (self.winfo_screenheight() // 2) - (height // 2)
        self.geometry(f'{width}x{height}+{x}+{y}')
    
    def on_ok(self):
        selected_department = self.recipient_var.get().strip()
        if not selected_department:
            messagebox.showwarning("Keine Auswahl", 
                                 "Bitte wählen Sie eine Abteilung aus.", 
                                 parent=self)
            return
        
        self.result = self.recipient_map.get(selected_department)
        if not self.result:
            messagebox.showerror("Fehler", 
                               "Die E-Mail-Adresse für die ausgewählte Abteilung konnte nicht gefunden werden.", 
                               parent=self)
            return
        
        self.destroy()
    
    def on_cancel(self):
        self.result = None
        self.destroy()
    
    def show(self):
        self.wait_window(self)
        return self.result


class MODRundgangPDF(FPDF):
    def __init__(self, data, logo_path=None):
        super().__init__('P', 'mm', 'A4')
        self.data = data
        self.logo_path = logo_path
        self.font_family = "Helvetica"
        # Versucht, Unicode-Schriftarten zu laden
        try:
            font_dir = resource_path('fonts')
            if os.path.exists(os.path.join(font_dir, "DejaVuSans.ttf")):
                self.add_font("DejaVuSans", "", os.path.join(font_dir, "DejaVuSans.ttf"))
                self.add_font("DejaVuSans", "B", os.path.join(font_dir, "DejaVuSans-Bold.ttf"))
                self.font_family = "DejaVuSans"
        except: pass

    def header(self):
        HEADER_TOP = 8      # mm from top edge
        MAX_LOGO_W = 35     # max logo width in mm
        MAX_LOGO_H = 20     # max logo height in mm

        logo_bottom_y = HEADER_TOP  # tracks how far down the logo reaches

        if self.logo_path and os.path.exists(self.logo_path):
            try:
                from PIL import Image as _PILImg
                with _PILImg.open(self.logo_path) as _im:
                    orig_w, orig_h = _im.size
                if orig_w > 0 and orig_h > 0:
                    scale = min(MAX_LOGO_W / orig_w, MAX_LOGO_H / orig_h)
                    logo_w = orig_w * scale
                    logo_h = orig_h * scale
                else:
                    logo_w, logo_h = MAX_LOGO_W, MAX_LOGO_H
            except Exception:
                logo_w, logo_h = MAX_LOGO_W, MAX_LOGO_H
            # Vertical center within the max area
            logo_y = HEADER_TOP + (MAX_LOGO_H - logo_h) / 2
            self.image(self.logo_path, x=10, y=logo_y, w=logo_w)
            logo_bottom_y = logo_y + logo_h

        # Title – positioned to the right of the logo area
        title_x = 10 + MAX_LOGO_W + 5
        self.set_font(self.font_family, 'B', 15)
        self.set_xy(title_x, HEADER_TOP)
        self.cell(0, 10, "M O D - R U N D G A N G   P R O T O K O L L",
                  new_x=XPos.LMARGIN, new_y=YPos.NEXT, align='C')

        # Date / MOD line
        date_str = self.data.get('date', '')
        mod_name = self.data.get('mod_name', '')
        self.set_font(self.font_family, '', 10)
        self.set_x(title_x)
        self.cell(0, 7, f"Datum: {date_str}  |  Name / MOD: {mod_name}",
                  new_x=XPos.LMARGIN, new_y=YPos.NEXT, align='C')

        # Separator line – always below both logo and text
        text_bottom_y = HEADER_TOP + 10 + 7  # title(10) + date(7) rows
        sep_y = max(logo_bottom_y, text_bottom_y) + 3

        self.set_draw_color(160, 160, 160)
        self.set_line_width(0.4)
        self.line(self.l_margin, sep_y, self.w - self.r_margin, sep_y)
        self.set_draw_color(0, 0, 0)
        self.set_line_width(0.2)

        # Position cursor below the separator with a small gap
        self.set_y(sep_y + 4)

    def footer(self):
        self.set_y(-15)
        self.set_font(self.font_family, '', 8)
        self.cell(0, 10, f'Seite {self.page_no()}', 0, align='C')

    def create_content(self, sections_ui):
        # Berechnet die exakte nutzbare Breite der Seite
        page_width = self.w - 2 * self.l_margin
        
        for section in sections_ui:
            # Überschrift der Sektion
            self.set_font(self.font_family, 'B', 11)
            self.set_fill_color(230, 230, 230)
            
            # Cursor sicher auf linken Rand setzen
            self.set_x(self.l_margin)
            self.cell(page_width, 8, section['title'], border=1, new_x=XPos.LMARGIN, new_y=YPos.NEXT, fill=True, align='L')
            
            # Aufgaben
            self.set_font(self.font_family, '', 9)
            for task in section['tasks']:
                status = " [X] " if task['var'].get() else " [  ] "
                comment = ""
                if task['comment_var'].get():
                    comment = f" | Notiz: {task['comment_var'].get()}"
                
                text_content = f"{status}{task['text']}{comment}"
                
                # Cursor explizit setzen und feste Breite verwenden
                self.set_x(self.l_margin)
                self.multi_cell(page_width, 6, text_content, border='LRB', align='L')
            
            self.ln(3)
        
        # Alarme Sektion
        self.set_x(self.l_margin)
        self.set_font(self.font_family, 'B', 11)
        self.set_fill_color(230, 230, 230)
        self.cell(page_width, 8, "ALARM STATUS (Rezeption)", border=1, new_x=XPos.LMARGIN, new_y=YPos.NEXT, fill=True, align='L')
        
        self.set_font(self.font_family, '', 9)
        for alarm in self.data.get('alarms', []):
            self.set_x(self.l_margin)
            self.cell(page_width, 6, f" - {alarm}", border='LRB', new_x=XPos.LMARGIN, new_y=YPos.NEXT)
        
        # Abschlussbericht
        self.ln(5)
        self.set_x(self.l_margin)
        self.set_font(self.font_family, 'B', 11)
        self.cell(page_width, 7, "Abschließender Bericht:", new_x=XPos.LMARGIN, new_y=YPos.NEXT)
        
        self.set_font(self.font_family, '', 10)
        self.set_x(self.l_margin)
        self.multi_cell(page_width, 5, self.data.get('final_report', ''), border=1)
        
        # Unterschrift
        self.ln(15)
        self.set_x(self.l_margin)
        self.cell(80, 0, '', border='T') # Linie für Unterschrift
        self.ln(2)
        self.set_x(self.l_margin)
        self.cell(80, 5, "Unterschrift / Bestätigung MOD")

