    def _create_text_widget(self, parent):
        """Erstellt ein scrollbares Text-Widget für die Inhalte."""
        frame = ttk.Frame(parent)
        frame.pack(fill='both', expand=True, padx=10, pady=10)
        
        scrollbar = ttk.Scrollbar(frame)
        scrollbar.pack(side='right', fill='y')
        
        text = tk.Text(frame, wrap='word', yscrollcommand=scrollbar.set, 
                       font=self.text_font, bg=self.bg_color, relief='flat', padx=10, pady=10)
        text.pack(side='left', fill='both', expand=True)
        scrollbar.config(command=text.yview)
        
        # Tags für Formatierung
        text.tag_configure("h1", font=self.header_font, foreground="#2F65C3", spacing1=15, spacing3=5)
        text.tag_configure("h2", font=self.sub_header_font, foreground="#444444", spacing1=10, spacing3=2)
        text.tag_configure("bold", font=("Segoe UI", 11, "bold"))
        text.tag_configure("bullet", lmargin1=20, lmargin2=30)
        
        return text

    def _insert_text(self, widget, content):
        """Fügt formatierten Text ein."""
        widget.config(state='normal')
        for item in content:
            if item['type'] == 'h1':
                widget.insert('end', item['text'] + "\n", "h1")
            elif item['type'] == 'h2':
                widget.insert('end', item['text'] + "\n", "h2")
            elif item['type'] == 'p':
                widget.insert('end', item['text'] + "\n\n")
            elif item['type'] == 'bullet':
                widget.insert('end', "• " + item['text'] + "\n", "bullet")
        widget.config(state='disabled')

