class ModernLoginScreen(tk.Frame):
    """
    Ein High-End Login-Screen mit Glassmorphism-Effekt, Zurück-Funktion 
    und automatischem Timeout-Countdown.
    FIX: Timer startet automatisch neu, wenn das Fenster wieder sichtbar wird.
    """
    def __init__(self, parent, login_callback, cancel_callback=None):
        super().__init__(parent)
        self.login_callback = login_callback
        self.cancel_callback = cancel_callback
        self.pack(fill='both', expand=True)

        # Farben
        self.c_bg_top = "#4facfe"
        self.c_bg_btm = "#00f2fe"
        self.c_card = "#6EB5FF"
        self.c_input_bg = "#8BC6EC"
        self.c_btn_bg = "#2C3E50"

        # Timer Variablen
        self.start_time = 60
        self.time_left = self.start_time
        self.timer_job = None
        self.is_running = False

        # Haupt-Canvas
        self.canvas = tk.Canvas(self, highlightthickness=0)
        self.canvas.pack(fill='both', expand=True)
        
        self.canvas.bind("<Configure>", self._draw_ui)
        
        # WICHTIG: Event-Listener für Sichtbarkeit
        # Wenn der User den Tab wechselt und zurückkommt, startet der Timer neu.
        self.bind("<Map>", self._on_visible)
        
        self.user_var = tk.StringVar()
        self.pass_var = tk.StringVar()
        
        # Timer initial starten
        self._start_countdown()

    def _on_visible(self, event):
        """Wird aufgerufen, wenn das Fenster (der Tab) sichtbar wird."""
        # Timer zurücksetzen
        self.time_left = self.start_time
        self._start_countdown()

    def _start_countdown(self):
        """Startet den Countdown sicher."""
        if self.timer_job:
            self.after_cancel(self.timer_job)
            self.timer_job = None
        
        self.is_running = True
        self._tick()

    def _tick(self):
        """Der Sekundentakt."""
        if not self.winfo_exists() or not self.is_running:
            return

        # Wenn das Fenster gerade nicht sichtbar ist (anderer Tab), pausieren wir nicht,
        # sondern lassen ihn im Hintergrund auslaufen oder stoppen ihn. 
        # Hier: Wir prüfen die Sichtbarkeit.
        if not self.winfo_viewable():
            # Wenn unsichtbar, machen wir nichts, warten aber auf das <Map> Event für Reset
            return

        # 1. Text aktualisieren
        try:
            self.canvas.itemconfig("timer_text", text=f"Auto-Abbruch in: {self.time_left}s")
        except:
            pass

        # 2. Prüfen
        if self.time_left <= 0:
            self.is_running = False
            if self.cancel_callback:
                self.cancel_callback()
            # Wir setzen hier NICHT zurück, das passiert beim nächsten _on_visible
            return

        # 3. Zählen
        self.time_left -= 1
        
        # 4. Nächster Tick
        self.timer_job = self.after(1000, self._tick)

    def destroy(self):
        self.is_running = False
        if self.timer_job:
            try: self.after_cancel(self.timer_job)
            except: pass
            self.timer_job = None
        super().destroy()

    def _create_rounded_rect(self, x1, y1, x2, y2, radius=25, **kwargs):
        points = [x1+radius, y1, x1+radius, y1, x2-radius, y1, x2-radius, y1, x2, y1, x2, y1+radius, x2, y1+radius, x2, y2-radius, x2, y2-radius, x2, y2, x2-radius, y2, x2-radius, y2, x1+radius, y2, x1+radius, y2, x1, y2, x1, y2-radius, x1, y2-radius, x1, y1+radius, x1, y1+radius, x1, y1]
        return self.canvas.create_polygon(points, **kwargs, smooth=True)

    def _draw_ui(self, event=None):
        self.canvas.delete("all")
        w = self.canvas.winfo_width()
        h = self.canvas.winfo_height()
        
        # 1. HINTERGRUND
        self.canvas.create_rectangle(0, 0, w, h, fill="#3b5998", outline="")
        self.canvas.create_oval(-200, -200, w+200, h*0.8, fill="#4facfe", outline="")
        self.canvas.create_oval(0, h*0.4, w, h+300, fill="#00c6ff", outline="")

        # --- ZURÜCK BUTTON (Oben Links) ---
        if self.cancel_callback:
            btn_back_bg = self._create_rounded_rect(20, 20, 240, 60, radius=20, fill="#000000", stipple="gray25", outline="white", width=1)
            btn_back_txt = self.canvas.create_text(130, 40, text="← Zurück zum Dashboard", font=("Segoe UI", 10, "bold"), fill="white")
            
            def go_back(e):
                self.is_running = False # Timer stoppen
                self.cancel_callback()
            
            self.canvas.tag_bind(btn_back_bg, "<Button-1>", go_back)
            self.canvas.tag_bind(btn_back_txt, "<Button-1>", go_back)
            
            def on_enter_back(e):
                self.canvas.config(cursor="hand2")
                self.canvas.itemconfig(btn_back_txt, fill="#FFFF00") 
            def on_leave_back(e):
                self.canvas.config(cursor="")
                self.canvas.itemconfig(btn_back_txt, fill="white")
                
            self.canvas.tag_bind(btn_back_bg, "<Enter>", on_enter_back)
            self.canvas.tag_bind(btn_back_bg, "<Leave>", on_leave_back)
            self.canvas.tag_bind(btn_back_txt, "<Enter>", on_enter_back)
            self.canvas.tag_bind(btn_back_txt, "<Leave>", on_leave_back)

        # --- NEU: TIMER ANZEIGE (Oben Rechts) ---
        # WICHTIG: Wir nutzen direkt self.time_left für die Initialanzeige beim Zeichnen
        self.canvas.create_text(w - 30, 40, 
                                text=f"Auto-Abbruch in: {self.time_left}s", 
                                font=("Segoe UI", 11, "bold"), 
                                fill="white", 
                                anchor="e", 
                                tags="timer_text")

        # 2. CARD
        card_w, card_h = 380, 500
        cx, cy = w // 2, h // 2
        x1, y1 = cx - card_w//2, cy - card_h//2
        x2, y2 = cx + card_w//2, cy + card_h//2
        
        # Schatten
        self._create_rounded_rect(x1+15, y1+15, x2+15, y2+15, radius=30, fill="#202020", stipple="gray50")
        self._create_rounded_rect(x1, y1, x2, y2, radius=30, fill=self.c_card, outline="white", width=2)
        
        # 3. ICON
        icon_y = y1 + 80
        self.canvas.create_oval(cx-40, icon_y-40, cx+40, icon_y+40, fill=self.c_btn_bg, outline="")
        self.canvas.create_arc(cx-20, icon_y+15, cx+20, icon_y+55, start=0, extent=180, style=tk.ARC, outline="white", width=3)
        self.canvas.create_oval(cx-12, icon_y-25, cx+12, icon_y-1, outline="white", width=3)

        # 4. TEXT
        self.canvas.create_text(cx, icon_y + 60, text="MITARBEITER LOGIN", font=("Segoe UI", 14), fill="white")

        # 5. INPUTS
        inp_w, inp_h = 300, 50
        user_y = icon_y + 110
        self._draw_input_pill(cx, user_y, inp_w, inp_h, "user")
        
        pass_y = user_y + 70
        self._draw_input_pill(cx, pass_y, inp_w, inp_h, "pass")

        # 6. LOGIN BUTTON
        btn_y = pass_y + 90
        btn_w, btn_h = 180, 50
        
        self._create_rounded_rect(cx-btn_w//2+5, btn_y-btn_h//2+5, cx+btn_w//2+5, btn_y+btn_h//2+5, radius=25, fill="#000000", stipple="gray50")
        btn_id = self._create_rounded_rect(cx-btn_w//2, btn_y-btn_h//2, cx+btn_w//2, btn_y+btn_h//2, radius=25, fill=self.c_btn_bg, outline="")
        txt_id = self.canvas.create_text(cx, btn_y, text="LOGIN", font=("Segoe UI", 12, "bold"), fill="white")
        
        self.canvas.tag_bind(btn_id, "<Button-1>", lambda e: self.login_callback(self.user_var.get(), self.pass_var.get()))
        self.canvas.tag_bind(txt_id, "<Button-1>", lambda e: self.login_callback(self.user_var.get(), self.pass_var.get()))
        
        self.canvas.tag_bind(btn_id, "<Enter>", lambda e: self.canvas.config(cursor="hand2"))
        self.canvas.tag_bind(btn_id, "<Leave>", lambda e: self.canvas.config(cursor=""))

    def _draw_input_pill(self, cx, cy, w, h, type_):
        x1, y1 = cx - w//2, cy - h//2
        x2, y2 = cx + w//2, cy + h//2
        self._create_rounded_rect(x1, y1, x2, y2, radius=25, fill=self.c_input_bg, outline="white", width=2)
        
        icon_x = x1 + 30
        if type_ == "user":
            self.canvas.create_oval(icon_x-7, cy-12, icon_x+7, cy+2, outline="white", width=2)
            self.canvas.create_arc(icon_x-10, cy+5, icon_x+10, cy+20, start=0, extent=180, style=tk.ARC, outline="white", width=2)
            var = self.user_var
            show_char = ""
        else:
            self.canvas.create_rectangle(icon_x-6, cy-2, icon_x+6, cy+10, outline="white", width=2)
            self.canvas.create_arc(icon_x-6, cy-12, icon_x+6, cy+2, start=0, extent=180, style=tk.ARC, outline="white", width=2)
            var = self.pass_var
            show_char = "*"

        entry = tk.Entry(self.canvas, textvariable=var, font=("Segoe UI", 12), 
                         bg=self.c_input_bg, fg="white", bd=0, highlightthickness=0, 
                         insertbackground="white", show=show_char)
        self.canvas.create_window(cx + 15, cy, window=entry, width=w-70, height=h-10)
        entry.bind("<Return>", lambda e: self.login_callback(self.user_var.get(), self.pass_var.get()))
        
        
class WeekendPlannerApp:
    """
    Modernes Jahres-Wochenend-Planungstool.
    Integriert als Sub-Modul in die Hauptanwendung.
    """
    def __init__(self, parent_frame, app_ref):
        self.parent_frame = parent_frame
        self.app = app_ref
        self.data_file = os.path.join(self.app.effective_data_root, 'weekend_planner_data.json')
        
        # Moderne "Light Theme" Palette (Weiß, Sauber, Bunt)
        self.colors = {
            'card_bg': '#FFFFFF',       # Weißer Hintergrund
            'card_border': '#E0E0E0',   # Sehr heller grauer Rand
            'shadow': '#D6D6D6',        # Sanfter grauer Schatten
            
            'text_header': '#333333',   # Dunkelgrau für Namen (besser lesbar als Schwarz)
            'text_sub': '#777777',      # Mittelgrau für Labels
            
            # Lebendige Akzentfarben (Nicht zu grell, aber kräftig)
            'accent_good': '#00C853',   # Kräftiges Grün
            'accent_avg': '#0091EA',    # Kräftiges Hellblau
            'accent_bad': '#FF3D00',    # Kräftiges Orange/Rot
            'accent_neutral': '#78909C',# Blau-Grau
            
            'weekend_sat': '#F3F4F6',   # Hintergrund der App (Hellgrau)
            'weekend_sun': '#E5E7EB'
        }
        
        self.current_year = datetime.date.today().year
        self.data = self._load_data()
        self.employee_stats = {}
        self.button_images = {} # <--- NEU: Cache für Bilder
         # --- NEU: Eigenes Passwort-Management ---
        # 1. Standard-Passwort setzen, falls noch keines existiert
        if 'admin_password' not in self.data:
            self.data['admin_password'] = "planer123" # Standard-Passwort
            self._save_data()
            
        # 2. Status-Variable: Ist der Bereich aktuell freigeschaltet?
        self.is_planner_unlocked = False 
        
         # --- NEU: User Rolle ---
        self.current_role = None # 'admin' oder 'user' oder None
        self.is_logged_in = False
        
        # --- AUTO-LOGOUT & TIMER ---
        self.TIMEOUT_SECONDS = 10 * 60  # 10 Minuten
        self.last_activity_time = 0
        self.timer_loop_id = None
        self.timer_bar_id = None # ID für den Balken im Canvas
        self._motion_bind_id = None
        self._key_bind_id = None
        self._button_bind_id = None
        
        # UI Aufbau
        self._build_ui()
        
    def _execute_if_planner_admin(self, callback, *args):
        """
        Spezielle Sicherheits-Methode NUR für den Wochenendplaner.
        Prüft das lokale Passwort dieses Moduls.
        """
        # 1. Prüfen, ob bereits freigeschaltet
        if self.is_planner_unlocked:
            if callback: callback(*args)
            return "break"

        # 2. Passwort abfragen
        password = simpledialog.askstring(
            "Wochenend-Planer Login", 
            "Bitte Passwort für den Planungsbereich eingeben:", 
            show='*', 
            parent=self.parent_frame
        )

        # 3. Prüfung
        stored_password = self.data.get('admin_password', 'planer123')
        
        if password == stored_password:
            # Erfolg
            self.is_planner_unlocked = True
            
            # KORREKTUR: Hier rufen wir jetzt die Sichtbarkeits-Methode auf, 
            # damit sofort alle Buttons erscheinen und das Schloss-Icon wechselt.
            if hasattr(self, '_update_nav_visibility'):
                self._update_nav_visibility()
            
            if 'SuccessToast' in globals():
                SuccessToast(self.parent_frame, "Login erfolgreich", "Bearbeitungsmodus aktiviert.", "success")
            
            # Aktion ausführen
            if callback: callback(*args)
        else:
            # Misserfolg
            if password is not None: 
                if 'SuccessToast' in globals():
                    SuccessToast(self.parent_frame, "Zugriff verweigert", "Falsches Passwort.", "error")
                else:
                    messagebox.showerror("Fehler", "Falsches Passwort.")
        
        return "break"

    def _load_data(self):
        if os.path.exists(self.data_file):
            try:
                with open(self.data_file, 'r', encoding='utf-8') as f:
                    return json.load(f)
            except: pass
        return {"employees": [], "assignments": {}, "year": self.current_year}

    def _save_data(self):
        try:
            with open(self.data_file, 'w', encoding='utf-8') as f:
                json.dump(self.data, f, indent=2, ensure_ascii=False)
        except Exception as e:
            print(f"Fehler beim Speichern des Wochenendplaners: {e}")
            
    def _configure_nav_button(self, btn, config_key, default_text, default_icon_char=""):
        """
        Konfiguriert einen Button dynamisch.
        FIX: Erzwingt die konfigurierte Höhe nun auch bei Standard-Buttons ohne eigenes Bild!
        """
        # --- EINSTELLUNGEN LADEN ---
        view_settings = self.data.get('view_settings', {})
        icon_size = view_settings.get('icon_size', 32)
        show_text = view_settings.get('show_text', False)

        configs = self.data.get('button_configs', {})
        icon_path = configs.get(config_key)
        
        # Imports prüfen
        try:
            from PIL import Image, ImageTk
            pil_available = True
        except ImportError:
            pil_available = False

        # --- FALL 1: Benutzerdefiniertes Bild vorhanden ---
        if pil_available and icon_path and os.path.exists(icon_path):
            try:
                # Bild laden und skalieren
                img = Image.open(icon_path).resize((icon_size, icon_size), Image.Resampling.LANCZOS)
                photo = ImageTk.PhotoImage(img)
                
                # Im Cache speichern
                self.button_images[config_key] = photo
                
                if show_text:
                    btn.config(image=photo, text=f" {default_text}", compound="left")
                else:
                    btn.config(image=photo, text="", compound="center")
                    if 'ToolTip' in globals():
                        ToolTip(btn, default_text)
                return 
            except Exception as e:
                print(f"Fehler Bild {config_key}: {e}")

        # --- FALL 2: Kein Bild (Standard) -> Höhe erzwingen! ---
        
        if pil_available:
            # Wir erstellen ein unsichtbares Platzhalter-Bild.
            # Breite: 1px, Höhe: exakt die eingestellte 'icon_size'
            spacer_img = Image.new("RGBA", (1, icon_size), (0, 0, 0, 0)) 
            spacer_photo = ImageTk.PhotoImage(spacer_img)
            
            # WICHTIG: Referenz speichern, sonst löscht Python das Bild sofort wieder
            self.button_images[f"{config_key}_spacer"] = spacer_photo
            
            display_text = f"{default_icon_char} {default_text}"
            
            # Wir setzen das unsichtbare Bild UND den Text.
            # compound="left" sorgt dafür, dass das Bild (die Höhe) den Button aufspannt.
            btn.config(image=spacer_photo, text=display_text, compound="left")
            
        else:
            # Fallback ohne PIL (sollte nicht passieren, da Rest der App PIL nutzt)
            btn.config(text=f"{default_icon_char} {default_text}", image="", compound="left")
            
    def _update_lock_button_appearance(self):
        """Aktualisiert Text und Icon des Lock-Buttons basierend auf Config."""
        if not hasattr(self, 'btn_lock'): return

        if self.is_planner_unlocked:
            # Zustand: Eingeloggt -> Zeige Logout
            self._configure_nav_button(self.btn_lock, 'btn_logout', "Logout", "🔒")
        else:
            # Zustand: Ausgeloggt -> Zeige Login
            self._configure_nav_button(self.btn_lock, 'btn_login', "Login", "🔓")

    def _handle_lock_click(self):
        """Logout Button: Zurück zum Login-Screen."""
        if messagebox.askyesno("Abmelden", "Möchten Sie sich abmelden?"):
            # --- NEU: Timer stoppen ---
            self._stop_inactivity_monitor()
            
            self.is_logged_in = False
            self.current_role = None
            self.is_planner_unlocked = False
            
            self._build_ui()
    
    def _update_nav_visibility(self):
        """
        Steuert die Sichtbarkeit der Navigations-Buttons basierend auf dem Login-Status.
        """
        # Sicherheitscheck, falls UI noch nicht gebaut wurde
        if not hasattr(self, 'nav_btn_frame'): return

        # 1. Alle Buttons erst einmal verstecken (aus dem Layout nehmen)
        for btn in [self.btn_help, self.btn_dashboard, self.btn_planner, 
                    self.btn_analysis, self.btn_settings, self.btn_lock, self.nav_separator]:
            btn.pack_forget()

        # 2. Hilfe-Button (Immer sichtbar oder nur bei Admin? Laut Anforderung "Nur Karten und Login")
        # Wir lassen Hilfe mal da, ist nützlich. Wenn strikt nur Login gewünscht, Zeile auskommentieren.
        self.btn_help.pack(side='left', padx=5)

        # 3. Wenn EINGELOGGT: Funktions-Buttons anzeigen
        if self.is_planner_unlocked:
            self.btn_dashboard.pack(side='left', padx=5)
            self.btn_planner.pack(side='left', padx=5)
            self.btn_analysis.pack(side='left', padx=5)
            self.btn_settings.pack(side='left', padx=5)
            self.nav_separator.pack(side='left', padx=10, fill='y', pady=10)

        # 4. Login/Logout Button (Immer sichtbar, aber ganz rechts)
        self.btn_lock.pack(side='left', padx=5)
        
        # Button-Text und Icon aktualisieren
        self._update_lock_button_appearance()
    

    def _build_ui(self):
        """
        Haupt-Einstiegspunkt für die UI.
        Entscheidet, ob der Login-Screen oder die App angezeigt wird.
        """
        # 1. Alles bereinigen
        for widget in self.parent_frame.winfo_children():
            widget.destroy()

        # 2. Entscheidung treffen
        # Wenn nicht eingeloggt -> Login Screen anzeigen
        if not getattr(self, 'is_logged_in', False):
            # Nur zum Dashboard navigieren, wenn der Wochenendplaner auch wirklich
            # die aktive Seite ist. Falls der Nutzer auf einer anderen Seite arbeitet
            # und der Timer im Hintergrund abläuft, wird der Redirect ignoriert.
            def _on_login_timeout():
                if self.app.current_page_name == "Wochenendplaner":
                    self.app.show_page("Dashboard")

            ModernLoginScreen(
                self.parent_frame,
                self._perform_login,
                cancel_callback=_on_login_timeout
            )
        else:
            # Wenn eingeloggt -> Die Haupt-App bauen
            self._build_main_app()
        
    def _show_help_window(self):
        """Öffnet das Hilfe-Fenster."""
        WeekendPlannerHelpDialog(self.parent_frame.winfo_toplevel())

    def _show_tab(self, tab_name):
        for widget in self.content_area.winfo_children(): widget.destroy()
        
        if tab_name == "dashboard":
            self._build_dashboard()
        elif tab_name == "planner":
            self._build_planner()
        
        
        elif tab_name == "analysis":   # <--- NEU
            self._build_analysis()     # <--- NEU
        
        elif tab_name == "settings":
            self._build_settings()

    def _reset_and_show_planner(self):
        """
        Setzt den Filter auf 'Alle' zurück und öffnet dann den Planer.
        Wird aufgerufen, wenn man oben im Menü auf 'Jahresplaner' klickt.
        """
        self.filter_var = "Alle"
        self._show_tab("planner")

    def _calculate_stats(self):
        """
        Zählt Wochenenden (angepasst auf Mehrfach-Belegung).
        """
        employees = self.data.get('employees', [])
        stats = {name: 0 for name in employees}
        
        year = int(self.data.get('year', self.current_year))
        
        date = datetime.date(year, 1, 1)
        end_date = datetime.date(year, 12, 31)
        
        while date <= end_date:
            if date.weekday() == 5: # Samstag
                sunday = date + datetime.timedelta(days=1)
                
                # Listen abrufen
                emps_sat = self._get_assignments_list(str(date))
                emps_sun = self._get_assignments_list(str(sunday)) if sunday.year == year else []
                
                # Einzigartige Mitarbeiter an diesem WE sammeln
                weekend_employees = set(emps_sat) | set(emps_sun)
                
                for emp in weekend_employees:
                    if emp in stats:
                        stats[emp] += 1
            
            date += datetime.timedelta(days=1)

        return stats

    def _build_dashboard(self):
        stats = self._calculate_stats()
        current_year = self.data.get('year')
        
        # --- 1. MODERNER DASHBOARD HEADER ---
        # Container (Hintergrundfarbe der App)
        header_container = tk.Frame(self.content_area, bg=self.colors['weekend_sat'], pady=0, padx=0)
        header_container.pack(fill='x', pady=(0, 20))

        # Die weiße "Karte" (Header Card)
        header_card = tk.Frame(header_container, bg="white", padx=25, pady=20)
        header_card.pack(fill='x')

        # Akzent-Balken links (Blau) - Das Design-Element
        accent_bar = tk.Frame(header_card, bg="#2F65C3", width=6) # BWP Blau
        accent_bar.pack(side='left', fill='y', padx=(0, 15))

        # Text-Bereich
        text_frame = tk.Frame(header_card, bg="white")
        text_frame.pack(side='left', fill='both')

        # Große Überschrift
        tk.Label(text_frame, text="Analyse & Statistik", 
                 font=("Segoe UI", 22, "bold"), fg="#2C3E50", bg="white").pack(anchor='w')

        # Feine Unterüberschrift mit dem Jahr
        tk.Label(text_frame, text=f"Übersicht der freien Wochenend-Tage im Jahr {current_year}", 
                 font=("Segoe UI", 11), fg="#7F8C8D", bg="white").pack(anchor='w', pady=(2, 0))

        # --- 2. KACHELN CONTAINER ---
        # Container für die Cards
        tiles_frame = ttk.Frame(self.content_area, style='AppBackground.TFrame')
        tiles_frame.pack(fill='both', expand=True)

        # Wenn keine Mitarbeiter da sind
        if not stats:
            empty_frame = tk.Frame(tiles_frame, bg=self.colors['weekend_sat'], pady=50)
            empty_frame.pack(fill='x')
            tk.Label(empty_frame, text="Noch keine Daten vorhanden.", 
                     font=("Segoe UI", 14, "bold"), fg="#999", bg=self.colors['weekend_sat']).pack()
            tk.Label(empty_frame, text="Fügen Sie Mitarbeiter in den Einstellungen hinzu.", 
                     font=("Segoe UI", 11), fg="#999", bg=self.colors['weekend_sat']).pack()
            return

        # Grid für Kacheln
        row = 0
        col = 0
        max_cols = 4
        
        for name, count in stats.items():
            self._create_stat_card(tiles_frame, name, count, row, col)
            col += 1
            if col >= max_cols:
                col = 0
                row += 1

    def _create_stat_card(self, parent, name, count, row, col):
        """
        Erstellt eine Karte.
        UPDATE: Toggle-Button ist für ALLE klickbar (Read-Only),
        der Rest der Karte (Sprung zum Planer) bleibt Admin-Only.
        """
        # --- 0. BERECHNUNG & LOGIK ---
        details = self._get_employee_weekend_details(name)
        weekend_count = count // 2 
        
        # Farben & Status
        if count == 0:
            accent_color = self.colors['accent_neutral']
            bg_color = "#FFFFFF"
            status_text = "Keine Einträge"
            list_header_bg = "#F3F4F6"
        elif weekend_count < 3:
            accent_color = self.colors['accent_bad']
            bg_color = "#FFF5F5"
            status_text = "Wenig frei"
            list_header_bg = "#FFF0F0"
        elif weekend_count < 6:
            accent_color = self.colors['accent_avg']
            bg_color = "#F0F7FF"
            status_text = "Durchschnitt"
            list_header_bg = "#E6F7FF"
        else:
            accent_color = self.colors['accent_good']
            bg_color = "#F1FBF5"
            status_text = "Viel frei"
            list_header_bg = "#E8F5E9"

        # --- 1. HAUPT-CONTAINER ---
        main_frame = tk.Frame(parent, bg=self.colors['weekend_sat'])
        main_frame.grid(row=row, column=col, padx=15, pady=15, sticky='n')

        # --- 2. DIE KARTE ---
        card_w = 280
        card_h = 130
        
        c = tk.Canvas(main_frame, width=card_w + 5, height=card_h + 15, 
                      bg=self.colors['weekend_sat'], bd=0, highlightthickness=0)
        c.pack(side='top')

        # Zeichnen
        c.create_rectangle(4, 4, card_w, card_h, fill=self.colors['shadow'], outline="", tag="bg_rect")
        c.create_rectangle(0, 0, card_w-4, card_h-4, fill=bg_color, outline=self.colors['card_border'], width=1, tag="bg_rect")
        c.create_rectangle(0, 0, 6, card_h-4, fill=accent_color, outline="", tag="bg_rect")

        # Avatar
        initials = "".join([n[0] for n in name.split()[:2]]).upper()
        c.create_oval(20, 20, 70, 70, fill="#FFFFFF", outline=accent_color, width=2, tag="content")
        c.create_text(45, 45, text=initials, font=("Segoe UI", 14, "bold"), fill=accent_color, tag="content")

        # Text
        c.create_text(80, 25, text=name, anchor='nw', font=("Segoe UI", 12, "bold"), 
                      fill=self.colors['text_header'], width=130, tag="content")
        c.create_text(80, 75, text=status_text, anchor='nw', font=("Segoe UI", 9), 
                      fill=self.colors['text_sub'], tag="content")

        # Zahl
        c.create_text(230, 50, text=str(weekend_count), anchor='center', font=("Segoe UI", 36, "bold"), 
                      fill=accent_color, tag="content")
        c.create_text(230, 85, text="WE", anchor='center', font=("Segoe UI", 8, "bold"), 
                      fill=self.colors['text_sub'], tag="content")

        # --- 3. TOGGLE BUTTON ---
        # Wichtig: Eigene Tags für den Button, um Events zu trennen
        btn_tag_bg = f"btn_bg_{row}_{col}"
        btn_tag_txt = f"btn_txt_{row}_{col}"
        btn_tag_group = f"btn_group_{row}_{col}"

        c.create_oval(120, card_h-20, 150, card_h+10, fill="#FFFFFF", outline=self.colors['card_border'], tags=(btn_tag_bg, btn_tag_group))
        arrow_id = c.create_text(135, card_h-3, text="▼", font=("Segoe UI", 10, "bold"), fill="#555555", tags=(btn_tag_txt, btn_tag_group))

        # --- 4. DETAIL-BEREICH ---
        detail_frame = tk.Frame(main_frame, bg="white", bd=1, relief="solid")
        detail_frame.config(highlightbackground=accent_color, highlightthickness=1, bd=0)

        header_f = tk.Frame(detail_frame, bg=list_header_bg, pady=8)
        header_f.pack(fill='x')
        tk.Label(header_f, text=f"Freie Wochenenden {self.data.get('year')}", 
                 font=("Segoe UI", 10, "bold"), bg=list_header_bg, fg="#333").pack()

        list_container = tk.Frame(detail_frame, bg="white", padx=5, pady=5)
        list_container.pack(fill='both', expand=True)

        if not details:
            tk.Label(list_container, text="Noch keine Eintragungen", bg="white", fg="#999", pady=10).pack()
        else:
            details.sort(key=lambda x: x['sat'])
            
            for d in details:
                # Text formatieren
                prefix = "•"
                if d.get('type') == "Nur Samstag": prefix = "Nur Sa,"
                elif d.get('type') == "Nur Sonntag": prefix = "Nur So,"
                else: prefix = "Sa & So,"

                date_str = f"{d['sat'].strftime('%d.%m.')} - {d['sun'].strftime('%d.%m.%Y')}"
                if d.get('type') == "Nur Samstag": date_str = f"{d['sat'].strftime('%d.%m.%Y')}"
                elif d.get('type') == "Nur Sonntag": date_str = f"{d['sun'].strftime('%d.%m.%Y')}"
                
                row_d = tk.Frame(list_container, bg="white", pady=2)
                row_d.pack(fill='x', pady=1)
                
                # Ticket Style
                tk.Label(row_d, text=f"{prefix} {date_str}".replace("Sa & So,", "•"), font=("Segoe UI", 8), bg="white", fg="#555").pack(side='left')
                tk.Label(row_d, text=f"(KW {d['kw']})", font=("Segoe UI", 7), bg="white", fg="#999").pack(side='right')

        # --- 5. LOGIK & BINDINGS ---
        state = {'expanded': False}

        def toggle_details(event=None):
            if state['expanded']:
                detail_frame.pack_forget()
                c.itemconfig(arrow_id, text="▼", fill="#555")
                state['expanded'] = False
            else:
                detail_frame.pack(fill='x', padx=2, pady=(0, 5))
                c.itemconfig(arrow_id, text="▲", fill=accent_color)
                state['expanded'] = True
            return "break"

        # KORREKTUR: Der Toggle-Button ist NICHT mehr admin-geschützt!
        # Jeder (auch Nur-Lesen-User) darf Details aufklappen.
        c.tag_bind(btn_tag_group, "<Button-1>", toggle_details)
        
        # Hover Effekte für Button
        def on_enter_btn(e): 
            c.config(cursor="hand2")
            c.itemconfig(btn_tag_bg, fill="#F9F9F9", outline=accent_color)
        def on_leave_btn(e): 
            c.config(cursor="")
            c.itemconfig(btn_tag_bg, fill="#FFFFFF", outline=self.colors['card_border'])
            
        c.tag_bind(btn_tag_group, "<Enter>", on_enter_btn)
        c.tag_bind(btn_tag_group, "<Leave>", on_leave_btn)
        
        # Admin-Funktion: Zum Planer springen
        def jump_to_planner(event=None):
            self._jump_to_planner_filter(name)

        # KORREKTUR: Der Sprung zum Planer bleibt ADMIN-ONLY!
        c.tag_bind("bg_rect", "<Button-1>", lambda e: self._execute_if_planner_admin(jump_to_planner))
        c.tag_bind("content", "<Button-1>", lambda e: self._execute_if_planner_admin(jump_to_planner))
        
        # Hover Effekte für Karte
        def on_enter_card(e): c.config(cursor="hand2")
        def on_leave_card(e): c.config(cursor="")
        c.tag_bind("bg_rect", "<Enter>", on_enter_card)
        c.tag_bind("bg_rect", "<Leave>", on_leave_card)

    def _jump_to_planner_filter(self, employee_name):
        self.filter_var = employee_name
        self._show_tab("planner")

    def _build_planner(self):
        # --- 1. FILTER BAR ---
        filter_container = tk.Frame(self.content_area, bg="#F3F4F6", pady=15, padx=20)
        filter_container.pack(fill='x')
        
        filter_card = tk.Frame(filter_container, bg="white", padx=15, pady=10)
        filter_card.pack(fill='x')
        filter_card.config(highlightbackground="#E0E0E0", highlightthickness=1)
        
        tk.Label(filter_card, text="🔍 MITARBEITER FILTERN:", font=("Segoe UI", 9, "bold"), fg="#7F8C8D", bg="white").pack(side='left', padx=(0, 10))
        
        employees = ["Alle"] + self.data.get('employees', [])
        self.filter_combo = ttk.Combobox(filter_card, values=employees, state="readonly", font=("Segoe UI", 11), width=30)
        
        if hasattr(self, 'filter_var') and self.filter_var in employees:
            self.filter_combo.set(self.filter_var)
        else:
            self.filter_combo.set("Alle")
            
        self.filter_combo.pack(side='left')
        self.filter_combo.bind("<<ComboboxSelected>>", self._refresh_planner_list)
        
        if self.filter_combo.get() != "Alle":
            tk.Label(filter_card, text="✕ Filter aktiv", fg="#E74C3C", bg="white", font=("Segoe UI", 9), cursor="hand2").pack(side='left', padx=10)

        # --- 2. SPLIT CONTAINER ---
        split_frame = tk.Frame(self.content_area, bg=self.colors['weekend_sat'])
        split_frame.pack(fill='both', expand=True)

        # --- A) LINKER BEREICH: Kalender (Monate) ---
        left_area = tk.Frame(split_frame, bg=self.colors['weekend_sat'])
        left_area.pack(side='left', fill='both', expand=True, padx=(0, 10))

        self.calendar_canvas = tk.Canvas(left_area, bg=self.colors['weekend_sat'], highlightthickness=0)
        scrollbar = ttk.Scrollbar(left_area, orient="vertical", command=self.calendar_canvas.yview)
        
        self.scrollable_frame = ttk.Frame(self.calendar_canvas, style='AppBackground.TFrame')
        self.scrollable_frame.bind("<Configure>", lambda e: self.calendar_canvas.configure(scrollregion=self.calendar_canvas.bbox("all")))

        self.calendar_canvas.create_window((0, 0), window=self.scrollable_frame, anchor="nw")
        self.calendar_canvas.configure(yscrollcommand=scrollbar.set)

        self.calendar_canvas.pack(side="left", fill="both", expand=True)
        scrollbar.pack(side="right", fill="y")
        
        # FIX: Smart Scroll für LINKS aktivieren
        self._attach_smart_scroll(self.calendar_canvas, self.scrollable_frame)

        # --- B) RECHTER BEREICH: Live-Statistik ---
        right_area = tk.Frame(split_frame, bg="white", width=350)
        right_area.pack(side='right', fill='y')
        right_area.pack_propagate(False)

        # Header Sidebar
        header_f = tk.Frame(right_area, bg="white")
        header_f.pack(fill='x', padx=10)
        tk.Label(header_f, text="Aktueller Stand", font=("Segoe UI", 12, "bold"), bg="white", fg="#2C3E50").pack(pady=(20, 5))
        tk.Label(header_f, text=f"Jahr {self.data.get('year')}", font=("Segoe UI", 10), bg="white", fg="#7F8C8D").pack(pady=(0, 10))
        ttk.Separator(header_f, orient='horizontal').pack(fill='x', pady=5)

        # Scrollbarer Bereich Sidebar
        self.sidebar_canvas = tk.Canvas(right_area, bg="white", highlightthickness=0)
        sb_scroll = ttk.Scrollbar(right_area, orient="vertical", command=self.sidebar_canvas.yview)
        
        self.stats_list_frame = tk.Frame(self.sidebar_canvas, bg="white")
        self.stats_list_frame.bind("<Configure>", lambda e: self.sidebar_canvas.configure(scrollregion=self.sidebar_canvas.bbox("all")))
        
        self.sidebar_canvas.create_window((0, 0), window=self.stats_list_frame, anchor="nw", width=330)
        self.sidebar_canvas.configure(yscrollcommand=sb_scroll.set)
        
        self.sidebar_canvas.pack(side="left", fill="both", expand=True)
        sb_scroll.pack(side="right", fill="y")
        
        # FIX: Smart Scroll für RECHTS aktivieren
        self._attach_smart_scroll(self.sidebar_canvas, self.stats_list_frame)

        # Initial generieren
        self._populate_planner_days()
        self._update_planner_sidebar_stats()

    def _populate_planner_days(self):
        """
        Generiert die moderne Timeline-Liste mit aufklappbaren Monaten (Accordion).
        """
        # 1. Bereinigen
        for widget in self.scrollable_frame.winfo_children(): widget.destroy()

        self.scrollable_frame.configure(style='AppBackground.TFrame')

        # 2. Daten sammeln
        year = int(self.data.get('year', self.current_year))
        filter_val = self.filter_combo.get()
        month_buckets = {i: [] for i in range(1, 13)}
        
        date = datetime.date(year, 1, 1)
        end_date = datetime.date(year, 12, 31)
        
        while date <= end_date:
            if date.weekday() in [5, 6]:
                assigned_emp = self.data.get('assignments', {}).get(str(date), "")
                is_match = True
                if filter_val != "Alle" and assigned_emp != filter_val:
                    is_match = False
                
                if is_match:
                    month_buckets[date.month].append((date, assigned_emp, filter_val))
            date += datetime.timedelta(days=1)

        # 3. UI erstellen
        for month_idx in range(1, 13):
            days = month_buckets[month_idx]
            if not days: continue 
            
            # Alle zugeklappt beim Start
            is_expanded = False
            self._create_month_section(self.scrollable_frame, year, month_idx, days, is_expanded)

        # --- FIX: Scrollregion nach dem Aufbau aktualisieren ---
        self.scrollable_frame.update_idletasks()
        if hasattr(self, 'calendar_canvas'):
            self.calendar_canvas.configure(scrollregion=self.calendar_canvas.bbox("all"))
            
    def _create_month_section(self, parent, year, month_idx, days, is_expanded_initially):
        """
        Erstellt einen aufklappbaren Monats-Container.
        Mit Scroll-Fix beim Auf/Zuklappen.
        """
        month_names = ["", "Januar", "Februar", "März", "April", "Mai", "Juni", "Juli", "August", "September", "Oktober", "November", "Dezember"]
        month_name = month_names[month_idx]

        # 1. Wrapper
        section_container = tk.Frame(parent, bg=self.colors['weekend_sat'])
        section_container.pack(fill='x', pady=(15, 0))

        # 2. Header
        header_frame = tk.Frame(section_container, bg="#FFFFFF", cursor="hand2", pady=8, padx=10)
        header_frame.pack(fill='x')
        
        tk.Frame(header_frame, bg="#2F65C3", height=2).pack(fill='x', side='top', pady=(0, 5))

        header_inner = tk.Frame(header_frame, bg="#FFFFFF")
        header_inner.pack(fill='x')

        arrow_var = tk.StringVar(value="▼" if is_expanded_initially else "▶")
        icon_lbl = tk.Label(header_inner, textvariable=arrow_var, font=("Segoe UI", 12), fg="#555", bg="#FFFFFF")
        icon_lbl.pack(side='left', padx=(5, 10))

        title_lbl = tk.Label(header_inner, text=f"{month_name} {year}", font=("Segoe UI", 14, "bold"), fg="#2C3E50", bg="#FFFFFF")
        title_lbl.pack(side='left')

        count_lbl = tk.Label(header_inner, text=f"({len(days)} Tage)", font=("Segoe UI", 10), fg="#999", bg="#FFFFFF")
        count_lbl.pack(side='left', padx=10)

        # 3. Content
        content_frame = tk.Frame(section_container, bg=self.colors['weekend_sat'])
        for date_obj, assigned_emp, filter_val in days:
            self._create_day_card(content_frame, date_obj, assigned_emp, filter_val)

        # 4. Toggle Logik
        state = {'expanded': is_expanded_initially}

        def toggle(event=None):
            if state['expanded']:
                # Zuklappen
                content_frame.pack_forget()
                arrow_var.set("▶")
                title_lbl.config(fg="#777")
                state['expanded'] = False
            else:
                # Aufklappen
                content_frame.pack(fill='x', pady=(0, 10))
                arrow_var.set("▼")
                title_lbl.config(fg="#2C3E50")
                state['expanded'] = True
            
            # --- FIX: SCROLLBAR AKTUALISIEREN ---
            # Wir warten kurz, bis das Layout neu berechnet ist, und updaten dann den Canvas
            self.scrollable_frame.update_idletasks()
            if hasattr(self, 'calendar_canvas'):
                self.calendar_canvas.configure(scrollregion=self.calendar_canvas.bbox("all"))

            return "break"

        for w in [header_frame, header_inner, icon_lbl, title_lbl, count_lbl]:
            w.bind("<Button-1>", toggle)

        # 5. Initialer Status
        if is_expanded_initially:
            content_frame.pack(fill='x', pady=(0, 10))
            title_lbl.config(fg="#2C3E50")
        else:
            content_frame.pack_forget()
            title_lbl.config(fg="#777")

    def _create_day_card(self, parent, date_obj, assigned_emp_raw, filter_active):
        """
        Erstellt eine Zeile im Kalender.
        UPDATE: Unterstützt jetzt MEHRERE Mitarbeiter pro Tag.
        """
        # Daten sicher als Liste laden
        assigned_list = self._get_assignments_list(str(date_obj))
        
        is_saturday = (date_obj.weekday() == 5)
        day_accent = "#3498DB" if is_saturday else "#E67E22"
        day_label = "SAMSTAG" if is_saturday else "SONNTAG"
        
        # Hintergrund: Grünlich, wenn JEMAND eingetragen ist
        has_assignments = len(assigned_list) > 0
        
        # Spezieller Check für Filter: Ist der GEFILTERTE MA dabei?
        is_filter_match = True
        if filter_active != "Alle":
            if filter_active not in assigned_list:
                is_filter_match = False
        
        # Hintergrundlogik
        card_bg = "#FFFFFF"
        if has_assignments:
            card_bg = "#F4FDF4" # Generell belegt
        
        # Visueller Fokus wenn Filter aktiv und Match
        if filter_active != "Alle" and is_filter_match:
             card_bg = "#E8F5E9" # Stärkeres Grün für Treffer

        # Container
        card_container = tk.Frame(parent, bg=self.colors['weekend_sat'], pady=4, padx=10)
        card_container.pack(fill='x')

        # Karte
        border_col = self.colors['card_border']
        if filter_active != "Alle" and is_filter_match: border_col = "#27AE60" # Grüner Rand bei Filter-Treffer
            
        card = tk.Frame(card_container, bg=card_bg, highlightbackground=border_col, highlightthickness=1)
        card.pack(fill='x', ipady=5)

        # 1. Datum (Links)
        date_canvas = tk.Canvas(card, width=70, height=50, bg=card_bg, highlightthickness=0)
        date_canvas.pack(side='left', padx=(0, 15))
        date_canvas.create_rectangle(0, 0, 6, 60, fill=day_accent, outline="")
        day_num = date_obj.strftime("%d")
        date_canvas.create_text(38, 25, text=day_num, font=("Segoe UI", 20, "bold"), fill="#333333")

        # 2. Info
        info_frame = tk.Frame(card, bg=card_bg)
        info_frame.pack(side='left', fill='y')
        month_str = date_obj.strftime("%m.%Y")
        tk.Label(info_frame, text=day_label, font=("Segoe UI", 9, "bold"), fg=day_accent, bg=card_bg, anchor='w').pack(fill='x')
        tk.Label(info_frame, text=month_str, font=("Segoe UI", 9), fg="#888888", bg=card_bg, anchor='w').pack(fill='x')

        # 3. Status (Rechts)
        status_frame = tk.Frame(card, bg=card_bg)
        status_frame.pack(side='right', padx=20)
        
        if has_assignments:
            tk.Label(status_frame, text="✔", font=("Segoe UI", 14), fg="#27AE60", bg=card_bg).pack(side='left')
            # Text zeigt Anzahl
            count_txt = "Eingeteilt" if len(assigned_list) == 1 else f"{len(assigned_list)} Pers."
            tk.Label(status_frame, text=count_txt, font=("Segoe UI", 9, "bold"), fg="#27AE60", bg=card_bg).pack(side='left', padx=5)
        else:
            tk.Label(status_frame, text="○", font=("Segoe UI", 14), fg="#CCCCCC", bg=card_bg).pack(side='left')
            tk.Label(status_frame, text="Offen", font=("Segoe UI", 9), fg="#CCCCCC", bg=card_bg).pack(side='left', padx=5)

        # 4. Input-Bereich (Mitte) - JETZT TEXT + BUTTON
        input_frame = tk.Frame(card, bg=card_bg)
        input_frame.pack(side='left', fill='x', expand=True, padx=20)
        
        tk.Label(input_frame, text="Mitarbeiter:", font=("Segoe UI", 8), fg="#888888", bg=card_bg, anchor='w').pack(fill='x')
        
        # Anzeige-String generieren
        if not assigned_list:
            display_text = "--- Klicken zum Auswählen ---"
            fg_color = "#999"
        else:
            # Zeige erste 2 Namen, dann "..."
            display_text = ", ".join(assigned_list)
            if len(display_text) > 40:
                display_text = display_text[:37] + "..."
            fg_color = "#333"

        # Frame für die "Fake-Combobox" Optik
        click_area = tk.Frame(input_frame, bg="white", highlightbackground="#ADADAD", highlightthickness=1, cursor="hand2")
        click_area.pack(fill='x', ipady=4)
        
        lbl_names = tk.Label(click_area, text=display_text, font=("Segoe UI", 10), bg="white", fg=fg_color, anchor="w")
        lbl_names.pack(side='left', fill='x', expand=True, padx=5)
        
        # Icon rechts (Stift oder Plus)
        btn_icon = tk.Label(click_area, text="👥", font=("Segoe UI Emoji", 10), bg="white")
        btn_icon.pack(side='right', padx=5)

        # --- LOGIK: POPUP DIALOG ---
        def open_multi_select(event=None):
            # Prüfen ob Admin
            self._execute_if_planner_admin(self._show_multi_select_dialog, date_obj, assigned_list)

        # Klick-Events binden
        click_area.bind("<Button-1>", open_multi_select)
        lbl_names.bind("<Button-1>", open_multi_select)
        btn_icon.bind("<Button-1>", open_multi_select)

    def _refresh_planner_list(self, event=None):
        self._populate_planner_days()

    def _bind_mousewheel(self, widget, target):
        """
        Binds mousewheel to a widget and its children for scrolling.
        Enthält jetzt Sicherheitschecks, um Abstürze beim Tab-Wechsel zu verhindern.
        """
        def _on_mousewheel(event):
            try:
                # 1. Prüfen, ob das Widget überhaupt noch existiert
                if not widget.winfo_exists():
                    return
                
                # 2. Prüfen, ob das Widget aktuell sichtbar ist (verhindert Scrollen im Hintergrund)
                if not widget.winfo_viewable():
                    return

                # 3. Scrollen ausführen
                if platform.system() == 'Windows':
                    widget.yview_scroll(int(-1*(event.delta/120)), "units")
                elif platform.system() == 'Darwin':
                    widget.yview_scroll(int(-1*event.delta), "units")
                else:
                    if event.num == 4: widget.yview_scroll(-1, "units")
                    elif event.num == 5: widget.yview_scroll(1, "units")
            
            except (tk.TclError, Exception):
                # Fängt Fehler ab, falls das Widget während des Scrollens zerstört wird
                pass
        
        # Wir nutzen bind_all hier, müssen aber sicherstellen, dass es nicht crasht
        # Eine sauberere Lösung wäre bind auf <Enter>/<Leave>, aber der try-except Block
        # behebt den akuten Absturz zuverlässig.
        target.bind_all("<MouseWheel>", _on_mousewheel)
        target.bind_all("<Button-4>", _on_mousewheel)
        target.bind_all("<Button-5>", _on_mousewheel)

    def _build_settings(self):
        # Haupt-Container für den Einstellungs-Tab
        f = ttk.Frame(self.content_area, style='AppBackground.TFrame', padding=20)
        f.pack(fill='both', expand=True)

        # Überschrift
        ttk.Label(f, text="Einstellungen", font=("Segoe UI", 16, "bold")).pack(anchor='w', pady=(0, 10))

        # --- 1. SEKTION: Design & Navigation ---
        frm_design = ttk.LabelFrame(f, text="Design & Navigation")
        frm_design.pack(fill='x', pady=10)
        
        design_grid = ttk.Frame(frm_design)
        design_grid.pack(fill='x', padx=10, pady=10)
        
        if 'view_settings' not in self.data:
            self.data['view_settings'] = {}
        
        current_size = self.data['view_settings'].get('icon_size', 32)
        current_show_text = self.data['view_settings'].get('show_text', False)
        
        ttk.Label(design_grid, text="Button-Größe (px):").grid(row=0, column=0, sticky='w', padx=5)
        v_size = tk.IntVar(value=current_size)
        sp_size = ttk.Spinbox(design_grid, from_=16, to=128, textvariable=v_size, width=5)
        sp_size.grid(row=0, column=1, sticky='w', padx=5)
        
        v_show_text = tk.BooleanVar(value=current_show_text)
        cb_text = ttk.Checkbutton(design_grid, text="Beschriftung neben Icon anzeigen", variable=v_show_text)
        cb_text.grid(row=0, column=2, sticky='w', padx=20)
        
        def save_design():
            self.data['view_settings']['icon_size'] = v_size.get()
            self.data['view_settings']['show_text'] = v_show_text.get()
            self._save_data()
            self._build_ui()
            self._show_tab("settings")
            
        ttk.Button(design_grid, text="Design anwenden", command=save_design).grid(row=0, column=3, sticky='e', padx=20)

        # --- 2. SEKTION: Planungsjahr ---
        frm_year = ttk.LabelFrame(f, text="Planungsjahr")
        frm_year.pack(fill='x', pady=10)
        
        current_year_val = self.data.get('year', self.current_year)
        v_year = tk.IntVar(value=current_year_val)
        sp_year = ttk.Spinbox(frm_year, from_=2024, to=2030, textvariable=v_year)
        sp_year.pack(side='left', padx=10, pady=10)
        
        def save_year():
            self.data['year'] = v_year.get()
            self._save_data()
            self._show_tab("settings")
            if 'SuccessToast' in globals():
                SuccessToast(self.parent_frame, "Gespeichert", f"Jahr auf {v_year.get()} gesetzt.")
            
        ttk.Button(frm_year, text="Jahr übernehmen (Reset Ansicht)", command=save_year).pack(side='left', padx=10)

        # --- 3. SEKTION: Button-Icons konfigurieren ---
        frm_btns = ttk.LabelFrame(f, text="Button-Icons konfigurieren")
        frm_btns.pack(fill='x', pady=10)
        
        btn_defs = [
            ('btn_help', 'Hilfe-Button'),
            ('btn_dashboard', 'Dashboard-Button'),
            ('btn_planner', 'Planer-Button'),
            ('btn_analysis', 'Analyse & E-Mail-Button'),
            ('btn_settings', 'Einstellungen-Button'),
            ('btn_emp_add', 'Mitarbeiter Hinzufügen'),
            ('btn_emp_edit', 'Mitarbeiter Bearbeiten'),
            ('btn_emp_del', 'Mitarbeiter Löschen'),
            ('btn_login', 'Login-Button'),
            ('btn_logout', 'Logout-Button')
        ]
        
        grid_frame = ttk.Frame(frm_btns)
        grid_frame.pack(fill='x', padx=10, pady=10)
        
        for i, (key, label) in enumerate(btn_defs):
            # Zeile berechnen (2 Spalten Layout für Platzersparnis)
            row = i // 2
            col = (i % 2) * 4 # 0 oder 4 für Abstand
            
            ttk.Label(grid_frame, text=f"{label}:", width=25).grid(row=row, column=col, sticky='w', pady=5)
            
            current_path = self.data.get('button_configs', {}).get(key, "")
            display_path = os.path.basename(current_path) if current_path else "Standard"
            
            ttk.Label(grid_frame, text=display_path, width=15, relief="sunken").grid(row=row, column=col+1, sticky='w', padx=5)
            
            # Wir nutzen lambda mit default args, um den key zu binden
            def upload_icon(k=key):
                file_path = filedialog.askopenfilename(
                    title=f"Icon für {k} wählen",
                    filetypes=[("Bilder", "*.png *.jpg *.jpeg *.gif *.avif"), ("Alle", "*.*")],
                    parent=f.winfo_toplevel()
                )
                if file_path:
                    if 'button_configs' not in self.data: self.data['button_configs'] = {}
                    self.data['button_configs'][k] = file_path
                    self._save_data()
                    self._build_ui(); self._show_tab("settings")

            ttk.Button(grid_frame, text="Bild...", width=8, command=upload_icon).grid(row=row, column=col+2, padx=2)
            
            def reset_icon(k=key):
                if 'button_configs' in self.data and k in self.data['button_configs']:
                    del self.data['button_configs'][k]
                    self._save_data(); self._build_ui(); self._show_tab("settings")

            ttk.Button(grid_frame, text="X", width=3, command=reset_icon).grid(row=row, column=col+3, padx=2)

        # --- 4. SEKTION: Mitarbeiter & E-Mail verwalten ---
        frm_emp = ttk.LabelFrame(f, text="Mitarbeiter & E-Mail Adressen verwalten")
        frm_emp.pack(fill='both', expand=True, pady=10)
        
        # Layout: Links Liste, Rechts Buttons (oder Unten) -> Wir machen Unten wie gewünscht
        list_frame = ttk.Frame(frm_emp)
        list_frame.pack(side='top', fill='both', expand=True, padx=10, pady=10)
        
        lb = tk.Listbox(list_frame, height=8)
        lb.pack(side='left', fill='both', expand=True)
        
        sb = ttk.Scrollbar(list_frame, command=lb.yview)
        sb.pack(side='right', fill='y')
        lb.config(yscrollcommand=sb.set)
        
        if 'employee_emails' not in self.data:
            self.data['employee_emails'] = {}
            
        def refresh_list():
            lb.delete(0, tk.END)
            for emp in self.data.get('employees', []):
                email = self.data['employee_emails'].get(emp, "")
                display_text = f"{emp} ({email})" if email else emp
                lb.insert(tk.END, display_text)
        
        refresh_list()
            
        btn_frame_emp = ttk.Frame(frm_emp)
        btn_frame_emp.pack(side='bottom', fill='x', padx=10, pady=(0, 10))
        
        # --- FUNKTIONEN (MIT FIX FÜR FENSTER-FOKUS) ---
        
        def add_emp():
            # Parent explizit setzen
            parent_win = f.winfo_toplevel()
            
            name = simpledialog.askstring("Neuer Mitarbeiter", "Name des Mitarbeiters:", parent=parent_win)
            if not name: return
            
            # FIX: Update erzwingen, damit das nächste Fenster sicher erscheint
            parent_win.update()
            
            email = simpledialog.askstring("E-Mail Adresse", f"E-Mail für {name} (optional):", parent=parent_win)
            
            if name not in self.data['employees']:
                self.data['employees'].append(name)
                self.data['employees'].sort()
                
                if email:
                    self.data['employee_emails'][name] = email
                
                self._save_data()
                refresh_list()

        def edit_emp():
            sel = lb.curselection()
            if not sel:
                # Parent auch hier setzen
                messagebox.showinfo("Hinweis", "Bitte wählen Sie einen Mitarbeiter aus der Liste aus.", parent=f.winfo_toplevel())
                return

            list_text = lb.get(sel[0])
            old_name = list_text.split(" (")[0] if " (" in list_text else list_text
            old_email = self.data['employee_emails'].get(old_name, "")
            
            # Parent explizit setzen
            parent_win = f.winfo_toplevel()
            
            # Dialog 1: Name
            new_name = simpledialog.askstring("Bearbeiten", "Name ändern:", initialvalue=old_name, parent=parent_win)
            
            # Wenn Abbrechen geklickt wurde -> komplett raus
            if new_name is None: return 
            
            # FIX: WICHTIG! Das Fenster aktualisieren, damit der Fokus zurückkommt, bevor der nächste Dialog startet
            parent_win.update()
            
            # Dialog 2: E-Mail
            new_email = simpledialog.askstring("Bearbeiten", "E-Mail ändern:", initialvalue=old_email, parent=parent_win)
            
            # Wenn Abbrechen geklickt wurde beim zweiten Dialog -> auch abbrechen (oder nur Name speichern? Besser alles abbrechen für Konsistenz)
            if new_email is None: return

            # Prüfen auf Duplikate
            if new_name != old_name and new_name in self.data['employees']:
                 messagebox.showerror("Fehler", f"Der Mitarbeiter '{new_name}' existiert bereits!", parent=parent_win)
                 return

            # Speichern
            idx = self.data['employees'].index(old_name)
            self.data['employees'][idx] = new_name
            self.data['employees'].sort()
            
            # Emails updaten
            if old_name in self.data['employee_emails']:
                del self.data['employee_emails'][old_name]
            if new_email:
                self.data['employee_emails'][new_name] = new_email
            
            # Kalendereinträge migrieren
            if new_name != old_name and 'assignments' in self.data:
                count_renamed = 0
                for date_key, assigned_emp in self.data['assignments'].items():
                    if assigned_emp == old_name:
                        self.data['assignments'][date_key] = new_name
                        count_renamed += 1

            self._save_data()
            refresh_list()
            
            if 'SuccessToast' in globals():
                SuccessToast(self.parent_frame, "Gespeichert", f"Daten für {new_name} aktualisiert.")

        def del_emp():
            sel = lb.curselection()
            if not sel: return
            
            list_text = lb.get(sel[0])
            name = list_text.split(" (")[0] if " (" in list_text else list_text
            
            if messagebox.askyesno("Löschen", f"{name} wirklich löschen?", parent=f.winfo_toplevel()):
                if name in self.data['employees']:
                    self.data['employees'].remove(name)
                
                if name in self.data.get('employee_emails', {}):
                    del self.data['employee_emails'][name]
                    
                self._save_data()
                refresh_list()

        # Buttons (Gleichmäßig verteilt unten)
        self.btn_emp_add = ttk.Button(btn_frame_emp, command=add_emp)
        self._configure_nav_button(self.btn_emp_add, 'btn_emp_add', "Hinzufügen", "➕")
        self.btn_emp_add.pack(side='left', fill='x', expand=True, padx=5)
        
        self.btn_emp_edit = ttk.Button(btn_frame_emp, command=edit_emp)
        self._configure_nav_button(self.btn_emp_edit, 'btn_emp_edit', "Bearbeiten", "✏️")
        self.btn_emp_edit.pack(side='left', fill='x', expand=True, padx=5)
        
        self.btn_emp_del = ttk.Button(btn_frame_emp, command=del_emp)
        self._configure_nav_button(self.btn_emp_del, 'btn_emp_del', "Löschen", "🗑️")
        self.btn_emp_del.pack(side='left', fill='x', expand=True, padx=5)
