    def _calculate_and_show_weekends(self):
        """Berechnet die freien Wochenenden und zeigt sie an."""
        name = self.analysis_emp_var.get()
        if not name:
            # Wenn leer ausgewählt wurde, Bereich leeren und abbrechen
            for w in self.analysis_results_frame.winfo_children(): w.destroy()
            return

        # Alten Inhalt löschen
        for w in self.analysis_results_frame.winfo_children(): w.destroy()

        # Logik: Finde Wochenenden (Sa+So), wo der Mitarbeiter eingetragen ist
        year = int(self.data.get('year', self.current_year))
        date = datetime.date(year, 1, 1)
        end_date = datetime.date(year, 12, 31)
        
        free_weekends = [] # Liste von (Samstag_Datum, Sonntag_Datum)
        
        while date <= end_date:
            if date.weekday() == 5: # Samstag
                sunday = date + datetime.timedelta(days=1)
                if sunday.year == year:
                    # KORREKTUR: Daten sicher als Liste laden
                    # Wir nutzen die Hilfsmethode _get_assignments_list
                    emp_sat_list = self._get_assignments_list(str(date))
                    emp_sun_list = self._get_assignments_list(str(sunday))
                    
                    # KORREKTUR: Prüfen ob Name IN der Liste ist
                    if name in emp_sat_list and name in emp_sun_list:
                        free_weekends.append((date, sunday))
            
            date += datetime.timedelta(days=1)

        # --- UI Aufbau der Ergebnisse ---
        
        # Header Resultat
        res_header = tk.Frame(self.analysis_results_frame, bg=self.colors['weekend_sat'])
        res_header.pack(fill='x', pady=(0, 10))
        
        tk.Label(res_header, text=f"Ergebnis für {name}:", font=("Segoe UI", 14, "bold"), bg=self.colors['weekend_sat']).pack(side='left')
        tk.Label(res_header, text=f"{len(free_weekends)} freie Wochenenden gefunden", font=("Segoe UI", 14), fg="#2F65C3", bg=self.colors['weekend_sat']).pack(side='left', padx=10)

        if not free_weekends:
            tk.Label(self.analysis_results_frame, text="Keine kompletten freien Wochenenden (Sa+So) in diesem Jahr gefunden.", font=("Segoe UI", 12, "italic"), bg=self.colors['weekend_sat'], fg="#777").pack(pady=20)
            return

        # E-Mail Button
        btn_email = tk.Button(res_header, text="📧 Liste per E-Mail senden", 
                              font=("Segoe UI", 11, "bold"), bg="#2F65C3", fg="white", 
                              relief="flat", padx=20, pady=5, cursor="hand2",
                              command=lambda: self._open_email_dialog(name, free_weekends))
        btn_email.pack(side='right')

        # Scrollbare Liste
        canvas = tk.Canvas(self.analysis_results_frame, bg="white", highlightthickness=0)
        scrollbar = ttk.Scrollbar(self.analysis_results_frame, orient="vertical", command=canvas.yview)
        scroll_frame = tk.Frame(canvas, bg="white", padx=20, pady=20)

        scroll_frame.bind("<Configure>", lambda e: canvas.configure(scrollregion=canvas.bbox("all")))
        canvas.create_window((0, 0), window=scroll_frame, anchor="nw", width=800)
        canvas.configure(yscrollcommand=scrollbar.set)

        canvas.pack(side="left", fill="both", expand=True)
        scrollbar.pack(side="right", fill="y")
        
        self._bind_mousewheel(canvas, scroll_frame)

        # Liste Generieren
        for sat, sun in free_weekends:
            row = tk.Frame(scroll_frame, bg="white", pady=5)
            row.pack(fill='x')
            
            tk.Label(row, text="📅", font=("Segoe UI Emoji", 12), bg="white").pack(side='left', padx=(0, 10))
            
            date_str = f"{sat.strftime('%d.%m.')} – {sun.strftime('%d.%m.%Y')}"
            kw = sat.isocalendar()[1]
            
            tk.Label(row, text=date_str, font=("Segoe UI", 12, "bold"), bg="white", fg="#333").pack(side='left')
            tk.Label(row, text=f"(KW {kw})", font=("Segoe UI", 11), bg="white", fg="#777").pack(side='left', padx=10)
            
            tk.Frame(scroll_frame, height=1, bg="#EEEEEE").pack(fill='x', pady=5)

    def _open_email_dialog(self, employee_name, weekend_list):
        """Bereitet die Daten vor und öffnet den EmailPreviewDialog."""
        
        # 1. E-Mail Adresse suchen
        recipient_email = ""
        
        # PRIORITÄT A: Im Wochenendplaner gespeicherte E-Mail (neu)
        if 'employee_emails' in self.data:
            recipient_email = self.data['employee_emails'].get(employee_name, "")
            
        # PRIORITÄT B: Falls leer, Suche im globalen Adressbuch der Haupt-App (Fallback)
        if not recipient_email and hasattr(self.app, 'adressbuch_data_cache'):
            for contact in self.app.adressbuch_data_cache:
                contact_name = contact.get('name', '')
                # Unscharfe Suche (falls Vor/Nachname vertauscht)
                if employee_name.lower() in contact_name.lower() or contact_name.lower() in employee_name.lower():
                    recipient_email = contact.get('email', '')
                    break
        
        # 2. HTML Body erstellen
        year = self.data.get('year', self.current_year)
        
        html_rows = ""
        for sat, sun in weekend_list:
            html_rows += f"<tr><td style='padding: 8px; border-bottom: 1px solid #ddd;'><b>{sat.strftime('%d.%m.')} – {sun.strftime('%d.%m.%Y')}</b></td><td style='padding: 8px; border-bottom: 1px solid #ddd; color: #666;'>KW {sat.isocalendar()[1]}</td></tr>"

        body_html = f"""
        <html>
        <body style="font-family: Segoe UI, Arial, sans-serif; color: #333;">
            <h2 style="color: #2F65C3;">Deine freien Wochenenden {year}</h2>
            <p>Hallo {employee_name},</p>
            <p>hier ist die Übersicht deiner eingetragenen freien Wochenenden (Samstag & Sonntag) für das aktuelle Planungsjahr:</p>
            
            <table style="width: 100%; max-width: 500px; border-collapse: collapse; margin-top: 15px;">
                <tr style="background-color: #f2f2f2;">
                    <th style="text-align: left; padding: 10px;">Datum</th>
                    <th style="text-align: left; padding: 10px;">Kalenderwoche</th>
                </tr>
                {html_rows}
            </table>
            
            <p style="margin-top: 20px; font-size: 0.9em; color: #777;">
                Gesamt: {len(weekend_list)} Wochenenden.<br>
                Automatisch erstellt mit dem Wochenend-Planer.
            </p>
        </body>
        </html>
        """
        
        # 3. Dialog öffnen (jetzt mit automatischer E-Mail!)
        self._show_simple_email_preview(recipient_email, f"Deine freien Wochenenden {year}", body_html)

    def _show_simple_email_preview(self, recipient, subject, html_body):
        """
        Zeigt eine bereinigte Text-Vorschau an, sendet aber HTML im Hintergrund.
        """
        import re # Für das Entfernen der HTML-Tags

        dialog = tk.Toplevel(self.parent_frame)
        dialog.title("E-Mail Vorschau")
        dialog.geometry("600x700")
        dialog.transient(self.parent_frame.winfo_toplevel())
        
        # --- HTML zu Text Konverter für die Vorschau ---
        # 1. Zeilenumbrüche simulieren
        preview_text = html_body.replace("</tr>", "\n")
        preview_text = preview_text.replace("</p>", "\n\n")
        preview_text = preview_text.replace("<br>", "\n")
        preview_text = preview_text.replace("</h1>", "\n\n")
        preview_text = preview_text.replace("</h2>", "\n\n")
        
        # 2. Tabellenspalten simulieren
        preview_text = preview_text.replace("</td>", "    |    ")
        preview_text = preview_text.replace("</th>", "    |    ")
        
        # 3. Alle verbleibenden HTML-Tags entfernen (<...>)
        preview_text = re.sub('<[^<]+?>', '', preview_text)
        
        # 4. Leere Zeilen bereinigen
        lines = [line.strip() for line in preview_text.splitlines()]
        clean_preview_text = "\n".join(line for line in lines if line)
        # -----------------------------------------------

        # UI Aufbau
        f = ttk.Frame(dialog, padding=15)
        f.pack(fill='both', expand=True)
        
        # Empfänger
        ttk.Label(f, text="Empfänger:", font=("Segoe UI", 10, "bold")).pack(anchor='w')
        var_rec = tk.StringVar(value=recipient)
        ttk.Entry(f, textvariable=var_rec).pack(fill='x', pady=(0, 10))
        
        # Betreff
        ttk.Label(f, text="Betreff:", font=("Segoe UI", 10, "bold")).pack(anchor='w')
        var_sub = tk.StringVar(value=subject)
        ttk.Entry(f, textvariable=var_sub).pack(fill='x', pady=(0, 10))
        
        # Vorschau-Label
        ttk.Label(f, text="Inhalt (Text-Vorschau):", font=("Segoe UI", 10, "bold")).pack(anchor='w')
        ttk.Label(f, text="(Die E-Mail wird formatiert mit Tabelle versendet)", 
                  font=("Segoe UI", 8), foreground="#666").pack(anchor='w')
        
        # Textbereich
        text_frame = ttk.Frame(f)
        text_frame.pack(fill='both', expand=True, pady=5)
        
        text_w = tk.Text(text_frame, height=15, font=("Consolas", 10), padx=5, pady=5)
        scrollbar = ttk.Scrollbar(text_frame, orient="vertical", command=text_w.yview)
        text_w.configure(yscrollcommand=scrollbar.set)
        
        text_w.pack(side='left', fill='both', expand=True)
        scrollbar.pack(side='right', fill='y')
        
        # Text einfügen
        text_w.insert("1.0", clean_preview_text)
        text_w.config(state='disabled') # Read-only, da wir hier nur Text zeigen, aber HTML senden
        
        # Buttons
        btn_frame = ttk.Frame(f)
        btn_frame.pack(fill='x', pady=10)
        
        def do_send():
            rec = var_rec.get()
            sub = var_sub.get()
            
            # Wir senden das ORIGINAL html_body, nicht den Vorschau-Text!
            
            # 1. Outlook Versuch
            if hasattr(self.app, '_send_html_email_via_outlook') and self.app._send_html_email_via_outlook(rec, sub, html_body):
                dialog.destroy()
                SuccessToast(self.parent_frame, "Gesendet", "E-Mail erfolgreich an Outlook übergeben.")
                return

            # 2. SMTP Fallback
            if hasattr(self.app, '_send_html_email_silently'):
                success, msg = self.app._send_html_email_silently(rec, sub, html_body)
                if success:
                    dialog.destroy()
                    SuccessToast(self.parent_frame, "Gesendet", "E-Mail per SMTP versendet.")
                else:
                    messagebox.showerror("Fehler", f"Versand fehlgeschlagen: {msg}")
            else:
                messagebox.showerror("Fehler", "Keine Versandmethode gefunden.")

        ttk.Button(btn_frame, text="Senden", command=do_send).pack(side='right')
        ttk.Button(btn_frame, text="Abbrechen", command=dialog.destroy).pack(side='right', padx=10)

    def _get_employee_weekend_details(self, employee_name):
        """
        Sucht Details (angepasst auf Mehrfach-Belegung).
        """
        year = int(self.data.get('year', self.current_year))
        details = []
        
        date = datetime.date(year, 1, 1)
        end_date = datetime.date(year, 12, 31)
        
        while date <= end_date:
            if date.weekday() == 5: # Samstag
                sunday = date + datetime.timedelta(days=1)
                
                # Listen abrufen
                emps_sat = self._get_assignments_list(str(date))
                emps_sun = self._get_assignments_list(str(sunday)) if sunday.year == year else []
                
                is_sat = (employee_name in emps_sat)
                is_sun = (employee_name in emps_sun)
                
                if is_sat or is_sun:
                    if is_sat and is_sun: type_str = "Komplett"
                    elif is_sat: type_str = "Nur Samstag"
                    else: type_str = "Nur Sonntag"
                        
                    details.append({
                        'kw': date.isocalendar()[1],
                        'sat': date,
                        'sun': sunday,
                        'type': type_str
                    })
                    
            date += datetime.timedelta(days=1)
        return details
    
    def _perform_login(self, username, password):
        """Prüft die Zugangsdaten und setzt die Rolle."""
        admin_pw = self.data.get('admin_password', 'planer123')
        
        success = False
        
        if username.lower() == "admin" and password == admin_pw:
            self.current_role = 'admin'
            self.is_logged_in = True
            self.is_planner_unlocked = True
            self._build_main_app()
            success = True
            if 'SuccessToast' in globals():
                SuccessToast(self.parent_frame, "Willkommen", "Admin-Zugriff gewährt.", "success")
        
        elif username.lower() == "user" and password == "user":
            self.current_role = 'user'
            self.is_logged_in = True
            self.is_planner_unlocked = False
            self._build_main_app()
            success = True
            if 'SuccessToast' in globals():
                SuccessToast(self.parent_frame, "Willkommen", "Lese-Modus aktiviert.", "info")
                
        else:
            messagebox.showerror("Fehler", "Benutzername oder Passwort falsch!")

        # --- NEU: Wenn Login erfolgreich, starte Timer ---
        if success:
            self._start_inactivity_monitor()
            
    def _build_main_app(self):
        # Bereinigen
        for widget in self.parent_frame.winfo_children(): widget.destroy()

        self.parent_frame.grid_rowconfigure(1, weight=0)  # Timer-Balken (feste Höhe)
        self.parent_frame.grid_rowconfigure(2, weight=1)  # Content-Bereich (expandierend)
        self.parent_frame.grid_columnconfigure(0, weight=1)

        # --- 1. HEADER (Container) ---
        header_height = 80
        
        # Hintergrund-Canvas
        self.nav_canvas = tk.Canvas(self.parent_frame, height=header_height, bg="white", highlightthickness=0)
        self.nav_canvas.grid(row=0, column=0, sticky='ew')
        
        # Schattenlinie unten
        self.nav_canvas.create_line(0, header_height-1, 5000, header_height-1, fill="#E0E0E0", width=1)
        
        # TIMER BALKEN (Unten im Header)
        # Als Kind des Canvas, damit er sicher sichtbar ist
        self.timer_bar = tk.Frame(self.nav_canvas, bg="#2F65C3", height=5)
        self.timer_bar.place(x=0, rely=1.0, y=-5, relwidth=1.0, anchor='nw')

        # --- INHALT DES HEADERS ---
        # Container über dem Canvas. 
        # FIX: Wir nutzen die volle Breite (relwidth=1.0) und steuern Abstände über inneres Padding.
        # Das verhindert feste Ränder, die auf kleinen Screens Platz verschwenden.
        nav_content = tk.Frame(self.parent_frame, bg="white")
        nav_content.place(x=0, y=10, relwidth=1.0, height=60)

        # --- WICHTIG: RECHTER BEREICH ZUERST (Buttons) ---
        # Damit diese bei kleinen Bildschirmen NICHT abgeschnitten werden, 
        # müssen sie zuerst mit side='right' gepackt werden.
        self.nav_btn_frame = tk.Frame(nav_content, bg="white")
        self.nav_btn_frame.pack(side='right', fill='y', padx=(0, 20)) # Rechtsabstand 20px zum Fensterrand

        # 1. Hilfe
        self.btn_help = ttk.Button(self.nav_btn_frame, command=self._show_help_window)
        self._configure_nav_button(self.btn_help, 'btn_help', "Hilfe", "❓")
        self.btn_help.pack(side='left', padx=5)

        # 2. Dashboard
        self.btn_dashboard = ttk.Button(self.nav_btn_frame, command=lambda: self._show_tab("dashboard"))
        self._configure_nav_button(self.btn_dashboard, 'btn_dashboard', "Dashboard", "📊")
        self.btn_dashboard.pack(side='left', padx=5)
        
        # Admin Buttons
        if self.current_role == 'admin':
            self.btn_planner = ttk.Button(self.nav_btn_frame, command=self._reset_and_show_planner)
            self._configure_nav_button(self.btn_planner, 'btn_planner', "Jahresplaner", "📅")
            self.btn_planner.pack(side='left', padx=5)

            self.btn_analysis = ttk.Button(self.nav_btn_frame, command=lambda: self._show_tab("analysis"))
            self._configure_nav_button(self.btn_analysis, 'btn_analysis', "Analyse & E-Mail", "📧")
            self.btn_analysis.pack(side='left', padx=5)
            
            self.btn_settings = ttk.Button(self.nav_btn_frame, command=lambda: self._show_tab("settings"))
            self._configure_nav_button(self.btn_settings, 'btn_settings', "Einstellungen", "⚙️")
            self.btn_settings.pack(side='left', padx=5)

        # Trennlinie
        tk.Frame(self.nav_btn_frame, width=1, bg="#E0E0E0", height=30).pack(side='left', padx=10, fill='y', pady=10)

        # Logout Button
        self.btn_lock = ttk.Button(self.nav_btn_frame, command=self._handle_lock_click)
        self._configure_nav_button(self.btn_lock, 'btn_logout', "Logout", "🔒")
        self.btn_lock.pack(side='left', padx=5)

        # --- DANACH: LINKER BEREICH (Titel) ---
        # Dieser nimmt den verbleibenden Platz ein (side='left').
        # Wenn zu wenig Platz da ist, wird dieser Bereich vom rechten Bereich "überlappt" bzw. hat weniger Platz,
        # aber die Buttons rechts bleiben stehen.
        left_frame = tk.Frame(nav_content, bg="white")
        left_frame.pack(side='left', fill='y', padx=(20, 0)) # Linksabstand 20px

        if hasattr(self.app, '_create_home_button'):
            hb = self.app._create_home_button(left_frame)
            if hb: hb.pack(side='left', padx=(0, 15))

        role_suffix = " (Admin)" if self.current_role == 'admin' else " (Nur Lesen)"
        full_title = "Wochenend-Planer" + role_suffix
        
        # Titel-Label
        tk.Label(left_frame, text=full_title, font=("Segoe UI", 24, "bold"), bg="white", fg="#2C3E50").pack(side='left')
        tk.Label(left_frame, text="|  Jahresübersicht", font=("Segoe UI", 16), bg="white", fg="#95A5A6").pack(side='left', padx=10, pady=(6,0))

        # --- 2. TIMER-BALKEN CANVAS (zwischen Header und Content) ---
