    # HIER BEGINNT DIE NEUE, FEHLENDE METHODE
    # vvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvv
    def _setupTreeViewCellNavigation(self, tree, edit_command_func=None):
        """
        Erstellt und initialisiert die zellenbasierte Navigation für ein
        gegebenes Treeview-Widget.
        Dies ist eine zentrale Helper-Methode, um die TreeViewCellNavigation-Klasse
        konsistent in der gesamten Anwendung zu verwenden.
        """
        # Die Instanz der Navigationsklasse wird erstellt, aber nicht als
        # Attribut von 'self' gespeichert, da sie sich über Event-Bindings
        # selbst am Leben erhält, solange das Treeview-Widget existiert.
        TreeViewCellNavigation(tree, edit_command_func=edit_command_func)
    # ^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^
    # HIER ENDET DIE NEUE METHODE
    # ^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^
    
    def _focus_next_if_at_end(self, event):
        """Springt zum nächsten Feld, wenn der Cursor am Ende des Textes steht."""
        widget = event.widget
        try:
            if widget.index(tk.INSERT) == len(widget.get()):
                widget.tk_focusNext().focus_set()
                return "break"
        except (tk.TclError, AttributeError):
            # Fallback für Widgets ohne Text oder bei Fehlern
            pass
        return None # Erlaubt die Standard-Tastenaktion

    def _focus_prev_if_at_start(self, event):
        """Springt zum vorherigen Feld, wenn der Cursor am Anfang des Textes steht."""
        widget = event.widget
        try:
            if widget.index(tk.INSERT) == 0:
                widget.tk_focusPrev().focus_set()
                return "break"
        except (tk.TclError, AttributeError):
            pass
        return None
    
    
       # vvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvv
    # HIER BEGINNT DIE NEUE METHODE ZUM AUTOMATISCHEN MARKIEREN
    # vvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvv
    def _select_all_on_focus(self, event):
        """Wählt den gesamten Inhalt eines Eingabefeldes aus, wenn es den Fokus erhält."""
        try:
            # 'after_idle' stellt sicher, dass die Auswahl zuverlässig erfolgt,
            # nachdem das Widget den Fokus vollständig erhalten hat.
            event.widget.after_idle(lambda: event.widget.select_range(0, 'end'))
        except tk.TclError:
            # Ignoriert Fehler, falls das Widget keine Textauswahl unterstützt
            # oder in einem Zustand ist, in dem es nicht markiert werden kann.
            pass
    # ^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^
    # HIER ENDET DIE NEUE METHODE
    # ^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^
    
    # vvvvv HIER IST DIE PERFEKTE STELLE, UM DEN NEUEN CODE EINZUFÜGEN vvvvv
    def _bind_dialog_navigation(self, widget):
        """Bindet die Pfeiltasten-Navigation an ein Widget in einem Dialogfenster."""
        if widget and widget.winfo_exists():
            widget.bind("<Up>", lambda e: (e.widget.tk_focusPrev().focus_set(), "break"))
            widget.bind("<Down>", lambda e: (e.widget.tk_focusNext().focus_set(), "break"))
            # Die Navigation mit Links/Rechts springt nur am Anfang/Ende des Feldes
            widget.bind("<Left>", self._focus_prev_if_at_start)
            widget.bind("<Right>", self._focus_next_if_at_end)
    # ^^^^^ HIER ENDET DER NEUE CODEBLOCK ^^^^^

    
    
