    def _check_for_alarms(self, current_time):
        if not self.current_settings.get('alarm_enabled', False) or not pygame_available:
            return

        today_iso = current_time.date().isoformat()

        for weckruf in self.weckruf_data_cache:
            weckruf_id = weckruf.get('id')
            if not weckruf_id or weckruf_id in self.triggered_alarm_ids_today:

                continue
            
            if weckruf.get('datum') == today_iso:
                try:
                    uhrzeit_str = weckruf.get('zeit', '')
                    if len(uhrzeit_str) == 5:
                        uhrzeit_str += ':00'
                    
                    alarm_time_str = f"{weckruf['datum']} {uhrzeit_str}"
                    alarm_datetime = datetime.datetime.strptime(alarm_time_str, "%Y-%m-%d %H:%M:%S")
                    
                    if current_time >= alarm_datetime:
                        self.triggered_alarm_ids_today.add(weckruf_id)
                        self._trigger_alarm(weckruf)

                except (ValueError, KeyError) as e:
                    print(f"Skipping alarm check for invalid entry: {weckruf} - Error: {e}")
                    continue
                
    def stop_alarm_sound(self):
        """Stops any playing alarm sound and properly unloads the resource."""
        if pygame_available and pygame.mixer.music.get_busy():
            try:
                pygame.mixer.music.stop()
                pygame.mixer.music.unload()
            except Exception as e:
                print(f"Error while stopping and unloading alarm sound: {e}")
    

    def _trigger_alarm(self, weckruf_data):
        # HINZUGEFÜGT: Stellt sicher, dass das Hauptfenster noch existiert,
        # bevor versucht wird, ein neues Fenster (den Alarm) zu erstellen.
        # Dies verhindert einen Absturz, wenn der Alarm genau beim Beenden
        # der Anwendung ausgelöst wird.
        try:
            if not self.master.winfo_exists():
                return
        except (tk.TclError, AttributeError):
            return

        weckruf_id = weckruf_data.get('id')
        if not weckruf_id:
            return

        # Verhindert, dass für den gleichen Weckruf mehrere Fenster geöffnet werden
        if weckruf_id in self.active_alarms and self.active_alarms[weckruf_id].get('window') and self.active_alarms[weckruf_id]['window'].winfo_exists():
            return

        # Speichert Referenzen auf das Fenster und den Sound-Prozess
        self.active_alarms[weckruf_id] = {'window': None, 'process': None}

        # 1. Relativen Pfad aus den Einstellungen holen (z.B. "sounds/alarm.mp3")
        relative_sound_path = self.current_settings.get('alarm_sound_path', '')
        
        if pygame_available and relative_sound_path:
            # 2. Den relativen Pfad in einen absoluten, funktionierenden Pfad umwandeln
            absolute_sound_path = resource_path(relative_sound_path)

            if os.path.exists(absolute_sound_path):
                try:
                    # 3. Den separaten Prozess mit dem absoluten Pfad starten
                    p = multiprocessing.Process(target=play_sound_in_process, args=(absolute_sound_path,))
                    p.start()
                    self.active_alarms[weckruf_id]['process'] = p
                except Exception as e:
                    print(f"Error starting sound process: {e}")
            else:
                # Diese Warnung hilft bei der Fehlersuche mit der .exe
                messagebox.showwarning(
                    "Alarmton nicht gefunden",
                    f"Die Sound-Datei konnte unter dem erwarteten Pfad nicht gefunden werden:\n\n{absolute_sound_path}\n\nStellen Sie sicher, dass die Datei existiert und der Pfad in den Einstellungen korrekt ist.",
                    parent=self.master
                )
        
        # --- Das Erstellen des Alarmfensters bleibt unverändert ---
        alarm_window = tk.Toplevel(self.master)
        alarm_window.title("!! WECKRUF !!")
        alarm_window.transient(self.master)
        alarm_window.attributes("-topmost", True)
        self.master.update_idletasks()
        master_x, master_y = self.master.winfo_x(), self.master.winfo_y()
        master_w, master_h = self.master.winfo_width(), self.master.winfo_height()
        win_w, win_h = 450, 220
        x = master_x + (master_w // 2) - (win_w // 2)
        y = master_y + (master_h // 2) - (win_h // 2)
        alarm_window.geometry(f"{win_w}x{win_h}+{x}+{y}")
        alarm_window.resizable(False, False)
        main_frame = ttk.Frame(alarm_window, padding=20)
        main_frame.pack(expand=True, fill="both")
        main_frame.columnconfigure(0, weight=1)
        info_font = ("Segoe UI", 16)
        bold_info_font = ("Segoe UI", 16, "bold")
        message1 = f"Zimmer: {weckruf_data.get('zimmer', 'N/A')}"
        message2 = f"Gast: {weckruf_data.get('gastname', 'N/A')}"
        ttk.Label(main_frame, text=message1, font=bold_info_font, justify='center', anchor='center').pack(pady=(5, 2))
        ttk.Label(main_frame, text=message2, font=info_font, justify='center', anchor='center').pack(pady=(2, 15))
        
        def stop_alarm():
            alarm_info = self.active_alarms.pop(weckruf_id, None)
            if alarm_info and alarm_info.get('process'):
                try:
                    # Beendet den Sound-Prozess sicher
                    if alarm_info['process'].is_alive():
                        alarm_info['process'].terminate()
                        alarm_info['process'].join(timeout=1) # Warte kurz auf das Beenden
                except Exception as e:
                    print(f"Error terminating sound process: {e}")
            
            if alarm_window.winfo_exists():
                alarm_window.destroy()

        stop_button = ttk.Button(main_frame, text="STOP", command=stop_alarm, style='TButton')
        stop_button.pack(pady=10, ipadx=30, ipady=15)
        alarm_window.protocol("WM_DELETE_WINDOW", stop_alarm)
        
        self.active_alarms[weckruf_id]['window'] = alarm_window
        
        
        
