    def _load_hover_sound(self):
        """Lädt den Hover-Sound basierend auf den Einstellungen. Wird bei Einstellungsänderungen aufgerufen."""
        self.is_hover_sound_loaded = False
        self.hover_sound = None
        if not pygame_available or not self.current_settings.get('hover_sound_enabled', False):
            return

        relative_path = self.current_settings.get('hover_sound_path', '')
        if not relative_path:
            return

        try:
            absolute_path = resource_path(relative_path)
            if os.path.exists(absolute_path):
                # pygame.mixer.Sound ist besser für kurze Effekte geeignet
                self.hover_sound = pygame.mixer.Sound(absolute_path)
                self.is_hover_sound_loaded = True
            else:
                print(f"Warnung: Hover-Sound-Datei nicht gefunden unter: {absolute_path}")
        except Exception as e:
            print(f"Fehler beim Laden des Hover-Sounds: {e}")

    def _play_hover_sound(self):
        """Spielt den vorgeladenen Hover-Sound einmal ab."""
        if self.is_hover_sound_loaded and self.hover_sound:
            try:
                # Stoppt zuerst jeden laufenden Hover-Sound, um Überlappungen zu vermeiden
                # und spielt dann den neuen ab. Dies ist bei sehr schnellen Mausbewegungen nützlich.
                pygame.mixer.stop() 
                self.hover_sound.play()
            except Exception as e:
                print(f"Fehler beim Abspielen des Hover-Sounds: {e}")
    # ^^^^^ HIER ENDET DER NEUE CODEBLOCK ^^^^^
        
        

    def _determine_effective_data_root(self):
        path_config_file_locator = get_app_data_path(self.APP_PATH_CONFIG_FILENAME)
        custom_root_path_from_config = None

        if os.path.exists(path_config_file_locator):
            try:
                with open(path_config_file_locator, 'r', encoding='utf-8') as f_cfg:
                    path_cfg_data = json.load(f_cfg)
                    if isinstance(path_cfg_data, dict):
                        candidate_path = path_cfg_data.get("custom_data_path")
                        if isinstance(candidate_path, str) and candidate_path.strip():
                            if os.path.isdir(candidate_path.strip()):
                                custom_root_path_from_config = candidate_path.strip()
                            else:
                                print(f"Warning: Custom data path '{candidate_path}' in '{self.APP_PATH_CONFIG_FILENAME}' is not a valid directory. Falling back to default.")
            except (json.JSONDecodeError, IOError, Exception) as e_path_cfg:
                print(f"Warning: Error reading/parsing '{self.APP_PATH_CONFIG_FILENAME}': {e_path_cfg}. Fallback to default path.")

        if custom_root_path_from_config:
            return custom_root_path_from_config
        else:
            return os.path.dirname(get_app_data_path("dummy_for_default_dir.txt"))


    def _get_tk_var_value_safely(self, tk_var_candidate, default_string_if_invalid="N/A"):
        if tk_var_candidate is not None and \
           hasattr(tk_var_candidate, 'get') and \
           callable(tk_var_candidate.get):
            try:
                return tk_var_candidate.get()
            except Exception:
                return default_string_if_invalid
        return default_string_if_invalid

