    # HIER BEGINNT DER NEUE CODEBLOCK FÜR DIE DIASHOW
    # vvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvv
    def _load_slideshow_images(self):
        """
        Lädt Bilder für die Diashow robuster und gibt Debug-Infos aus.
        """
        self.slideshow_images = []
        
        # Pfad zum Ordner "images/slideshow"
        slideshow_dir = resource_path(os.path.join("images", "slideshow"))
        
        print(f"\n--- DIASHOW DIAGNOSE START ---")
        print(f"Ordner-Pfad: {slideshow_dir}")

        if not os.path.isdir(slideshow_dir):
            print(f"FEHLER: Ordner existiert nicht!")
            return

        # Erlaubte Endungen (alles klein schreiben)
        valid_extensions = {'.png', '.jpg', '.jpeg', '.gif', '.bmp', '.webp', '.tiff', '.tif'}
        if 'pillow_avif' in sys.modules:
            valid_extensions.add('.avif')

        found_files = []

        try:
            # Alle Dateien auflisten
            files_in_dir = os.listdir(slideshow_dir)
            print(f"Dateien im Ordner gefunden: {len(files_in_dir)}")

            for filename in files_in_dir:
                # Versteckte Dateien ignorieren
                if filename.startswith('.'): 
                    continue

                full_path = os.path.join(slideshow_dir, filename)
                
                if os.path.isfile(full_path):
                    # Endung prüfen (Groß-/Kleinschreibung egal)
                    _, ext = os.path.splitext(filename)
                    if ext.lower() in valid_extensions:
                        # Integritätsprüfung
                        try:
                            with Image.open(full_path) as img:
                                img.verify()
                            found_files.append(full_path)
                            print(f"  [OK] Geladen: {filename}")
                        except Exception as e:
                            print(f"  [DEFEKT] Konnte Bild nicht öffnen: {filename} - Fehler: {e}")
                    else:
                        # Zeigt an, welche Dateien ignoriert wurden (oft der Grund für fehlende Bilder)
                        print(f"  [IGNORIERT] Ungültige Endung: {filename}")

        except Exception as e:
            print(f"Kritischer Fehler beim Lesen des Ordners: {e}")

        self.slideshow_images = found_files

        # Mischen
        if self.slideshow_images:
            import random
            random.shuffle(self.slideshow_images)
            print(f"--- DIAGNOSE ENDE: {len(self.slideshow_images)} Bilder bereit für Diashow ---")
        else:
            print("--- DIAGNOSE ENDE: KEINE BILDER GEFUNDEN ---")

         # vvvvv HIER IST DIE PERFEKTE STELLE ZUM EINFÜGEN DER NEUEN METHODE vvvvv
    def _manage_slideshow_state(self):
        """
        Zentrale Steuerungsmethode für den Dashboard-Hintergrund.
        Startet/stoppt die Diashow ODER lädt das statische Bild, je nach Einstellung und Sichtbarkeit.
        """
        if self.is_shutting_down:
            return

        # Prüfen, ob das Dashboard die aktuell sichtbare Seite ist
        if self.current_page_name == "Dashboard":
            # Den in den Einstellungen gewählten Hintergrundmodus auslesen
            background_mode = self.current_settings.get('dashboard_background_mode', 'slideshow')

            if background_mode == 'slideshow':
                # Fall 1: Wir sind im Dashboard und die Diashow ist gewünscht.
                # Stoppt zuerst ein eventuell angezeigtes statisches Bild.
                if self.slideshow_canvas_item and self.dashboard_bg_canvas.winfo_exists():
                    self.dashboard_bg_canvas.itemconfig(self.slideshow_canvas_item, image=None)
                
                # Startet die Diashow, aber nur, wenn sie nicht bereits läuft.
                if self.slideshow_job_id is None:
                    print("Dashboard aktiv: Starte Diashow.")
                    self._start_slideshow()
            else:
                # Fall 2: Wir sind im Dashboard und ein statisches Bild ist gewünscht.
                # Stellt sicher, dass eine eventuell laufende Diashow zuerst gestoppt wird.
                if self.slideshow_job_id is not None:
                    print("Wechsle von Diashow zu statischem Bild: Stoppe Diashow.")
                    self._stop_slideshow()
                
                # Ruft die Funktion auf, die das statische Bild lädt und anzeigt.
                print("Dashboard aktiv: Lade statisches Hintergrundbild.")
                self._update_dashboard_background()
        else:
            # Fall 3: Wir sind nicht im Dashboard.
            # Jede Art von Hintergrundaktivität (Diashow) muss gestoppt werden.
            if self.slideshow_job_id is not None:
                print(f"Dashboard verlassen: Stoppe Diashow (Aktuelle Seite: {self.current_page_name}).")
                self._stop_slideshow()



    def _start_slideshow(self):
        """Initialisiert und startet den Zyklus der Diashow."""
        if self.slideshow_job_id:
            try:
                self.master.after_cancel(self.slideshow_job_id)
            except tk.TclError:
                pass
            self.slideshow_job_id = None

        self.slideshow_photo_objects.clear()

        # Canvas-Items sicher zurücksetzen
        if self.slideshow_canvas_item and self.dashboard_bg_canvas.winfo_exists():
            self.dashboard_bg_canvas.itemconfig(self.slideshow_canvas_item, image=None)
        if self.slideshow_canvas_item_back and self.dashboard_bg_canvas.winfo_exists():
            self.dashboard_bg_canvas.itemconfig(self.slideshow_canvas_item_back, image=None)

        self.active_canvas_item = None
        
        self._load_slideshow_images()
        
        if not self.slideshow_images:
            self._update_dashboard_background()
            return
        
        self.slideshow_current_index = -1
        # Das erste Bild wird ohne Animation geladen, um einen sauberen Start zu gewährleisten
        self._prepare_and_show_first_slide()
    
    def _stop_slideshow(self):
        """
        Stoppt den laufenden Diashow-Timer sicher und setzt alle relevanten
        Variablen und Caches zurück, um das Speicherleck zu schließen.
        """
        if self.slideshow_job_id:
            try:
                self.master.after_cancel(self.slideshow_job_id)
            except tk.TclError:
                pass  # Job existiert möglicherweise nicht mehr
        
        # WICHTIG: Alle Referenzen zurücksetzen, um laufende Animationen zu unterbrechen
        self.slideshow_job_id = None
        self.slideshow_canvas_item = None
        self.slideshow_canvas_item_back = None
        self.active_canvas_item = None
        
        # ENTSCHEIDEND: Leert den Cache, um den Speicher von allen Bildobjekten freizugeben
        self.slideshow_photo_objects.clear()
        
        print("Diashow gestoppt und alle Ressourcen freigegeben.")
    
    
    
    def _prepare_and_show_first_slide(self):
        """Lädt das erste Bild statisch und plant die erste animierte Überblendung."""
        if not self.slideshow_images or not self.dashboard_bg_canvas.winfo_exists():
            return
        
        self.slideshow_current_index = 0
        image_path = self.slideshow_images[self.slideshow_current_index]

        try:
            canvas_width = self.dashboard_bg_canvas.winfo_width()
            canvas_height = self.dashboard_bg_canvas.winfo_height()

            if canvas_width <= 1 or canvas_height <= 1:
                self.slideshow_job_id = self.master.after(100, self._prepare_and_show_first_slide)
                return

            with Image.open(image_path) as img:
                prepared_image = self._resize_and_crop_image(img, canvas_width, canvas_height)
            
            photo = ImageTk.PhotoImage(prepared_image)
            self.slideshow_photo_objects['initial'] = photo

            # Erstellt die beiden Bild-Elemente auf dem Canvas, falls noch nicht geschehen
            if self.slideshow_canvas_item is None:
                self.slideshow_canvas_item = self.dashboard_bg_canvas.create_image(0, 0, anchor="nw")
            if self.slideshow_canvas_item_back is None:
                self.slideshow_canvas_item_back = self.dashboard_bg_canvas.create_image(0, 0, anchor="nw")
            
            self.dashboard_bg_canvas.itemconfig(self.slideshow_canvas_item, image=photo)
            self.active_canvas_item = self.slideshow_canvas_item
            
            delay = 6000
            self.slideshow_job_id = self.master.after(delay, self._animate_next_slide)

        except Exception as e:
            print(f"Fehler beim Vorbereiten des ersten Slides: {e}")
            self.slideshow_job_id = self.master.after(200, self._prepare_and_show_first_slide)

    def _resize_and_crop_image(self, img, canvas_width, canvas_height):
        """Hilfsfunktion, um ein Bild proportional zu skalieren und zuzuschneiden."""
        img_ratio = img.width / img.height
        canvas_ratio = canvas_width / canvas_height
        if img_ratio > canvas_ratio:
            new_height = canvas_height; new_width = int(new_height * img_ratio)
        else:
            new_width = canvas_width; new_height = int(new_width / img_ratio)
        
        img_resized = img.resize((new_width, new_height), Image.Resampling.LANCZOS)
        
        left, top = (new_width - canvas_width) / 2, (new_height - canvas_height) / 2
        return img_resized.crop((left, top, left + canvas_width, top + canvas_height)).convert("RGBA")

    def _animate_next_slide(self):
        """
        Zeigt das nächste Bild an.
        FINAL: Animationen sind AKTIV und Speicher-Management unterstützt viele Bilder.
        """
        if self.is_shutting_down or not self.dashboard_bg_canvas.winfo_exists():
            return
        
        # Nur weitermachen, wenn wir auf dem Dashboard sind
        if self.current_page_name != "Dashboard":
            self.slideshow_job_id = self.master.after(2000, self._animate_next_slide)
            return

        if not self.slideshow_images:
            self._load_slideshow_images()
            if not self.slideshow_images: return

        # Index erhöhen (endlos)
        self.slideshow_current_index = (self.slideshow_current_index + 1) % len(self.slideshow_images)
        image_path = self.slideshow_images[self.slideshow_current_index]

        # Canvas Items vorbereiten
        front_item = self.active_canvas_item
        if front_item is None:
            self._prepare_and_show_first_slide()
            return

        back_item = self.slideshow_canvas_item_back if self.active_canvas_item == self.slideshow_canvas_item else self.slideshow_canvas_item
        
        try:
            canvas_width = self.dashboard_bg_canvas.winfo_width()
            canvas_height = self.dashboard_bg_canvas.winfo_height()

            if canvas_width <= 10:
                self.slideshow_job_id = self.master.after(500, self._animate_next_slide)
                return

            # 1. Bild laden
            with Image.open(image_path) as img:
                img = img.convert("RGBA") # Wichtig für Stabilität
                prepared_image = self._resize_and_crop_image(img, canvas_width, canvas_height)

            # 2. PhotoImage erstellen
            new_photo = ImageTk.PhotoImage(prepared_image)
            new_photo.original_pillow_object = prepared_image
            
            # 3. Speicher-Management (WICHTIG: Kein komplettes Löschen!)
            self.slideshow_photo_objects[image_path] = new_photo
            
            # Wir behalten bis zu 25 Bilder im Speicher. 
            # Wenn es mehr werden, löschen wir nur das ÄLTESTE, damit der Fluss nicht bricht.
            if len(self.slideshow_photo_objects) > 25:
                oldest_key = next(iter(self.slideshow_photo_objects))
                del self.slideshow_photo_objects[oldest_key]

            # 4. Effekt aus Einstellungen wählen
            effect = self.current_settings.get('slideshow_transition_effect', 'curtain')

            if effect == 'fly_in':
                self._animate_fly_in(new_photo, front_item, back_item, canvas_width)
            elif effect == 'flip':
                # Das ist der "Umfallen" / "Umkippen" Effekt
                self._animate_flip(new_photo, front_item, back_item, canvas_width)
            elif effect == 'fade':
                self._animate_fade(new_photo, front_item, back_item)
            else: 
                # Standard: Vorhang
                self._animate_curtain_down(new_photo, front_item, back_item, canvas_height)
            
            # Aktives Item wechseln
            self.active_canvas_item = back_item if self.active_canvas_item == front_item else front_item

        except Exception as e:
            print(f"Fehler bei Bild '{os.path.basename(image_path)}': {e}")
            # Bei Fehler sofort zum nächsten Bild springen, damit es nicht hängt
            self.slideshow_job_id = self.master.after(100, self._animate_next_slide)

    def _animate_curtain_down(self, new_photo, new_item, old_item, canvas_height):
        if self.is_shutting_down or self.slideshow_job_id is None: return
        
        self.dashboard_bg_canvas.itemconfig(new_item, image=new_photo)
        self.dashboard_bg_canvas.coords(new_item, 0, -canvas_height)
        self.dashboard_bg_canvas.tag_raise(new_item)
        
        def animate(start_y, end_y, start_time, duration_ms=800):
            if self.is_shutting_down or self.slideshow_job_id is None: return
            progress = min(((time.time() - start_time) * 1000) / duration_ms, 1.0)
            eased = 1 - (1 - progress) ** 3
            current_y = start_y + (end_y - start_y) * eased
            try:
                if self.dashboard_bg_canvas.winfo_exists(): self.dashboard_bg_canvas.coords(new_item, 0, current_y)
            except tk.TclError: return
            if progress < 1.0:
                self.master.after(15, lambda: animate(start_y, end_y, start_time, duration_ms))
            else:
                self.dashboard_bg_canvas.itemconfig(old_item, image=None)
                self.slideshow_job_id = self.master.after(6000, self._animate_next_slide)
        animate(-canvas_height, 0, time.time())

    def _animate_fly_in(self, new_photo, new_item, old_item, canvas_width):
        if self.is_shutting_down or self.slideshow_job_id is None: return
        
        self.dashboard_bg_canvas.itemconfig(new_item, image=new_photo)
        self.dashboard_bg_canvas.coords(new_item, canvas_width, 0)
        self.dashboard_bg_canvas.tag_raise(new_item)

        def animate(start_time, duration_ms=800):
            if self.is_shutting_down or self.slideshow_job_id is None: return
            progress = min(((time.time() - start_time) * 1000) / duration_ms, 1.0)
            eased = 1 - (1 - progress) ** 3
            new_x = canvas_width * (1 - eased)
            old_x = -canvas_width * eased
            try:
                if self.dashboard_bg_canvas.winfo_exists():
                    self.dashboard_bg_canvas.coords(new_item, new_x, 0)
                    self.dashboard_bg_canvas.coords(old_item, old_x, 0)
            except tk.TclError: return
            if progress < 1.0:
                self.master.after(15, lambda: animate(start_time, duration_ms))
            else:
                self.dashboard_bg_canvas.itemconfig(old_item, image=None)
                self.slideshow_job_id = self.master.after(6000, self._animate_next_slide)
        animate(time.time())

    def _animate_flip(self, new_photo, item_to_flip_out, item_to_flip_in, canvas_width):
        if self.is_shutting_down or self.slideshow_job_id is None: return
        
        canvas_height = self.dashboard_bg_canvas.winfo_height()
        old_photo_ref = self.dashboard_bg_canvas.itemcget(item_to_flip_out, "image")
        old_pillow_object = None
        if old_photo_ref:
            for img in self.slideshow_photo_objects.values():
                if str(img) == old_photo_ref and hasattr(img, 'original_pillow_object'):
                    old_pillow_object = img.original_pillow_object
                    break
        
        if not old_pillow_object:
            self.dashboard_bg_canvas.itemconfig(item_to_flip_out, image=None)
            self.dashboard_bg_canvas.itemconfig(item_to_flip_in, image=new_photo)
            self.slideshow_job_id = self.master.after(6000, self._animate_next_slide)
            return

        def animate_phase1(start_time, duration_ms=400):
            if self.is_shutting_down or self.slideshow_job_id is None: return
            progress = min(((time.time() - start_time) * 1000) / duration_ms, 1.0)
            current_width = max(1, int(canvas_width * (1 - progress)))
            current_x = int((canvas_width - current_width) / 2)
            try:
                if self.dashboard_bg_canvas.winfo_exists():
                    img = old_pillow_object.resize((current_width, canvas_height), Image.Resampling.LANCZOS)
                    temp_photo = ImageTk.PhotoImage(img)
                    self.dashboard_bg_canvas.itemconfig(item_to_flip_out, image=temp_photo)
                    self.dashboard_bg_canvas.coords(item_to_flip_out, current_x, 0)
                    self.dashboard_bg_canvas._animation_photo_ref_p1 = temp_photo
            except (tk.TclError, AttributeError, RuntimeError): return

            if progress < 1.0:
                self.master.after(15, lambda: animate_phase1(start_time, duration_ms))
            else:
                self.dashboard_bg_canvas.itemconfig(item_to_flip_out, image=None)
                self.dashboard_bg_canvas.itemconfig(item_to_flip_in, image=new_photo)
                self.dashboard_bg_canvas.tag_raise(item_to_flip_in)
                animate_phase2(time.time(), canvas_height=canvas_height)

        def animate_phase2(start_time, canvas_height, duration_ms=400):
            if self.is_shutting_down or self.slideshow_job_id is None: return
            progress = min(((time.time() - start_time) * 1000) / duration_ms, 1.0)
            current_width = max(1, int(canvas_width * progress))
            current_x = int((canvas_width - current_width) / 2)
            try:
                if self.dashboard_bg_canvas.winfo_exists() and hasattr(new_photo, 'original_pillow_object'):
                    img = new_photo.original_pillow_object.resize((current_width, canvas_height), Image.Resampling.LANCZOS)
                    temp_photo = ImageTk.PhotoImage(img)
                    self.dashboard_bg_canvas.itemconfig(item_to_flip_in, image=temp_photo)
                    self.dashboard_bg_canvas.coords(item_to_flip_in, current_x, 0)
                    self.dashboard_bg_canvas._animation_photo_ref_p2 = temp_photo
            except (tk.TclError, AttributeError, RuntimeError): return
            
            if progress < 1.0:
                self.master.after(15, lambda: animate_phase2(start_time, canvas_height, duration_ms))
            else:
                final_img = new_photo.original_pillow_object.resize((canvas_width, canvas_height), Image.Resampling.LANCZOS)
                final_photo = ImageTk.PhotoImage(final_img)
                self.dashboard_bg_canvas.itemconfig(item_to_flip_in, image=final_photo)
                self.dashboard_bg_canvas.coords(item_to_flip_in, 0, 0)
                self.dashboard_bg_canvas._animation_photo_ref_final = final_photo
                
                self.slideshow_job_id = self.master.after(6000, self._animate_next_slide)
        
        animate_phase1(time.time())

    def _animate_fade(self, new_photo, new_item, old_item):
        if self.is_shutting_down or self.slideshow_job_id is None: return
        
        self.dashboard_bg_canvas.itemconfig(new_item, image=new_photo)
        self.dashboard_bg_canvas.coords(new_item, 0, 0)
        self.dashboard_bg_canvas.tag_lower(new_item)
        
        photo_ref = self.dashboard_bg_canvas.itemcget(old_item, "image")
        original_pillow = None
        for img in self.slideshow_photo_objects.values():
            if str(img) == photo_ref and hasattr(img, 'original_pillow_object'):
                original_pillow = img.original_pillow_object
                break
        
        if not original_pillow:
             self.dashboard_bg_canvas.itemconfig(old_item, image=None)
             self.slideshow_job_id = self.master.after(6000, self._animate_next_slide)
             return
        
        def animate(alpha=1.0, duration_ms=800, start_time=time.time()):
            if self.is_shutting_down or self.slideshow_job_id is None: return
            progress = min(((time.time() - start_time) * 1000) / duration_ms, 1.0)
            current_alpha = 1.0 - progress
            try:
                if self.dashboard_bg_canvas.winfo_exists():
                    img_copy = original_pillow.copy()
                    img_copy.putalpha(int(current_alpha * 255))
                    temp_photo = ImageTk.PhotoImage(img_copy)
                    self.dashboard_bg_canvas.itemconfig(old_item, image=temp_photo)
                    self.dashboard_bg_canvas._animation_photo_ref = temp_photo
            except (tk.TclError, AttributeError, RuntimeError): return
            if progress < 1.0:
                self.master.after(25, lambda: animate(start_time=start_time))
            else:
                self.dashboard_bg_canvas.itemconfig(old_item, image=None)
                self.slideshow_job_id = self.master.after(6000, self._animate_next_slide)
        animate()
   
   
   
