    def _create_auth_code_finder_page(self, parent_frame):
        """Erstellt die Instanz der AuthCodeApp."""
        self.auth_code_app_instance = AuthCodeApp(parent_frame, app_ref=self)
        self.sub_app_instances.append(self.auth_code_app_instance)

        
          # VVVVVV HIER DIE NEUEN ZEILEN FÜR DIE GLOBALE FOKUS-MARKIERUNG EINFÜGEN VVVVVV
        # Bindet die _select_all_on_focus-Methode an alle ttk.Entry- und ttk.Combobox-Widgets.
        # "TEntry" ist der interne Klassenname für ttk.Entry.
        self.master.bind_class("TEntry", "<FocusIn>", self._select_all_on_focus)
        self.master.bind_class("TCombobox", "<FocusIn>", self._select_all_on_focus)
        # ^^^^^^ HIER ENDEN DIE NEUEN ZEILEN ^^^^^^

        
        
        
        ### KORREKTUR ###
        # Der Aufruf erfolgt über die Instanz der AuthCodeApp, da der Treeview darin erstellt wird.
        self._setupTreeViewCellNavigation(self.auth_code_app_instance.internal_db_tree, edit_command_func=self.auth_code_app_instance._on_edit)
        
        self.time_after_id = None
        self.background_task_id = None # NEUE ZEILE: Variable für den neuen Timer
        self._last_updated_date_for_header = "" 
        self._update_time() 
        self.master.after(10000, self._periodic_background_tasks) # NEUE ZEILE: Startet den langsamen Timer nach 10s
        self.master.after(100, self._initialize_dashboard_and_essential_data)

        
        
    def _create_layover_page(self, parent_frame):
        """Instanziiert die LayoverApp und registriert sie."""
        self.layover_app_instance = LayoverApp(parent_frame, app_ref=self)
        self.sub_app_instances.append(self.layover_app_instance)
        
    def _do_nothing(self):
        """Verhindert das Schließen des Hauptfensters über den [X]-Button."""
        pass
        
        
        
    def _load_all_data_files(self):
        """
        Lädt NUR die anwendungsweiten Daten, die für den initialen Start (Dashboard, Benachrichtigungen)
        zwingend erforderlich sind. Alle anderen Daten werden verzögert geladen.
        """
        print("Lese essentielle Start-Daten von der Festplatte ein...")
        
        self._load_settings()

        # Daten, die für Benachrichtigungen auf dem Dashboard benötigt werden
        self._load_weckruf_data()
        self._load_shuttle_data()
        self._load_taxi_data()
        
        # Daten für das Kassenprotokoll, das auf dem Dashboard angezeigt wird
        self._load_kassenprotokoll_data()
        self._load_latest_from_history()
        self._load_latest_tagesabrechnung_from_history()
        
        # Trinkgeld- und Minibar-Daten vorab laden, damit der sofortige Autosave beim Start
        # keine leeren Caches speichert und vorhandene Daten nicht überschreibt.
        self._load_trinkgeld_data()
        self._load_minibar_data()

        # Daten für die Checklisten-Statusanzeige
        self._load_checklist_state('frueh')
        self._load_checklist_state('spaet')
        self._load_checklist_state('nacht')
        
        
        
    def _initialize_dashboard_and_essential_data(self):
        """
        Lädt nur die absolut notwendigen Daten für den Start und das Dashboard.
        Alle anderen Daten werden erst bei Bedarf geladen ("lazy loading").
        """
        self._load_all_data_files()
        
        # Nur die Widgets für das Kassenprotokoll (links) erstellen, da sie auf dem Dashboard sichtbar sind
        self._clear_widget_tracking_lists()
        self._create_shift_widgets(self.fruehdienst_frame, self.fruehdienst_vars, "Frühdienst", self.spaetdienst_vars)
        self._create_shift_widgets(self.spaetdienst_frame, self.spaetdienst_vars, "Spätdienst", self.fruehdienst_vars)
        
        # Berechnungen durchführen und Benachrichtigungen aktualisieren
        self._update_all_calculations(called_by_button=False)
        self._update_notifications()
        self._update_button_appearances()
        self._schedule_autosave()

        # vvvvv HIER IST DIE KORREKTUR vvvvv
        # Das Schließen-Protokoll wird auf die korrekte Beenden-Methode umgeleitet
        self.master.protocol("WM_DELETE_WINDOW", self._on_closing)
        # ^^^^^ ENDE DER KORREKTUR ^^^^^

        self.show_page("Dashboard")
        self.is_loading_data = False
        self.initialized_pages.add("Dashboard")
        self.initialized_pages.add("Kassenprotokoll") # Gehört logisch zum Dashboard

    def _initialize_page_data(self, page_name):
        """Lädt die Daten für eine bestimmte Seite, wenn sie zum ersten Mal aufgerufen wird."""
        if page_name == "Trinkgeldliste":
            self._load_trinkgeld_data()
            self._set_default_trinkgeld_period_and_load()
        elif page_name == "Minibarliste":
            self._load_minibar_data()
            self._set_default_minibar_period_and_load()
        elif page_name == "Weckrufliste":
            self._load_and_display_weckrufe()
        elif page_name == "Shuttle Hinfahrt":
            self._load_and_display_shuttle_data('Hinfahrt')
        elif page_name == "Shuttle Rückfahrt":
            self._load_and_display_shuttle_data('Rückfahrt')
        elif page_name == "Tagesabrechnung":
            self._update_tagesabrechnung_calculations(show_feedback=False)
        elif page_name == "Taxibestellung":
            self._load_and_display_taxi_orders()
        elif page_name == "Namensliste":
            self._load_namensliste_data()
            self._load_and_display_namensliste()
        elif page_name == "Adressbuch":
            self._load_adressbuch_data()
            self._load_and_display_adressbuch()
        elif page_name == "Urlaubsantraege":
            self._load_urlaubsantraege_data()
            self._load_and_display_urlaubsantraege()
        elif page_name == "Überstundenantrag":
            self._load_ueberstundenantrag_data()
            self._load_and_display_ueberstundenantraege()
        elif page_name == "Zimmerreservierung":
            self._load_zimmerreservierung_data()
            self._load_and_display_zimmerreservierungen()
        elif page_name == "Tischreservierung":
            self._load_tischreservierung_data()
            self._load_and_display_tischreservierungen()
        elif page_name == "Anrufliste":
            self._load_anrufliste_data()
            self._load_and_display_anrufe()
        elif page_name == "Offene Rechnungen" and self.offene_rechnungen_app_instance:
            # Diese Sub-App lädt ihre Daten bereits verzögert, wir müssen nur die Tabelle befüllen.
            self.offene_rechnungen_app_instance.populate_tables()
        # Für Spickzettel, Layover etc. passiert das Laden bereits innerhalb der jeweiligen Sub-App-Klasse.
    
    
    def _create_comment_icon(self):
        """Erstellt ein 16x16 Pixel großes Notiz-Icon zur Laufzeit mit PIL."""
        if pil_available_for_rechnungen:
            try:
                # Erstellt ein gelbliches Bild
                img = Image.new('RGBA', (16, 16), (255, 255, 204, 255))
                draw = ImageDraw.Draw(img)
                # Zeichnet graue Linien, um Text anzudeuten
                line_color = (150, 150, 150, 255)
                for y in range(4, 14, 3):
                    draw.line((3, y, 13, y), fill=line_color)
                return ImageTk.PhotoImage(img)
            except Exception as e:
                print(f"Fehler beim Erstellen des Kommentar-Icons: {e}")
                return None
        return None

    # vvvvv HIER IST DIE PERFEKTE STELLE ZUM EINFÜGEN vvvvv
    def _create_checkbox_images(self, size=24):
        """
        Erstellt Bilder für eine größere Checkbox zur Laufzeit.
        size: Die gewünschte Kantenlänge des Kästchens in Pixeln.
        """
        if not Image or not ImageTk:
            self.checked_image = None
            self.unchecked_image = None
            return

        # Bild für den leeren Zustand (unchecked)
        unchecked_img = Image.new("RGBA", (size, size), (0, 0, 0, 0))
        draw = ImageDraw.Draw(unchecked_img)
        draw.rounded_rectangle((1, 1, size-2, size-2), radius=4, outline="#888888", width=2, fill="#FFFFFF")
        self.unchecked_image = ImageTk.PhotoImage(unchecked_img, master=self.master)

        # Bild für den angekreuzten Zustand (checked)
        checked_img = Image.new("RGBA", (size, size), (0, 0, 0, 0))
        draw = ImageDraw.Draw(checked_img)
        draw.rounded_rectangle((1, 1, size-2, size-2), radius=4, outline="#0078D7", width=2, fill="#3399FF")
        # Haken zeichnen
        draw.line([(size*0.25, size*0.5), (size*0.45, size*0.7), (size*0.75, size*0.3)], fill="#FFFFFF", width=3)
        self.checked_image = ImageTk.PhotoImage(checked_img, master=self.master)
        
        
        
    def _setup_custom_styles(self):
        """Erstellt und konfiguriert alle benutzerdefinierten ttk-Stile zentral.
        Wird beim Start einmalig aufgerufen, um große Checkboxen für alle ttk.Checkbutton zu aktivieren."""
        if getattr(self, '_checkbox_style_created', False):
            return

        if getattr(self, 'checked_image', None) and getattr(self, 'unchecked_image', None):
            try:
                self.style.element_create(
                    "LargeCheckbutton.indicator", "image",
                    self.unchecked_image,
                    ('selected', '!disabled', self.checked_image),
                    ('selected', 'disabled', self.checked_image),
                    border=0, sticky='w'
                )
                large_layout = [
                    ("LargeCheckbutton.indicator", {'side': 'left', 'sticky': ''}),
                    ("Checkbutton.focus", {'side': 'left', 'sticky': '', 'children': [
                        ("Checkbutton.padding", {'side': 'left', 'sticky': '', 'children': [
                            ("Checkbutton.label", {'side': 'left', 'sticky': ''})
                        ]})
                    ]})
                ]
                # Globaler TCheckbutton – betrifft ALLE ttk.Checkbutton-Widgets
                self.style.layout("TCheckbutton", large_layout)
                # Benannter Stil als Alias (Rückwärtskompatibilität)
                self.style.layout("LargeChecklist.TCheckbutton", large_layout)

                vertical_padding = max(0, (self.checkbox_size - 16) // 2)
                self.style.configure("TCheckbutton", padding=(5, vertical_padding))
                self.style.configure("LargeChecklist.TCheckbutton", padding=(5, vertical_padding))
                self._checkbox_style_created = True
            except tk.TclError as e:
                print(f"Fehler beim Erstellen des benutzerdefinierten Checkbox-Stils: {e}")
                # Fallback: nur Font und Padding vergrößern
                self.style.configure("TCheckbutton", padding=(6, 8))
        else:
            # Fallback ohne PIL: indicatorsize + Padding
            try:
                self.style.configure("TCheckbutton", indicatorsize=18, padding=(6, 8))
            except tk.TclError:
                pass
        
        
        
    def _create_rounded_rectangle(self, canvas, x1, y1, x2, y2, radius, **kwargs):
        """Zeichnet ein abgerundetes Rechteck auf einem Canvas-Widget."""
        points = [x1 + radius, y1,
                  x1 + radius, y1,
                  x2 - radius, y1,
                  x2 - radius, y1,
                  x2, y1,
                  x2, y1 + radius,
                  x2, y1 + radius,
                  x2, y2 - radius,
                  x2, y2 - radius,
                  x2, y2,
                  x2 - radius, y2,
                  x2 - radius, y2,
                  x1 + radius, y2,
                  x1 + radius, y2,
                  x1, y2,
                  x1, y2 - radius,
                  x1, y2 - radius,
                  x1, y1 + radius,
                  x1, y1 + radius,
                  x1, y1]

        return canvas.create_polygon(points, **kwargs, smooth=True)
