            pdf = TaxiPDF(self.taxi_data_cache, logo_path=_get_pdf_logo_path(self.current_settings, 'taxi'))
            pdf.add_page()
            pdf.create_table()
            pdf.output(temp_pdf_path)
            self._open_file(temp_pdf_path)
