    def _create_shuttle_page(self, parent_frame, booking_type):
        """Erstellt die Shuttle-Seite (Hinfahrt oder Rückfahrt) mit allen Buttons."""
        for widget in parent_frame.winfo_children():
            widget.destroy()

        parent_frame.grid_rowconfigure(1, weight=1)
        parent_frame.grid_columnconfigure(0, weight=1)
        
        header = ttk.Frame(parent_frame, style='AppBackground.TFrame', height=60)
        header.grid(row=0, column=0, sticky='ew')
            
        title = f"Shuttle-Service: {booking_type}"
        header.columnconfigure(0, weight=0)
        header.columnconfigure(1, weight=1)
        
        home_button = self._create_home_button(header)
        if home_button:
            ipady = self.current_settings.get('home_button_config', {}).get('ipady', 2)
            home_button.grid(row=0, column=0, sticky='w', padx=10, pady=10, ipady=ipady)

        ttk.Label(header, text=title, font=("Segoe UI", 20, "bold")).grid(row=0, column=1, sticky='w', padx=20, pady=10)
        
        content_frame = ttk.Frame(parent_frame, style='AppBackground.TFrame', padding=(8,8))
        content_frame.grid(row=1, column=0, sticky='nsew', padx=15, pady=(0, 8))
        content_frame.columnconfigure(0, weight=1)
        content_frame.rowconfigure(0, weight=1)

        size_settings = self.current_settings.get('configurable_sizes', {})
        shuttle_config = size_settings.get('shuttle_service', {'font_size': 14})
        font_size = shuttle_config.get('font_size', 14)
        
        try:
            base_font_family = tkFont.Font(font=self.style.lookup('TLabel', 'font')).actual('family')
        except (tk.TclError, AttributeError):
            base_font_family = "Segoe UI"
        list_font = tkFont.Font(family=base_font_family, size=font_size, weight="bold")

        style_name = "Shuttle.Treeview"
        self.style.configure(style_name, font=list_font, rowheight=int(font_size * 2.5))
        self.style.configure(f"{style_name}.Heading", font=(base_font_family, font_size, 'bold'))

        tree_frame = ttk.Frame(content_frame)
        tree_frame.grid(row=0, column=0, sticky="nsew")
        tree_frame.rowconfigure(0, weight=1)
        tree_frame.columnconfigure(0, weight=0)  # Checkbox-Canvas
        tree_frame.columnconfigure(1, weight=1)  # Treeview
        tree_frame.columnconfigure(2, weight=0)  # Scrollbar

        # --- Canvas-Checkbox-Spalte links neben der Treeview ---
        cb_col_width = self.checkbox_size + 14  # z.B. 44 px bei checkbox_size=30
        cb_canvas = tk.Canvas(tree_frame, width=cb_col_width,
                              highlightthickness=0, cursor="hand2")
        cb_canvas.grid(row=0, column=0, sticky="ns")

        # --- Treeview (ohne Status-Spalte) ---
        columns = ("datum", "zeit", "gastname", "zimmer", "personen")
        tree = ttk.Treeview(tree_frame, columns=columns, show="headings", style=style_name)
        tree.heading("datum", text="Datum")
        tree.heading("zeit", text="Uhrzeit")
        tree.heading("gastname", text="Gastname(n)")
        tree.heading("zimmer", text="Zimmer")
        tree.heading("personen", text="Personen")

        tree.column("datum", width=120, anchor="center", stretch=tk.NO)
        tree.column("zeit", width=120, anchor="center", stretch=tk.NO)
        tree.column("gastname", width=350, anchor="w")
        tree.column("zimmer", width=120, anchor="center")
        tree.column("personen", width=100, anchor="center", stretch=tk.NO)

        tree.tag_configure('erledigt_tag', background='#c8e6c9', foreground='#4a7c59')

        # Scrollbar – beim Scrollen auch den Canvas aktualisieren
        vsb = ttk.Scrollbar(tree_frame, orient="vertical")
        vsb.grid(row=0, column=2, sticky="ns")

        def _on_shuttle_scroll(*args):
            vsb.set(*args)
            self._redraw_shuttle_cb_canvas(booking_type)

        tree.configure(yscrollcommand=_on_shuttle_scroll)
        vsb.configure(command=lambda *a: (tree.yview(*a),
                                          self._redraw_shuttle_cb_canvas(booking_type)))

        tree.grid(row=0, column=1, sticky="nsew")

        # Canvas-Klick → Checkbox toggeln
        cb_canvas.bind("<Button-1>",
                       lambda e, bt=booking_type: self._handle_shuttle_cb_click(bt, e.y))

        # Treeview-Refs und Canvas-Refs speichern
        if booking_type == 'Hinfahrt':
            self.shuttle_hinfahrt_tree = tree
            self.shuttle_hinfahrt_cb_canvas = cb_canvas
        else:
            self.shuttle_rueckfahrt_tree = tree
            self.shuttle_rueckfahrt_cb_canvas = cb_canvas

        tree.bind("<Double-1>", lambda e, b_type=booking_type: self._edit_shuttle_entry(b_type))
        self._setupTreeViewCellNavigation(tree, edit_command_func=lambda: self._edit_shuttle_entry(booking_type))
       
        button_frame = ttk.Frame(content_frame, style='AppBackground.TFrame')
        button_frame.grid(row=1, column=0, sticky='w', pady=(10, 0))

        style_cfg = self.current_settings.get('list_views_button_style', self.default_settings['list_views_button_style'])
        ipady = style_cfg.get('ipady', 5)
        pady = style_cfg.get('pady', 5)

        button_configs = self.current_settings.get('shuttle_button_configs', {})

        button_defs = [
            ('Shuttle_Add', 'Buchen', lambda: self._add_shuttle_entry(booking_type)),
            ('Shuttle_Edit', 'Bearbeiten', lambda: self._edit_shuttle_entry(booking_type)),
            ('Shuttle_Delete', 'Stornieren', lambda: self._delete_shuttle_entry(booking_type)),
            ('Shuttle_DeleteDone', 'Erledigte löschen', lambda: self._delete_erledigte_shuttle(booking_type)),
            (None, None, None),
            ('Shuttle_SavePDF', 'PDF Speichern', lambda: self._save_shuttle_list_to_pdf(booking_type)),
            ('Shuttle_Print', 'Drucken', lambda: self._print_shuttle_list(booking_type)),
            ('Shuttle_History', 'Verlauf', self._open_shuttle_history_dialog),
            (None, None, None),
            ('Shuttle_ManualBackup', 'Manuelles Backup', self._perform_manual_backup_shuttle), # <--- Wieder da!
            ('Shuttle_ManageBackups', 'Backups verwalten', self._open_backup_manager_shuttle),
            (None, None, None),
            ('Shuttle_Overlay', 'Info-Fenster', self._toggle_shuttle_overlay)
        ]

        for key, text, cmd in button_defs:
            if key is None:
                ttk.Separator(button_frame, orient='vertical').pack(side="left", fill='y', padx=8, pady=4)
                continue
            
            btn = ttk.Button(button_frame, command=cmd)
            self._configure_shuttle_button(btn, key, text)
            btn.pack(side="left", padx=2, ipady=ipady, pady=pady)
    
