        content_frame.grid_columnconfigure((0, 2), weight=1) 

        tiles_container = ttk.Frame(content_frame, style='AppBackground.TFrame')
        tiles_container.grid(row=0, column=1, sticky="") 

        # --- DYNAMISCHE KACHEL-ERSTELLUNG ---
        command_map = {
            "Shuttle Hinfahrt": lambda: self.show_page("Shuttle Hinfahrt"),
            "Shuttle Rückfahrt": lambda: self.show_page("Shuttle Rückfahrt"),
        }
        
        shuttle_configs = self.current_settings.get('shuttle_main_menu_button_configs', {})
        button_order = ["Shuttle Hinfahrt", "Shuttle Rückfahrt"]
        
        # Style-Definitionen
        tile_background_color = "#FFFFFF"
        tile_hover_background_color = "#F2F3F4"
        border_color = "#AAAAAA"
        border_thickness = 1
        icon_size = 72
        font_size = 15
        text_color_style = "Blue.Card.TLabel"

        col = 0
        for key in button_order:
            config = shuttle_configs.get(key)
            if not config or not config.get('is_active', False):
                continue
            
            border_frame = tk.Frame(tiles_container, bg=border_color, cursor="hand2")
            border_frame.grid(row=0, column=col, padx=15, pady=15, sticky="nsew")
            col += 1

            tile = tk.Frame(border_frame, bg=tile_background_color)
            tile.pack(padx=border_thickness, pady=border_thickness, fill="both", expand=True)
            
            icon_label = ttk.Label(tile, style='Card.TLabel', anchor='center', background=tile_background_color)
            
            icon_type = config.get('type', 'symbol')
            icon_value = config.get('value', '❓')

            if icon_type == 'image' and icon_value and os.path.exists(icon_value) and Image and ImageTk:
                try:
                    img = Image.open(icon_value).resize((icon_size, icon_size), Image.Resampling.LANCZOS)
                    photo = ImageTk.PhotoImage(img)
                    icon_label.config(image=photo)
                    icon_label.image = photo 
                except Exception as e:
                    print(f"Fehler beim Laden des Shuttle-Icons für '{key}': {e}")
                    icon_label.config(text="🖼️", font=("Segoe UI Emoji", int(icon_size * 0.9)))
            else:
                icon_label.config(text=icon_value, font=("Segoe UI Emoji", int(icon_size * 0.9)))
            
            icon_label.pack(pady=(30, 6), padx=20, expand=True)

            text_label = ttk.Label(tile, text=config.get('label', key), style=text_color_style, font=("Segoe UI", font_size, "bold"), anchor='center', background=tile_background_color)
            text_label.pack(pady=(6, 30), padx=20, expand=True)
            
            tile_command = command_map.get(key)
            
            def on_enter(e, t=tile, il=icon_label, tl=text_label):
                t.config(bg=tile_hover_background_color)
                il.config(background=tile_hover_background_color)
                tl.config(background=tile_hover_background_color)

            def on_leave(e, t=tile, il=icon_label, tl=text_label):
                t.config(bg=tile_background_color)
                il.config(background=tile_background_color)
                tl.config(background=tile_background_color)
            
            if tile_command:
                for widget in (border_frame, tile, icon_label, text_label):
                    widget.bind("<Button-1>", lambda e, cmd=tile_command: cmd())
                    widget.bind("<Enter>", on_enter)
                    widget.bind("<Leave>", on_leave)
                
