    def _configure_shuttle_overlay_button(self, button_widget):
        """Konfiguriert den 'Info-Fenster'-Button im Shuttle-Menü basierend auf den Einstellungen."""
        if not button_widget or not button_widget.winfo_exists():
            return

        settings_key = 'shuttle_button_configs'
        button_key = 'Shuttle_Overlay'
        button_configs = self.current_settings.get(settings_key, {})
        config = button_configs.get(button_key, self.default_settings.get(settings_key, {}).get(button_key, {}))

        if not config.get('is_active', True):
            button_widget.grid_remove()
            return
        else:
            button_widget.grid()

        btn_type = config.get('type', 'symbol')
        btn_value = config.get('value', '👁️ Info-Fenster')
        
        style_cfg = self.current_settings.get('list_views_button_style', {})
        icon_size = style_cfg.get('icon_size', 24)

        if not hasattr(self, 'shuttle_button_images'):
            self.shuttle_button_images = {}

        if btn_type == 'image' and btn_value and os.path.exists(btn_value) and Image and ImageTk:
            try:
                img = Image.open(btn_value).resize((icon_size, icon_size), Image.Resampling.LANCZOS)
                photo = ImageTk.PhotoImage(img)
                self.shuttle_button_images[button_key] = photo
                button_widget.image = photo
                button_widget.config(image=photo, text="", compound='center')
                ToolTip(button_widget, "Info-Fenster anzeigen/schließen")
            except Exception as e:
                print(f"Fehler beim Laden des Icons für Button '{button_key}': {e}")
                button_widget.config(text=btn_value, image="", compound='left')
        else:
            button_widget.config(text=btn_value, image="", compound='left')
