    def _load_and_display_taxi_orders(self):
        if not self.taxibestellung_tree or not self.taxibestellung_tree.winfo_exists():
            return

        for item in self.taxibestellung_tree.get_children():
            self.taxibestellung_tree.delete(item)

        sorted_data = sorted(self.taxi_data_cache, key=lambda x: (x.get('datum', ''), x.get('uhrzeit', '')))

        for entry in sorted_data:
            display_datum = datetime.datetime.strptime(entry['datum'], "%Y-%m-%d").strftime("%d.%m.%Y")
            values = (
                display_datum,
                entry.get('uhrzeit', ''),
                entry.get('name_zimmer', ''),
                entry.get('zielort', ''),
                str(entry.get('personen', '')),
                entry.get('kuerzel', '')
            )
            item_id = entry.get('id', uuid.uuid4().hex)
            self.taxibestellung_tree.insert("", "end", values=values, iid=item_id)
            
    def _add_taxi_entry(self):
        dialog = TaxiEntryDialog(self.master, self)
        new_entry_data = dialog.show()
        if new_entry_data:
            self.taxi_data_cache.append(new_entry_data)
            self._save_taxi_data()
            
            # AUTOMATISCHES BACKUP
            self._perform_manual_backup_taxi(ask_confirmation=False)
            
            self._save_list_entry_to_history(new_entry_data, "Hinzugefügt", "Taxi")
            self._load_and_display_taxi_orders()
            self._update_notifications()

            if self.taxi_overlay_window and self.taxi_overlay_window.winfo_exists():
                self.taxi_overlay_window.update_display()
                
            SuccessToast(self.master, title="Gespeichert", message="Taxi bestellt und gesichert.", toast_type='success', colors=self.current_settings.get('toast_colors'))

    def _edit_taxi_entry(self):
        selected_ids = self.taxibestellung_tree.selection()
        if not selected_ids:
            SuccessToast(self.master, title="Keine Auswahl", message="Bitte Eintrag auswählen.", toast_type='warning', colors=self.current_settings.get('toast_colors'))
            return
        
        entry_to_edit = next((e for e in self.taxi_data_cache if e.get("id") == selected_ids[0]), None)
        if not entry_to_edit: return

        dialog = TaxiEntryDialog(self.master, self, entry_data=entry_to_edit.copy())
        updated_data = dialog.show()
        if updated_data:
            idx = self.taxi_data_cache.index(entry_to_edit)
            self.taxi_data_cache[idx] = updated_data
            self._save_taxi_data()
            
            # AUTOMATISCHES BACKUP
            self._perform_manual_backup_taxi(ask_confirmation=False)
            
            self._save_list_entry_to_history(updated_data, "Bearbeitet", "Taxi")
            self._load_and_display_taxi_orders()
            self._update_notifications()
            
            # Adressbuch-Update (optional, falls gewünscht)
            # self.adressbuch_data_cache[idx] = updated_data
            # self._save_adressbuch_data()
            # self._load_and_display_adressbuch()
            
            if self.taxi_overlay_window and self.taxi_overlay_window.winfo_exists():
                self.taxi_overlay_window.update_display()

            SuccessToast(self.master, title="Aktualisiert", message="Eintrag aktualisiert und gesichert.", toast_type='success', colors=self.current_settings.get('toast_colors'))

    def _delete_taxi_entry(self):
        selected_ids = self.taxibestellung_tree.selection()
        if not selected_ids: return
            
        if not messagebox.askyesno("Löschen bestätigen", "Wirklich löschen?", parent=self.master): return

        for item_id in selected_ids:
            entry_to_delete = next((e for e in self.taxi_data_cache if e.get("id") == item_id), None)
            if entry_to_delete:
                self._save_list_entry_to_history(entry_to_delete, "Gelöscht", "Taxi")

        self.taxi_data_cache = [e for e in self.taxi_data_cache if e.get("id") not in selected_ids]
        self._save_taxi_data()
        
        # AUTOMATISCHES BACKUP
        self._perform_manual_backup_taxi(ask_confirmation=False)
        
        self._load_and_display_taxi_orders()
        self._update_notifications()

        if self.taxi_overlay_window and self.taxi_overlay_window.winfo_exists():
            self.taxi_overlay_window.update_display()
            
        SuccessToast(self.master, title="Gelöscht", message="Eintrag gelöscht und Backup aktualisiert.", toast_type='success', colors=self.current_settings.get('toast_colors'))

        if self.taxi_overlay_window and self.taxi_overlay_window.winfo_exists():
            self.taxi_overlay_window.update_display()
            # vvvvv HIER IST DIE PERFEKTE STELLE ZUM EINFÜGEN vvvvv
    def _open_taxi_history_dialog(self):
        """Öffnet den Dialog für den Verlauf der Taxibestellungen."""
        self._open_generic_list_history_dialog(
            "Taxibestellungen",
            self.taxi_history_file,
            self._get_taxi_history_summary_line,
            self._restore_taxi_from_history
        )

    def _get_taxi_history_summary_line(self, snapshot):
        """Erstellt eine Zusammenfassungszeile für einen Taxi-Verlaufseintrag."""
        data = snapshot.get('data')
        action = snapshot.get('action', 'Unbekannt')
        if not data:
            return f"[{action}] - Ungültige Daten"
        
        try:
            datum = datetime.datetime.strptime(data.get('datum', ''), "%Y-%m-%d").strftime("%d.%m.%y")
        except ValueError:
            datum = data.get('datum', '??.??.??')

        uhrzeit = data.get('uhrzeit', '??:??')
        name_zimmer = data.get('name_zimmer', 'N/A')
        zielort = data.get('zielort', 'Unbekannt')

        return f"[{action}] {datum} {uhrzeit} - Gast/Zi: {name_zimmer} - Ziel: {zielort}"

    def _restore_taxi_from_history(self, history_dialog):
        """Stellt einen Taxi-Eintrag aus dem Verlauf wieder her."""
        # Die Logik zum Extrahieren der Daten wird direkt hier implementiert.
        try:
            listbox = history_dialog.listbox_widget
            all_snapshots = history_dialog.displayed_snapshots
            selected_indices = listbox.curselection()

            if not selected_indices:
                messagebox.showwarning("Auswahl", "Bitte einen Eintrag zum Wiederherstellen auswählen.", parent=history_dialog)
                return
            
            if len(selected_indices) > 1:
                messagebox.showwarning("Mehrfachauswahl", "Bitte nur einen Eintrag auf einmal wiederherstellen.", parent=history_dialog)
                return
            
            # Holt den korrekten Snapshot basierend auf der Auswahl in der Listbox
            snapshot_data = all_snapshots[selected_indices[0]]
        except (AttributeError, IndexError) as e:
            messagebox.showerror("Fehler", f"Die Daten aus dem Verlaufsfenster konnten nicht gelesen werden: {e}", parent=history_dialog)
            return

        entry_to_restore = snapshot_data.get('data')
        if not entry_to_restore:
            messagebox.showerror("Fehler", "Keine Daten zum Wiederherstellen in diesem Eintrag.", parent=history_dialog)
            return

        if messagebox.askyesno("Wiederherstellen",
                               "Diesen Taxi-Eintrag wirklich wiederherstellen?\nEin eventuell vorhandener Eintrag mit derselben ID wird überschrieben.",
                               parent=history_dialog):
            
            # Entfernt einen möglicherweise vorhandenen alten Eintrag mit derselben ID
            self.taxi_data_cache = [e for e in self.taxi_data_cache if e.get('id') != entry_to_restore.get('id')]
            
            # Fügt den wiederhergestellten Eintrag hinzu
            self.taxi_data_cache.append(entry_to_restore)
            
            self._save_taxi_data()
            self._save_list_entry_to_history(entry_to_restore, "Wiederhergestellt", "Taxi")
            self._load_and_display_taxi_orders()
            self._update_notifications()
            
            history_dialog.destroy()
            SuccessToast(self.master, title="Erfolg", message="Taxibestellung wurde wiederhergestellt.", toast_type='success', colors=self.current_settings.get('toast_colors'))
    # ^^^^^ HIER ENDET DER NEUE CODEBLOCK ^^^^^^^^^^^^^^^^^^
        



    def _load_namensliste_data(self):
        if os.path.exists(self.namensliste_data_file):
            try:
                with open(self.namensliste_data_file, 'r', encoding='utf-8') as f:
                    self.namensliste_data_cache = json.load(f)
                    if not isinstance(self.namensliste_data_cache, list): self.namensliste_data_cache = []
            except (json.JSONDecodeError, IOError): self.namensliste_data_cache = []
        else: self.namensliste_data_cache = []

    def _save_taxi_data(self):
        """Speichert den Taxi-Cache in die JSON-Datei."""
        try:
            data_dir = os.path.dirname(self.taxi_data_file)
            if not os.path.exists(data_dir):
                os.makedirs(data_dir, exist_ok=True)
            with open(self.taxi_data_file, 'w', encoding='utf-8') as f:
                json.dump(self.taxi_data_cache, f, indent=2, ensure_ascii=False)
        except Exception as e:
            print(f"Fehler beim Speichern der Taxidaten: {e}")

    # vvvvv HIER BEGINNT DIE NEUE, FEHLENDE METHODE vvvvv
    def _load_taxi_data(self):
        """Lädt die Taxibestellungen aus der JSON-Datei in den Cache."""
        if os.path.exists(self.taxi_data_file):
            try:
                with open(self.taxi_data_file, 'r', encoding='utf-8') as f:
                    self.taxi_data_cache = json.load(f)
                    if not isinstance(self.taxi_data_cache, list):
                        print("Warnung: Taxidaten sind keine Liste. Werden zurückgesetzt.")
                        self.taxi_data_cache = []
            except (json.JSONDecodeError, IOError) as e:
                print(f"Fehler beim Laden der Taxidaten: {e}")
                self.taxi_data_cache = []
        else:
            self.taxi_data_cache = []
    # ^^^^^ HIER ENDET DIE NEUE, FEHLENDE METHODE ^^^^^

    def _configure_shuttle_button(self, button_widget, config_key, default_text):
        shuttle_configs = self.current_settings.get('shuttle_button_configs', {})
        config = shuttle_configs.get(config_key, {'type': 'symbol', 'value': default_text, 'is_active': True})

        if not config.get('is_active', True):
            try:
                button_widget.pack_forget()
            except tk.TclError:
                pass
            return
        
        style_cfg = self.current_settings.get('list_views_button_style', self.default_settings['list_views_button_style'])
        icon_size = style_cfg.get('icon_size', 24)
        btn_type = config.get('type', 'symbol')
        
        btn_value = config.get('value', default_text)
        
        if not hasattr(self, 'shuttle_button_images'):
            self.shuttle_button_images = {}

        if btn_type == 'image' and btn_value and os.path.exists(btn_value) and Image and ImageTk:
            try:
                img = Image.open(btn_value).resize((icon_size, icon_size), Image.Resampling.LANCZOS)
                photo = ImageTk.PhotoImage(img)
                self.shuttle_button_images[config_key] = photo
                button_widget.image = photo
                button_widget.config(image=photo, text="", compound='center')
            except Exception as e:
                print(f"Fehler beim Laden des Bildes für Button '{config_key}': {e}")
                button_widget.config(text=default_text, image="")
        else:
            unique_style_name = f"{config_key}.{icon_size}px.TButton"
            
            try:
                base_font_info = tkFont.Font(font=self.style.lookup('TButton', 'font'))
                base_family = base_font_info.actual("family")
                base_weight = base_font_info.actual("weight")
                base_slant = base_font_info.actual("slant")
            except (tk.TclError, AttributeError):
                base_family = "Segoe UI"
                base_weight = "normal"
                base_slant = "roman"
                
            custom_font = tkFont.Font(
                family=base_family,
                size=-abs(icon_size),
                weight=base_weight,
                slant=base_slant
            )
            
            self.style.configure(unique_style_name, font=custom_font)
            button_widget.config(style=unique_style_name, text=btn_value)

