    def _redraw_shuttle_cb_canvas(self, booking_type):
        """Zeichnet die Checkbox-Bilder auf den Canvas links neben der Shuttle-Treeview."""
        tree = self.shuttle_hinfahrt_tree if booking_type == 'Hinfahrt' else self.shuttle_rueckfahrt_tree
        cb_canvas = (self.shuttle_hinfahrt_cb_canvas if booking_type == 'Hinfahrt'
                     else self.shuttle_rueckfahrt_cb_canvas)
        if not cb_canvas or not cb_canvas.winfo_exists():
            return
        if not tree or not tree.winfo_exists():
            return

        cb_canvas.delete("all")
        cw = cb_canvas.winfo_width()
        if cw <= 1:
            cw = self.checkbox_size + 14
        cx = cw // 2

        children = tree.get_children()

        # Überschrift "✓" im Heading-Bereich des Canvas zeichnen
        heading_height = None
        for item in children:
            bbox = tree.bbox(item)
            if bbox:
                heading_height = bbox[1]
                break
        if heading_height is None:
            try:
                heading_height = int(self.style.lookup("Shuttle.Treeview", "rowheight") or 35)
            except Exception:
                heading_height = 35

        try:
            heading_bg = self.style.lookup("Shuttle.Treeview.Heading", "background") or '#d9d9d9'
        except Exception:
            heading_bg = '#d9d9d9'

        cb_canvas.create_rectangle(0, 0, cw, heading_height,
                                   fill=heading_bg, outline='#9e9e9e')
        try:
            font_size = self.current_settings.get('configurable_sizes', {}).get(
                'shuttle_service', {}).get('font_size', 14)
            base_family = tkFont.Font(font=self.style.lookup('TLabel', 'font')).actual('family')
        except Exception:
            font_size = 14
            base_family = 'Segoe UI'
        cb_canvas.create_text(cx, heading_height // 2, text="✓",
                              font=(base_family, font_size, 'bold'), anchor="center")

        # Checkbox-Bilder für jede sichtbare Zeile zeichnen
        for item in children:
            bbox = tree.bbox(item)
            if bbox:
                bx, by, bw, bh = bbox
                entry = next((e for e in self.shuttle_data_cache if e.get('id') == item), None)
                erledigt = entry.get('erledigt', False) if entry else False
                img = (getattr(self, 'checked_image', None) if erledigt
                       else getattr(self, 'unchecked_image', None))
                cy = by + bh // 2
                if img:
                    cb_canvas.create_image(cx, cy, image=img, anchor="center")
                else:
                    cb_canvas.create_text(cx, cy, text='☑' if erledigt else '☐',
                                          font=(base_family, font_size), anchor="center")

    def _handle_shuttle_cb_click(self, booking_type, click_y):
        """Toggelt den erledigt-Status bei Klick auf den Checkbox-Canvas."""
        tree = self.shuttle_hinfahrt_tree if booking_type == 'Hinfahrt' else self.shuttle_rueckfahrt_tree
        if not tree or not tree.winfo_exists():
            return
        for item in tree.get_children():
            bbox = tree.bbox(item)
            if bbox:
                bx, by, bw, bh = bbox
                if by <= click_y < by + bh:
                    for entry in self.shuttle_data_cache:
                        if entry.get('id') == item:
                            entry['erledigt'] = not entry.get('erledigt', False)
                            break
                    self._save_shuttle_data()
                    self._load_and_display_shuttle_data(booking_type)
                    return

    def _load_and_display_shuttle_data(self, booking_type):
        tree = self.shuttle_hinfahrt_tree if booking_type == 'Hinfahrt' else self.shuttle_rueckfahrt_tree
        if not tree or not tree.winfo_exists():
            return

        for item in tree.get_children():
            tree.delete(item)

        filtered_data = [entry for entry in self.shuttle_data_cache if entry.get('type') == booking_type]
        filtered_data.sort(key=lambda x: (x.get('datum', ''), x.get('zeit', '')))

        for entry in filtered_data:
            erledigt = entry.get('erledigt', False)
            values = (
                entry.get('datum', ''),
                entry.get('zeit', ''),
                entry.get('gastname', ''),
                entry.get('zimmer', ''),
                entry.get('personen', '')
            )
            item_id = entry.get('id', uuid.uuid4().hex)
            tags = ('erledigt_tag',) if erledigt else ()
            tree.insert("", "end", values=values, iid=item_id, tags=tags)

        # Canvas-Checkboxen nach dem Befüllen der Treeview neu zeichnen
        tree.after(20, lambda bt=booking_type: self._redraw_shuttle_cb_canvas(bt))

    def _add_shuttle_entry(self, booking_type):
        """Öffnet den Dialog zum Hinzufügen von Shuttle-Buchungen mit autom. Backup."""
        def handle_save(new_entry_data):
            self.shuttle_data_cache.append(new_entry_data)
            self._save_shuttle_data()
            
            # AUTOMATISCHES BACKUP (ohne Nachfrage)
            self._perform_manual_backup_shuttle(ask_confirmation=False)
            
            self._save_list_entry_to_history(new_entry_data, "Hinzugefügt", "Shuttle")
            self._load_and_display_shuttle_data(booking_type)
            self._update_notifications() 
            
            if self.shuttle_overlay_window and self.shuttle_overlay_window.winfo_exists():
                self.shuttle_overlay_window.update_display()
            
            SuccessToast(self.master, 
                         title="Gespeichert", 
                         message=f"Buchung für {new_entry_data.get('zeit', '??:??')} Uhr hinzugefügt (+ Backup).", 
                         toast_type='success', 
                         colors=self.current_settings.get('toast_colors'),
                         duration=1500)

        dialog = ShuttleEntryDialog(self.master, self, booking_type=booking_type, save_callback=handle_save)
        dialog.show()

    def _edit_shuttle_entry(self, booking_type):
        tree = self.shuttle_hinfahrt_tree if booking_type == 'Hinfahrt' else self.shuttle_rueckfahrt_tree
        selected_item_ids = tree.selection()
        if not selected_item_ids:
            SuccessToast(self.master, title="Keine Auswahl", message="Bitte einen Eintrag auswählen.", toast_type='warning', colors=self.current_settings.get('toast_colors'))
            return

        selected_item_id = selected_item_ids[0]
        entry_to_edit = None
        entry_index = -1
        for i, entry in enumerate(self.shuttle_data_cache):
            if entry.get("id") == selected_item_id:
                entry_to_edit = entry
                entry_index = i
                break
        
        if not entry_to_edit:
            return

        dialog = ShuttleEntryDialog(self.master, self, entry_data=entry_to_edit.copy(), booking_type=booking_type)
        updated_entry_data = dialog.show()

        if updated_entry_data:
            self.shuttle_data_cache[entry_index] = updated_entry_data
            self._save_shuttle_data()
            
            # AUTOMATISCHES BACKUP
            self._perform_manual_backup_shuttle(ask_confirmation=False)
            
            self._save_list_entry_to_history(updated_entry_data, "Bearbeitet", "Shuttle")
            self._load_and_display_shuttle_data(booking_type)
            self._update_notifications()
            if self.shuttle_overlay_window and self.shuttle_overlay_window.winfo_exists():
                self.shuttle_overlay_window.update_display()
            
            SuccessToast(self.master, title="Aktualisiert", message="Eintrag aktualisiert und gesichert.", toast_type='success', colors=self.current_settings.get('toast_colors'))

    def _delete_shuttle_entry(self, booking_type):
        tree = self.shuttle_hinfahrt_tree if booking_type == 'Hinfahrt' else self.shuttle_rueckfahrt_tree
        selected_item_ids = tree.selection()
        
        if not selected_item_ids:
            SuccessToast(self.master, title="Keine Auswahl", message="Bitte einen Eintrag auswählen.", toast_type='warning', colors=self.current_settings.get('toast_colors'))
            return
            
        if not messagebox.askyesno("Stornierung bestätigen", "Wirklich stornieren?", parent=self.master):
            return

        for item_id in selected_item_ids:
            entry_to_delete = next((e for e in self.shuttle_data_cache if e.get("id") == item_id), None)
            if entry_to_delete:
                self._save_list_entry_to_history(entry_to_delete, "Gelöscht", "Shuttle")

        self.shuttle_data_cache = [entry for entry in self.shuttle_data_cache if entry.get("id") not in selected_item_ids]
        
        self._save_shuttle_data()
        
        # AUTOMATISCHES BACKUP
        self._perform_manual_backup_shuttle(ask_confirmation=False)
        
        self._load_and_display_shuttle_data(booking_type)
        self._update_notifications()
        
        if self.shuttle_overlay_window and self.shuttle_overlay_window.winfo_exists():
            self.shuttle_overlay_window.update_display()

        SuccessToast(self.master, title="Storniert", message="Buchung storniert und Backup erstellt.", toast_type='success', colors=self.current_settings.get('toast_colors'))

    def _toggle_shuttle_erledigt(self, booking_type, event=None):
        """Nicht mehr direkt genutzt – Toggle erfolgt über _handle_shuttle_cb_click."""
        pass

    def _delete_erledigte_shuttle(self, booking_type):
        """Löscht alle als erledigt markierten Shuttle-Einträge des gewählten Typs."""
        erledigte = [e for e in self.shuttle_data_cache if e.get('type') == booking_type and e.get('erledigt', False)]
        if not erledigte:
            SuccessToast(self.master, title="Nichts zu löschen", message="Keine erledigten Buchungen vorhanden.", toast_type='info', colors=self.current_settings.get('toast_colors'))
            return
        count = len(erledigte)
        if not messagebox.askyesno("Erledigte löschen", f"{count} erledigte Buchung(en) endgültig löschen?", parent=self.master):
            return
        for entry in erledigte:
            self._save_list_entry_to_history(entry, "Erledigt gelöscht", "Shuttle")
        self.shuttle_data_cache = [e for e in self.shuttle_data_cache if not (e.get('type') == booking_type and e.get('erledigt', False))]
        self._save_shuttle_data()
        self._perform_manual_backup_shuttle(ask_confirmation=False)
        self._load_and_display_shuttle_data(booking_type)
        self._update_notifications()
        if self.shuttle_overlay_window and self.shuttle_overlay_window.winfo_exists():
            self.shuttle_overlay_window.update_display()
        SuccessToast(self.master, title="Gelöscht", message=f"{count} erledigte Buchung(en) gelöscht.", toast_type='success', colors=self.current_settings.get('toast_colors'))

    def _load_shuttle_data(self):
        if os.path.exists(self.shuttle_data_file):
            try:
                with open(self.shuttle_data_file, 'r', encoding='utf-8') as f:
                    self.shuttle_data_cache = json.load(f)
                    if not isinstance(self.shuttle_data_cache, list):
                        self.shuttle_data_cache = []
            except (json.JSONDecodeError, IOError):
                self.shuttle_data_cache = []
            self._update_notifications()



    def _save_shuttle_data(self):
        """Speichert die Shuttle-Daten in die JSON-Datei."""
        try:
            data_dir = os.path.dirname(self.shuttle_data_file)
            os.makedirs(data_dir, exist_ok=True)
            with open(self.shuttle_data_file, 'w', encoding='utf-8') as f:
                json.dump(self.shuttle_data_cache, f, indent=2, ensure_ascii=False)
        except Exception as e:
            print(f"Fehler beim Speichern der Shuttle-Daten: {e}")
    # +++ ENDE: NEUE METHODEN FÜR SHUTTLE-SERVICE +++
    
     # HIER DEN NEUEN CODEBLOCK EINFÜGEN
    # +++ START: NEUE METHODEN FÜR SHUTTLE-VERLAUF +++
    def _open_shuttle_history_dialog(self):
        """Öffnet den Dialog für den Shuttle-Buchungsverlauf."""
        self._open_generic_list_history_dialog(
            "Shuttle-Buchungen",
            self.shuttle_history_file,
            self._get_shuttle_history_summary_line,
            self._restore_shuttle_from_history
        )

    def _get_shuttle_history_summary_line(self, snapshot):
        """Erstellt eine Zusammenfassungszeile für einen Shuttle-Verlaufseintrag."""
        data = snapshot.get('data')
        action = snapshot.get('action', 'Unbekannte Aktion')
        if not data:
            return f"[{action}] - Ungültige Daten"
        
        booking_type = data.get('type', 'Unbekannt')
        zeit = data.get('zeit', '??:??')
        zimmer = data.get('zimmer', 'N/A')
        gast = data.get('gastname', 'N/A')

        return f"[{action}] {booking_type} - {zeit} Uhr - Zimmer: {zimmer} - Gast: {gast}"

    def _restore_shuttle_from_history(self, history_dialog):
        """Stellt einen Shuttle-Eintrag aus dem Verlauf wieder her."""
        # Die Logik zum Extrahieren der Daten wird direkt hier implementiert.
        try:
            listbox = history_dialog.listbox_widget
            all_snapshots = history_dialog.displayed_snapshots
            selected_indices = listbox.curselection()

            if not selected_indices:
                messagebox.showwarning("Auswahl", "Bitte einen Eintrag zum Wiederherstellen auswählen.", parent=history_dialog)
                return
            
            if len(selected_indices) > 1:
                messagebox.showwarning("Mehrfachauswahl", "Bitte nur einen Eintrag auf einmal wiederherstellen.", parent=history_dialog)
                return
            
            # Holt den korrekten Snapshot basierend auf der Auswahl in der Listbox
            snapshot_data = all_snapshots[selected_indices[0]]
        except (AttributeError, IndexError) as e:
            messagebox.showerror("Fehler", f"Die Daten aus dem Verlaufsfenster konnten nicht gelesen werden: {e}", parent=history_dialog)
            return

        entry_to_restore = snapshot_data.get('data')
        if not entry_to_restore:
            messagebox.showerror("Fehler", "Keine Daten zum Wiederherstellen in diesem Eintrag.", parent=history_dialog)
            return

        if messagebox.askyesno("Wiederherstellen",
                               "Diesen Shuttle-Eintrag wirklich wiederherstellen?\nEin eventuell vorhandener Eintrag mit derselben ID wird überschrieben.",
                               parent=history_dialog):
            
            # Entfernt einen möglicherweise vorhandenen alten Eintrag mit derselben ID
            self.shuttle_data_cache = [e for e in self.shuttle_data_cache if e.get('id') != entry_to_restore.get('id')]
            
            # Fügt den wiederhergestellten Eintrag hinzu
            self.shuttle_data_cache.append(entry_to_restore)
            
            self._save_shuttle_data()
            self._save_list_entry_to_history(entry_to_restore, "Wiederhergestellt", "Shuttle")
            
            # Lade die Ansichten für beide Shuttle-Typen neu
            self._load_and_display_shuttle_data('Hinfahrt')
            self._load_and_display_shuttle_data('Rückfahrt')
            self._update_notifications()
            
            history_dialog.destroy()
            SuccessToast(self.master, title="Erfolg", message="Shuttle-Eintrag wurde wiederhergestellt.", toast_type='success', colors=self.current_settings.get('toast_colors'))
    # +++ ENDE: NEUE METHODEN FÜR SHUTTLE-VERLAUF +++



    def _open_weckruf_history_dialog(self):
        """Öffnet den Dialog für den Weckruf-Verlauf."""
        self._open_generic_list_history_dialog(
            "Weckrufe",
            self.weckruf_history_file,
            self._get_weckruf_history_summary_line,
            self._restore_weckruf_from_history
        )

    def _get_weckruf_history_summary_line(self, snapshot):
        """Erstellt eine Zusammenfassungszeile für einen Weckruf-Verlaufseintrag."""
        data = snapshot.get('data')
        action = snapshot.get('action', 'Unbekannt')
        if not data:
            return f"[{action}] - Ungültige Daten"
        
        datum = data.get('datum', '??.??.??')
        zeit = data.get('zeit', '??:??')
        zimmer = data.get('zimmer', 'N/A')
        gast = data.get('gastname', 'N/A')
        return f"[{action}] {datum} {zeit} - Zimmer: {zimmer} - Gast: {gast}"

    def _restore_weckruf_from_history(self, history_dialog):
        """Stellt einen Weckruf-Eintrag aus dem Verlauf wieder her."""
        # Die Logik zum Extrahieren der Daten wird direkt hier implementiert.
        try:
            listbox = history_dialog.listbox_widget
            all_snapshots = history_dialog.displayed_snapshots
            selected_indices = listbox.curselection()

            if not selected_indices:
                messagebox.showwarning("Auswahl", "Bitte einen Eintrag zum Wiederherstellen auswählen.", parent=history_dialog)
                return
            
            if len(selected_indices) > 1:
                messagebox.showwarning("Mehrfachauswahl", "Bitte nur einen Eintrag auf einmal wiederherstellen.", parent=history_dialog)
                return
            
            # Holt den korrekten Snapshot basierend auf der Auswahl in der Listbox
            snapshot_data = all_snapshots[selected_indices[0]]
        except (AttributeError, IndexError) as e:
            messagebox.showerror("Fehler", f"Die Daten aus dem Verlaufsfenster konnten nicht gelesen werden: {e}", parent=history_dialog)
            return

        entry_to_restore = snapshot_data.get('data')
        if not entry_to_restore:
            messagebox.showerror("Fehler", "Keine Daten zum Wiederherstellen in diesem Eintrag.", parent=history_dialog)
            return

        if messagebox.askyesno("Wiederherstellen", "Diesen Weckruf wiederherstellen? Ein eventuell vorhandener Eintrag mit derselben ID wird überschrieben.", parent=history_dialog):
            # Entfernt einen möglicherweise vorhandenen alten Eintrag mit derselben ID
            self.weckruf_data_cache = [e for e in self.weckruf_data_cache if e.get('id') != entry_to_restore.get('id')]
            # Fügt den wiederhergestellten Eintrag hinzu
            self.weckruf_data_cache.append(entry_to_restore)
            
            self._save_weckruf_data()
            self._save_list_entry_to_history(entry_to_restore, "Wiederhergestellt", "Weckruf")
            self._load_and_display_weckrufe()
            self._update_notifications()

            history_dialog.destroy()
            SuccessToast(self.master, title="Erfolg", message="Weckruf wurde wiederhergestellt.", toast_type='success', colors=self.current_settings.get('toast_colors'))



    def _hide_completed_tasks(self, shift_key):
        """
        Blendet alle Aufgaben aus, deren Checkbox aktiviert ist.
        KORREKTUR: Greift nun direkt auf die synchronisierte Datenstruktur 'checklist_data' zu,
        statt auf unsichere Hilfslisten, wodurch das Ausblenden zuverlässig funktioniert.
        """
        # Zugriff auf die UI-Frames (die Zeilen in der Checkliste)
        widgets = self.checklist_widgets.get(shift_key, {})
        task_frames = widgets.get('task_frames', [])
        
        # Zugriff auf die Daten (enthält die BooleanVars für die Checkboxen)
        task_data_list = self.checklist_data.get(shift_key, [])
        
        # Sicherheitsprüfung: Anzahl der Daten muss mit Anzahl der UI-Zeilen übereinstimmen
        if len(task_data_list) != len(task_frames):
            print(f"Warnung: Inkonsistenz zwischen Daten und Anzeige in Schicht '{shift_key}'.")
            return

        # Durchlaufe alle Aufgaben
        for i, task_info in enumerate(task_data_list):
            check_var = task_info.get('check_var')
            
            # Prüfen, ob die Checkbox aktiviert ist (True = Erledigt)
            if check_var and check_var.get():
                # Das entsprechende Frame aus dem Grid-Layout entfernen (ausblenden)
                # 'grid_remove' merkt sich die Position für ein späteres 'grid()'
                task_frames[i].grid_remove()
    
    def _show_all_tasks(self, shift_key):
        """Shows all checklist tasks."""
        widgets = self.checklist_widgets.get(shift_key, {})
        task_frames = widgets.get('task_frames', [])
        for frame in task_frames:
            if not frame.winfo_viewable():
                frame.grid() # Re-add the widget to the grid; it remembers its options
                
                
    def _update_open_tasks_display(self, shift_key, *args):
        """
        Aktualisiert die "Meine offenen Aufgaben"-Liste für eine beliebige Schicht.
        """
        offene_aufgaben_frame = self.offene_aufgaben_frames.get(shift_key)
        canvas = self.offene_aufgaben_canvases.get(shift_key)
        
        if not offene_aufgaben_frame or not offene_aufgaben_frame.winfo_exists():
            return

        for widget in offene_aufgaben_frame.winfo_children():
            widget.destroy()

        current_category = None
        category_frame = None
        
        if shift_key not in self.checklist_data:
            return

        for task_info in self.checklist_data[shift_key]:
            # Eine Aufgabe ist offen, wenn ihre Checkbox nicht aktiviert ist.
            if not task_info['check_var'].get():
                if task_info['category'] != current_category:
                    current_category = task_info['category']
                    category_frame = ttk.LabelFrame(offene_aufgaben_frame, text=current_category, style='TLabelframe', padding=(10, 5))
                    category_frame.pack(fill='x', expand=True, pady=5, padx=5)
                    category_frame.columnconfigure(0, weight=1)
                
                if category_frame:
                    task_frame_open = ttk.Frame(category_frame, style='AppBackground.TFrame')
                    task_frame_open.pack(fill='x', expand=True, pady=2)
                    task_frame_open.columnconfigure(0, weight=1)
                    
                    ttk.Label(task_frame_open, text=task_info['text'], wraplength=450, justify='left').grid(row=0, column=0, sticky='w')

        offene_aufgaben_frame.update_idletasks()
        if canvas and canvas.winfo_exists():
            canvas.configure(scrollregion=canvas.bbox("all"))

    def _create_generic_checklist_page(self, parent_frame, title, data, shift_key):
        """
        Erstellt eine generische Checklisten-Seite, die bei Klick auf die Checkbox
        sofort prüft, ob ein Kürzel vorhanden ist, und andernfalls die Aktion blockiert.
        """
        for widget in parent_frame.winfo_children():
            widget.destroy()

        try:
            base_font_family = tkFont.Font(font=self.style.lookup('TLabel', 'font')).actual('family')
        except (tk.TclError, AttributeError):
            base_font_family = "Segoe UI"
        kuerzel_font = tkFont.Font(family=base_font_family, size=14)

        # --- UI-Layout (Header, Aktionen, Split-Frame) ---
        header_frame = ttk.Frame(parent_frame, style='AppBackground.TFrame')
        header_frame.pack(fill='x', pady=5)
        header_frame.columnconfigure(1, weight=1)
        home_button = self._create_home_button(header_frame)
        if home_button: home_button.grid(row=0, column=0, sticky='w', padx=10)
        ttk.Label(header_frame, text=title, font=("Segoe UI", 16, "bold")).grid(row=0, column=1, sticky='w', padx=10)
        right_info_frame = ttk.Frame(header_frame, style='AppBackground.TFrame')
        right_info_frame.grid(row=0, column=2, sticky='e', padx=(5, 15), pady=2)
        ttk.Label(right_info_frame, textvariable=self.time_display_var, style='TLabel').pack(side='right', anchor='e', pady=2)
        ttk.Label(right_info_frame, textvariable=self.date_display_var, style='TLabel').pack(side='right', anchor='e', padx=(0,10), pady=2)

        action_frame = ttk.Frame(parent_frame, style='AppBackground.TFrame')
        action_frame.pack(fill='x', pady=(5, 10))
        action_frame.columnconfigure((0, 1, 2, 3, 4), weight=1)

        main_split_frame = ttk.Frame(parent_frame, style='AppBackground.TFrame')
        main_split_frame.pack(fill='both', expand=True, padx=15, pady=(0, 8))
        main_split_frame.columnconfigure(0, weight=1); main_split_frame.columnconfigure(1, weight=1); main_split_frame.rowconfigure(1, weight=1)

        ttk.Label(main_split_frame, text="Alle Aufgaben", font=("Segoe UI", 14, "bold")).grid(row=0, column=0, sticky='w', padx=10, pady=(5, 2))
        ttk.Label(main_split_frame, text="Meine offenen Aufgaben", font=("Segoe UI", 14, "bold")).grid(row=0, column=1, sticky='w', padx=10, pady=(5, 2))

        left_container = ttk.Frame(main_split_frame); left_container.grid(row=1, column=0, sticky='nsew', padx=(10, 5)); left_container.rowconfigure(0, weight=1); left_container.columnconfigure(0, weight=1)
        left_canvas = tk.Canvas(left_container, borderwidth=0, highlightthickness=0)
        left_vsb = ttk.Scrollbar(left_container, orient="vertical", command=left_canvas.yview); left_canvas.configure(yscrollcommand=left_vsb.set); left_vsb.grid(row=0, column=1, sticky='ns'); left_canvas.grid(row=0, column=0, sticky='nsew')
        content_frame = ttk.Frame(left_canvas, style='AppBackground.TFrame', padding=(10, 10))
        left_canvas_window = left_canvas.create_window((0, 0), window=content_frame, anchor="nw")
        content_frame.bind("<Configure>", lambda e: left_canvas.configure(scrollregion=left_canvas.bbox("all")))
        left_canvas.bind("<Configure>", lambda e: left_canvas.itemconfig(left_canvas_window, width=e.width))
        right_container = ttk.Frame(main_split_frame); right_container.grid(row=1, column=1, sticky='nsew', padx=(5, 10)); right_container.rowconfigure(0, weight=1); right_container.columnconfigure(0, weight=1)
        right_canvas = tk.Canvas(right_container, borderwidth=0, highlightthickness=0)
        right_vsb = ttk.Scrollbar(right_container, orient="vertical", command=right_canvas.yview); right_canvas.configure(yscrollcommand=right_vsb.set); right_vsb.grid(row=0, column=1, sticky='ns'); right_canvas.grid(row=0, column=0, sticky='nsew')
        offene_aufgaben_frame = ttk.Frame(right_canvas, style='AppBackground.TFrame', padding=(10, 10))
        right_canvas_window = right_canvas.create_window((0, 0), window=offene_aufgaben_frame, anchor="nw")
        offene_aufgaben_frame.bind("<Configure>", lambda e: right_canvas.configure(scrollregion=right_canvas.bbox("all")))
        right_canvas.bind("<Configure>", lambda e: right_canvas.itemconfig(right_canvas_window, width=e.width))

        self.offene_aufgaben_frames[shift_key] = offene_aufgaben_frame
        self.offene_aufgaben_canvases[shift_key] = right_canvas
        self.checklist_data[shift_key] = []
        task_frames = []
        
