                checkbox_label = tk.Label(task_frame, image=self.unchecked_image, cursor="hand2", background=self.style.lookup('AppBackground.TFrame', 'background'))
                
                # vvvvv HIER IST DIE KORREKTUR vvvvv
                # Wir speichern eine Referenz auf das Label-Widget der Checkbox
                task_info = {'category': category, 'text': task, 'check_var': check_var, 'checkbox_label': checkbox_label}
                # ^^^^^ ENDE DER KORREKTUR ^^^^^

                if shift_key in ['frueh', 'spaet']:
                    kuerzel_var = tk.StringVar()
                    task_info['kuerzel_var'] = kuerzel_var
                    
                    kuerzel_entry = ttk.Entry(task_frame, textvariable=kuerzel_var, width=10, justify='center', font=kuerzel_font)
                    task_info['kuerzel_entry'] = kuerzel_entry
                    self._add_widget_to_list(kuerzel_entry, 'entry', is_main_input=True)
                    kuerzel_entry.bind("<FocusOut>", lambda e, w=kuerzel_entry, ti=task_info: self._validate_checklist_kuerzel(w, ti))
                    
                    def on_checkbox_click(event, cv=check_var, kv=kuerzel_var, t_label=task_label):
                        intended_to_be_checked = not cv.get()
                        if intended_to_be_checked and not kv.get().strip():
                            messagebox.showwarning(
                                "Kürzel erforderlich",
                                f"Für die Aufgabe:\n\n'{t_label.cget('text')}'\n\nmuss zuerst ein Kürzel eingetragen werden, bevor sie als erledigt markiert werden kann.",
                                parent=self.master
                            )
                            return "break"
                        cv.set(not cv.get())

                    checkbox_label.bind("<Button-1>", on_checkbox_click)

                    def on_kuerzel_entry(*args, cv=check_var, kv=kuerzel_var):
                        if kv.get().strip() and not cv.get():
                            cv.set(True)
                        on_any_checklist_change()

                    kuerzel_var.trace_add("write", on_kuerzel_entry)

                    def on_check_var_change(*args, cv=check_var, kv=kuerzel_var, cl=checkbox_label, tf=task_frame, tl=task_label):
                        # vvvvv HIER IST DIE KORREKTUR vvvvv
                        # Prüft, ob das Label-Widget noch existiert, bevor es konfiguriert wird.
                        if not cl.winfo_exists():
                            return
