    def _configure_single_ta_button(self, button_widget, config):
        """Helper to configure a Tagesabrechnung button based on settings."""
        if not config or not isinstance(config, dict):
            button_widget.config(text="?")
            return

        btn_type = config.get('type', 'symbol')
        btn_value = config.get('value', '?')
        icon_size = 50  # A fixed reasonable size for these smaller buttons

        if btn_type == 'image' and btn_value and os.path.exists(btn_value) and Image and ImageTk:
            try:
                img = Image.open(btn_value).resize((icon_size, icon_size), Image.Resampling.LANCZOS)
                photo = ImageTk.PhotoImage(img)
                button_widget.image_ref = photo  # Store reference
                button_widget.config(image=photo, text="", compound='center')
            except Exception as e:
                print(f"Error loading image for TA button: {e}")
                button_widget.config(text="🖼️", image="") # Fallback symbol
        else:
            # Use text for symbol type or as fallback
            button_widget.config(text=btn_value, image="")
            
    def _update_tagesabrechnung_calculations(self, show_feedback=True):
        """Calculates all sums in the Tagesabrechnung tab based on current input fields."""
        # Calculate FO Sum
        fo_sum = decimal.Decimal('0.0')
        fo_vars = [self.ta_einnahmen_fo_frueh_var, self.ta_einnahmen_fo_spaet_var,
                   self.ta_einnahmen_fo_nacht_var, self.ta_einnahmen_fo_tip_var]
        for var in fo_vars:
            fo_sum += self._parse_input_string(var.get()) or decimal.Decimal('0.0')
        self.ta_einnahmen_fo_summe_var.set(self._format_decimal_for_display(fo_sum))
        
        # Calculate Bar Sum
        bar_sum = decimal.Decimal('0.0')
        bar_vars = [self.ta_einnahmen_bar_haupt_var, self.ta_einnahmen_bar_tip_var]
        for var in bar_vars:
            bar_sum += self._parse_input_string(var.get()) or decimal.Decimal('0.0')
        self.ta_einnahmen_bar_summe_var.set(self._format_decimal_for_display(bar_sum))

        # Calculate Ausgaben Sum
        ausgaben_sum = decimal.Decimal('0.0')
        for row in self.ta_ausgaben_rows:
            ausgaben_sum += self._parse_input_string(row["betrag"].get()) or decimal.Decimal('0.0')
        self.ta_ausgaben_summe_var.set(self._format_decimal_for_display(ausgaben_sum))
        
        # Update Final Summary
        self.ta_summary_einnahmen_fo_var.set(self._format_decimal_for_display(fo_sum))
        self.ta_summary_einnahmen_bar_var.set(self._format_decimal_for_display(bar_sum))
        
        total_einnahmen = fo_sum + bar_sum
        self.ta_summary_summe_einnahmen_var.set(self._format_decimal_for_display(total_einnahmen))
        
        self.ta_summary_summe_ausgaben_var.set(self._format_decimal_for_display(ausgaben_sum))
        
        total_bareinnahmen = total_einnahmen - ausgaben_sum
        self.ta_summary_summe_bareinnahmen_var.set(self._format_decimal_for_display(total_bareinnahmen))
        
        # HIER BEGINNT DIE ERGÄNZUNG
        # Speichert den Verlauf der Tagesabrechnung automatisch nach jeder Neuberechnung.
        if not self.is_loading_data:
            self._save_tagesabrechnung_to_history()
        # HIER ENDET DIE ERGÄNZUNG
        
        

        # Provide user feedback that the refresh was successful, if requested.
        if show_feedback:
            messagebox.showinfo("Aktualisiert", "Alle Summen in der Tagesabrechnung wurden neu berechnet.", parent=self.master)



        self._update_tagesabrechnung_sum_colors() # <-- Dieser Aufruf wurde bereits hinzugefügt

    def _update_tagesabrechnung_sum_colors(self):
        """Wendet die Farbkodierung auf alle Summen-Labels in der Tagesabrechnung an."""
        if not hasattr(self, 'ta_sum_labels'):
            return

        # Farbwerte aus den Einstellungen holen
        default_fg = self.current_settings.get('number_elements_fg_color', '#000000')
        red_fg = self.current_settings.get('diff_negative_fg', '#FF0000')
        green_fg = self.current_settings.get('diff_positive_fg', '#008000')

        for label in self.ta_sum_labels:
            if not label.winfo_exists():
                continue

            var_str_name = str(label.cget('textvariable'))
            if not var_str_name:
                continue
            
            try:
                val_str_content = self.master.getvar(var_str_name)
                val = self._parse_input_string(val_str_content) or decimal.Decimal('0.00')
                
                # is_zero mit einer kleinen Toleranz prüfen
                is_zero = abs(val) < decimal.Decimal('0.01')

                target_fg = default_fg

                if is_zero:
                    target_fg = green_fg    # Regel 1: NULL-SUMME -> GRÜN
                elif val < 0:
                    target_fg = red_fg      # Regel 2: NEGATIVE SUMME -> ROT
                
                # Farbe nur ändern, wenn nötig, um Flackern zu vermeiden
                if label.cget('foreground') != target_fg:
                    label.config(fg=target_fg)

            except (tk.TclError, AttributeError, Exception) as e:
                # Bei einem Fehler auf die Standardfarbe zurücksetzen
                print(f"Error updating Tagesabrechnung sum color for var '{var_str_name}': {e}")
                if label.winfo_exists() and label.cget('foreground') != default_fg:
                    try:
                        label.config(fg=default_fg)
                    except tk.TclError:
                        pass


    def _clear_tagesabrechnung_fields(self):
        if not messagebox.askyesno("Löschen", "Alle Einträge der Tagesabrechnung wirklich löschen?", parent=self.master):
            return

        for var in [self.ta_einnahmen_fo_frueh_var, self.ta_einnahmen_fo_spaet_var,
                    self.ta_einnahmen_fo_nacht_var, self.ta_einnahmen_fo_tip_var,
                    self.ta_einnahmen_bar_haupt_var, self.ta_einnahmen_bar_tip_var]:
            var.set("0,00 €")
            
        for row in self.ta_ausgaben_rows:
            row["mitarbeiter"].set("")
            row["wofuer"].set("")
            row["betrag"].set("0,00 €")
            
        self._update_tagesabrechnung_calculations(show_feedback=False)
        self._perform_manual_backup_tagesabrechnung(ask_confirmation=False)
        
        SuccessToast(self.master, 
             title="Erfolgreich gelöscht & Gesichert",  
             message="Alle Felder der Tagesabrechnung wurden zurückgesetzt und die Sicherung wurde aktualisiert.", 
             toast_type='success', 
             colors=self.current_settings.get('toast_colors'))
        
        self._update_tagesabrechnung_sum_colors()

    def _print_tagesabrechnung(self):
        messagebox.showinfo("Drucken", "Diese Funktion speichert die Tagesabrechnung als PDF.", parent=self.master)
        self._save_tagesabrechnung_to_pdf()

    def _open_folder(self, path):
        """Öffnet den angegebenen Ordner im Datei-Explorer des Systems."""
        if not os.path.isdir(path):
            messagebox.showerror("Fehler", f"Der Ordner konnte nicht gefunden werden:\n{path}", parent=self.master)
            return
        try:
            if platform.system() == "Windows":
                os.startfile(path)
            elif platform.system() == "Darwin": # macOS
                subprocess.run(["open", path], check=True)
            else: # Linux
                subprocess.run(["xdg-open", path], check=True)
        except Exception as e:
            messagebox.showerror("Fehler", f"Der Ordner konnte nicht geöffnet werden:\n{e}", parent=self.master)

    def _show_tagesabrechnung_verlauf(self):
        """Opens the folder containing the history of saved Tagesabrechnung PDFs."""
        self._open_folder(self.ZIELORDNER_TAGESABRECHNUNG)

    def _email_tagesabrechnung(self):
        # vvvvv HIER BEGINNT DIE ÄNDERUNG vvvvv
        temp_pdf_path = ""
        try:
            # Erstellt einen Pfad für eine Datei mit einem festen, sauberen Namen
            # im temporären Verzeichnis des Betriebssystems.
            temp_dir = tempfile.gettempdir()
            temp_pdf_path = os.path.join(temp_dir, "tagesabrechnung.pdf")
            
            # Die PDF wird nun unter diesem festen Namen erstellt und gespeichert.
            created_path = self._save_tagesabrechnung_to_pdf(
                file_path=temp_pdf_path, 
                show_success_message=False, 
                open_folder_after=False
            )
        # ^^^^^ HIER ENDET DIE ÄNDERUNG ^^^^^
        
            if not created_path or not os.path.exists(created_path):
                SuccessToast(self.master, title="PDF-Fehler", message="Die PDF-Datei für die Vorschau konnte nicht erstellt werden.", toast_type='error', colors=self.current_settings.get('toast_colors'))
                if os.path.exists(temp_pdf_path):
                    try: os.remove(temp_pdf_path)
                    except OSError: pass
                return

            def email_callback_for_tagesabrechnung(pdf_path, recipient, subject, body):
                success, message = False, ""
                
                use_outlook = platform.system() == "Windows" and win32_available
                try:
                    if use_outlook:
                        win32.Dispatch('outlook.application')
                    else:
                        use_outlook = False
                except Exception:
                    use_outlook = False

                if use_outlook:
                    success, message = self._send_email_via_outlook(pdf_path, recipient, subject, body)
                else:
                    smtp_cfg = self.current_settings.get('smtp_settings', {})
                    if not all(smtp_cfg.get(k) for k in ['server', 'port', 'sender_email', 'username', 'password']):
                        return False, "SMTP-Einstellungen unvollständig."
                    success, message = self._send_email_silently(pdf_path, recipient, subject, body)

                if success:
                    self._save_tagesabrechnung_to_pdf(show_success_message=False, open_folder_after=False)
                    
                return success, message

            recipient = self.EMAIL_RECIPIENT_TAGESABRECHNUNG
           
            
            
            # vvvvv HIER BEGINNT DER NEUE/GEÄNDERTE CODEBLOCK vvvvv
            # Das Datum wird aus dem UI-Feld gelesen und validiert
            date_str = self.ta_datum_var.get()
            try:
                # Validiert das Datumsformat, bevor die E-Mail erstellt wird
                datetime.datetime.strptime(date_str, "%d.%m.%Y")
            except ValueError:
                messagebox.showerror("Ungültiges Datum", "Bitte geben Sie in der Kopfzeile ein gültiges Datum im Format TT.MM.JJJJ ein, bevor Sie eine E-Mail senden.", parent=self.master)
                return
            # ^^^^^ HIER ENDET DER NEUE/GEÄNDERTE CODEBLOCK ^^^^^
            
            
            
            subject = f"Tagesabrechnung vom {date_str}"
            body = (
                f"Hi Basti, Hi Annika,\n\n"
                f"anbei die Tagesabrechnung vom {date_str}.\n\n"
                f"Falls ihr Rückfragen habt, gebt einfach kurz Bescheid. Liebe Grüße, Dadgar\n"
            )
            
            preview_dialog = PDFPreviewDialog(
                parent=self.master, app_ref=self, pdf_path=created_path,
                email_callback=email_callback_for_tagesabrechnung,
                recipient=recipient, subject=subject, body_text=body,
                success_title="E-Mail erfolgreich versendet", success_message="Die Tagesabrechnung wurde versendet."
            )
            preview_dialog.show()

        except Exception as e:
            messagebox.showerror("Fehler bei E-Mail-Vorbereitung", f"Ein Fehler ist aufgetreten:\n{e}", parent=self.master)
            if temp_pdf_path and os.path.exists(temp_pdf_path):
                try:
                    os.remove(temp_pdf_path)
                except OSError:
                    pass
    
    
    def _send_email_via_outlook(self, pdf_path, recipient, subject, body, cc=None):
        """Sendet E-Mail via Outlook mit optionalem CC."""
        if not (platform.system() == "Windows" and win32_available):
            return False, "Outlook-Automatisierung ist nicht verfügbar."

        try:
            outlook = win32.Dispatch('outlook.application')
            mail = outlook.CreateItem(0)
            
            # To
            if isinstance(recipient, list): mail.To = "; ".join(recipient)
            else: mail.To = str(recipient)

            # CC (NEU)
            if cc:
                if isinstance(cc, list): mail.CC = "; ".join(cc)
                else: mail.CC = str(cc)

            mail.Subject = subject
            mail.Body = body
            
            if pdf_path and os.path.exists(pdf_path):
                attachment = mail.Attachments.Add(pdf_path)
                if "Tagesabrechnung" in subject:
                    attachment.DisplayName = "tagesabrechnung.pdf"

            mail.Send()
            return True, "E-Mail wurde erfolgreich über Outlook versendet."
        except Exception as e:
            return False, f"Fehler bei Outlook: {e}"

    def _send_email_silently(self, pdf_path, recipient, subject, body, cc=None):
        """Sendet E-Mail via SMTP mit optionalem CC."""
        smtp_cfg = self.current_settings.get('smtp_settings', {})
        msg = MIMEMultipart()
        msg['From'] = smtp_cfg.get('sender_email', '')

        # To
        if isinstance(recipient, list): msg['To'] = ", ".join(recipient)
        else: msg['To'] = str(recipient)
        
        # CC (NEU)
        if cc:
            if isinstance(cc, list): cc_str = ", ".join(cc)
            else: cc_str = str(cc)
            msg['Cc'] = cc_str
            
            # WICHTIG: Empfängerliste für SMTP muss To UND CC enthalten
            if isinstance(recipient, list): recipients_list = recipient + [cc_str]
            else: recipients_list = [str(recipient), cc_str]
        else:
            recipients_list = recipient if isinstance(recipient, list) else [str(recipient)]

        msg['Subject'] = subject
        msg.attach(MIMEText(body, 'plain', 'utf-8'))

        try:
            if pdf_path and os.path.exists(pdf_path):
                with open(pdf_path, "rb") as attachment:
                    part = MIMEBase("application", "octet-stream")
                    part.set_payload(attachment.read())
                encoders.encode_base64(part)
                basename = "tagesabrechnung.pdf" if "Tagesabrechnung" in subject else os.path.basename(pdf_path)
                part.add_header("Content-Disposition", f"attachment; filename={basename}")
                msg.attach(part)
        except Exception as e:
            return False, f"Fehler beim Anhängen: {e}"

        context = ssl.create_default_context()
        try:
            with smtplib.SMTP(smtp_cfg.get('server'), smtp_cfg.get('port', 587)) as server:
                server.starttls(context=context)
                server.login(smtp_cfg.get('username'), smtp_cfg.get('password'))
                # send_message extrahiert CC automatisch aus dem Header, wenn to_addrs nicht angegeben ist,
                # aber es ist sicherer, alle Empfänger explizit zu übergeben.
                server.send_message(msg, to_addrs=recipients_list) 
                return True, "E-Mail via SMTP versendet."
        except Exception as e:
            return False, f"SMTP Fehler: {e}"
        
        
        
        # Fügen Sie diese beiden Methoden in der KassenprotokollApp-Klasse hinzu
    def _send_html_email_via_outlook(self, recipient, subject, body):
        """Sendet eine HTML-E-Mail über Outlook."""
        if not (platform.system() == "Windows" and win32_available):
            return False, "Outlook-Automatisierung ist nur auf Windows mit pywin32 verfügbar."
        try:
            outlook = win32.Dispatch('outlook.application')
            mail = outlook.CreateItem(0)
            mail.To = recipient
            mail.Subject = subject
            mail.HTMLBody = body
            mail.Send()
            return True, "E-Mail wurde erfolgreich über Outlook versendet."
        except Exception as e:
            return False, f"Fehler bei der Outlook-Automatisierung:\n{e}"

    def _send_html_email_silently(self, recipient, subject, body):
        """Sendet eine HTML-E-Mail im Hintergrund per SMTP."""
        smtp_cfg = self.current_settings['smtp_settings']
        msg = MIMEMultipart()
        msg['From'] = smtp_cfg['sender_email']
        msg['To'] = recipient
        msg['Subject'] = subject
        msg.attach(MIMEText(body, 'html', 'utf-8'))

        context = ssl.create_default_context()
        try:
            with smtplib.SMTP(smtp_cfg['server'], smtp_cfg['port']) as server:
                server.starttls(context=context)
                server.login(smtp_cfg['username'], smtp_cfg['password'])
                server.send_message(msg)
                return True, "E-Mail erfolgreich via SMTP versendet."
        except Exception as e:
            return False, f"Ein Fehler ist beim Senden aufgetreten:\n{e}"
        
        
    def _save_data_to_pdf(self):
        """
        Speichert den aktuellen Kassenprotokoll-Status als PDF, markiert ihn im Verlauf
        und erstellt automatisch ein manuelles Backup der Rohdaten.
        """
        target_folder = self.ZIELORDNER_KASSENPROTOKOLL
        file_path = ""

        try:
            # SCHRITT 1: Alle Berechnungen vor dem Speichern erzwingen
            # Dies stellt sicher, dass die zu speichernden Daten aktuell sind.
            self._update_all_calculations(called_by_button=False)

            # Schritt 2: Verlaufs-Eintrag mit den frisch berechneten Daten erstellen
            self._save_current_state_to_history(save_type='manual')
            
            # Schritt 3: Zielordner sicherstellen
            try:
                os.makedirs(target_folder, exist_ok=True)
            except OSError as e_mkdir:
                SuccessToast(self.master, 
                             title="Fehler bei Ordnererstellung", 
                             message=f"Der Zielordner konnte nicht erstellt werden:\n{e_mkdir}", 
                             toast_type='error', 
                             colors=self.current_settings.get('toast_colors'))
                return

            # Schritt 4: Dateinamen generieren
            timestamp = datetime.datetime.now().strftime("%d.%m.%Y_%H%M%S")
            file_name = f"Kassenprotokoll_{timestamp}.pdf"
            file_path = os.path.join(target_folder, file_name)

            # Schritt 5: PDF-Objekt erstellen und mit Daten füllen
            pdf = FPDF()
            self._populate_pdf(pdf)

            # Schritt 6: PDF-Datei auf die Festplatte schreiben
            pdf.output(file_path)

            # Schritt 7: Das manuelle Backup AUTOMATISCH ohne Nachfrage erstellen
            # Der Parameter ask_confirmation=False sorgt dafür, dass keine Dialogbox erscheint.
            self._perform_manual_backup(ask_confirmation=False)

            # Schritt 8: Erfolgsmeldung anzeigen und Ordner öffnen
            self._show_save_success_and_open_folder(target_folder)

        except PermissionError:
            error_msg = (f"Zugriff auf die Datei verweigert:\n{file_path}\n\n"
                         "Ursachen:\n1. PDF ist bereits geöffnet.\n2. Keine Schreibrechte.")
            SuccessToast(self.master, 
                         title="Zugriffsfehler", 
                         message=error_msg, 
                         toast_type='error', 
                         colors=self.current_settings.get('toast_colors'), 
                         duration=6000)
        
        except Exception as e_general:
            SuccessToast(self.master, 
                         title="Unerwarteter Fehler", 
                         message=f"Ein Fehler ist beim Speichern aufgetreten:\n{e_general}", 
                         toast_type='error', 
                         colors=self.current_settings.get('toast_colors'), 
                         duration=6000)
            import traceback
            traceback.print_exc()

    
    def _show_save_success_and_open_folder(self, folder_path):
        """Zeigt die Erfolgsmeldung an und versucht dann, den Ordner zu öffnen."""
        try:
            # ALTE ZEILE (zum Löschen):
            # messagebox.showinfo("Erfolg", "✅ Der aktuellste Datensatz wurde erfolgreich gespeichert und ist im Verlauf gelb markiert.", parent=self.master)
            
            # NEUE ZEILE (zum Einfügen):
            SuccessToast(parent=self.master,
                         title="Erfolgreich gespeichert",
                         message="Der aktuellste Datensatz ist im Verlauf gelb markiert.",
                         toast_type='success',
                         colors=self.current_settings.get('toast_colors'))
            
            # Aktion 2: Ordner öffnen (bleibt unverändert)
            try:
                self._open_folder(folder_path)
            except Exception as e_open:
                messagebox.showwarning("Warnung", f"PDF wurde gespeichert, aber der Ordner konnte nicht geöffnet werden:\n{e_open}", parent=self.master)
        except Exception as e:
            print(f"Fehler in _show_save_success_and_open_folder: {e}")
    
    def _save_tagesabrechnung_to_pdf(self, file_path=None, show_success_message=True, open_folder_after=True):
        """
        Speichert die Tagesabrechnung als PDF, sichert den Verlauf und erstellt automatisch
        ein manuelles Backup der Daten.
        """
        # 1. Verlauf speichern
        self._save_tagesabrechnung_to_history()
        
        # 2. Datum aus UI lesen und validieren
        datum_str_from_ui = self.ta_datum_var.get()
        try:
            # Validiert das Format und erstellt ein Datumsobjekt
            vortag = datetime.datetime.strptime(datum_str_from_ui, "%d.%m.%Y")
        except ValueError:
            messagebox.showerror("Ungültiges Datum", "Bitte geben Sie in der Kopfzeile ein gültiges Datum im Format TT.MM.JJJJ ein.", parent=self.master)
            return None

        # 3. Zielpfad bestimmen
        target_file_path = file_path 

        if target_file_path is None:
            target_folder = self.ZIELORDNER_TAGESABRECHNUNG
            try:
                os.makedirs(target_folder, exist_ok=True)
            except OSError as e:
                if show_success_message:
                     messagebox.showerror("Fehler beim Speichern", f"Zielordner konnte nicht erstellt werden:\n{target_folder}\n\nFehler: {e}", parent=self.master)
                print(f"Error creating target folder {target_folder}: {e}")
                return None

            timestamp_str = vortag.strftime("%d.%m.%Y")
            file_name = f"Tagesabrechnung_{timestamp_str}.pdf"
            
            target_file_path = os.path.join(target_folder, file_name)
        else:
            target_folder = os.path.dirname(target_file_path)

        try:
            # 4. PDF Initialisierung
            pdf = FPDF(orientation='P', unit='mm', format='A4')
            
            font_dir = resource_path('fonts')
            dejavu_sans_path = os.path.join(font_dir, "DejaVuSans.ttf")
            dejavu_sans_bold_path = os.path.join(font_dir, "DejaVuSans-Bold.ttf")
            pdf_font_family_name = "Helvetica" 
            
            try:
                if os.path.exists(dejavu_sans_path) and os.path.exists(dejavu_sans_bold_path):
                    pdf.add_font("DejaVuSans", "", dejavu_sans_path)
                    pdf.add_font("DejaVuSans", "B", dejavu_sans_bold_path)
                    pdf_font_family_name = "DejaVuSans"
                else:
                    print(f"Warning: DejaVuSans font files not found in {font_dir}. Using default Helvetica.")
            except RuntimeError as e:
                print(f"PDF Font Add Error: {e}. Using default Helvetica.")
                pdf_font_family_name = "Helvetica" 
            except Exception as e:
                 print(f"Unexpected error adding PDF font: {e}. Using default Helvetica.")
                 pdf_font_family_name = "Helvetica"

            pdf.set_auto_page_break(True, margin=15)
            pdf.add_page()
            
            # Farben laden
            colors_pdf = {
                'header_bg': hex_to_rgb(self.current_settings.get('header_bg', '#D0D0D0')),
                'header_fg': hex_to_rgb(self.current_settings.get('general_font_color', '#000000')),
                'sum_bg': hex_to_rgb(self.current_settings.get('sum_bg', '#E0E0E0')),
                'sum_fg': hex_to_rgb(self.current_settings.get('number_elements_fg_color', '#000000')),
                'data_fg': hex_to_rgb(self.current_settings.get('general_font_color', '#000000')),
                'number_data_fg': hex_to_rgb(self.current_settings.get('number_elements_fg_color', '#000000')),
                'overall_header_bg': hex_to_rgb(self.current_settings.get('overall_header_bg', '#FF9933')),
                'overall_header_fg': hex_to_rgb(self.current_settings.get('overall_header_fg', '#000000')),
            }

            page_width = pdf.w - 2 * pdf.l_margin
            col_width_left = page_width * 0.48
            col_width_right = page_width * 0.48
            col_gap = page_width * 0.04

            # PDF Header
            pdf.set_font(pdf_font_family_name, 'B', 16)
            pdf.cell(0, 10, "Tagesabrechnung", border=0, new_x=XPos.LMARGIN, new_y=YPos.NEXT, align='C')
            pdf.set_font(pdf_font_family_name, '', 10)
            pdf.cell(0, 6, f"Datum: {vortag.strftime('%d.%m.%Y')}", border=0, new_x=XPos.LMARGIN, new_y=YPos.NEXT, align='C')
            pdf.ln(8)
            
            start_y = pdf.get_y()

            # Helper Funktion für Tabellen
            def draw_key_value_table(title, data, width, is_summary=False):
                pdf.set_font(pdf_font_family_name, 'B', 11)
                pdf.cell(width, 7, title, border='LTR', new_x=XPos.LMARGIN, new_y=YPos.NEXT, align='C')
                for key, value in data.items():
                    is_sum = "Summe" in key
                    font_style = 'B' if is_sum or is_summary else ''
                    pdf.set_font(pdf_font_family_name, font_style, 9)
                    key_width = width * 0.6
                    val_width = width * 0.4
                    display_value = str(value).replace('€', '').strip()
                    pdf.cell(key_width, 6, key, border='L')
                    pdf.cell(val_width, 6, display_value, border='R', new_x=XPos.LMARGIN, new_y=YPos.NEXT, align='R')
                pdf.cell(width, 0, '', border='T', new_x=XPos.LMARGIN, new_y=YPos.NEXT)
                pdf.ln(4)

            # --- Linke Spalte Inhalt ---
            pdf.set_y(start_y)
            
            # Einnahmen FO
            fo_data = {
                "FO Frühdienst:": self.ta_einnahmen_fo_frueh_var.get(), 
                "FO Spätdienst:": self.ta_einnahmen_fo_spaet_var.get(),
                "FO Nachtdienst:": self.ta_einnahmen_fo_nacht_var.get(), 
                "FO TIP:": self.ta_einnahmen_fo_tip_var.get(),
                "Summe:": self.ta_einnahmen_fo_summe_var.get()
            }
            draw_key_value_table("Einnahmen FO", fo_data, col_width_left)

            # Einnahmen Bar
            bar_data = {
                "Bock's/Bar:": self.ta_einnahmen_bar_haupt_var.get(), 
                "TIP Bock's/BAR:": self.ta_einnahmen_bar_tip_var.get(),
                "Summe:": self.ta_einnahmen_bar_summe_var.get()
            }
            draw_key_value_table("Einnahmen Bock's/Bar", bar_data, col_width_left)
            
            # Zusammenfassung
            summary_data = {
                "Einnamen FO:": self.ta_summary_einnahmen_fo_var.get(), 
                "Einnamen Bock's/BAR:": self.ta_summary_einnahmen_bar_var.get(),
                "Summe Einnahmen:": self.ta_summary_summe_einnahmen_var.get(), 
                "Summe Ausgaben:": self.ta_summary_summe_ausgaben_var.get(),
                "Summe Bareinnahmen:": self.ta_summary_summe_bareinnahmen_var.get()
            }
            draw_key_value_table("Tagesabrechnung", summary_data, col_width_left, is_summary=True)

            # --- Rechte Spalte Inhalt (Ausgaben) ---
            pdf.set_y(start_y)
            pdf.set_x(pdf.l_margin + col_width_left + col_gap)

            pdf.set_font(pdf_font_family_name, 'B', 11)
            pdf.cell(col_width_right, 7, "Ausgaben", border='LTR', new_x=XPos.LMARGIN, new_y=YPos.NEXT, align='C')
            
            ausgaben_header_widths = [col_width_right * 0.3, col_width_right * 0.5, col_width_right * 0.2]
            pdf.set_font(pdf_font_family_name, 'B', 9)
            pdf.set_x(pdf.l_margin + col_width_left + col_gap)
            pdf.cell(ausgaben_header_widths[0], 6, "Mitarbeiter", border=1, align='C')
            pdf.cell(ausgaben_header_widths[1], 6, "Wofür", border=1, align='C')
            pdf.cell(ausgaben_header_widths[2], 6, "Betrag", border=1, new_x=XPos.LMARGIN, new_y=YPos.NEXT, align='C')

            pdf.set_font(pdf_font_family_name, "", 8)
            for row_data in self.ta_ausgaben_rows:
                pdf.set_x(pdf.l_margin + col_width_left + col_gap)
                pdf.cell(ausgaben_header_widths[0], 5, row_data["mitarbeiter"].get(), border=1)
                pdf.cell(ausgaben_header_widths[1], 5, row_data["wofuer"].get(), border=1)
                pdf.cell(ausgaben_header_widths[2], 5, str(row_data["betrag"].get()).replace(' €', '').strip(), border=1, new_x=XPos.LMARGIN, new_y=YPos.NEXT, align='R')
            
            pdf.set_font(pdf_font_family_name, 'B', 9)
            pdf.set_x(pdf.l_margin + col_width_left + col_gap)
            pdf.cell(ausgaben_header_widths[0] + ausgaben_header_widths[1], 6, "Summe:", border=1, align='R')
            pdf.cell(ausgaben_header_widths[2], 6, str(self.ta_ausgaben_summe_var.get()).replace(' €', '').strip(), border=1, new_x=XPos.LMARGIN, new_y=YPos.NEXT, align='R')
            
            # 5. PDF Schreiben
            pdf.output(target_file_path)

            # 6. AUTOMATISCHES BACKUP DURCHFÜHREN (ohne Bestätigung)
            self._perform_manual_backup_tagesabrechnung(ask_confirmation=False)

            # 7. Erfolgsmeldung und Ordner öffnen
            if show_success_message:
                SuccessToast(self.master, 
                     title="Erfolgreich gespeichert", 
                     message="Tagesabrechnung als PDF gespeichert und eine Sicherung erstellt.", 
                     toast_type='success', 
                     colors=self.current_settings.get('toast_colors'))
            
            if open_folder_after:
                self._open_folder(target_folder)
            
            return target_file_path 
            
        except Exception as e:
            if show_success_message:
                 messagebox.showerror("PDF Export Fehler", f"Fehler beim Erstellen der Tagesabrechnungs-PDF: {e}", parent=self.master)
            print(f"PDF Export Error in _save_tagesabrechnung_to_pdf: {e}")
            import traceback
            traceback.print_exc()
            return None


        
    def _get_current_active_shift_name_internal(self):
        if not hasattr(self, 'notebook') or not self.notebook.tabs():
            return "Frühdienst" # Default fallback
        try:
            current_tab_idx = self.notebook.index(self.notebook.select())
            if current_tab_idx == 1:
                return "Spätdienst"
            else: # Frühdienst, Trinkgeldliste, Minibarliste, Tagesabrechnung etc. all keep "Frühdienst" context for dashboard
                return "Frühdienst"
        except tk.TclError:
            return "Frühdienst" # Fallback if tab selection fails

    def _on_notebook_tab_changed(self, event=None):
        try:
            # SCHRITT 1: Baut die Dashboard-UI für den neuen Tab neu auf (macht "Umsatz Spät" sichtbar/inaktiv).
            self._rebuild_dashboard()
            
            # SCHRITT 2: Führt alle Berechnungen aus und überträgt die Werte.
            self._update_all_calculations(called_by_button=False)
            
            # SCHRITT 3: Aktualisiert die Farbe des aktiven Tabs.
            self._update_notebook_style()
        except tk.TclError:
            # Fehler abfangen, falls das Widget während der Aktualisierung zerstört wird.
            pass
        except Exception as e:
            print(f"Fehler in _on_notebook_tab_changed: {e}")
        # +++ START: NEUE METHODE +++
    def _configure_checklist_button(self, button_widget, config_key, default_text):
        """Konfiguriert einen Button auf einer Checklisten-Seite basierend auf den Einstellungen."""
        try:
            checklist_configs = self.current_settings.get('checklist_button_configs', {})
            config = checklist_configs.get(config_key)
            
            if not config:
                button_widget.config(text=default_text, image="", compound='center')
                return

            if not config.get('is_active', True):
                button_widget.grid_remove()
                return
            
            btn_type = config.get('type', 'symbol')
            style_cfg = self.current_settings.get('list_views_button_style', {})
            icon_size = style_cfg.get('icon_size', 24)
            
            if not hasattr(self, 'checklist_button_images'):
                self.checklist_button_images = {}

            # Fall A: Button soll ein Bild haben
            if btn_type == 'image':
                image_path = config.get('value', '')
                
                if image_path and os.path.exists(image_path) and Image and ImageTk:
                    img = Image.open(image_path).resize((icon_size, icon_size), Image.Resampling.LANCZOS)
                    photo = ImageTk.PhotoImage(img)
                    
                    # Referenz auf dem Widget speichern, um Garbage Collection zu verhindern
                    button_widget.image = photo
                    self.checklist_button_images[config_key] = photo
                    
                    button_widget.config(image=photo, text="", compound='center')
                else:
                    # Fallback: Wenn Bild nicht gefunden wird, nur den Text/Symbol anzeigen
                    button_widget.config(text=default_text, image="", compound='center')

            # Fall B: Button soll nur Text/Symbol sein
            else:
                # Der 'value' aus der Konfiguration enthält den anzuzeigenden Text/Symbol
                symbol_text = config.get('value', default_text)
                button_widget.config(text=symbol_text, image="", compound='center')

        except Exception as e:
            print(f"Fehler in _configure_checklist_button für '{config_key}': {e}")
            button_widget.config(text=default_text, compound='center')
    

    def _configure_list_tab_button(self, button_widget, config_key, default_text, button_config_source=None, image_cache_dict=None):
        """Konfiguriert einen Button basierend auf den Einstellungen."""
        # Wenn keine spezifische Quelle übergeben wird, die Standardquelle verwenden
        if button_config_source is None:
            button_config_source = self.current_settings.get('list_tab_button_configs', {})

        config = button_config_source.get(config_key, {'type': 'symbol', 'value': default_text, 'is_active': True})

        if not config.get('is_active', True):
            try:
                button_widget.pack_forget()
            except tk.TclError:
                pass
            return
        
        style_cfg = self.current_settings.get('list_views_button_style', self.default_settings['list_views_button_style'])
        icon_size = style_cfg.get('icon_size', 24)
        
        btn_type = config.get('type', 'symbol')
        btn_value = config.get('value', default_text)

        # HIER IST DIE KORREKTUR:
        # Verwendet das übergebene image_cache_dict, falls vorhanden,
        # andernfalls wird auf den Standard-Cache der Haupt-App zurückgegriffen.
        image_dict = image_cache_dict if image_cache_dict is not None else self.list_tab_button_images

        if btn_type == 'image' and btn_value and os.path.exists(btn_value) and Image and ImageTk:
            try:
                img = Image.open(btn_value).resize((icon_size, icon_size), Image.Resampling.LANCZOS)
                photo = ImageTk.PhotoImage(img)
                image_dict[config_key] = photo
                button_widget.image = photo
                button_widget.config(image=photo, text="", compound='center')
            except Exception as e:
                print(f"Fehler beim Laden des Bildes für Button '{config_key}': {e}")
                button_widget.config(text=default_text, image="")
        else:
            button_widget.config(text=btn_value, image="", compound='center')
        
        ToolTip(button_widget, default_text)

