    def _handle_dashboard_input_change(self, kassenabschluss_key, dashboard_var):
        active_shift = self._get_current_active_shift_name_internal()
        if not active_shift: return

        current_input = dashboard_var.get()
        parsed_val = self._parse_input_string(current_input.replace("€", "").strip())
        formatted_value = self._format_decimal_for_display(parsed_val if parsed_val is not None else decimal.Decimal('0.00'))

        # Nur aktualisieren, wenn sich der formatierte Wert unterscheidet
        if dashboard_var.get() != formatted_value:
            dashboard_var.set(formatted_value)

        # Hervorhebung des Dashboard-Feldes aktualisieren
        entry_widget = self.dashboard_input_entry_widget_refs.get(kassenabschluss_key)
        if entry_widget:
            self._update_dashboard_input_field_highlight(entry_widget, dashboard_var)

        # vvvvv HIER BEGINNT DIE ENTSCHEIDENDE KORREKTUR vvvvv
        # Standardmäßig wird die aktive Schicht als Ziel für die Synchronisation verwendet
        target_shift_for_sync = active_shift

        # SONDERFALL: 'UMSATZ_FRUEH' gehört IMMER zu den Frühdienst-Daten.
        if kassenabschluss_key == 'UMSATZ_FRUEH':
            target_shift_for_sync = 'Frühdienst'
        # SONDERFALL: 'UMSATZ_SPAET' gehört IMMER zu den Spätdienst-Daten.
        elif kassenabschluss_key == 'UMSATZ_SPAET':
            target_shift_for_sync = 'Spätdienst'
        # Für alle anderen Felder (Quittung, Diverses etc.) ist das Ziel die aktive Schicht.

        # Synchronisiere mit der Variable der ZIEL-Schicht
        if target_shift_for_sync in self.kassenabschluss_wert_vars and kassenabschluss_key in self.kassenabschluss_wert_vars[target_shift_for_sync]:
            target_sv = self.kassenabschluss_wert_vars[target_shift_for_sync][kassenabschluss_key]
            if target_sv.get() != formatted_value:
                target_sv.set(formatted_value)
        # ^^^^^ HIER ENDET DIE KORREKTUR ^^^^^
        
        # Stößt die Neuberechnung aller abhängigen Felder an
        self._update_all_calculations(called_by_button=False)




    def _on_kassenabschluss_input_var_changed(self, shift_of_var_change, kassenabschluss_key, kassenabschluss_var_instance):
        if self.is_loading_data:
            return

        # Verhindert rekursive Aufrufe (Endlosschleife).
        if hasattr(self, '_is_syncing') and self._is_syncing:
            return

        try:
            self._is_syncing = True
            new_value = kassenabschluss_var_instance.get()
            
            # Synchronisation der Eingabe mit dem Dashboard (bleibt unverändert)
            active_shift_name_for_dashboard = self._get_current_active_shift_name_internal()
            if shift_of_var_change == active_shift_name_for_dashboard:
                if kassenabschluss_key in self.dashboard_direct_input_map:
                    dashboard_var = self.dashboard_direct_input_map[kassenabschluss_key]["var"]
                    if dashboard_var.get() != new_value:
                        dashboard_var.set(new_value)

            # Nach jeder Änderung die Berechnungen aktualisieren.
            self._update_all_calculations(called_by_button=False)

        finally:
            self._is_syncing = False
    
    def _create_dashboard_widgets(self, parent_frame):
        parent_frame.columnconfigure(0, weight=1)
        active_shift_for_dashboard = self._get_current_active_shift_name_internal()
        current_row_idx = 0

        if hasattr(self, 'dashboard_input_entry_widget_refs'):
            self.dashboard_input_entry_widget_refs.clear()
        else:
            self.dashboard_input_entry_widget_refs = {}

        current_icon_configs = self.current_settings.get('dashboard_icon_configs',
                                                        self.default_settings['dashboard_icon_configs'])

        schicht_info_frame = ttk.Frame(parent_frame, style='Dashboard.TFrame')
        schicht_info_frame.grid(row=current_row_idx, column=0, sticky='ew', pady=(1, 3))
        schicht_info_frame.columnconfigure(0, weight=0); schicht_info_frame.columnconfigure(1, weight=1)
        schicht_icon_config = current_icon_configs.get("schicht", {"type": "char", "value": "📅"})
        schicht_icon_label = ttk.Label(schicht_info_frame, style='Dashboard.Bold.TLabel', anchor='w')
        self.dashboard_schicht_icon_widget_ref = schicht_icon_label
        self._update_single_dashboard_icon_display("schicht", schicht_icon_label, schicht_icon_config, self.icon_colors.get("schicht", "black"))
        schicht_icon_label.grid(row=0, column=0, padx=(5, 1), pady=0, sticky='w')
        schicht_text_label = ttk.Label(schicht_info_frame, textvariable=self.dashboard_shift_text_var,
                                       style='Dashboard.SectionHeader.TLabel', anchor='w')
        schicht_text_label.grid(row=0, column=1, padx=(0, 5), pady=0, sticky='ew')
        current_row_idx += 1

        self.kassenabschluss_header_frame = ttk.Frame(parent_frame, style='Dashboard.TFrame')
        self.kassenabschluss_header_frame.grid(row=current_row_idx, column=0, sticky='ew', pady=(5, 0))
        self.kassenabschluss_header_frame.columnconfigure(0, weight=1)
        self.kassenabschluss_header_frame.columnconfigure(1, weight=0)
        kassenabschluss_title_label = ttk.Label(self.kassenabschluss_header_frame,
                                                text="Kassenabschluss",
                                                style='Dashboard.SectionHeader.TLabel',
                                                anchor='center')
        kassenabschluss_title_label.grid(row=0, column=0, sticky='ew')
        toggle_button_text = "▲" if self.kassenabschluss_expanded else "▼"
        self.kassenabschluss_toggle_button = ttk.Button(self.kassenabschluss_header_frame,
                                                         text=toggle_button_text,
                                                         command=lambda: self._toggle_kassenabschluss_section(target_state=None),
                                                         width=3, style='TButton')
        self.kassenabschluss_toggle_button.grid(row=0, column=1, sticky='e', padx=(2,5))
        current_row_idx += 1
        
        self.kassenabschluss_items_frame = ttk.Frame(parent_frame, style='Dashboard.TFrame')
        all_reco_defs = self.current_settings.get('kassenabschluss_zeilen_definitionen', [])
        dashboard_items_ordered = sorted([d for d in all_reco_defs if d.get('key') in self.all_dashboard_item_keys and d.get('aktiv', True)], key=lambda x: x.get('reihenfolge', 999))

        if self.kassenabschluss_expanded:
            self.kassenabschluss_items_frame.grid(row=current_row_idx, column=0, sticky='ew', pady=(0,2))
        
        self.kassenabschluss_items_frame.columnconfigure(0, weight=0)
        self.kassenabschluss_items_frame.columnconfigure(1, weight=0)
        self.kassenabschluss_items_frame.columnconfigure(2, weight=1)

        if hasattr(self, 'dashboard_data_item_icon_widget_refs'):
            self.dashboard_data_item_icon_widget_refs.clear()
        else:
            self.dashboard_data_item_icon_widget_refs = {}
            
        entry_font_size = self.current_settings.get('dashboard_input_field_font_size', 20)
        entry_font = tkFont.Font(size=entry_font_size)

        for i, reco_item_def in enumerate(dashboard_items_ordered):
            kassenabschluss_key = reco_item_def['key']
            
            
            
                        # vvvvvvvvvvvvvvvvvvvvvvvv HIER IST DIE ZWEITE ANPASSUNG vvvvvvvvvvvvvvvvvvvvvvvv
            # Überspringt die Erstellung der UI-Elemente für 'Umsatz Spät' und 'Umsatz Total',
            # wenn die Frühschicht-Ansicht aktiv ist.
            if active_shift_for_dashboard == "Frühdienst" and kassenabschluss_key in ('UMSATZ_SPAET', 'UMSATZ_TOTAL'):
                continue
            # ^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^

            
            
            
            if kassenabschluss_key not in self.dashboard_item_configs: continue

            item_config_from_map = self.dashboard_item_configs[kassenabschluss_key]
            label_text = reco_item_def.get('label', kassenabschluss_key)
            value_var = item_config_from_map["var"]
            icon_lookup_key = item_config_from_map["icon_key"]
            widget_type = item_config_from_map["widget_type"]
            item_icon_config_detail = current_icon_configs.get(icon_lookup_key, {"type": "char", "value": FALLBACK_DASHBOARD_ICON_CHAR})
            icon_color_to_use = self.icon_colors.get(icon_lookup_key, self.current_settings.get('dashboard_content_fg', self.default_settings['dashboard_content_fg']))

            icon_label_widget = ttk.Label(self.kassenabschluss_items_frame, style='Dashboard.Bold.TLabel', anchor='w')
            self.dashboard_data_item_icon_widget_refs[icon_lookup_key] = icon_label_widget
            
            self._update_single_dashboard_icon_display(icon_lookup_key, icon_label_widget, item_icon_config_detail, icon_color_to_use)

            icon_label_widget.grid(row=i, column=0, padx=(5, 0), pady=(1,0), sticky='w')

            text_label_widget = ttk.Label(self.kassenabschluss_items_frame, text=label_text, style='Dashboard.Bold.TLabel', anchor='w')
            text_label_widget.grid(row=i, column=1, padx=(2, 3), pady=(1,0), sticky='w')

            if widget_type == "input":
                entry_widget = ttk.Entry(self.kassenabschluss_items_frame,
                                         textvariable=value_var,
                                         style='Dashboard.Input.TEntry',
                                          width=self.current_settings.get('dashboard_input_field_width', self.default_settings['dashboard_input_field_width']),
                                         justify='right',
                                         font=entry_font)
                
                entry_widget.grid(row=i, column=2, padx=(3, 5), pady=(1,0), sticky='ew',
                                  ipady=self.current_settings.get('dashboard_input_field_ipady', self.default_settings['dashboard_input_field_ipady']))

                # vvvvvvvvvvvvvvvvvvvvvvvv HIER IST DIE KORREKTUR vvvvvvvvvvvvvvvvvvvvvvvv
                is_disabled = False
                if kassenabschluss_key == "UMSATZ_FRUEH" and active_shift_for_dashboard == "Spätdienst":
                    is_disabled = True
                if kassenabschluss_key == "UMSATZ_SPAET" and active_shift_for_dashboard == "Frühdienst":
                    is_disabled = True
                
                entry_widget.config(state='disabled' if is_disabled else 'normal')
                # ^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^
                
                self._add_widget_to_list(entry_widget, 'entry', is_main_input=True)
                
                self.dashboard_input_entry_widget_refs[kassenabschluss_key] = entry_widget
                self._update_dashboard_input_field_highlight(entry_widget, value_var)
                entry_widget.bind("<FocusOut>", lambda e, k_bind=kassenabschluss_key, v_bind=value_var: self._handle_dashboard_input_change(k_bind, v_bind))
                entry_widget.bind("<Return>", lambda e, k_bind=kassenabschluss_key, v_bind=value_var: self._handle_dashboard_input_change(k_bind, v_bind))
            elif widget_type == "display":
                value_wrapper_frame = tk.Frame(self.kassenabschluss_items_frame,
                                               relief='sunken', borderwidth=1,
                                               bg=self.current_settings.get('dashboard_content_bg', self.default_settings['dashboard_content_bg']))
                value_wrapper_frame.grid(row=i, column=2, padx=(3, 5), pady=(1,0), sticky='ew',
                                         ipady=self.current_settings.get('dashboard_input_field_ipady', self.default_settings['dashboard_input_field_ipady']))

                value_label_widget = tk.Label(value_wrapper_frame, textvariable=value_var, 
                                              anchor='e', font=self.ta_sum_font,
                                              bg=self.current_settings.get('dashboard_content_bg', self.default_settings['dashboard_content_bg']),
                                              fg=self.current_settings.get('dashboard_content_fg', self.default_settings['dashboard_content_fg']))
                value_label_widget.pack(fill='x', expand=True, padx=1, pady=1)

                if reco_item_def.get('style') == 'diff_display_auto':
                    value_label_widget._custom_type = 'dashboard_sum'
                    self._add_widget_to_list(value_label_widget, 'label', is_diff_label=True)

    def _toggle_kassenabschluss_section(self, target_state=None):
        if target_state is None:
            self.kassenabschluss_expanded = not self.kassenabschluss_expanded
        else:
            self.kassenabschluss_expanded = target_state
        
        items_frame_target_row = 2 # Row below the Kassenabschluss header
        
        if self.kassenabschluss_expanded:
            if self.kassenabschluss_items_frame and self.kassenabschluss_items_frame.winfo_exists():
                 self.kassenabschluss_items_frame.grid(row=items_frame_target_row, column=0, sticky='ew', pady=(0,2))
            if self.kassenabschluss_toggle_button and self.kassenabschluss_toggle_button.winfo_exists():
                self.kassenabschluss_toggle_button.config(text="▲")
        else:
            if self.kassenabschluss_items_frame and self.kassenabschluss_items_frame.winfo_exists():
                self.kassenabschluss_items_frame.grid_remove()
            if self.kassenabschluss_toggle_button and self.kassenabschluss_toggle_button.winfo_exists():
                self.kassenabschluss_toggle_button.config(text="▼")

        # Ensure the parent (dashboard_frame) resizes correctly if needed
        if self.dashboard_frame and self.dashboard_frame.winfo_exists():
            self.dashboard_frame.update_idletasks()


    def _update_single_dashboard_icon_display(self, item_key, icon_widget, icon_config, text_icon_color="black"):
        if not icon_widget.winfo_exists(): return
        icon_type = icon_config.get("type", "char"); icon_value = icon_config.get("value", FALLBACK_DASHBOARD_ICON_CHAR)
        
        # Determine effective color for character icons, preferring dashboard_content_fg
        effective_char_icon_color = text_icon_color
        if text_icon_color == "black" or text_icon_color == self.default_settings['general_font_color']: # if it's default or generic black
             effective_char_icon_color = self.current_settings.get('dashboard_content_fg', self.default_settings['dashboard_content_fg'])

        if icon_type == "image" and icon_value and Image and ImageTk:
            try:
                if os.path.exists(icon_value):
                    img = Image.open(icon_value); img_resized = img.resize((DASHBOARD_ICON_WIDTH, DASHBOARD_ICON_HEIGHT), Image.Resampling.LANCZOS)
                    photo = ImageTk.PhotoImage(img_resized); self.dashboard_icon_photo_images[item_key] = photo # Cache PhotoImage
                    icon_widget.config(image=photo, text="")
                else:
                    self.dashboard_icon_photo_images.pop(item_key, None) # Remove if path invalid
                    icon_widget.config(image="", text=FALLBACK_DASHBOARD_ICON_CHAR, foreground=effective_char_icon_color) # Fallback
            except Exception as e:
                # print(f"Error loading/processing image for dashboard icon '{item_key}': {e}")
                self.dashboard_icon_photo_images.pop(item_key, None)
                icon_widget.config(image="", text=FALLBACK_DASHBOARD_ICON_CHAR, foreground=effective_char_icon_color) # Fallback
        else: # Char type or image loading failed/not available
            self.dashboard_icon_photo_images.pop(item_key, None) # Clear any previous image
            icon_widget.config(image="", text=str(icon_value) if icon_value else FALLBACK_DASHBOARD_ICON_CHAR, foreground=effective_char_icon_color)


    def _rebuild_dashboard(self):
        # Destroys and recreates all widgets within the self.dashboard_frame
        for widget in self.dashboard_frame.winfo_children(): widget.destroy()
        self._create_dashboard_widgets(self.dashboard_frame) # This calls _update_dashboard_display indirectly via _create_dashboard_widgets
        self._update_dashboard_display() # Explicit call to ensure vars are set


    def _update_dashboard_display(self):
        if not hasattr(self, 'notebook') or not self.notebook.tabs() or \
           not hasattr(self, 'dashboard_shift_text_var'): return

        try:
            current_active_shift_for_dashboard = self._get_current_active_shift_name_internal()
            current_shift_display_name = current_active_shift_for_dashboard if current_active_shift_for_dashboard else "Unbekannt"
            self.dashboard_shift_text_var.set(f"Aktuelle Schicht: {current_shift_display_name}")

            shift_reco_vars = None
            if current_active_shift_for_dashboard and hasattr(self, 'kassenabschluss_wert_vars') and \
               current_active_shift_for_dashboard in self.kassenabschluss_wert_vars and \
               isinstance(self.kassenabschluss_wert_vars[current_active_shift_for_dashboard], dict):
                shift_reco_vars = self.kassenabschluss_wert_vars[current_active_shift_for_dashboard]

            for k_key, config in self.dashboard_item_configs.items():
                dashboard_var = config["var"]; value_to_set = "0,00 €" # Default
                
                if shift_reco_vars: # If we have Kassenabschluss vars for the current dashboard context shift
                    kassenabschluss_sv = shift_reco_vars.get(k_key)
                    if isinstance(kassenabschluss_sv, tk.StringVar):
                        value_to_set = kassenabschluss_sv.get()
                        # Special handling for 'ENTNAHME' and 'TIP' if asteval is not available
                        if k_key in ["ENTNAHME", "TIP"] and (not value_to_set or value_to_set.strip().upper() == "N/A" or value_to_set.strip().upper() == "ASTEVAL N.V."):
                            value_to_set = "0,00 €" # Show 0,00 € instead of error message
                    elif k_key == "SOLL": # SOLL is special, directly from settings
                        value_to_set = self._format_decimal_for_display(decimal.Decimal(str(self.current_settings.get('starting_float_value', 800.0))))
                    elif k_key == "MINIBAR_UMSATZ_TOTAL": # MINIBAR_UMSATZ_TOTAL is special
                        value_to_set = self._format_decimal_for_display(self.current_minibar_umsatz_monat)

                elif k_key == "SOLL": # Fallback for SOLL if shift_reco_vars is not available
                     value_to_set = self._format_decimal_for_display(decimal.Decimal(str(self.current_settings.get('starting_float_value', 800.0))))
                elif k_key == "MINIBAR_UMSATZ_TOTAL": # Fallback for MINIBAR_UMSATZ_TOTAL
                     value_to_set = self._format_decimal_for_display(self.current_minibar_umsatz_monat)


                if dashboard_var.get() != value_to_set: dashboard_var.set(value_to_set)

                # Update highlight for input fields
                if config["widget_type"] == "input" and hasattr(self, 'dashboard_input_entry_widget_refs'):
                    entry_widget = self.dashboard_input_entry_widget_refs.get(k_key)
                    if entry_widget: self._update_dashboard_input_field_highlight(entry_widget, dashboard_var)
        except tk.TclError: # Can happen if widgets/vars are being destroyed/recreated
            if hasattr(self, 'dashboard_shift_text_var'): self.dashboard_shift_text_var.set("Aktuelle Schicht: N/A")
            for config_item in self.dashboard_item_configs.values():
                 if config_item["var"].get() != "0,00 €": config_item["var"].set("0,00 €")
        except Exception as e:
            if hasattr(self, 'dashboard_shift_text_var'): self.dashboard_shift_text_var.set("Aktuelle Schicht: Fehler")
            for config_item in self.dashboard_item_configs.values():
                 if config_item["var"].get() != "0,00 €": config_item["var"].set("0,00 €")
            print(f"Error updating dashboard display: {e}")

    def _handle_custom_button_click(self, button_config):
        label = button_config.get('label', 'Benutzerdefinierter Button')
        command_text = button_config.get('command_placeholder', 'Keine Aktion für diesen Button definiert.')
        messagebox.showinfo(f"Aktion: {label}", command_text, parent=self.master)
    def _update_admin_editable_state(self):
        """Aktualisiert den Zustand (aktiviert/deaktiviert) aller admin-editierbaren Widgets."""
        state = 'normal' if self.is_admin_mode else 'disabled'
        
        if hasattr(self, 'admin_editable_entries'):
            for widget in self.admin_editable_entries:
                if widget and widget.winfo_exists():
                    try:
                        if widget.cget('state') != state:
                            widget.config(state=state)
                    except tk.TclError:
                        # Ignoriert Fehler, falls das Widget während eines Updates zerstört wird
                        pass

    def _clear_all_fields(self):
        if not messagebox.askyesno("Leeren", "Alle Eingaben (außer Admin-setzbare Preise und Briefmarkenbestände) leeren?"): return
        
        # KORRIGIERTER AUFRUF OHNE 'if'
        SuccessToast(self.master,
            title="Erfolgreich gelöscht",
            message="Alle Eingaben (außer Admin-setzbare Preise und Briefmarkenbestände) wurden gelöscht.",
            toast_type='success',
            colors=self.current_settings.get('toast_colors'))
        
        
        default_qty_str_on_clear = str(self.current_settings.get('quantity_combobox_default_value', 0))
        num_reception_fields = self.current_settings.get('reception_fields_count', 3)
        zero_euro_display = self._format_decimal_for_display(decimal.Decimal('0.00'))

        for vars_dict_idx, vars_dict_tuple in enumerate([(self.fruehdienst_vars, "Frühdienst"), (self.spaetdienst_vars, "Spätdienst")]):
            vars_dict, shift_name_for_clear = vars_dict_tuple
            other_vars_dict = self.spaetdienst_vars if shift_name_for_clear == "Frühdienst" else self.fruehdienst_vars
            
            # Clear cash counts/amounts
            for denom in list(vars_dict.get('cash_denominations', [])):
                 if denom >= 5.0: # Denominations where count is entered
                    if denom in vars_dict.get('cash_counts', {}):
                        vars_dict['cash_counts'][denom].set(default_qty_str_on_clear)
                 else: # Denominations where amount is entered directly
                    if denom in vars_dict.get('cash_amounts_display', {}):
                        vars_dict['cash_amounts_display'][denom].set(zero_euro_display)
                        # Reset highlight for amount labels if they exist
                        amount_label_widget = vars_dict.get('cash_amount_label_widgets', {}).get(denom)
                    if amount_label_widget and amount_label_widget.winfo_exists() and amount_label_widget.cget('style') != 'NumberDisplay.TLabel':
                       amount_label_widget.config(style='NumberDisplay.TLabel')

            # Clear stamp counts (prices are admin-editable, not cleared here)
            # Reset highlight for stamp qty/price/amount widgets
            for price_key in vars_dict.get('stamp_qty_widgets', {}).keys():
                qty_widget = vars_dict['stamp_qty_widgets'].get(price_key)
                if qty_widget and qty_widget.winfo_exists():
                    base_style = 'NumberInput.TCombobox' if isinstance(qty_widget, ttk.Combobox) else 'NumberInput.TEntry'
                    if qty_widget.cget('style') != base_style:
                        qty_widget.config(style=base_style)
                        self._sync_stamp_field_highlight(price_key, 'qty', base_style, other_vars_dict)
            
            for price_key in vars_dict.get('stamp_price_entry_widgets', {}).keys():
                price_entry_widget = vars_dict['stamp_price_entry_widgets'].get(price_key)
                if price_entry_widget and price_entry_widget.winfo_exists() and price_entry_widget.cget('style') != 'NumberInput.TEntry':
                    price_entry_widget.config(style='NumberInput.TEntry') # Assuming not highlighted if admin doesn't touch

            for price_key in vars_dict.get('stamp_amount_label_widgets', {}).keys():
                amount_label_widget = vars_dict['stamp_amount_label_widgets'].get(price_key)
                if amount_label_widget and amount_label_widget.winfo_exists() and amount_label_widget.cget('style') != 'NumberDisplay.TLabel':
                    amount_label_widget.config(style='NumberDisplay.TLabel')
            
            # Clear card data
            for card_key in vars_dict.get('card_type_keys', []):
                if card_key in vars_dict.get('card_data', {}):
                    cd = vars_dict['card_data'][card_key]
                    for i in range(1, num_reception_fields + 1):
                        field_name = f'reception{i}'
                        if field_name in cd and isinstance(cd[field_name], tk.StringVar):
                            cd[field_name].set(zero_euro_display)
                    
                    if shift_name_for_clear == "Frühdienst":
                        if 'manual_total_input' in cd and isinstance(cd['manual_total_input'], tk.StringVar):
                            cd['manual_total_input'].set(zero_euro_display)
                            # Also clear the corresponding fruehdienst_sum_input in Spätdienst
                            if hasattr(self, 'spaetdienst_vars') and \
                               self.spaetdienst_vars and \
                               card_key in self.spaetdienst_vars.get('card_data', {}) and \
                               'fruehdienst_sum_input' in self.spaetdienst_vars['card_data'][card_key] and \
                               isinstance(self.spaetdienst_vars['card_data'][card_key]['fruehdienst_sum_input'], tk.StringVar):
                                self.spaetdienst_vars['card_data'][card_key]['fruehdienst_sum_input'].set(zero_euro_display)
                                
                    elif shift_name_for_clear == "Spätdienst":
                        if 'spaetdienst_sum_input' in cd and isinstance(cd['spaetdienst_sum_input'], tk.StringVar):
                            cd['spaetdienst_sum_input'].set(zero_euro_display)
                            # fruehdienst_sum_input in Spätdienst is not user-editable, cleared if Frühdienst manual_total is cleared

            # Clear Kassenabschluss EINGABE fields to their initial values from settings
            active_reco_defs = self.current_settings.get('kassenabschluss_zeilen_definitionen', [])
            for item_def in active_reco_defs:
                if item_def.get('aktiv') and item_def.get('typ') in ['EINGABE', 'EINGABE_KERN']:
                    key = item_def['key']
                    initial_val = decimal.Decimal(str(item_def.get('initialwert_eingabe', 0.0)))
                    if shift_name_for_clear in self.kassenabschluss_wert_vars and \
                       key in self.kassenabschluss_wert_vars[shift_name_for_clear]:
                          self.kassenabschluss_wert_vars[shift_name_for_clear][key].set(self._format_decimal_for_display(initial_val))

            # Clear notes
            if vars_dict.get('notes_text_widget') and vars_dict['notes_text_widget'].winfo_exists():
                vars_dict['notes_text_widget'].delete("1.0", tk.END)
            vars_dict['notes_initial_content'] = "" # Clear initial content cache too

        # Reset highlights for all relevant entry fields (non-dashboard)
        for entry_widget in self.all_entries:
            if entry_widget.winfo_exists():
                parent_name = str(entry_widget.winfo_parent()) # Get parent widget path as string
                # Skip if it's a dashboard entry (handled separately or not at all by _clear_all_fields)
                if parent_name.startswith(str(self.dashboard_frame)): 
                    # Special handling for dashboard fields if they were to be cleared to a default
                    if hasattr(self, 'dashboard_input_entry_widget_refs'):
                        for key, dash_entry in self.dashboard_input_entry_widget_refs.items():
                            if dash_entry == entry_widget:
                                dash_var = self.dashboard_item_configs[key]['var']
                                self._update_dashboard_input_field_highlight(dash_entry, dash_var)
                                break
                    continue 

                var_name = ""
                try: var_name = entry_widget.cget("textvariable")
                except tk.TclError: continue # If widget or var is gone
                
                if isinstance(var_name, str) and var_name: # If it has a textvariable string
                    try:
                        string_var = entry_widget.tk.globalgetvar(var_name) # Get the actual tk.StringVar
                        is_count = False
                        # Determine if it's a count field (cash or stamp quantity)
                        if isinstance(entry_widget, ttk.Combobox):
                             # Heuristic: check if parent name contains denomination or stamp price string
                             is_cash_qty_combo = any(str(denom_val) in parent_name for denom_val in self.fruehdienst_vars.get('cash_denominations',[])) if self.fruehdienst_vars else False
                             is_stamp_qty_combo = any(str(s_def['price']) in parent_name for s_def in self.fruehdienst_vars.get('stamp_definitions',[])) if self.fruehdienst_vars else False
                             if is_cash_qty_combo or is_stamp_qty_combo : is_count = True
                        elif isinstance(entry_widget, ttk.Entry) and hasattr(entry_widget, '_is_stamp_price_entry'):
                            # Stamp price entries are not count fields, handled by admin state
                            pass
                        elif hasattr(entry_widget, '_reco_key_ref'): # Kassenabschluss entries
                            pass # Highlighting based on initial value
                        
                        self._update_input_field_highlight(entry_widget, string_var, is_count_field=is_count)
                    except tk.TclError: pass # Variable might not exist
                    except AttributeError: pass # If string_var is not a tk.StringVar

        self._update_all_calculations(called_by_button=False) # Recalculate everything

    def _clear_fruehdienst_data(self):
        """
        Löscht die angegebenen Frühdienst-Daten: Umsatz, Bargeld, Karten, Quittungen und Diverses.
        """
        if not messagebox.askyesno(
            "Frühdienst löschen",
            "Wollen Sie wirklich alle Frühdienst-Daten (Umsatz, Bar, Karten, Quittungen, Diverses) löschen?\n\nACHTUNG: Briefmarken werden NICHT gelöscht!",
            parent=self.master
        ):
            return

        # Hilfswerte
        zero_euro_display = self._format_decimal_for_display(decimal.Decimal('0.00'))
        default_qty_str = str(self.current_settings.get('quantity_combobox_default_value', 0))

        # 1. Kassenabschluss-Felder für Frühdienst zurücksetzen
        if 'Frühdienst' in self.kassenabschluss_wert_vars:
            k_vars = self.kassenabschluss_wert_vars['Frühdienst']
            # Setzt Umsatz, alle Quittungen und Diverses auf 0,00 €
            for key in ['UMSATZ_FRUEH', 'QUITTUNG_1', 'QUITTUNG_2', 'QUITTUNG_3', 'DIVERSES']:
                if key in k_vars:
                    k_vars[key].set(zero_euro_display)

        # 2. Barzählung (Bargeld) zurücksetzen
        vars_dict = self.fruehdienst_vars
        for denom in vars_dict.get('cash_denominations', []):
            if denom >= 5.0:  # Anzahl wird eingegeben
                if denom in vars_dict.get('cash_counts', {}):
                    vars_dict['cash_counts'][denom].set(default_qty_str)
            else:  # Betrag wird eingegeben
                if denom in vars_dict.get('cash_amounts_display', {}):
                    vars_dict['cash_amounts_display'][denom].set(zero_euro_display)
        
        # 3. Kartenzahlungen zurücksetzen
        num_reception_fields = self.current_settings.get('reception_fields_count', 3)
        for card_key in vars_dict.get('card_type_keys', []):
            if card_key in vars_dict.get('card_data', {}):
                cd = vars_dict['card_data'][card_key]
                if 'manual_total_input' in cd and isinstance(cd.get('manual_total_input'), tk.StringVar):
                    cd['manual_total_input'].set(zero_euro_display)
                for i in range(1, num_reception_fields + 1):
                    field_name = f'reception{i}'
                    if field_name in cd and isinstance(cd.get(field_name), tk.StringVar):
                        cd[field_name].set(zero_euro_display)

        # 4. Alle Berechnungen und die UI aktualisieren
        self._update_all_calculations(called_by_button=False)
        self._perform_manual_backup(ask_confirmation=False)
        
        SuccessToast(self.master,
            title="Erfolgreich gelöscht & Gesichert",
            message="Frühdienst-Daten wurden gelöscht und die Sicherung wurde aktualisiert.",
            toast_type='success',
            colors=self.current_settings.get('toast_colors'))
        

    def _clear_spaetdienst_data(self):
        """Löscht die angegebenen Spätdienst-Daten: Umsatz, Bargeld, Karten, Quittungen und Diverses."""
        if not messagebox.askyesno(
            "Spätdienst löschen",
            "Wollen Sie wirklich alle Spätdienst-spezifischen Daten (Umsatz, Barzählung, Kartenzahlungen, Quittungen, Diverses) löschen?\n\nACHTUNG: Briefmarken und vom Frühdienst übertragene Summen bleiben erhalten!",
            parent=self.master
        ):
            return

        zero_euro_display = self._format_decimal_for_display(decimal.Decimal('0.00'))
        default_qty_str = str(self.current_settings.get('quantity_combobox_default_value', 0))
        vars_dict = self.spaetdienst_vars

        # 1. Kassenabschluss-Felder für Spätdienst zurücksetzen
        if 'Spätdienst' in self.kassenabschluss_wert_vars:
            k_vars = self.kassenabschluss_wert_vars['Spätdienst']
            keys_to_clear = ['UMSATZ_SPAET', 'QUITTUNG_1', 'QUITTUNG_2', 'QUITTUNG_3', 'DIVERSES']
            for key in keys_to_clear:
                if key in k_vars:
                    k_vars[key].set(zero_euro_display)

        # 2. Barzählung (Bargeld) zurücksetzen
        for denom in vars_dict.get('cash_denominations', []):
            if denom >= 5.0:
                if denom in vars_dict.get('cash_counts', {}):
                    vars_dict['cash_counts'][denom].set(default_qty_str)
            else:
                if denom in vars_dict.get('cash_amounts_display', {}):
                    vars_dict['cash_amounts_display'][denom].set(zero_euro_display)

        # 3. Kartenzahlungen zurücksetzen (NUR Spätdienst-spezifische Felder)
        num_reception_fields = self.current_settings.get('reception_fields_count', 3)
        for card_key in vars_dict.get('card_type_keys', []):
            if card_key in vars_dict.get('card_data', {}):
                cd = vars_dict['card_data'][card_key]
                
                # Das Eingabefeld für die Summe des Spätdienstes leeren
                if 'spaetdienst_sum_input' in cd and isinstance(cd.get('spaetdienst_sum_input'), tk.StringVar):
                    cd['spaetdienst_sum_input'].set(zero_euro_display)
                
                # Alle Rezeptions-Eingabefelder für diesen Kartentyp leeren
                for i in range(1, num_reception_fields + 1):
                    field_name = f'reception{i}'
                    if field_name in cd and isinstance(cd.get(field_name), tk.StringVar):
                        cd[field_name].set(zero_euro_display)
                        
        # 4. Alle Berechnungen und die UI aktualisieren
        self._update_all_calculations(called_by_button=False)
        self._perform_manual_backup(ask_confirmation=False)
        SuccessToast(self.master,
            title="Erfolgreich gelöscht & Gesichert",
            message="Spätdienst-spezifische Daten wurden gelöscht und die Sicherung wurde aktualisiert.",
            toast_type='success',
            colors=self.current_settings.get('toast_colors'))
    
    

    
    
    
    
    def _update_time(self):
        """
        Aktualisiert NUR die Zeit- und Datumsanzeige und prüft auf Alarme.
        Aufwändige Hintergrundaufgaben wurden in einen separaten Timer ausgelagert.
        """
        if self.is_shutting_down:
            return

        try:
            now = datetime.datetime.now()
            
            # 1. Datum nur bei Tageswechsel aktualisieren
            current_date_str_iso = now.strftime("%Y-%m-%d")
            if current_date_str_iso != self._last_updated_date_for_header:
                self._update_date_display(now)
                self._last_updated_date_for_header = current_date_str_iso
                self.triggered_alarm_ids_today.clear()

            # 2. Uhrzeit immer aktualisieren
            time_str = now.strftime("%H:%M:%S")
            self.time_display_var.set(time_str)
            
            # 3. Canvas-Header im Dashboard aktualisieren
            if self.current_page_name == "Dashboard" and self.dashboard_header_canvas:
                if self.dashboard_date_text_id:
                    self.dashboard_header_canvas.itemconfig(self.dashboard_date_text_id, text=self.date_display_var.get())
                if self.dashboard_time_text_id:
                    self.dashboard_header_canvas.itemconfig(self.dashboard_time_text_id, text=time_str)

            # 4. Nur noch die zeitkritische Alarmprüfung hier ausführen
            self._check_for_alarms(now)

            # 5. Nächsten Aufruf planen
            self.time_after_id = self.master.after(1000, self._update_time)

        except (tk.TclError, RuntimeError):
            if self.time_after_id:
                try: self.master.after_cancel(self.time_after_id)
                except (tk.TclError, RuntimeError): pass
                self.time_after_id = None
            return
        except Exception as e:
            print(f"!!! FEHLER IN DER HAUPT-UPDATE-SCHLEIFE (_update_time): {e} !!!")
            import traceback
            traceback.print_exc()
            if not self.is_shutting_down:
                try: self.time_after_id = self.master.after(1000, self._update_time)
                except (tk.TclError, RuntimeError): pass
                
    def _periodic_background_tasks(self):
        """
        Führt weniger zeitkritische Hintergrundaufgaben (Benachrichtigungen, Aufräumen)
        in einem langsameren Intervall aus. Robust gegen Fenster-Zerstörung.
        """
        # 1. Abbruch, wenn Shutdown läuft
        if self.is_shutting_down:
            return

        # 2. Prüfen, ob das Hauptfenster noch existiert
        try:
            if not self.master.winfo_exists():
                return
        except (tk.TclError, AttributeError):
            return

        # 3. Aufgaben ausführen
        try:
            # print(f"[{datetime.datetime.now().strftime('%H:%M:%S')}] Führe periodische Hintergrundaufgaben aus...")
            self._update_notifications()
            self._cleanup_old_list_entries()
        except Exception as e:
            print(f"Fehler in _periodic_background_tasks (wird ignoriert): {e}")

        # 4. Nächsten Lauf planen (nur wenn Fenster noch da ist)
        if not self.is_shutting_down:
            try:
                self.background_task_id = self.master.after(60000, self._periodic_background_tasks)
            except (tk.TclError, RuntimeError):
                self.background_task_id = None

    def _update_time(self):
        """
        Aktualisiert NUR die Zeit- und Datumsanzeige und prüft auf Alarme.
        Robust gegen Fenster-Zerstörung.
        """
        # 1. Abbruch, wenn Shutdown läuft
        if self.is_shutting_down:
            return

        # 2. Prüfen, ob das Hauptfenster noch existiert
        try:
            if not self.master.winfo_exists():
                return
        except (tk.TclError, AttributeError):
            return

        try:
            now = datetime.datetime.now()
            
            # Datum nur bei Tageswechsel aktualisieren
            current_date_str_iso = now.strftime("%Y-%m-%d")
            if current_date_str_iso != self._last_updated_date_for_header:
                self._update_date_display(now)
                self._last_updated_date_for_header = current_date_str_iso
                self.triggered_alarm_ids_today.clear()

            # Uhrzeit aktualisieren
            time_str = now.strftime("%H:%M:%S")
            self.time_display_var.set(time_str)
            
            # Canvas-Header im Dashboard aktualisieren
            if self.current_page_name == "Dashboard" and self.dashboard_header_canvas:
                try:
                    if self.dashboard_date_text_id:
                        self.dashboard_header_canvas.itemconfig(self.dashboard_date_text_id, text=self.date_display_var.get())
                    if self.dashboard_time_text_id:
                        self.dashboard_header_canvas.itemconfig(self.dashboard_time_text_id, text=time_str)
                except tk.TclError:
                    pass # Ignorieren, falls Canvas gerade neu gezeichnet wird

            # Alarmprüfung
            self._check_for_alarms(now)

            # 3. Nächsten Lauf planen
            self.time_after_id = self.master.after(1000, self._update_time)

        except (tk.TclError, RuntimeError):
            # Falls während der Ausführung das Fenster zerstört wurde
            if self.time_after_id:
                try: self.master.after_cancel(self.time_after_id)
                except (tk.TclError, RuntimeError): pass
                self.time_after_id = None
            return
        except Exception as e:
            print(f"Fehler in _update_time: {e}")
            if not self.is_shutting_down:
                try: self.time_after_id = self.master.after(1000, self._update_time)
                except (tk.TclError, RuntimeError): pass            
    
        
    def _cleanup_old_list_entries(self):
        """
        Entfernt veraltete Einträge aus Weckruf-, Taxi- und Shuttle-Listen.
        Behält Einträge für mindestens 3 Tage (inklusive des aktuellen Tages) bei.
        """
        now = datetime.datetime.now()
        cleanup_occurred = False
        
        # Das Datum, vor dem alle Einträge gelöscht werden sollen (heute - 3 Tage)
        three_days_ago = (now - datetime.timedelta(days=3)).date()

        
        # --- Weckrufe bereinigen ---
        initial_weckruf_count = len(self.weckruf_data_cache)
        weckrufe_to_keep = []
        for weckruf in self.weckruf_data_cache:
            try:
                # Das Datum des Eintrags aus dem ISO-Format (%Y-%m-%d) lesen
                entry_date = datetime.datetime.strptime(weckruf.get('datum'), "%Y-%m-%d").date()
                if entry_date >= three_days_ago:
                    weckrufe_to_keep.append(weckruf)
            except (ValueError, KeyError, TypeError):
                weckrufe_to_keep.append(weckruf) # Behalte Einträge mit Formatfehlern
        
        if len(weckrufe_to_keep) < initial_weckruf_count:
            self.weckruf_data_cache = weckrufe_to_keep
            cleanup_occurred = True

        # --- Taxibestellungen bereinigen ---
        initial_taxi_count = len(self.taxi_data_cache)
        taxis_to_keep = []
        for taxi in self.taxi_data_cache:
            try:
                # Das Datum des Eintrags aus dem ISO-Format (%Y-%m-%d) lesen
                entry_date = datetime.datetime.strptime(taxi.get('datum'), "%Y-%m-%d").date()
                if entry_date >= three_days_ago:
                    taxis_to_keep.append(taxi)
            except (ValueError, KeyError, TypeError):
                taxis_to_keep.append(taxi) # Behalte Einträge mit Formatfehlern

        if len(taxis_to_keep) < initial_taxi_count:
            self.taxi_data_cache = taxis_to_keep
            cleanup_occurred = True

        # --- Shuttle-Buchungen bereinigen ---
        initial_shuttle_count = len(self.shuttle_data_cache)
        shuttles_to_keep = []
        for shuttle in self.shuttle_data_cache:
            try:
                # Das Datum des Eintrags aus dem deutschen Format (%d.%m.%Y) lesen
                entry_date = datetime.datetime.strptime(shuttle.get('datum'), "%d.%m.%Y").date()
                if entry_date >= three_days_ago:
                    shuttles_to_keep.append(shuttle)
            except (ValueError, KeyError, TypeError):
                shuttles_to_keep.append(shuttle) # Behalte Einträge mit Formatfehlern
        
        if len(shuttles_to_keep) < initial_shuttle_count:
            self.shuttle_data_cache = shuttles_to_keep
            cleanup_occurred = True

        # Wenn etwas bereinigt wurde, speichere die Daten und aktualisiere die relevanten Ansichten
        if cleanup_occurred:
            print(f"[{now.strftime('%H:%M:%S')}] Alte Listen-Einträge bereinigt.")
            self._save_weckruf_data()
            self._save_taxi_data()
            self._save_shuttle_data()
            
            # Aktualisiere die UI, falls die entsprechende Seite gerade angezeigt wird
            if self.current_page_name == "Weckrufliste":
                self._load_and_display_weckrufe()
            elif self.current_page_name == "Taxibestellung":
                self._load_and_display_taxi_orders()
            elif self.current_page_name == "Shuttle Hinfahrt":
                self._load_and_display_shuttle_data('Hinfahrt')
            elif self.current_page_name == "Shuttle Rückfahrt":
                self._load_and_display_shuttle_data('Rückfahrt')
            
            self._update_notifications()
        
        
    def _update_notifications(self):
        """Prüft auf offene Einträge und aktualisiert die visuelle Darstellung der Aufgaben-Kacheln."""
        try:
            if not hasattr(self, 'notification_widgets') or not self.notification_widgets or \
               not hasattr(self, 'task_notification_frame') or not self.task_notification_frame or \
               not self.task_notification_frame.winfo_exists():
                return
        except (tk.TclError, RuntimeError):
            return

        now = datetime.datetime.now()
        
        def get_task_status(entries, date_key, time_key):
            now_local = datetime.datetime.now() 
            one_minute_grace = datetime.timedelta(minutes=1)
            cleanup_margin = datetime.timedelta(minutes=30) 

            count = 0
            is_urgent = False
            urgent_count = 0
            future_entries = []

            for entry in entries:
                try:
                    entry_dt = None
                    if date_key:
                        dt_str = f"{entry.get(date_key)} {entry.get(time_key)}"
                        try:
                            entry_dt = datetime.datetime.strptime(dt_str, "%Y-%m-%d %H:%M")
                        except ValueError:
                            entry_dt = datetime.datetime.strptime(dt_str, "%d.%m.%Y %H:%M")
                    else: 
                        time_obj = datetime.datetime.strptime(entry.get(time_key), "%H:%M").time()
                        entry_dt = datetime.datetime.combine(now_local.date(), time_obj)
                    
                    if entry_dt < (now_local - cleanup_margin):
                        continue
                    
                    count += 1

                    if (entry_dt + one_minute_grace) < now_local:
                        is_urgent = True
                        urgent_count += 1
                    
                    if entry_dt >= now_local:
                        future_entries.append({'dt': entry_dt, 'entry': entry})

                except (ValueError, KeyError, TypeError):
                    continue

            soonest_deadline = None
            soonest_time_str = ""
            if future_entries:
                future_entries.sort(key=lambda x: x['dt'])
                soonest_entry = future_entries[0]
                soonest_deadline = soonest_entry['dt']
                soonest_time_str = soonest_entry['entry'].get(time_key, "")

            return count, is_urgent, soonest_deadline, urgent_count, soonest_time_str

        weckruf_count, weckruf_urgent, weckruf_deadline, weckruf_urgent_count, weckruf_time = get_task_status(self.weckruf_data_cache, 'datum', 'zeit')
        taxi_count, taxi_urgent, taxi_deadline, taxi_urgent_count, taxi_time = get_task_status(self.taxi_data_cache, 'datum', 'uhrzeit')
        shuttle_h_count, shuttle_h_urgent, shuttle_h_deadline, shuttle_h_urgent_count, shuttle_h_time = get_task_status([s for s in self.shuttle_data_cache if s.get('type') == 'Hinfahrt'], 'datum', 'zeit')
        shuttle_r_count, shuttle_r_urgent, shuttle_r_deadline, shuttle_r_urgent_count, shuttle_r_time = get_task_status([s for s in self.shuttle_data_cache if s.get('type') == 'Rückfahrt'], 'datum', 'zeit')
            
        task_info = {
            'weckruf': {'count': weckruf_count, 'urgent': weckruf_urgent, 'deadline': weckruf_deadline, 'urgent_count': weckruf_urgent_count, 'time': weckruf_time},
            'taxi': {'count': taxi_count, 'urgent': taxi_urgent, 'deadline': taxi_deadline, 'urgent_count': taxi_urgent_count, 'time': taxi_time},
            'shuttle_hinfahrt': {'count': shuttle_h_count, 'urgent': shuttle_h_urgent, 'deadline': shuttle_h_deadline, 'urgent_count': shuttle_h_urgent_count, 'time': shuttle_h_time},
            'shuttle_rueckfahrt': {'count': shuttle_r_count, 'urgent': shuttle_r_urgent, 'deadline': shuttle_r_deadline, 'urgent_count': shuttle_r_urgent_count, 'time': shuttle_r_time}
        }

        any_open_tasks = any(info['count'] > 0 for info in task_info.values())

        if any_open_tasks:
            if not self.task_notification_frame.winfo_viewable(): self.task_notification_frame.pack(fill='x', pady=(20, 5))
        else:
            if self.task_notification_frame.winfo_viewable(): self.task_notification_frame.pack_forget()
            return

        card_urgent_bg_color = "#FFF0F0"; card_urgent_icon_color = "#D32F2F"; card_warning_bg_color = "#FFF9E6"; card_normal_bg_color = "#FFFFFF"; card_normal_icon_color = "#333333"; card_shadow_color = "#1C1C1C"
        icons = { 'weckruf': {'default': '⏰', 'urgent': '🔔'}, 'taxi': {'default': '🚕', 'urgent': '❗️'}, 'shuttle_hinfahrt': {'default': '🚌➡️', 'urgent': '❗️'}, 'shuttle_rueckfahrt': {'default': '🚌⬅️', 'urgent': '❗️'}, 'hourglass_full': '⏳', 'hourglass_half': '⌛' }

        warning_margin_30 = datetime.timedelta(minutes=30)
        warning_margin_5 = datetime.timedelta(minutes=5)

        for key, data in self.notification_widgets.items():
            info = task_info.get(key, {'count': 0, 'urgent': False, 'deadline': None, 'urgent_count': 0, 'time': ''})
            count = info['count']; is_urgent = info['urgent']; deadline = info['deadline']; urgent_count = info['urgent_count']; time_str = info['time']
            
            task_canvas = data['canvas']
            detail_label = data['detail']; icon_label = data['icon']
            
            if count > 0:
                if not task_canvas.winfo_viewable():
                    task_canvas.pack(fill='x', pady=(0, 8))
                
                open_tasks_count = count - urgent_count
                plural_open = "" if open_tasks_count == 1 else "n"
                detail_text = f"{open_tasks_count} offene Aufgabe{plural_open}"
                if time_str and open_tasks_count > 0:
                    detail_text += f" - Nächste um {time_str} Uhr"

                bg_color = card_normal_bg_color; icon_color = card_normal_icon_color; icon_char = icons[key]['default']

                if is_urgent:
                    bg_color = card_urgent_bg_color; icon_color = card_urgent_icon_color; icon_char = icons[key]['urgent']
                    plural_urgent = " ist" if urgent_count == 1 else " sind"
                    detail_text = f"{urgent_count} Aufgabe{plural_urgent} erledigt" if urgent_count == count else f"{urgent_count} überfällig, {open_tasks_count} offen"
                elif deadline:
                    time_left = deadline - now
                    if time_left < warning_margin_30:
                        bg_color = card_warning_bg_color
                        icon_char = icons['hourglass_full'] if time_left >= warning_margin_5 else icons['hourglass_half']
                
                detail_label.config(text=detail_text)
                icon_label.config(text=icon_char, fg=icon_color)
                
                task_canvas.delete("all")
                w, h = task_canvas.winfo_width(), task_canvas.winfo_height()
                if w > 1 and h > 1:
                    self._create_rounded_rectangle(task_canvas, 2, 2, w, h, radius=10, fill=card_shadow_color, outline="")
                    self._create_rounded_rectangle(task_canvas, 0, 0, w-2, h-2, radius=10, fill=bg_color, outline="")
                    task_canvas.create_window(0, 0, window=data['widgets'][0], anchor="nw", width=w-2, height=h-2)

                for widget in data['widgets']:
                    widget.config(bg=bg_color)
            else:
                task_canvas.pack_forget()            
                
                
                
    def _update_date_display(self, now_datetime_obj):
        """
        Updates the date display in the header. Called only when the day changes.
        Expects a datetime object as input to avoid redundant datetime.date.today() calls.
        """
        if not self.master.winfo_exists():
            return

        try:
            # Use the provided datetime object for formatting
            formatted_date = now_datetime_obj.strftime("%A, %d. %B %Y")
        except UnicodeEncodeError:
            # Fallback for systems that might struggle with certain characters in locale-specific date formatting
            formatted_date = now_datetime_obj.strftime("%Y-%m-%d") 
        except Exception:
            # Generic fallback for any other unexpected formatting error
            formatted_date = now_datetime_obj.strftime("%Y-%m-%d")

        self.date_display_var.set(formatted_date)
        
    def _minimize_window(self):
        """Minimiert das Hauptfenster, anstatt es zu schließen."""
        self.master.iconify()



    def _cleanup_sub_apps(self):
        """
        Sicherstellt, dass alle Instanzen von Unter-Anwendungen sauber beendet
        und deren Referenzen entfernt werden, um einen sauberen Neustart zu ermöglichen.
        """
        print("Räume alte App-Instanzen und Timer auf...")
        
        # Zuerst alle Overlay-Fenster schließen, da sie eigene Timer haben
        if hasattr(self, 'shuttle_overlay_window') and self.shuttle_overlay_window and self.shuttle_overlay_window.winfo_exists():
            self.shuttle_overlay_window.destroy()
        if hasattr(self, 'taxi_overlay_window') and self.taxi_overlay_window and self.taxi_overlay_window.winfo_exists():
            self.taxi_overlay_window.destroy()
        if hasattr(self, 'weckruf_overlay_window') and self.weckruf_overlay_window and self.weckruf_overlay_window.winfo_exists():
            self.weckruf_overlay_window.destroy()

        # Iteriert durch die zentrale Registrierung der Sub-App-Instanzen
        if hasattr(self, 'sub_app_instances'):
            for instance in self.sub_app_instances:
                if instance:
                    app_name = instance.__class__.__name__
                    # Wenn die Instanz eine 'destroy'-Methode hat, rufen wir sie auf,
                    # um interne Timer oder Jobs zu beenden.
                    if hasattr(instance, 'destroy') and callable(instance.destroy):
                        try:
                            instance.destroy()
                            print(f"  - {app_name}.destroy() aufgerufen.")
                        except Exception as e:
                            print(f"  - Fehler beim Aufruf von destroy() für {app_name}: {e}")

        # Leert die Liste der Instanzen, um alle alten Referenzen zu entfernen
        self.sub_app_instances = []
        
        # Setzt zusätzlich die alten, expliziten Attribute zurück (doppelt hält besser)
        self.offene_rechnungen_app_instance = None
        self.spickzettel_app_instance = None
        self.auth_code_app_instance = None
        self.layover_app_instance = None
        self.tischreservierung_app_instance = None
        
        print("Aufräumen der App-Instanzen abgeschlossen.")
    
    
    def _restart_application(self):
        """
        Führt einen robusten "Soft-Neustart" durch. Diese Version hat den korrekten, linearen Ablauf:
        Aufräumen -> UI neu bauen -> Daten laden -> Seite anzeigen.
        """
        try:
            print("Umfassender Soft-Neustart wird eingeleitet...")
            current_page_before_restart = self.current_page_name or "Dashboard"

            self._stop_slideshow()
            self._cleanup_sub_apps()
            self._load_settings()
            self._apply_settings_to_styles()

            # Schritt 1: Nur die Benutzeroberfläche neu aufbauen.
            self._rebuild_ui_after_settings_change()

            # HIER IST DIE KORREKTUR:
            # Der Aufruf zum Laden der Daten wird hier wieder eingefügt,
            # da er an dieser Stelle logisch korrekt ist.
            self._initialize_dashboard_and_essential_data()

            # Schritt 2: Die korrekte Seite wieder anzeigen.
            self.show_page(current_page_before_restart)
            
            print("Soft-Neustart erfolgreich abgeschlossen.")
            
            messagebox.showinfo("Aktualisiert",
                                "Die Anwendung wurde neu geladen.\n"
                                "Änderungen von anderen Rechnern sind jetzt sichtbar.")

        except Exception as e:
            messagebox.showerror("Fehler beim Neustart", f"Die Daten konnten nicht neu geladen werden:\n{e}")
            import traceback
            traceback.print_exc()
    
    
    
    def _on_closing(self):
        """Leitet den sicheren Schließvorgang der Anwendung ein."""
        # 1. Checklisten-Validierung vor dem Schließen
        if self.checklist_dirty.get('frueh') and self.current_page_name == "Checkliste Früh":
             if not self._validate_checklist('frueh'): return
        if self.checklist_dirty.get('spaet') and self.current_page_name == "Checkliste Spät":
             if not self._validate_checklist('spaet'): return

        self._stop_slideshow()
        self.is_shutting_down = True
        print("Shutdown eingeleitet. Stoppe Hintergrundaufgaben...")

        # 2. Timer stoppen (Nur die, die sicher existieren)
        
        # Globaler Backup-Timer
        if hasattr(self, 'auto_backup_job_id') and self.auto_backup_job_id:
            try: self.master.after_cancel(self.auto_backup_job_id)
            except tk.TclError: pass
            self.auto_backup_job_id = None
            print("  - Globaler Auto-Backup-Timer gestoppt.")

        # Haupt-Uhrzeit/Alarm Timer
        if hasattr(self, 'time_after_id') and self.time_after_id:
            try: self.master.after_cancel(self.time_after_id)
            except tk.TclError: pass
            self.time_after_id = None
            print("  - Haupt-Update-Timer gestoppt.")

        # Hintergrundaufgaben (Cleanup etc.)
        if hasattr(self, 'background_task_id') and self.background_task_id:
            try: self.master.after_cancel(self.background_task_id)
            except tk.TclError: pass
            self.background_task_id = None
            print("  - Hintergrundaufgaben-Timer gestoppt.")
        
        # Autosave (Verlauf)
        if hasattr(self, 'autosave_after_id') and self.autosave_after_id:
            try: self.master.after_cancel(self.autosave_after_id)
            except tk.TclError: pass
            self.autosave_after_id = None
            print("  - Autosave-Timer gestoppt.")

        # Sub-Apps aufräumen
        self._cleanup_sub_apps()

        # 3. Daten speichern
        print("Speichere Daten...")
        try:
            if self.checklist_dirty.get('frueh', False): self._save_checklist_state('frueh', show_feedback=False)
            if self.checklist_dirty.get('spaet', False): self._save_checklist_state('spaet', show_feedback=False)
            if self.checklist_dirty.get('nacht', False): self._save_checklist_state('nacht', show_feedback=False)
            
            self._save_tischreservierung_data()
            self._save_anrufliste_data()
            
            self._save_kassenprotokoll_data()
            self._save_current_state_to_history(save_type='manual', changes={'action': 'Programm beendet'})
            self._save_trinkgeld_data()
            self._save_minibar_data()
            self._save_tagesabrechnung_to_history()
            self._save_weckruf_data()
            self._save_shuttle_data()
            self._save_taxi_data()
            self._save_namensliste_data()
            self._save_adressbuch_data()
            self._save_urlaubsantraege_data()
            self._save_ueberstundenantrag_data()
            
            if hasattr(self, 'layover_app_instance') and self.layover_app_instance: 
                self.layover_app_instance.save_data()
            
            if hasattr(self, 'offene_rechnungen_app_instance') and self.offene_rechnungen_app_instance: 
                self.offene_rechnungen_app_instance.save_data(show_toast=False)

            print("Datenspeicherung abgeschlossen.")
        except Exception as e:
            print(f"!!! FEHLER BEIM SPEICHERN WÄHREND DES BEENDENS: {e}")
            import traceback
            traceback.print_exc()

        # 4. Ressourcen freigeben und Fenster schließen
        if pygame_available:
            try:
                if pygame.mixer.get_init():
                    pygame.mixer.stop()
                    pygame.mixer.quit()
                if pygame.get_init():
                    pygame.quit()
                print("Pygame beendet.")
            except Exception as e:
                print(f"Fehler beim Beenden von Pygame: {e}")

        print("Zerstöre Hauptfenster.")
        try:
            self.master.destroy()
        except tk.TclError:
            print("Fenster wurde bereits zerstört.")
            
            
    def _validate_checklist_kuerzel(self, entry_widget, task_info):
        """
        Validiert ein eingegebenes Kürzel sofort, wenn der Fokus das Feld verlässt.
        Blockiert den Fokus, wenn das Kürzel ungültig ist.
        """
        kuerzel = entry_widget.get().strip()
        
        if not kuerzel:
            return

        # vvvvv HIER IST DIE KORREKTUR vvvvv
        # Greift jetzt auf die dynamische Liste aus den Programmeinstellungen zu.
        allowed_kuerzel_list = self.current_settings.get('checkliste_kuerzel_list', [])
        allowed_kuerzel = {k.upper() for k in allowed_kuerzel_list}
        # ^^^^^ ENDE DER KORREKTUR ^^^^^

        # Prüfung (Groß-/Kleinschreibung wird ignoriert)
        if kuerzel.upper() not in allowed_kuerzel:
            messagebox.showerror(
                "Ungültiges Kürzel!",
                f"Das Kürzel '{kuerzel}' ist nicht erlaubt.\n\n"
                "Bitte korrigieren Sie die Eingabe, um fortzufahren.",
                parent=self.master
            )
            # BLOCKIEREN: Leert das Feld und setzt den Fokus zurück.
            entry_widget.delete(0, tk.END)
            entry_widget.focus_set()
            # Stellt sicher, dass die Checkbox nicht als erledigt markiert ist
            task_info['check_var'].set(False)
        else:
            # KORREKTE EINGABE: Formatiert das Kürzel in Großbuchstaben
            entry_widget.delete(0, tk.END)
            entry_widget.insert(0, kuerzel.upper())
            # Setzt die Checkbox automatisch, da ein gültiges Kürzel eingegeben wurde
            task_info['check_var'].set(True)

            
            
    def _add_time_display_to_header(self, header_frame, grid_column):
        """Fügt die Standard-Datums- und Uhrzeitanzeige zu einem Header-Frame hinzu."""
        time_frame = ttk.Frame(header_frame, style='AppBackground.TFrame')
        time_frame.grid(row=0, column=grid_column, sticky='e', padx=10, pady=10)
        
        date_label = ttk.Label(time_frame, textvariable=self.date_display_var, style='TLabel')
        date_label.pack(side='left', padx=(0, 10))
        
        time_label = ttk.Label(time_frame, textvariable=self.time_display_var, style='TLabel')
        time_label.pack(side='left')

    def _calculate_contrast_color(self, hex_color):
        """Bestimmt, ob schwarzer oder weißer Text auf einem gegebenen Hex-Hintergrund besser lesbar ist."""
        try:
            if not isinstance(hex_color, str):
                return '#000000' # Fallback auf Schwarz
            hex_color = hex_color.lstrip('#')
            if len(hex_color) != 6:
                return '#000000' # Fallback bei ungültigem Format
            
            r, g, b = tuple(int(hex_color[i:i+2], 16) for i in (0, 2, 4))
            # Formel für die Luminanz (Wahrnehmungshelligkeit)
            luminance = (0.299 * r + 0.587 * g + 0.114 * b) / 255
            return '#000000' if luminance > 0.5 else '#FFFFFF'
        except Exception:
            return '#000000' # Fallback auf Schwarz bei Fehlern
        
    def _apply_and_style_section_header(self, label_widget, section_key, title_text):
        """Wendet den konfigurierten Stil auf eine Sektions-Überschrift an."""
        if not label_widget or not label_widget.winfo_exists():
            return
            
        header_colors = self.current_settings.get('section_header_colors', {})
        default_colors = self.default_settings.get('section_header_colors', {})
        
        bg_color = header_colors.get(section_key, default_colors.get(section_key, '#434C5E'))
        fg_color = self._calculate_contrast_color(bg_color)
        
        # Erstellt einen einzigartigen Stilnamen, um Konflikte zu vermeiden
        unique_style_name = f"{section_key.capitalize()}.BlackBoldHeading.TLabel"
        
        base_font = self.style.lookup('BlackBoldHeading.TLabel', 'font')
        
        self.style.configure(unique_style_name, 
                             font=base_font, 
                             background=bg_color, 
                             foreground=fg_color,
                             padding=(5, 3)) # Etwas Padding für die Optik
                             
        label_widget.config(text=title_text, style=unique_style_name)
        
        

    # +++ NEU: METHODE ZUM AKTUALISIEREN DES TAB-STILS +++
    def _update_notebook_style(self):
        """
        Aktualisiert den Stil des Notebook-Tabs basierend auf der Konfiguration
        für den aktuell ausgewählten Tab.
        Hinweis: Aufgrund von Einschränkungen im ttk.Notebook-Widget ändert dies die Farbe
        des aktiven Tabs, aber nicht die der inaktiven Tabs individuell.
        """
        if not hasattr(self, 'notebook') or not self.notebook.tabs():
            return
        
        try:
            # Den aktuell ausgewählten Tab-Text ermitteln
            selected_tab_text = self.notebook.tab(self.notebook.select(), "text")
        except tk.TclError:
            return # Kein Tab ausgewählt oder Widget zerstört

        # Farben aus den Einstellungen laden
        tab_colors = self.current_settings.get('tab_colors', self.default_settings.get('tab_colors', {}))
         # Die konfigurierte Hintergrundfarbe für den aktuellen Tab holen
        bg_color = tab_colors.get(selected_tab_text, '#EFEFEF')
        # Eine passende, kontrastreiche Textfarbe berechnen
        fg_color = self._calculate_contrast_color(bg_color)

        # Den Stil für 'TNotebook.Tab' anpassen
        # 'padding' sorgt für etwas mehr Platz um den Text im Tab-Reiter
        self.style.configure('TNotebook.Tab', padding=[10, 3])

        # 'map' wird verwendet, um den Stil für bestimmte Zustände zu ändern
        # Hier ändern wir Hintergrund- und Vordergrundfarbe für den Zustand 'selected' (ausgewählt)
        self.style.map('TNotebook.Tab',
            background=[('selected', bg_color)],
            foreground=[('selected', fg_color)]
        )



    def _load_settings(self):
        """
        Lädt die Einstellungen robust. Erstellt eine Basis aus den Standardwerten
        und überschreibt diese dann rekursiv mit den Werten aus der gespeicherten
        Einstellungsdatei.
        """
        self.current_settings = json.loads(json.dumps(self.default_settings))

        if os.path.exists(self.settings_file):
            try:
                with open(self.settings_file, 'r', encoding='utf-8') as f:
                    loaded_settings = json.load(f)

                def recursive_update(target, source):
                    for key, value in source.items():
                        if key in ['zimmerreservierung_email_recipients', 'anrufliste_email_recipients', 'mod_checkliste_email_recipients']:
                            target[key] = value
                            continue

                        if key in target and isinstance(target.get(key), dict) and isinstance(value, dict):
                            recursive_update(target[key], value)
                        else:
                            target[key] = value
                
                if isinstance(loaded_settings, dict):
                    recursive_update(self.current_settings, loaded_settings)

            except (json.JSONDecodeError, IOError, Exception) as e:
                messagebox.showwarning(
                    "Einstellungen Ladefehler",
                    f"Die Einstellungsdatei ist beschädigt: {e}\nEs werden die Standardeinstellungen verwendet.",
                    parent=self.master
                )

    def _save_settings(self):
        try:
            # Sort custom buttons by key before saving for consistent file output
            if 'custom_buttons' in self.current_settings:
                self.current_settings['custom_buttons'].sort(key=lambda x: x.get('key',''))

            settings_to_save = json.loads(json.dumps(self.current_settings)) # Deep copy for saving

            # --- KORREKTUR START ---
            # Die Variable wird hier initialisiert, um den Fehler zu verhindern.
            stamp_defs_to_save = settings_to_save.get('stamp_definitions', [])
            # --- KORREKTUR ENDE ---

            # Update stamp prices in settings from current UI state (if admin mode allowed changes)
            if hasattr(self, 'fruehdienst_vars') and self.fruehdienst_vars.get('stamp_price_value'):
                   if not isinstance(stamp_defs_to_save, list) or not all(isinstance(item, dict) for item in stamp_defs_to_save):
                     stamp_defs_to_save = self.default_settings['stamp_definitions']

                   for price_key_float, price_double_var in self.fruehdienst_vars['stamp_price_value'].items():
                     target_idx = -1
                     for idx, s_def in enumerate(stamp_defs_to_save):
                         if 'price' in s_def and abs(float(s_def['price']) - price_key_float) < 0.0001:
                             target_idx = idx; break
                     if target_idx != -1:
                         try: stamp_defs_to_save[target_idx]['price'] = price_double_var.get()
                         except Exception: pass
            
            settings_to_save['stamp_definitions'] = stamp_defs_to_save
            
            settings_dir = os.path.dirname(self.settings_file)
            if not os.path.exists(settings_dir):
                try: os.makedirs(settings_dir, exist_ok=True)
                except OSError as e_mkdir:
                    messagebox.showerror("Einstellungen speichern", f"Fehler beim Erstellen des Verzeichnisses '{settings_dir}': {e_mkdir}")
                    return
            
            with open(self.settings_file, 'w', encoding='utf-8') as f:
                json.dump(settings_to_save, f, indent=4)
        except Exception as e:
            messagebox.showerror("Einstellungen speichern", f"Fehler beim Speichern der Einstellungen in '{self.settings_file}': {e}")
