    def _configure_header_elements(self):
        """Lädt das in den Einstellungen festgelegte Logo und zeigt es im Header an.
        Fällt auf ein Standardlogo zurück, wenn kein benutzerdefiniertes Logo gesetzt ist."""
        if not hasattr(self, 'header_logo_label') or not self.header_logo_label.winfo_exists():
            return

        logo_path = self.current_settings.get('header_logo_path', '')
        
        path_to_load = None
        if logo_path and os.path.exists(logo_path):
            path_to_load = logo_path
        else:
            try:
                path_to_load = resource_path("icons/bwp_logo.png")
            except Exception:
                path_to_load = None

        if path_to_load and os.path.exists(path_to_load):
            try:
                # vvvvvvvvvvvvvvvvvvvvvv HIER BEGINNT DIE ÄNDERUNG vvvvvvvvvvvvvvvvvvvvvv
                # Die maximale Höhe wird jetzt aus den Einstellungen gelesen
                header_icon_cfg = self.current_settings.get('dashboard_header_icon_config', self.default_settings['dashboard_header_icon_config'])
                max_logo_height_px = header_icon_cfg.get('icon_size', 40)
                # ^^^^^^^^^^^^^^^^^^^^^^ HIER ENDET DIE ÄNDERUNG ^^^^^^^^^^^^^^^^^^^^^^
                
                img = Image.open(path_to_load)
                img_w, img_h = img.size
                if img_h == 0: raise ValueError("Bildhöhe ist null.")
                
                aspect_ratio = img_w / img_h
                new_h = min(img_h, max_logo_height_px)
                new_w = int(new_h * aspect_ratio)
                new_w = max(1, new_w)
                
                img_resized = img.resize((new_w, new_h), Image.Resampling.LANCZOS)
                
                self.header_logo_image_tk = ImageTk.PhotoImage(img_resized)
                self.header_logo_label.config(image=self.header_logo_image_tk)
            except Exception as e:
                print(f"Fehler beim Laden des Header-Logos von '{path_to_load}': {e}")
                self.header_logo_label.config(image='')
                self.header_logo_image_tk = None
        else:
            self.header_logo_label.config(image='')
            self.header_logo_image_tk = None

    def _update_button_appearances(self):
        if not hasattr(self, 'button_references'): return

        system_button_configs = self.current_settings.get('button_configs', self.default_settings['button_configs'])
        custom_buttons_list = self.current_settings.get('custom_buttons', [])
        custom_button_configs_dict = {btn.get('key'): btn for btn in custom_buttons_list if btn.get('key')}
        
        active_button_keys = set()
        for name, config in system_button_configs.items():
            if config.get('is_active', True): active_button_keys.add(name)
        for custom_btn in custom_buttons_list:
            if custom_btn.get('is_active', False) and custom_btn.get('key'): active_button_keys.add(custom_btn.get('key'))

        keys_to_remove_from_refs = []
        for btn_key_ref in list(self.button_references.keys()):
            if btn_key_ref not in active_button_keys:
                 if self.button_references[btn_key_ref].winfo_exists(): self.button_references[btn_key_ref].destroy()
                 keys_to_remove_from_refs.append(btn_key_ref)
        for key_rem in keys_to_remove_from_refs:
            del self.button_references[key_rem]
            if key_rem in self.button_images:
                del self.button_images[key_rem]

        for btn_key_or_name, btn_widget_reapply in self.button_references.items():
            if not btn_widget_reapply.winfo_exists(): continue

            config_reapply = None
            display_name_for_button = btn_key_or_name
            is_system_button_in_panel = False

            if btn_key_or_name in system_button_configs:
                config_reapply = system_button_configs.get(btn_key_or_name)
                is_system_button_in_panel = True
            elif btn_key_or_name in custom_button_configs_dict:
                config_reapply = custom_button_configs_dict.get(btn_key_or_name)
                display_name_for_button = config_reapply.get('label', btn_key_or_name)

            if not config_reapply:
                config_reapply = {"type": "symbol", "value": "?", "is_active": True}

            # KORRIGIERTER BLOCK ZUM AUSLESEN DER EINSTELLUNGEN
            style_cfg = self.current_settings.get('right_panel_button_style', self.default_settings['right_panel_button_style'])
            icon_size_to_use = style_cfg.get('icon_size', 30)
            
            btn_widget_reapply.config(image="", text="", compound='center')

            btn_type = config_reapply.get('type', 'symbol')
            btn_value = config_reapply.get('value', '')

            tooltip_text = config_reapply.get('command_placeholder', display_name_for_button)

            if btn_type == 'image' and btn_value and os.path.exists(btn_value) and Image and ImageTk:
                try:
                    img = Image.open(btn_value).resize((icon_size_to_use, icon_size_to_use), Image.Resampling.LANCZOS)
                    photo = ImageTk.PhotoImage(img)
                    self.button_images[btn_key_or_name] = photo
                    btn_widget_reapply.image = photo
                    
                    final_text = ""
                    if not is_system_button_in_panel:
                        final_text = display_name_for_button

                    btn_widget_reapply.config(image=photo, text=final_text, compound='top' if final_text else 'center')

                except Exception as e:
                    print(f"Fehler beim Laden des Bildes für Button '{btn_key_or_name}': {e}")
                    btn_widget_reapply.config(text=display_name_for_button, image="")
            
            else:
                final_text = btn_value if btn_type == 'symbol' else display_name_for_button
                if not is_system_button_in_panel and btn_type == 'symbol':
                    final_text = f"{btn_value}\n{display_name_for_button}"
                
                if btn_key_or_name == "Admin" and self.admin_action_button == btn_widget_reapply:
                    admin_icon = "👤" if not self.is_admin_mode else "🔓"
                    final_text = f"{admin_icon}\nAdmin"

                btn_widget_reapply.config(text=final_text, image="", compound='top' if '\n' in final_text else 'center')
                
            ToolTip(btn_widget_reapply, tooltip_text)

