    def _propagate_stamp_count(self, price_key, new_count_str, target_shift_vars):
        if target_shift_vars and 'stamp_counts' in target_shift_vars and price_key in target_shift_vars['stamp_counts']:
            if target_shift_vars['stamp_counts'][price_key].get() != new_count_str: target_shift_vars['stamp_counts'][price_key].set(new_count_str)


    def _get_current_font_at_cursor(self, text_widget, index=None):
        if index is None:
            index = text_widget.index(tk.INSERT) # Current cursor position if no index given
        
        # Get base font of the Text widget
        current_font = tkFont.Font(font=text_widget.cget("font")) # Create a Font object from widget's font config
        font_config = current_font.actual() # Get actual font properties as a dict
        
        # Reset common style attributes to their defaults before checking tags
        font_config["weight"] = "normal" # Default weight
        font_config["slant"] = "roman"   # Default slant (not italic)
        font_config["underline"] = False # Default underline

        tags_at_index = text_widget.tag_names(index) # Get all tags at the given index
        
        # Preserve family and size from the base font unless a specific userfont tag overrides them
        applied_font_family = font_config["family"]
        applied_font_size = font_config["size"]

        for tag in tags_at_index:
            if tag.startswith("userfont_") or tag.startswith("fg_color_"): # Custom composite tags
                tag_font_config_tuple = text_widget.tag_cget(tag, "font") # Get font tuple/string from tag
                if tag_font_config_tuple: # If font is configured for this tag
                    try:
                        temp_font = tkFont.Font(font=tag_font_config_tuple) # Create Font object from tag's font
                        actual_tag_font = temp_font.actual() # Get actual properties of tag's font
                        
                        # Update applied family and size if specified by the tag
                        applied_font_family = actual_tag_font.get("family", applied_font_family)
                        applied_font_size = actual_tag_font.get("size", applied_font_size)
                        
                        # Apply weight, slant, underline from the tag's font
                        if actual_tag_font.get("weight") == "bold": font_config["weight"] = "bold"
                        if actual_tag_font.get("slant") == "italic": font_config["slant"] = "italic"
                        if actual_tag_font.get("underline"): font_config["underline"] = True
                    except tk.TclError:
                        # Font string from tag might be invalid if manually edited or from old data
                        pass 
            else: # Standard Tk tags (less likely to be used with userfont system but check for completeness)
                if tag == "bold": font_config["weight"] = "bold"
                elif tag == "italic": font_config["slant"] = "italic"
                elif tag == "underline": font_config["underline"] = True
        
        # Set the final family and size
        font_config["family"] = applied_font_family
        font_config["size"] = applied_font_size
        
        return tkFont.Font(**font_config) # Return a new Font object with combined properties
    def _toggle_format_tag(self, text_widget, style_attribute):
        try:
            if not text_widget.tag_ranges(tk.SEL): # No selection
                return "break" # Prevent further processing of the event
            
            sel_first = text_widget.index(tk.SEL_FIRST)
            sel_last = text_widget.index(tk.SEL_LAST)

            # Get the font configuration at the start of the selection
            current_font_obj_at_sel_start = self._get_current_font_at_cursor(text_widget, sel_first)
            font_config = current_font_obj_at_sel_start.actual() # Get dict of actual font properties

            # Get current foreground color at selection start (if any custom color tag is applied)
            current_fg_color = None
            tags_at_start = text_widget.tag_names(sel_first)
            for t in tags_at_start:
                if t.startswith("userfont_") or t.startswith("fg_color_"): # Check our custom tags
                    try:
                        color_from_tag = text_widget.tag_cget(t, "foreground")
                        if color_from_tag and isinstance(color_from_tag, str) and color_from_tag: # Ensure it's a valid color string
                            current_fg_color = color_from_tag
                            break # Found a color, no need to check other tags for color
                    except tk.TclError: pass # Tag might not have 'foreground' configured

            # Toggle the desired style attribute
            if style_attribute == "bold":
                font_config["weight"] = "normal" if font_config.get("weight") == "bold" else "bold"
            elif style_attribute == "italic":
                font_config["slant"] = "roman" if font_config.get("slant") == "italic" else "italic"
            elif style_attribute == "underline":
                font_config["underline"] = False if font_config.get("underline", False) else True
            
            self.notes_font_tag_counter +=1
            new_composite_tag_name = f"userfont_{self.notes_font_tag_counter}" # Unique tag name
            
            new_font = tkFont.Font(**font_config) # Create a new Font object with the (toggled) properties
            
            tag_configs = {"font": new_font}
            if current_fg_color: # If a foreground color was active, re-apply it with the new tag
                 tag_configs["foreground"] = current_fg_color

            text_widget.tag_configure(new_composite_tag_name, **tag_configs)
            
            # Remove old custom font/color tags and basic style tags from the selection
            # to prevent conflicting styles and simplify tag management.
            for tag_name_to_remove in list(text_widget.tag_names(sel_first)): # Iterate over a copy
                if tag_name_to_remove.startswith("userfont_") or \
                   tag_name_to_remove.startswith("fg_color_") or \
                   tag_name_to_remove in ["bold", "italic", "underline"]: # Tk's default style tags
                    if tag_name_to_remove != new_composite_tag_name: # Don't remove the tag we just added
                        text_widget.tag_remove(tag_name_to_remove, sel_first, sel_last)
            
            text_widget.tag_add(new_composite_tag_name, sel_first, sel_last) # Apply the new composite tag
        except tk.TclError:
            # This can happen if selection is lost or widget is in a weird state
            pass 
        return "break" # Important to stop default event processing for Text widget bindings

    def _apply_font_to_selection(self, text_widget, font_family=None, font_size=None):
        try:
            if not text_widget.tag_ranges(tk.SEL): # No selection
                return "break"
            
            sel_first = text_widget.index(tk.SEL_FIRST)
            sel_last = text_widget.index(tk.SEL_LAST)

            current_font_obj_at_sel_start = self._get_current_font_at_cursor(text_widget, sel_first)
            font_config = current_font_obj_at_sel_start.actual()

            # Get current foreground color
            current_fg_color = None
            tags_at_start = text_widget.tag_names(sel_first)
            for t in tags_at_start:
                if t.startswith("userfont_") or t.startswith("fg_color_"):
                    try:
                        color_from_tag = text_widget.tag_cget(t, "foreground")
                        if color_from_tag and isinstance(color_from_tag, str) and color_from_tag:
                            current_fg_color = color_from_tag
                            break
                    except tk.TclError: pass

            if font_family:
                font_config["family"] = font_family
            if font_size:
                try: font_config["size"] = int(font_size) # Ensure size is integer
                except ValueError: pass # Ignore if font_size is not a valid int string
            
            self.notes_font_tag_counter +=1
            new_composite_tag_name = f"userfont_{self.notes_font_tag_counter}"
            
            new_font = tkFont.Font(**font_config) 
            
            tag_configs = {"font": new_font}
            if current_fg_color:
                 tag_configs["foreground"] = current_fg_color
            
            text_widget.tag_configure(new_composite_tag_name, **tag_configs)

            for tag_name_to_remove in list(text_widget.tag_names(sel_first)):
                if tag_name_to_remove.startswith("userfont_") or \
                   tag_name_to_remove.startswith("fg_color_") or \
                   tag_name_to_remove in ["bold", "italic", "underline"]:
                    if tag_name_to_remove != new_composite_tag_name:
                        text_widget.tag_remove(tag_name_to_remove, sel_first, sel_last)
            
            text_widget.tag_add(new_composite_tag_name, sel_first, sel_last)
        except tk.TclError: pass
        return "break"

    def _choose_text_color(self, text_widget):
        color_code = colorchooser.askcolor(title="Textfarbe auswählen", parent=self.master)
        if color_code and color_code: # If a color was chosen and is valid hex
            hex_color = color_code
            try:
                if not text_widget.tag_ranges(tk.SEL): return "break" # No selection
                sel_first = text_widget.index(tk.SEL_FIRST); sel_last = text_widget.index(tk.SEL_LAST)
                
                # Get current font properties (family, size, weight, slant, underline) at selection start
                current_font_obj_at_sel_start = self._get_current_font_at_cursor(text_widget, sel_first)
                font_config = current_font_obj_at_sel_start.actual() # Get dict of font properties
                
                self.notes_font_tag_counter += 1
                new_composite_tag_name = f"userfont_{self.notes_font_tag_counter}" # Unique tag name
                
                new_font_for_color = tkFont.Font(**font_config) # Create a Font object with existing style attributes
                
                # Configure the new composite tag with both font and new color
                text_widget.tag_configure(new_composite_tag_name, font=new_font_for_color, foreground=hex_color)
                
                 # Remove old custom tags from the selection
                for tag_name_to_remove in list(text_widget.tag_names(sel_first)):
                      if tag_name_to_remove.startswith("userfont_") or \
                        tag_name_to_remove.startswith("fg_color_") or \
                        tag_name_to_remove in ["bold", "italic", "underline"]:
                         if tag_name_to_remove != new_composite_tag_name:
                            text_widget.tag_remove(tag_name_to_remove, sel_first, sel_last)
                
                text_widget.tag_add(new_composite_tag_name, sel_first, sel_last)
            except tk.TclError: pass
            return "break"

    def _setup_notes_formatting_toolbar(self, parent_frame, text_widget):
        toolbar = ttk.Frame(parent_frame, style='FormattingToolbar.TFrame')
        toolbar.pack(fill='x', pady=(0, 2), side=tk.TOP)

        basic_format_frame = ttk.Frame(toolbar, style='FormattingToolbar.TFrame')
        basic_format_frame.pack(side=tk.LEFT, padx=(0,5)) # Frame for B, I, U, Color

        # Get base font details from the text widget itself
        base_font_details = tkFont.Font(font=text_widget.cget("font")).actual()

        # Pre-configure basic tags (though userfont tags will mostly override)
        text_widget.tag_configure("bold") # Default bold, if needed
        text_widget.tag_configure("italic") # Default italic
        text_widget.tag_configure("underline") # Default underline

        bold_button = ttk.Button(basic_format_frame, text="F", width=3, command=lambda: self._toggle_format_tag(text_widget, "bold"))
        bold_button.pack(side="left", padx=1, pady=2); ToolTip(bold_button, "Fett (Strg+B)")
        
        italic_button = ttk.Button(basic_format_frame, text="K", width=3, command=lambda: self._toggle_format_tag(text_widget, "italic"))
        italic_button.pack(side="left", padx=1, pady=2); ToolTip(italic_button, "Kursiv (Strg+I)")
        
        underline_button = ttk.Button(basic_format_frame, text="U", width=3, command=lambda: self._toggle_format_tag(text_widget, "underline"))
        underline_button.pack(side="left", padx=1, pady=2); ToolTip(underline_button, "Unterstrichen (Strg+U)")

        color_button = ttk.Button(basic_format_frame, text="A", width=3, command=lambda: self._choose_text_color(text_widget))
        color_button.pack(side="left", padx=1, pady=2); ToolTip(color_button, "Textfarbe auswählen")

        # Font Family Combobox
        font_family_var = tk.StringVar()
        available_fonts = sorted(list(tkFont.families()))
        # Prioritize common, widely available fonts
        common_fonts = [f for f in ["Arial", "Calibri", "Courier New", "Georgia", "Helvetica", "Impact", "Segoe UI", "Tahoma", "Times New Roman", "Verdana"] if f in available_fonts]
        display_fonts = common_fonts + [f for f in available_fonts if f not in common_fonts][:10] # Add some more available ones
        font_family_combo = ttk.Combobox(toolbar, textvariable=font_family_var, values=display_fonts, width=15, state="readonly")
        font_family_combo.pack(side=tk.LEFT, padx=2, pady=2); font_family_combo.set(base_font_details["family"]) # Set initial value
        font_family_combo.bind("<<ComboboxSelected>>", lambda event: self._apply_font_to_selection(text_widget, font_family=font_family_var.get())); ToolTip(font_family_combo, "Schriftart auswählen")

        # Font Size Combobox
        font_size_var = tk.StringVar()
        font_sizes = [str(s) for s in [8, 9, 10, 11, 12, 14, 16, 18, 20, 22, 24, 26, 28, 36, 48, 72]]

        font_size_combo = ttk.Combobox(toolbar, textvariable=font_size_var, values=font_sizes, width=4, state="readonly")
        font_size_combo.pack(side=tk.LEFT, padx=2, pady=2); font_size_combo.set(str(base_font_details["size"])) # Set initial value
        font_size_combo.bind("<<ComboboxSelected>>", lambda event: self._apply_font_to_selection(text_widget, font_size=font_size_var.get())); ToolTip(font_size_combo, "Schriftgröße auswählen")
        
        # Keyboard shortcuts for basic formatting
        text_widget.bind("<Control-b>", lambda event: self._toggle_format_tag(text_widget, "bold"))
        text_widget.bind("<Control-B>", lambda event: self._toggle_format_tag(text_widget, "bold")) # For Shift+Ctrl+B
        text_widget.bind("<Control-i>", lambda event: self._toggle_format_tag(text_widget, "italic"))
        text_widget.bind("<Control-I>", lambda event: self._toggle_format_tag(text_widget, "italic"))
        text_widget.bind("<Control-u>", lambda event: self._toggle_format_tag(text_widget, "underline"))
        text_widget.bind("<Control-U>", lambda event: self._toggle_format_tag(text_widget, "underline"))


    def _toggle_bargeldzaehlung_section(self, shift_name, target_state=None):
        vars_dict_ref = self.fruehdienst_vars if shift_name == "Frühdienst" else self.spaetdienst_vars
        toggle_button = vars_dict_ref.get('bargeldzaehlung_toggle_button')
        content_frame = vars_dict_ref.get('bargeldzaehlung_content_frame')

        if not toggle_button or not content_frame or not toggle_button.winfo_exists() or not content_frame.winfo_exists(): return
        
        parent_scrollable_frame = vars_dict_ref.get('scrollable_frame')
        current_expanded_state = vars_dict_ref.get('bargeldzaehlung_expanded_state', True)
        
        if target_state is None: new_expanded_state = not current_expanded_state
        else: new_expanded_state = target_state
        
        if new_expanded_state == current_expanded_state: return # No change needed

        vars_dict_ref['bargeldzaehlung_expanded_state'] = new_expanded_state
        if new_expanded_state:
            content_frame.grid(row=1, column=0, sticky='new', padx=0, pady=(0,0))
            toggle_button.config(text="▲")
        else:
            content_frame.grid_remove()
            toggle_button.config(text="▼")
        
        # Update scrollregion of the canvas
        if parent_scrollable_frame and parent_scrollable_frame.winfo_exists():
             parent_scrollable_frame.update_idletasks() # Ensure layout changes are processed
             canvas_ref = vars_dict_ref.get('canvas')
             if canvas_ref and canvas_ref.winfo_exists():
                 canvas_ref.configure(scrollregion=canvas_ref.bbox("all"))


