    def _toggle_all_sections_in_current_shift(self):
        active_shift_name = self._get_current_active_shift_name_internal()
        if not active_shift_name: # Should not happen if a tab is selected
            self._toggle_kassenabschluss_section(target_state=None) # Toggle dashboard section if no specific shift context
            return

        vars_dict_ref = self.fruehdienst_vars if active_shift_name == "Frühdienst" else self.spaetdienst_vars
        
        # Determine target state based on one section (e.g., Bargeldzählung)
        # If bargeld is expanded, target is to collapse all. Else, expand all.
        current_bargeld_expanded = vars_dict_ref.get('bargeldzaehlung_expanded_state', True)
        target_expanded_state = not current_bargeld_expanded # This will be the new state for all sections

        self._toggle_kassenabschluss_section(target_state=target_expanded_state) # Toggle Dashboard's Kassenabschluss section
        self._toggle_bargeldzaehlung_section(active_shift_name, target_state=target_expanded_state)
        self._toggle_stamps_section(active_shift_name, target_state=target_expanded_state)
        for card_key in vars_dict_ref.get('card_type_keys', []):
             self._toggle_card_section(active_shift_name, card_key, target_state=target_expanded_state)
        self._toggle_notes_section(active_shift_name, target_state=target_expanded_state)
        
        # Update scrollregion of the canvas for the active shift's tab
        canvas_ref = vars_dict_ref.get('canvas'); scrollable_frame_ref = vars_dict_ref.get('scrollable_frame')
        if scrollable_frame_ref and scrollable_frame_ref.winfo_exists():
            scrollable_frame_ref.update_idletasks()
            if canvas_ref and canvas_ref.winfo_exists():
                canvas_ref.configure(scrollregion=canvas_ref.bbox("all"))

    def _configure_shift_delete_button(self, button_widget, config_key):
        """Configures a shift-specific delete button based on settings."""
        shift_action_configs = self.current_settings.get('shift_action_button_configs', {})
        config = shift_action_configs.get(config_key, {'type': 'symbol', 'value': 'Löschen', 'is_active': True})

        if not config.get('is_active', True):
            try:
                button_widget.pack_forget()
            except tk.TclError:
                pass
            return
        
        # +++ VERWENDUNG DER NEUEN EINSTELLUNGEN (START) +++
        icon_size = self.current_settings.get('shift_action_button_icon_size', 20)
        btn_type = config.get('type', 'symbol')
        btn_value = config.get('value', 'Löschen')
        ipady = self.current_settings.get('shift_action_button_ipady', 2)

        if btn_type == 'image' and btn_value and os.path.exists(btn_value) and Image and ImageTk:
            try:
                img = Image.open(btn_value).resize((icon_size, icon_size), Image.Resampling.LANCZOS)
                # Use a specific dictionary for these images to avoid conflicts
                if not hasattr(self, 'shift_action_button_images'):
                    self.shift_action_button_images = {}
                photo = ImageTk.PhotoImage(img)
                self.shift_action_button_images[config_key] = photo
                button_widget.config(image=photo, text="", compound='center')
            except Exception as e:
                print(f"Fehler beim Laden des Bildes für Button '{config_key}': {e}")
                button_widget.config(text="🗑️", image="") # Fallback symbol
        else:
            button_widget.config(text=btn_value, image="", compound='left')
            
        # Anwenden des Innen-Paddings
        try:
            button_widget.pack_configure(ipady=ipady)
        except Exception:
            # Fallback if pack_configure is not available or fails
            try:
                current_padding = list(button_widget.cget("padding"))
                current_padding[1] = ipady # Index 1 for top/bottom padding (ipy)
                button_widget.config(padding=tuple(current_padding))
            except (tk.TclError, IndexError):
                pass
        # +++ VERWENDUNG DER NEUEN EINSTELLUNGEN (ENDE) +++

    def _create_shift_widgets(self, parent_notebook_tab_frame, vars_dict, shift_name, other_shift_vars_dict):
        # Clear existing widgets in the tab frame
        for widget in parent_notebook_tab_frame.winfo_children():
            widget.destroy()

        # Setup scrollable area within the tab
        canvas = tk.Canvas(parent_notebook_tab_frame, borderwidth=0, highlightthickness=0)
        vsb = ttk.Scrollbar(parent_notebook_tab_frame, orient="vertical", command=canvas.yview)
        canvas.configure(yscrollcommand=vsb.set); vsb.pack(side="right", fill="y"); canvas.pack(side="left", fill="both", expand=True)
        vars_dict['canvas'] = canvas

        scrollable_frame = ttk.Frame(canvas, style='AppBackground.TFrame', padding=(5,5))
        vars_dict['scrollable_frame'] = scrollable_frame
        canvas_window_id = canvas.create_window((0, 0), window=scrollable_frame, anchor="nw", tags="scrollable_frame_tag")

        scrollable_frame.bind("<Configure>", lambda e: canvas.configure(scrollregion=canvas.bbox("all")))
        canvas.bind("<Configure>", lambda e: canvas.itemconfig(canvas_window_id, width=e.width))

        # VVVVVV HIER IST DIE KORRIGIERTE _on_mousewheel FUNKTION VVVVVV
        def _on_mousewheel(event):
            if platform.system() == "Linux":
                if event.num == 4:
                    canvas.yview_scroll(-1, "units")
                elif event.num == 5:
                    canvas.yview_scroll(1, "units")
            else: # Windows/macOS
                # event.delta ist auf Windows typischerweise ein Vielfaches von 120
                canvas.yview_scroll(int(-1 * (event.delta / 120)), "units")
        # ^^^^^^ HIER ENDET DIE KORREKTUR ^^^^^^

        def bind_mousewheel_recursively(widget, func):
            widget.bind("<MouseWheel>", func, add='+')
            if platform.system() == "Linux":
                widget.bind("<Button-4>", func, add='+')
                widget.bind("<Button-5>", func, add='+')
            for child in widget.winfo_children():
                bind_mousewheel_recursively(child, func)

        # Main content container inside the scrollable frame
        scrollable_frame.columnconfigure(0, weight=1); scrollable_frame.rowconfigure(0, weight=1)
        content_container = ttk.Frame(scrollable_frame, style='AppBackground.TFrame')
        content_container.grid(row=0, column=0, padx=0, pady=0, sticky='nsew')
        content_container.columnconfigure(0, weight=1)

        current_content_row = 0

        # Action frame for shift-specific delete buttons
        action_frame = ttk.Frame(content_container, style='AppBackground.TFrame')
        action_frame.grid(row=current_content_row, column=0, sticky='ew', pady=(0, 10))
        
        delete_button = None
        if shift_name == "Frühdienst":
            delete_button = ttk.Button(
                action_frame, 
                command=self._clear_fruehdienst_data,
                style='TButton'
            )
            self._configure_shift_delete_button(delete_button, 'Fruehdienst_Delete')
            if delete_button and delete_button.winfo_exists():
                delete_button.pack(side='right', padx=5, pady=2)
                ToolTip(delete_button, "Löscht alle Frühdienst-spezifischen Daten (Umsatz, Bar, Karten). Briefmarken bleiben erhalten.")
        elif shift_name == "Spätdienst":
            delete_button = ttk.Button(
                action_frame, 
                command=self._clear_spaetdienst_data,
                style='TButton'
            )
            self._configure_shift_delete_button(delete_button, 'Spaetdienst_Delete')
            if delete_button and delete_button.winfo_exists():
                delete_button.pack(side='right', padx=5, pady=2)
                ToolTip(delete_button, "Löscht alle Spätdienst-spezifischen Daten (Umsatz, Bar, Karten). Briefmarken bleiben erhalten.")

        current_content_row += 1

        # Bargeldzählung Section
        cash_section_overall_frame = ttk.Frame(content_container, style='AppBackground.TFrame')
        cash_section_overall_frame.grid(row=current_content_row, column=0, padx=0, pady=(0,6), sticky='new')
        cash_section_overall_frame.columnconfigure(0, weight=1)
        
        bargeld_header_subframe = ttk.Frame(cash_section_overall_frame, style='AppBackground.TFrame')
        bargeld_header_subframe.grid(row=0, column=0, sticky='ew', pady=(0,1))
        bargeld_header_subframe.columnconfigure(0, weight=1); bargeld_header_subframe.columnconfigure(1, weight=0)
        
        bargeld_title_label = ttk.Label(bargeld_header_subframe)
        self._apply_and_style_section_header(bargeld_title_label, 'cash_section', "Bargeldzählung")
        bargeld_title_label.grid(row=0, column=0, sticky='w', padx=(2,0))
        
        is_bargeld_expanded = vars_dict.get('bargeldzaehlung_expanded_state', True)
        bargeld_toggle_text = "▲" if is_bargeld_expanded else "▼"
        bargeld_toggle_button = ttk.Button(bargeld_header_subframe, text=bargeld_toggle_text, command=lambda s=shift_name: self._toggle_bargeldzaehlung_section(s, target_state=None), width=3, style='TButton')
        bargeld_toggle_button.grid(row=0, column=1, sticky='e', padx=(0,2))
        vars_dict['bargeldzaehlung_toggle_button'] = bargeld_toggle_button
        
        bargeld_content_frame = ttk.Frame(cash_section_overall_frame, style='AppBackground.TFrame', relief='groove', borderwidth=1)
        vars_dict['bargeldzaehlung_content_frame'] = bargeld_content_frame
        if is_bargeld_expanded: bargeld_content_frame.grid(row=1, column=0, sticky='new', padx=0, pady=(0,0))
        self._create_cash_section(bargeld_content_frame, vars_dict); current_content_row += 1
        
        # Card Sections
        for card_key in vars_dict.get('card_type_keys', []):
            if card_key in vars_dict.get('card_data', {}):
                card_label = vars_dict.get('card_display_info', {}).get(card_key, {}).get('label', card_key)
                
                card_overall_frame = ttk.Frame(content_container, style='AppBackground.TFrame')
                card_overall_frame.grid(row=current_content_row, column=0, padx=0, pady=6, sticky='new')
                card_overall_frame.columnconfigure(0, weight=1)

                card_header_subframe = ttk.Frame(card_overall_frame, style='AppBackground.TFrame')
                card_header_subframe.grid(row=0, column=0, sticky='ew', pady=(0,1))
                card_header_subframe.columnconfigure(0, weight=1); card_header_subframe.columnconfigure(1, weight=0)

                card_title_label = ttk.Label(card_header_subframe)
                self._apply_and_style_section_header(card_title_label, 'cards_section', f"{card_label} CP")
                card_title_label.grid(row=0, column=0, sticky='w', padx=(2,0))
                
                is_card_expanded = vars_dict['card_expanded_states'].get(card_key, True)
                card_toggle_text = "▲" if is_card_expanded else "▼"
                card_toggle_button_widget = ttk.Button(card_header_subframe, text=card_toggle_text, command=lambda s=shift_name, ck=card_key: self._toggle_card_section(s, ck, target_state=None), width=3, style='TButton')
                card_toggle_button_widget.grid(row=0, column=1, sticky='e', padx=(0,2))
                vars_dict['card_toggle_buttons'][card_key] = card_toggle_button_widget
                
                card_content_actual_frame = ttk.Frame(card_overall_frame, style='AppBackground.TFrame', relief='groove', borderwidth=1)
                vars_dict['card_content_frames'][card_key] = card_content_actual_frame
                if is_card_expanded: card_content_actual_frame.grid(row=1, column=0, sticky='new', padx=0, pady=(0,0))
                self._create_card_section_common(card_content_actual_frame, card_key, vars_dict, shift_name, other_shift_vars_dict)
                current_content_row += 1
        
        # Notizen Section
        notes_section_overall_frame = ttk.Frame(content_container, style='AppBackground.TFrame')
        notes_section_overall_frame.grid(row=current_content_row, column=0, padx=0, pady=6, sticky='nsew')
        notes_section_overall_frame.columnconfigure(0, weight=1); notes_section_overall_frame.rowconfigure(1, weight=1)
        content_container.rowconfigure(current_content_row, weight=1)

        notes_header_subframe = ttk.Frame(notes_section_overall_frame, style='AppBackground.TFrame')
        notes_header_subframe.grid(row=0, column=0, sticky='ew', pady=(0,1))
        notes_header_subframe.columnconfigure(0, weight=1); notes_header_subframe.columnconfigure(1, weight=0)
        
        notes_title_label = ttk.Label(notes_header_subframe)
        self._apply_and_style_section_header(notes_title_label, 'notes_section', f"Notizen {shift_name}")
        notes_title_label.grid(row=0, column=0, sticky='w', padx=(2,0))
        
        is_notes_expanded = vars_dict.get('notes_expanded_state', True)
        notes_toggle_text = "▲" if is_notes_expanded else "▼"
        notes_toggle_button_widget = ttk.Button(notes_header_subframe, text=notes_toggle_text, command=lambda s=shift_name: self._toggle_notes_section(s, target_state=None), width=3, style='TButton')
        notes_toggle_button_widget.grid(row=0, column=1, sticky='e', padx=(0,2))
        vars_dict['notes_toggle_button'] = notes_toggle_button_widget

        notes_content_inner_frame = ttk.Frame(notes_section_overall_frame, style='AppBackground.TFrame', relief='groove', borderwidth=1)
        vars_dict['notes_content_frame'] = notes_content_inner_frame
        notes_content_inner_frame.columnconfigure(0, weight=1); notes_content_inner_frame.rowconfigure(1, weight=1)
        if is_notes_expanded: notes_content_inner_frame.grid(row=1, column=0, sticky='nsew', padx=5, pady=(0,0))
        
        formatting_toolbar_frame = ttk.Frame(notes_content_inner_frame, style='FormattingToolbar.TFrame')
        formatting_toolbar_frame.grid(row=0, column=0, sticky='ew', padx=0, pady=(0,2))

        notes_font_family = "Segoe UI" if "Segoe UI" in tkFont.families() else "Arial"
        notes_base_font_size = self.current_settings.get('general_font_size', self.default_settings['general_font_size'])
        notes_text = tk.Text(notes_content_inner_frame, wrap=tk.WORD, height=10, relief=tk.SUNKEN, borderwidth=2, 
                             font=(notes_font_family, notes_base_font_size), 
                             background=self.current_settings.get('notes_area_bg', self.default_settings['notes_area_bg']),
                             foreground=self.current_settings.get('general_font_color', self.default_settings['general_font_color']),
                             undo=True)
        notes_text.grid(row=1, column=0, sticky='nsew', padx=5, pady=(0,5))
        vars_dict['notes_text_widget'] = notes_text
        
        self._setup_notes_formatting_toolbar(formatting_toolbar_frame, notes_text)

        initial_content_for_notes = vars_dict.get('notes_initial_content', '')
        if notes_text.winfo_exists():
            notes_text.delete("1.0", tk.END)
            if initial_content_for_notes: notes_text.insert("1.0", initial_content_for_notes)
        
        def _on_notes_content_changed(event=None):
            if notes_text.edit_modified():
                vars_dict['notes_initial_content'] = notes_text.get("1.0", tk.END + "-1c").strip()
                notes_text.edit_modified(False)

        notes_text.bind("<<Modified>>", _on_notes_content_changed)
        notes_text.bind("<KeyRelease>", _on_notes_content_changed)
        notes_text.bind("<FocusOut>", _on_notes_content_changed)

        current_content_row += 1
        
        bind_mousewheel_recursively(scrollable_frame, _on_mousewheel)
        scrollable_frame.update_idletasks(); canvas.configure(scrollregion=canvas.bbox("all"))
   
    def _add_widget_to_list(self, widget, widget_type, is_main_input=False, is_admin_editable=False, is_diff_label=False):
        if widget_type == 'label':
            self.all_labels.append(widget)
            if is_diff_label:
                self.diff_label_widgets.append(widget)
        elif widget_type in ['entry', 'combobox']:
            self.all_entries.append(widget)
            if is_admin_editable:
                self.admin_editable_entries.append(widget)

            # HIER IST DIE ZENTRALE NAVIGATIONS-LOGIK:
            # Jedes als "is_main_input" markierte Feld erhält die Pfeiltasten-Navigation.
            if is_main_input and widget:
                # Up/Down/Return wechseln immer das Feld
                widget.bind("<Up>", lambda e: (e.widget.tk_focusPrev().focus_set(), "break"))
                widget.bind("<Down>", lambda e: (e.widget.tk_focusNext().focus_set(), "break"))
                widget.bind("<Return>", lambda e: (e.widget.tk_focusNext().focus_set(), "break"))
                
                # Left/Right wechseln nur an den Rändern
                widget.bind("<Left>", self._focus_prev_if_at_start)
                widget.bind("<Right>", self._focus_next_if_at_end)
            
            # Wende Schriftart direkt nach dem Hinzufügen an
            if widget and widget.winfo_exists():
                try:
                    style_name = widget.cget("style")
                    if (style_name == 'NumberInput.TEntry' or style_name == 'NumberInput.TCombobox') and hasattr(self, 'number_font_tuple') and self.number_font_tuple:
                        if callable(getattr(widget, "configure", None)):
                            widget.configure(font=self.number_font_tuple)
                except tk.TclError:
                    pass

    def _clear_widget_tracking_lists(self):
        self.all_labels.clear()
        self.all_entries.clear()
        self.all_navigable_widgets.clear()
        self.admin_editable_entries.clear()
        self.diff_label_widgets.clear()


