    def _set_default_minibar_period_and_load(self):
        from datetime import datetime
        today = datetime.today()
        self.current_minibar_month_var.set(today.strftime("%m"))
        self.current_minibar_year_var.set(today.strftime("%Y"))
        self._load_and_display_minibar_for_period()
        
    def _calculate_current_month_minibar_umsatz(self):
        """
        Calculates the total minibar Umsatz for the month currently selected
        in the Minibarliste tab and updates the corresponding variable.
        """
        try:
            # Get the selected month and year from the Minibarliste tab UI variables.
            month_str = self.current_minibar_month_var.get()
            year_str = self.current_minibar_year_var.get()

            # If month or year is not selected, the total Umsatz is 0.
            if not month_str or not year_str:
                self.current_minibar_umsatz_monat = decimal.Decimal('0.0')
                self.minibar_total_umsatz_display_var.set(self._format_decimal_for_display(decimal.Decimal('0.0')))
                return

            # Construct the period key (YYYY-MM) for accessing the data cache.
            try:
                month = int(month_str)
                year = int(year_str)
                period_key = f"{year:04d}-{month:02d}"
            except ValueError:
                # If month or year are not valid integers, total Umsatz is 0 and log warning.
                print(f"Warning: Invalid month/year selected for Minibar calculation: {month_str}/{year_str}")
                self.minibar_total_umsatz_display_var.set(self._format_decimal_for_display(decimal.Decimal('0.0')))
                return

            # Construct the period key (YYYY-MM) for accessing the data cache.
            try:
                month = int(month_str)
                year = int(year_str)
                period_key = f"{year:04d}-{month:02d}"
            except ValueError:
                # If month or year are not valid integers, total Umsatz is 0 and log warning.
                print(f"Warning: Invalid month/year selected for Minibar calculation: {month_str}/{year_str}")
                self.current_minibar_umsatz_monat = decimal.Decimal('0.0')
                self.minibar_total_umsatz_display_var.set(self._format_decimal_for_display(decimal.Decimal('0.0')))
                return


            # Get the entries for the selected period from the cache. Default to empty list if key not found.
            entries_for_period = self.minibar_data_cache.get(period_key, [])
            
            # Calculate the sum of 'gesamt_umsatz' for all entries in the period.
            total_umsatz_for_period = decimal.Decimal('0.0')
            for entry in entries_for_period:
                 # Ensure 'gesamt_umsatz' exists and is numeric, add to total.
                umsatz_value = entry.get("gesamt_umsatz", 0.0)
                try:
                    total_umsatz_for_period += decimal.Decimal(str(umsatz_value))
                except decimal.InvalidOperation:
                    print(f"Warning: Invalid 'gesamt_umsatz' value in Minibar entry: {umsatz_value}")
                    pass # Skip this invalid entry value

            # Update the internal variable used by the Kassenabschluss formula.
            self.current_minibar_umsatz_monat = total_umsatz_for_period
            
            # Update the display variable shown in the Minibarliste tab summary.
            self.minibar_total_umsatz_display_var.set(self._format_decimal_for_display(total_umsatz_for_period))

        except Exception as e:
            # Catch any other unexpected errors during calculation.
            print(f"Error calculating current month minibar turnover: {e}")
            self.current_minibar_umsatz_monat = decimal.Decimal('0.0')
            self.minibar_total_umsatz_display_var.set(self._format_decimal_for_display(decimal.Decimal('0.0')))
            




            
            
            
    def _save_kassenprotokoll_data(self):
        """Speichert den aktuellen Zustand des Kassenprotokolls in eine dedizierte Datei."""
        try:
            data_to_save = {
                "fruehdienst_data": self._extract_data_for_snapshot(self.fruehdienst_vars, "Frühdienst"),
                "spaetdienst_data": self._extract_data_for_snapshot(self.spaetdienst_vars, "Spätdienst")
            }
            with open(self.kassenprotokoll_data_file, 'w', encoding='utf-8') as f:
                json.dump(data_to_save, f, indent=2, ensure_ascii=False)
        except Exception as e:
            print(f"Fehler beim Speichern der Kassenprotokoll-Daten: {e}")

    
    def _load_kassenprotokoll_data(self):
        """Lädt den letzten gespeicherten Zustand des Kassenprotokolls aus der dedizierten Datei."""
        if not os.path.exists(self.kassenprotokoll_data_file):
            return

        try:
            with open(self.kassenprotokoll_data_file, 'r', encoding='utf-8') as f:
                loaded_data = json.load(f)

            if isinstance(loaded_data, dict):
                fruehdienst_data = loaded_data.get("fruehdienst_data")
                spaetdienst_data = loaded_data.get("spaetdienst_data")
                
                if fruehdienst_data:
                    self._apply_snapshot_to_vars(self.fruehdienst_vars, fruehdienst_data, "Frühdienst")
                
                if spaetdienst_data:
                    self._apply_snapshot_to_vars(self.spaetdienst_vars, spaetdienst_data, "Spätdienst")

        except (json.JSONDecodeError, IOError, Exception) as e:
            print(f"Fehler beim Laden der Kassenprotokoll-Daten: {e}")
            
            
    def _perform_manual_backup(self, ask_confirmation=True):
        """Erstellt ein neues manuelles Backup des aktuellen Kassenprotokolls mit Zeitstempel."""
        if ask_confirmation:
            if not messagebox.askyesno("Manuelles Backup", "Möchten Sie ein neues manuelles Backup der Kassenprotokoll-Daten erstellen?", parent=self.master):
                return

        try:
            os.makedirs(self.kassenprotokoll_backup_dir, exist_ok=True)
            
            # Zeitstempel für eindeutigen Dateinamen
            timestamp = datetime.datetime.now().strftime("%Y-%m-%d_%H-%M-%S")
            file_name = f"manual_backup_kassenprotokoll_{timestamp}.json"
            file_path = os.path.join(self.kassenprotokoll_backup_dir, file_name)

            data_to_save = {
                "fruehdienst_data": self._extract_data_for_snapshot(self.fruehdienst_vars, "Frühdienst"),
                "spaetdienst_data": self._extract_data_for_snapshot(self.spaetdienst_vars, "Spätdienst")
            }

            with open(file_path, 'w', encoding='utf-8') as f:
                json.dump(data_to_save, f, indent=2, ensure_ascii=False)
            
            if ask_confirmation:
                SuccessToast(self.master, title="Backup erfolgreich", message=f"Neues Backup erstellt:\n{file_name}", toast_type='success', colors=self.current_settings.get('toast_colors'))
        except Exception as e:
            messagebox.showerror("Backup-Fehler", f"Das Backup konnte nicht erstellt werden:\n{e}", parent=self.master)
            
            

        
        


    def _perform_auto_backup_tagesabrechnung(self):
        """Führt ein automatisches Backup der Tagesabrechnungsdaten durch."""
        if self.is_shutting_down or not self.current_settings.get('auto_backup_tagesabrechnung_enabled', False):
            return

        try:
            os.makedirs(self.tagesabrechnung_backup_dir, exist_ok=True)
            
            all_backups = sorted(
                [f for f in os.listdir(self.tagesabrechnung_backup_dir) if f.startswith('auto_backup_') and f.endswith('.json')],
                key=lambda f: os.path.getmtime(os.path.join(self.tagesabrechnung_backup_dir, f))
            )
            
            max_auto_backups = 50
            if len(all_backups) >= max_auto_backups:
                for old_backup in all_backups[:len(all_backups) - max_auto_backups + 1]:
                    os.remove(os.path.join(self.tagesabrechnung_backup_dir, old_backup))

            timestamp = datetime.datetime.now().strftime("%Y-%m-%d_%H-%M-%S")
            file_name = f"auto_backup_tagesabrechnung_{timestamp}.json"
            file_path = os.path.join(self.tagesabrechnung_backup_dir, file_name)

            data_to_save = self._extract_tagesabrechnung_data_for_snapshot()

            with open(file_path, 'w', encoding='utf-8') as f:
                json.dump(data_to_save, f, indent=2, ensure_ascii=False)
            
            print(f"Automatisches Tagesabrechnung-Backup '{file_name}' erstellt.")
        except Exception as e:
            print(f"Fehler beim automatischen Tagesabrechnung-Backup: {e}")

