    def _load_latest_from_history(self):
        """Lädt den neuesten Zustand aus der Verlaufsdatei beim Start der Anwendung."""
        history_data = self._load_history_data()
        
        if not history_data:
            print("Info: Keine Verlaufsdaten zum Laden beim Start gefunden.")
            return

        try:
            # Der neueste Eintrag ist immer der erste in der Liste
            latest_snapshot = history_data[0]
            
            # Sicherstellen, dass der Snapshot die erwarteten Daten enthält
            if 'fruehdienst_data' in latest_snapshot and 'spaetdienst_data' in latest_snapshot:
                print("Lade letzten gespeicherten Zustand aus dem Verlauf...")
                self._apply_snapshot_to_vars(self.fruehdienst_vars, latest_snapshot['fruehdienst_data'], "Frühdienst")
                self._apply_snapshot_to_vars(self.spaetdienst_vars, latest_snapshot['spaetdienst_data'], "Spätdienst")
            else:
                print("Warnung: Der neueste Verlaufs-Snapshot ist ungültig und wird nicht geladen.")

        except (IndexError, KeyError, Exception) as e:
            print(f"Fehler beim Anwenden des letzten Verlaufs-Snapshots: {e}")
