    def _open_file(self, file_path):
        """Öffnet die angegebene Datei mit dem Standardprogramm des Systems."""
        if not os.path.isfile(file_path):
            messagebox.showerror("Fehler", f"Die Datei konnte nicht gefunden werden:\n{file_path}", parent=self.master)
            return
        try:
            if platform.system() == "Windows":
                os.startfile(file_path)
            elif platform.system() == "Darwin":  # macOS
                subprocess.run(["open", file_path], check=True)
            else:  # Linux
                subprocess.run(["xdg-open", file_path], check=True)
        except FileNotFoundError:
             messagebox.showerror("Fehler", f"Kein Standardprogramm zum Öffnen der Datei gefunden.\nBitte überprüfen Sie Ihre Systemeinstellungen.", parent=self.master)
        except Exception as e:
            messagebox.showerror("Fehler", f"Die Datei konnte nicht geöffnet werden:\n{e}", parent=self.master)

    def _schedule_temp_file_cleanup(self, file_path, attempts=5, delay_ms=2000):
        """
        Versucht, eine temporäre Datei mehrmals zu löschen, um PermissionErrors zu vermeiden.
        """
        if not file_path or not os.path.exists(file_path):
            return

        def try_delete():
            nonlocal attempts
            try:
                os.remove(file_path)
                print(f"Temporäre Datei '{file_path}' erfolgreich gelöscht.")
            except PermissionError:
                attempts -= 1
                if attempts > 0:
                    print(f"Datei '{file_path}' noch gesperrt. Versuche es in {delay_ms}ms erneut ({attempts} Versuche übrig).")
                    self.master.after(delay_ms, try_delete)
                else:
                    print(f"Fehler: Konnte temporäre Datei '{file_path}' nach mehreren Versuchen nicht löschen.")
            except Exception as e:
                print(f"Unerwarteter Fehler beim Löschen der temporären Datei '{file_path}': {e}")

        # Startet den ersten Löschversuch nach einer anfänglichen Verzögerung
        self.master.after(delay_ms, try_delete)
                



            

            
