    def _load_trinkgeld_data(self):
        if os.path.exists(self.trinkgeld_data_file):
            try:
                with open(self.trinkgeld_data_file, 'r', encoding='utf-8') as f:
                    self.trinkgeld_data_cache = json.load(f)
                    # Ensure all monetary values are floats (or Decimals if preferred for precision later)
                    # It's better to store floats and convert to Decimal on load/calculation
                    for month_key, entries in self.trinkgeld_data_cache.items():
                        # Ensure entries is a list
                        if not isinstance(entries, list):
                            print(f"Warning: Trinkgeld data for period '{month_key}' is not a list. Skipping.")
                            self.trinkgeld_data_cache[month_key] = [] # Replace with empty list
                            continue # Move to next month key
                        
                        valid_entries = []
                        for entry in entries:
                             # Ensure each entry is a dictionary
                             if not isinstance(entry, dict):
                                 print(f"Warning: Invalid entry format in Trinkgeld data for period '{month_key}'. Skipping entry.")
                                 continue # Skip non-dict entries

                             # Convert numeric fields to float
                             for field in ["bestand", "einnahme_frueh", "entnahme_frueh", "einnahme_spaet", "entnahme_spaet", "gesamt"]:
                                 if field in entry:
                                     try:
                                         entry[field] = float(entry[field])
                                     except (ValueError, TypeError):
                                         print(f"Warning: Invalid numeric value for field '{field}' in Trinkgeld entry for date '{entry.get('datum', 'N/A')}'. Setting to 0.0")
                                         entry[field] = 0.0 # Set to 0.0 on error

                             # Ensure 'datum' and 'kuerzel' fields exist
                             if 'datum' not in entry: entry['datum'] = 'Invalid Date'
                             if 'kuerzel_frueh' not in entry: entry['kuerzel_frueh'] = ''
                             if 'kuerzel_spaet' not in entry: entry['kuerzel_spaet'] = ''
                             
                             valid_entries.append(entry) # Add valid entry to the new list

                        self.trinkgeld_data_cache[month_key] = valid_entries # Replace potentially invalid list with valid one

            except (json.JSONDecodeError, IOError) as e:
                print(f"Error loading Trinkgeld data from '{self.trinkgeld_data_file}': {e}")
                self.trinkgeld_data_cache = {} # Reset cache on error
            except Exception as e:
                print(f"An unexpected error occurred while loading Trinkgeld data from '{self.trinkgeld_data_file}': {e}")
                self.trinkgeld_data_cache = {} # Reset cache on error

        else:
            self.trinkgeld_data_cache = {} # Initialize empty cache if file doesn't exist







        
            







        
            










        
            



    def _save_trinkgeld_data(self):
        # Sicherheits-Stopp: Verhindert das Überschreiben vorhandener Daten mit leerem Cache
        # (identische Logik wie bei _save_minibar_data)
        if not self.trinkgeld_data_cache and os.path.exists(self.trinkgeld_data_file):
            try:
                if os.path.getsize(self.trinkgeld_data_file) > 10:
                    print("SICHERHEITS-STOPP: Trinkgeld-Datei wird nicht mit leerem Cache überschrieben.")
                    return
            except OSError:
                pass
        try:
            data_dir = os.path.dirname(self.trinkgeld_data_file)
            if not os.path.exists(data_dir):
                os.makedirs(data_dir, exist_ok=True)
            with open(self.trinkgeld_data_file, 'w', encoding='utf-8') as f:
                # Use ensure_ascii=False to correctly save non-ASCII characters (like €)
                json.dump(self.trinkgeld_data_cache, f, indent=2, ensure_ascii=False)
        except IOError as e:
            # messagebox.showerror("Speicherfehler", f"Trinkgeld-Daten konnten nicht gespeichert werden: {e}", parent=self.master) # Avoid messagebox on autosave
            print(f"IOError saving Trinkgeld data: {e}")
        except Exception as e:
            # messagebox.showerror("Fehler", f"Ein unerwarteter Fehler ist beim Speichern der Trinkgeld-Daten aufgetreten: {e}", parent=self.master) # Avoid messagebox on autosave
            print(f"Unexpected error saving Trinkgeld data: {e}")






        
            










        
            









        
            










        
            










        
            










        
            









        
            









        
            









        
            









        
            








        
            








        
            









        
            









        
            









        
            









        
            









        
            









        
            








        
            









        
            









        
            









        
            









        
            









        
            








        
            









        
            









        
            






        


    def _handle_add_trinkgeld_entry(self):
        m = self.current_trinkgeld_month_var.get()
        y = self.current_trinkgeld_year_var.get()
        if not m or not y: return
        period_key = f"{int(y):04d}-{int(m):02d}"
        
        entries = self.trinkgeld_data_cache.get(period_key, [])
        prev_total = 0.0
        if entries:
            entries.sort(key=lambda x: x.get('datum', ''))
            prev_total = entries[-1].get('gesamt', 0.0)
            
        dlg = TrinkgeldEntryDialog(self.master, self, previous_day_total=prev_total)
        new_data = dlg.show()
        
        if new_data:
            self.trinkgeld_data_cache.setdefault(period_key, []).append(new_data)
            
            # 1. Speichern
            self._save_trinkgeld_data()
            
            # 2. Backup erstellen (Automatisch)
            self._perform_manual_backup_trinkgeld(ask_confirmation=False)
            
            self._save_list_entry_to_history(new_data, "Hinzugefügt", "Trinkgeld")
            self._load_and_display_trinkgeld_for_period()
            SuccessToast(self.master, "Gespeichert", "Eintrag hinzugefügt und gesichert.", "success")

    def _handle_edit_trinkgeld_entry(self, event=None):
        sel = self.trinkgeld_tree.selection()
        if not sel: return
        date_id = sel[0]
        
        m = self.current_trinkgeld_month_var.get()
        y = self.current_trinkgeld_year_var.get()
        period_key = f"{int(y):04d}-{int(m):02d}"
        entries = self.trinkgeld_data_cache.get(period_key, [])
        
        entry = next((e for e in entries if e.get('datum') == date_id), None)
        if not entry: return
        
        dlg = TrinkgeldEntryDialog(self.master, self, entry_data=entry.copy())
        upd = dlg.show()
        
        if upd:
            idx = entries.index(entry)
            entries[idx] = upd
            
            # 1. Speichern
            self._save_trinkgeld_data()
            
            # 2. Backup erstellen (Automatisch)
            self._perform_manual_backup_trinkgeld(ask_confirmation=False)
            
            self._save_list_entry_to_history(upd, "Bearbeitet", "Trinkgeld")
            self._load_and_display_trinkgeld_for_period()
            SuccessToast(self.master, "Aktualisiert", "Eintrag bearbeitet und gesichert.", "success")

    def _handle_delete_trinkgeld_entry(self):
        selected = self.trinkgeld_tree.selection()
        if not selected:
            SuccessToast(self.master, "Keine Auswahl", "Bitte wählen Sie einen Eintrag zum Löschen.", "warning")
            return
        
        if not messagebox.askyesno("Löschen", "Wollen Sie diesen Eintrag wirklich unwiderruflich löschen?"):
            return
        
        month_str = self.current_trinkgeld_month_var.get()
        year_str = self.current_trinkgeld_year_var.get()
        period_key = f"{int(year_str):04d}-{int(month_str):02d}"
        
        entries = self.trinkgeld_data_cache.get(period_key, [])
        
        # Eintrag für den Verlauf sichern, bevor er gelöscht wird
        for item_id in selected:
            entry = next((e for e in entries if e.get('datum') == item_id), None)
            if entry: 
                self._save_list_entry_to_history(entry, "Gelöscht", "Trinkgeld")
            
        # Daten filtern (Eintrag entfernen)
        self.trinkgeld_data_cache[period_key] = [e for e in entries if e.get('datum') not in selected]
        
        # 1. Speichern
        self._save_trinkgeld_data()
        
        # 2. Backup erstellen (Automatisch, ohne Nachfrage)
        self._perform_manual_backup_trinkgeld(ask_confirmation=False)
        
        # 3. UI aktualisieren
        self._load_and_display_trinkgeld_for_period()
        SuccessToast(self.master, title="Gelöscht", message="Eintrag gelöscht und Backup erstellt.", toast_type='success', colors=self.current_settings.get('toast_colors'))
            
    def _load_and_display_minibar_for_period(self):
        """Loads Minibar data for the selected period and displays it in the treeview."""
        # Ensure the treeview widget exists
        if not hasattr(self, 'minibar_tree') or not self.minibar_tree or not self.minibar_tree.winfo_exists():
            # print("Warning: Minibar treeview not available for display update.")
            return 

        month_str = self.current_minibar_month_var.get()
        year_str = self.current_minibar_year_var.get()

        if not month_str or not year_str:
             # If no period selected, clear treeview and summary.
             for item in self.minibar_tree.get_children(): self.minibar_tree.delete(item)
             self.minibar_total_umsatz_display_var.set(self._format_decimal_for_display(decimal.Decimal('0.00')))
             return 
        
        try:
            month = int(month_str)
            year = int(year_str)
             # Validate month and year range
            if not (1 <= month <= 12) or year < 1900 or year > 2200: # Basic validation
                 raise ValueError("Month or year out of range")

        except ValueError:
            messagebox.showerror("Fehler", "Ungültiger Monat oder Jahr ausgewählt.", parent=self.master)
            # Clear treeview and summary on error
            for item in self.minibar_tree.get_children(): self.minibar_tree.delete(item)
            self.minibar_total_umsatz_display_var.set(self._format_decimal_for_display(decimal.Decimal('0.00')))
            return

        period_key = f"{year:04d}-{month:02d}"
        
        # Clear the current contents of the treeview
        for item in self.minibar_tree.get_children(): self.minibar_tree.delete(item)

        # Get the entries for the selected period from the cache. Default to empty list if key not found.
        entries_for_period = self.minibar_data_cache.get(period_key, [])
        
        # Sort entries by date and then article name
        # Ensure 'datum' and 'artikel_name' keys exist for sorting
        entries_for_period.sort(key=lambda x: (x.get("datum", ""), x.get("artikel_name", "")))

        # Insert entries into the treeview
        for entry in entries_for_period:
            try:
                # Format date for display (e.g., DD.MM.YYYY)
                display_datum = datetime.datetime.strptime(entry.get("datum", ""), "%Y-%m-%d").strftime("%d.%m.%Y")
            except ValueError:
                display_datum = entry.get("datum", "Ungültiges Datum") # Fallback for invalid dates

            # Prepare the values tuple for the treeview row
            values_tuple = (
                display_datum,
                entry.get("artikel_name", ""), # Use get() with default empty string
                str(int(entry.get("menge", 0))), # Use get() with default 0, convert to string
                str(int(entry.get("verlust_anzahl", 0))), # Use get() with default 0, convert to string
                self._format_decimal_for_display(decimal.Decimal(str(entry.get("preis_pro_stueck", 0.0)))), # Format price
                self._format_decimal_for_display(decimal.Decimal(str(entry.get("gesamt_umsatz", 0.0)))), # Format total
            )
            # Insert the row. Use the unique 'id' as the treeview item ID for easy lookup during edit/delete.
            # If the 'id' is missing (for older data), generate a fallback ID.
            item_id = entry.get("id", f"invalid-id-{uuid.uuid4().hex}") 
            self.minibar_tree.insert("", "end", values=values_tuple, iid=item_id)

        # After displaying, update the total Umsatz for the selected month (used in Kassenabschluss)
        self._calculate_current_month_minibar_umsatz()
        # Also trigger a full calculation update in the main app to reflect the Minibar Total in the dashboard/KA
        self._update_all_calculations(called_by_button=False)


