    def _handle_edit_minibar_entry(self, event=None):
        """Opens dialog to edit the selected Minibar entry."""
        selected_item_ids = self.minibar_tree.selection()
        
        if not selected_item_ids:
            SuccessToast(self.master, 
                         title="Keine Auswahl getroffen", 
                         message="Bitte wählen Sie zuerst einen Eintrag aus der Liste aus.", 
                         toast_type='warning', 
                         colors=self.current_settings.get('toast_colors'))
            return

        selected_item_id = selected_item_ids[0]

        entry_to_edit = None
        period_key_of_entry = None
        index_of_entry = -1

        for year_month, entries in list(self.minibar_data_cache.items()):
            for i, entry in enumerate(entries):
                if entry.get("id") == selected_item_id:
                    entry_to_edit = entry
                    period_key_of_entry = year_month
                    index_of_entry = i
                    break
            if entry_to_edit: break

        if not entry_to_edit:
            messagebox.showerror("Fehler", "Ausgewählter Eintrag nicht in Daten gefunden.", parent=self.master)
            return

        minibar_item_defs = self.current_settings.get("minibar_items", [])
        dialog = MinibarEntryDialog(self.master, self, entry_data=entry_to_edit.copy(), minibar_items_definitions=minibar_item_defs)
        result = dialog.show()

        if result:
            old_period_key = period_key_of_entry
            
            try:
                new_entry_date_obj = datetime.datetime.strptime(result.get("datum", ""), '%Y-%m-%d').date()
                new_period_key = new_entry_date_obj.strftime("%Y-%m")
            except ValueError:
                 messagebox.showerror("Fehler", f"Ungültiges Datumsformat im Dialog erfasst: {result.get('datum')}", parent=self.master)
                 self._load_and_display_minibar_for_period() 
                 return

            if old_period_key == new_period_key:
                 self.minibar_data_cache[old_period_key][index_of_entry] = result 
            else: 
                 print(f"Warning: Minibar entry period changed from {old_period_key} to {new_period_key} during edit. Moving entry.")
                 if old_period_key in self.minibar_data_cache and len(self.minibar_data_cache[old_period_key]) > index_of_entry:
                      removed_entry = self.minibar_data_cache[old_period_key].pop(index_of_entry) 
                      if not self.minibar_data_cache[old_period_key]: 
                           del self.minibar_data_cache[old_period_key]
                 else:
                      print(f"Error: Could not remove entry {selected_item_id} from old period {old_period_key} at index {index_of_entry}.")
                 self.minibar_data_cache.setdefault(new_period_key, []).append(result) 

            self._save_minibar_data()
            self._perform_manual_backup_minibar(ask_confirmation=False)
            self._save_list_entry_to_history(result, "Bearbeitet", "Minibar")
            self._load_and_display_minibar_for_period()

            SuccessToast(self.master, 
                         title="Aktualisiert & Gesichert", 
                         message="Der Eintrag wurde aktualisiert und die Sicherung wurde erneuert.", 
                         toast_type='success', 
                         colors=self.current_settings.get('toast_colors'))


    def _on_minibar_item_double_click(self, event=None):
        """Handler for double-clicking an item in the Minibar treeview. Opens edit dialog."""
        # This method is called by the treeview bind. It essentially just calls _handle_edit_minibar_entry.
        # Passing the event might be useful for _handle_edit_minibar_entry to check if it was a double-click.
        self._handle_edit_minibar_entry(event)

