    def _save_minibar_data(self):
        """
        Saves the Minibar data cache to its JSON file using an atomic write process
        to prevent data corruption during concurrent access.
        """
        # Define the path for the temporary file
        temp_file_path = self.minibar_data_file + ".tmp"
        
        try:
            # Ensure the target directory exists.
            data_dir = os.path.dirname(self.minibar_data_file)
            if not os.path.exists(data_dir):
                os.makedirs(data_dir, exist_ok=True)

            # Step 1: Write the data to a new temporary file.
            with open(temp_file_path, 'w', encoding='utf-8') as f:
                json.dump(self.minibar_data_cache, f, indent=2, ensure_ascii=False)

            # Step 2: Atomically replace the old file with the new one.
            # This is an uninterruptible operation on most operating systems.
            os.replace(temp_file_path, self.minibar_data_file)

        except Exception as e:
            print(f"Error saving Minibar data atomically: {e}")
        finally:
            # Step 3: Ensure the temporary file is deleted, even if an error occurred.
            if os.path.exists(temp_file_path):
                try:
                    os.remove(temp_file_path)
                except OSError as e:
                    print(f"Error cleaning up temporary file '{temp_file_path}': {e}")

    
