    def _load_weckruf_data(self):
        """Lädt die Weckrufdaten aus der JSON-Datei in den Cache."""
        if os.path.exists(self.weckruf_data_file):
            try:
                with open(self.weckruf_data_file, 'r', encoding='utf-8') as f:
                    self.weckruf_data_cache = json.load(f)
                    if not isinstance(self.weckruf_data_cache, list):
                        print("Warnung: Weckrufdaten sind keine Liste. Werden zurückgesetzt.")
                        self.weckruf_data_cache = []
            # --- KORREKTUR START ---
            except (json.JSONDecodeError, IOError) as e:
                print(f"Fehler beim Laden der Weckrufdaten: {e}")
                self.weckruf_data_cache = []
            # --- KORREKTUR ENDE ---
        else:
            self.weckruf_data_cache = []

    def _save_weckruf_data(self):
        """Speichert den Weckruf-Cache in die JSON-Datei."""
        try:
            data_dir = os.path.dirname(self.weckruf_data_file)
            if not os.path.exists(data_dir):
                os.makedirs(data_dir, exist_ok=True)
            with open(self.weckruf_data_file, 'w', encoding='utf-8') as f:
                json.dump(self.weckruf_data_cache, f, indent=2, ensure_ascii=False)
        except Exception as e:
            print(f"Fehler beim Speichern der Weckrufdaten: {e}")
    # +++ ENDE: NEUER CODEBLOCK FÜR WECKRUF-DATENHANDHABUNG +++


    def _load_minibar_data(self):
        """Lädt Minibar-Daten und repariert beschädigte Einträge, statt sie zu löschen."""
        if os.path.exists(self.minibar_data_file):
            try:
                with open(self.minibar_data_file, 'r', encoding='utf-8') as f:
                    loaded_data = json.load(f)
                    
                if not isinstance(loaded_data, dict):
                    print("Warnung: Minibar-Datei-Format ungültig. Cache wird nicht überschrieben.")
                    return

                new_cache = {}
                for period_key, entries in loaded_data.items():
                    if not isinstance(entries, list):
                        continue
                    
                    valid_entries = []
                    for entry in entries:
                        if not isinstance(entry, dict):
                            continue
                        
                        # REPAIR-MODUS: Fehlende Felder ergänzen statt Eintrag löschen
                        entry['id'] = str(entry.get('id', uuid.uuid4().hex))
                        entry['datum'] = str(entry.get('datum', '1970-01-01'))
                        entry['artikel_name'] = str(entry.get('artikel_name', 'Unbekannter Artikel'))
                        
                        # Numerische Werte sicherstellen
                        for field in ["menge", "verlust_anzahl", "preis_pro_stueck", "gesamt_umsatz"]:
                            try:
                                entry[field] = float(entry.get(field, 0.0))
                            except (ValueError, TypeError):
                                entry[field] = 0.0
                        
                        valid_entries.append(entry)
                    
                    if valid_entries:
                        new_cache[period_key] = valid_entries
                
                # Nur wenn wir valide Daten gefunden haben oder die Datei wirklich leer war, 
                # aktualisieren wir den Cache
                if new_cache or not loaded_data:
                    self.minibar_data_cache = new_cache
                    print("Minibar-Daten erfolgreich geladen und validiert.")

            except (json.JSONDecodeError, IOError) as e:
                print(f"Kritischer Ladefehler Minibar: {e}. Ladevorgang abgebrochen, um Datenstand zu schützen.")

    def _save_minibar_data(self):
        """Speichert Daten atomar und verhindert das Löschen durch leere Datensätze."""
        temp_file_path = self.minibar_data_file + ".tmp"
        
        # SICHERHEITSPRÜFUNG: Wenn Cache leer, aber Datei existiert und Inhalt hat -> ABBRUCH
        if not self.minibar_data_cache and os.path.exists(self.minibar_data_file):
            if os.path.getsize(self.minibar_data_file) > 10: # Mehr als nur "{}"
                print("SICHERHEITS-STOPP: Versuch, Minibar-Datei mit leerem Cache zu überschreiben, wurde blockiert.")
                return

        try:
            data_dir = os.path.dirname(self.minibar_data_file)
            os.makedirs(data_dir, exist_ok=True)

            with open(temp_file_path, 'w', encoding='utf-8') as f:
                json.dump(self.minibar_data_cache, f, indent=2, ensure_ascii=False)

            os.replace(temp_file_path, self.minibar_data_file)
        except Exception as e:
            print(f"Fehler beim atomaren Speichern der Minibar: {e}")
        finally:
            if os.path.exists(temp_file_path):
                os.remove(temp_file_path)
            
            
    
