            pdf.set_font(pdf_font_family_name, "B", 16); pdf.set_fill_color(*hex_to_rgb(self.current_settings.get('overall_header_bg', '#FF9933'))); pdf.set_text_color(*hex_to_rgb(self.current_settings.get('overall_header_fg', '#000000')))
