    # +++ NEUE METHODEN FÜR DEN VERLAUF DER LISTEN-TABS +++
    def _open_trinkgeld_history_dialog(self):
        self._open_generic_list_history_dialog(
            "Trinkgeld",
            self.trinkgeld_history_file,
            self._get_trinkgeld_history_summary_line,
            self._restore_trinkgeld_from_history
        )

    def _open_minibar_history_dialog(self):
        self._open_generic_list_history_dialog(
            "Minibar",
            self.minibar_history_file,
            self._get_minibar_history_summary_line,
            self._restore_minibar_from_history
        )

    def _save_list_entry_to_history(self, entry_data, action, list_type):
        history_file = None
        if list_type == "Trinkgeld":
            history_file = self.trinkgeld_history_file
        elif list_type == "Minibar":
            history_file = self.minibar_history_file
        
         # +++ START: NEUER FALL FÜR SHUTTLE +++
        elif list_type == "Shuttle":
            history_file = self.shuttle_history_file
        # +++ ENDE: NEUER FALL FÜR SHUTTLE +++
        
        
          # vvvvv HIER DEN NEUEN BLOCK EINFÜGEN vvvvv
        elif list_type == "Weckruf":
            history_file = self.weckruf_history_file
        # ^^^^^ ENDE DES NEUEN BLOCKS ^^^^^
        
        
           # vvvvv HIER DEN NEUEN `elif`-BLOCK EINFÜGEN vvvvv
        elif list_type == "Taxi":
            history_file = self.taxi_history_file
        # ^^^^^ ENDE DES NEUEN BLOCKS ^^^^^
        
        elif list_type == "Tischreservierung":
            history_file = self.tischreservierung_history_file
        
        
        
               # vvvvv HIER IST DIE ERGÄNZUNG vvvvv
        elif list_type == "Überstundenantrag":
            history_file = self.ueberstundenantrag_history_file
        # ^^^^^ ENDE DER ERGÄNZUNG ^^^^^
        
        
         # vvvvv HIER IST DIE KORREKTUR vvvvv
        elif list_type == "Anrufliste":
            history_file = self.anrufliste_history_file
        # ^^^^^ ENDE DER KORREKTUR ^^^^^
        
        
        if history_file is None:
            # Don't save "System" or other unknown types to these specific history files
            return

        history_data = []
        if os.path.exists(history_file):
            try:
                with open(history_file, 'r', encoding='utf-8') as f:
                    history_data = json.load(f)
            except (json.JSONDecodeError, IOError):
                history_data = []

        snapshot = {
            "timestamp": datetime.datetime.now().isoformat(),
            "action": action,
            "data": entry_data
        }
        history_data.insert(0, snapshot)
        history_data = history_data[:self.max_history_entries]

        try:
            with open(history_file, 'w', encoding='utf-8') as f:
                json.dump(history_data, f, indent=2)
        except IOError as e:
            print(f"Error saving {list_type} history: {e}")
            
    def _get_trinkgeld_history_summary_line(self, snapshot):
        data = snapshot.get('data')
        action = snapshot.get('action', 'Unbekannte Aktion')
        if data is None:
            return f"[{action}]"
            
        datum = data.get('datum', 'Unbekannt')
        try:
            display_datum = datetime.datetime.strptime(datum, "%Y-%m-%d").strftime("%d.%m.%y")
        except ValueError:
            display_datum = datum
        e_f = data.get('einnahme_frueh', 0)
        e_s = data.get('einnahme_spaet', 0)
        gesamt = data.get('gesamt', 0)
        return f"[{action}] {display_datum} - EF: {e_f:.2f}, ES: {e_s:.2f}, Gesamt: {gesamt:.2f}"

    def _get_minibar_history_summary_line(self, snapshot):
        data = snapshot.get('data')
        action = snapshot.get('action', 'Unbekannte Aktion')
        if data is None:
            return f"[{action}]"
        
        datum = data.get('datum', 'Unbekannt')
        try:
            display_datum = datetime.datetime.strptime(datum, "%Y-%m-%d").strftime("%d.%m.%y")
        except ValueError:
            display_datum = datum
        artikel = data.get('artikel_name', 'Unbekannt')
        menge = data.get('menge', 0)
        verlust = data.get('verlust_anzahl', 0)
        preis = data.get('preis_pro_stueck', 0)
        umsatz = data.get('gesamt_umsatz', 0)
        return f"[{action}] {display_datum} {artikel} – {int(menge)} Stk – {int(verlust)} Verlust – {preis:.2f}€/Stk – {umsatz:.2f}€ Umsatz"

    def _restore_trinkgeld_from_history(self, history_dialog):
        # Greift auf die im Dialog gespeicherte Listbox und Daten zu
        listbox = history_dialog.listbox_widget
        all_snapshots = history_dialog.displayed_snapshots
        selected_indices = listbox.curselection()

        if not selected_indices:
            messagebox.showwarning("Keine Auswahl", "Bitte mindestens einen Eintrag zum Wiederherstellen auswählen.", parent=history_dialog)
            return

        if not messagebox.askyesno("Wiederherstellen",
                                   f"{len(selected_indices)} Trinkgeld-Eintrag/Einträge wirklich wiederherstellen?",
                                   parent=history_dialog):
            return

        restored_count = 0
        for index in selected_indices:
            entry_to_restore = all_snapshots[index].get('data')
            if entry_to_restore:
                period_key = entry_to_restore['datum'][:7]
                self.trinkgeld_data_cache.setdefault(period_key, []).append(entry_to_restore)
                restored_count += 1
        
        if restored_count > 0:
            # Nach der Schleife: Duplikate entfernen und sortieren
            for period_key in self.trinkgeld_data_cache:
                # Verwendet das Datum als eindeutigen Schlüssel, um Duplikate zu entfernen
                unique_entries = {e['datum']: e for e in self.trinkgeld_data_cache[period_key]}.values()
                self.trinkgeld_data_cache[period_key] = sorted(list(unique_entries), key=lambda x: x['datum'])
            
            self._save_trinkgeld_data()
            self._load_and_display_trinkgeld_for_period()
            
            # Erfolgsmeldung anzeigen
            SuccessToast(self.master, title="Erfolg", message=f"{restored_count} Datensätze wurden wiederhergestellt.", toast_type='success', colors=self.current_settings.get('toast_colors'))
        
        history_dialog.destroy()

    def _restore_minibar_from_history(self, history_dialog):
        # Greift auf die im Dialog gespeicherte Listbox und Daten zu
        listbox = history_dialog.listbox_widget
        all_snapshots = history_dialog.displayed_snapshots
        selected_indices = listbox.curselection()

        if not selected_indices:
            messagebox.showwarning("Keine Auswahl", "Bitte mindestens einen Eintrag zum Wiederherstellen auswählen.", parent=history_dialog)
            return

        if not messagebox.askyesno("Wiederherstellen",
                                   f"{len(selected_indices)} Minibar-Eintrag/Einträge wirklich wiederherstellen?",
                                   parent=history_dialog):
            return

        restored_count = 0
        for index in selected_indices:
            entry_to_restore = all_snapshots[index].get('data')
            if entry_to_restore:
                period_key = entry_to_restore['datum'][:7]
                self.minibar_data_cache.setdefault(period_key, []).append(entry_to_restore)
                restored_count += 1

        if restored_count > 0:
            # Nach der Schleife: Duplikate anhand der ID entfernen und sortieren
            for period_key in self.minibar_data_cache:
                unique_entries = {e['id']: e for e in self.minibar_data_cache[period_key]}.values()
                self.minibar_data_cache[period_key] = sorted(list(unique_entries), key=lambda x: (x['datum'], x['artikel_name']))

            self._save_minibar_data()
            self._load_and_display_minibar_for_period()

            # Erfolgsmeldung anzeigen
            SuccessToast(self.master, title="Erfolg", message=f"{restored_count} Datensätze wurden wiederhergestellt.", toast_type='success', colors=self.current_settings.get('toast_colors'))

        history_dialog.destroy()
    
    
    def _open_generic_list_history_dialog(self, list_type_name, history_file_path, summary_func, restore_func):
        history_data = []
        if os.path.exists(history_file_path):
            try:
                with open(history_file_path, 'r', encoding='utf-8') as f:
                    history_data = json.load(f)
            except (json.JSONDecodeError, IOError):
                history_data = []

        if not history_data:
            messagebox.showinfo("Verlauf", f"Kein Verlauf für {list_type_name} verfügbar.", parent=self.master)
            return

        history_window = tk.Toplevel(self.master)
        history_window.title(f"Verlauf der {list_type_name}")
        history_window.transient(self.master)
        history_window.grab_set()

        listbox_frame = ttk.Frame(history_window, padding=10)
        listbox_frame.pack(fill='both', expand=True)
        
        scrollbar = ttk.Scrollbar(listbox_frame, orient=tk.VERTICAL)
        scrollbar.pack(side='right', fill='y')
        
        # ANPASSUNG: selectmode="extended" für Mehrfachauswahl mit STRG/SHIFT
        listbox = tk.Listbox(listbox_frame, yscrollcommand=scrollbar.set, exportselection=False, selectmode=tk.EXTENDED)
        
        # Wichtig: Referenzen auf die Listbox und die Daten am Fensterobjekt speichern
        history_window.listbox_widget = listbox
        
        displayable_history = []
        for item in history_data:
            displayable_history.append(item)
            ts = datetime.datetime.fromisoformat(item['timestamp']).strftime('%d.%m.%y %H:%M:%S')
            summary = summary_func(item)
            listbox.insert(tk.END, f"{ts} - {summary}")
        
        history_window.displayed_snapshots = displayable_history

        listbox.pack(side='left', fill='both', expand=True)
        scrollbar.config(command=listbox.yview)

        button_frame = ttk.Frame(history_window, padding=(10, 5, 10, 10))
        button_frame.pack(fill='x')

        # KORREKTUR: Der Command übergibt nur noch das Dialogfenster.
        # Die Wiederherstellungsfunktion kümmert sich selbst um die Auswahl.
        restore_btn = ttk.Button(button_frame, text="Wiederherstellen", state='disabled',
                                 command=lambda: restore_func(history_window))
        
        self._configure_dialog_button(restore_btn, 'Dialog_Restore', 'Wiederherstellen')
        restore_btn.pack(side='left', expand=True, padx=2)

        def delete_history_entry():
            selected_indices = listbox.curselection()
            if not selected_indices: return
            if messagebox.askyesno("Löschen", "Ausgewählte Einträge wirklich aus dem Verlauf löschen?", parent=history_window):
                indices_to_delete = sorted(list(selected_indices), reverse=True)
                
                timestamps_to_delete = {displayable_history[i]['timestamp'] for i in indices_to_delete}
                new_master_list = [snap for snap in history_data if snap.get('timestamp') not in timestamps_to_delete]

                with open(history_file_path, 'w', encoding='utf-8') as f:
                    json.dump(new_master_list, f, indent=2)
                history_window.destroy()
                self._open_generic_list_history_dialog(list_type_name, history_file_path, summary_func, restore_func)

        delete_btn = ttk.Button(button_frame, text="Löschen", state='disabled', command=delete_history_entry)
        self._configure_dialog_button(delete_btn, 'Dialog_Delete', 'Löschen')
        delete_btn.pack(side='left', expand=True, padx=2)
        
        cancel_btn = ttk.Button(button_frame, text="Abbrechen", command=history_window.destroy)
        self._configure_dialog_button(cancel_btn, 'Dialog_Cancel', 'Abbrechen')
        cancel_btn.pack(side='left', expand=True, padx=2)

        def on_select(event):
            selections = listbox.curselection()
            # KORREKTUR: Button aktivieren, sobald mindestens ein Eintrag ausgewählt ist.
            can_restore = bool(selections)
            can_delete = bool(selections) and self.is_admin_mode
            
            restore_btn.config(state='normal' if can_restore else 'disabled')
            delete_btn.config(state='normal' if can_delete else 'disabled')

        listbox.bind('<<ListboxSelect>>', on_select)
        if listbox.size() > 0:
            listbox.selection_set(0)
            on_select(None)
        
        self.master.wait_window(history_window)
    
    
    def _populate_pdf(self, pdf):
        """Populates the FPDF object with Kassenprotokoll data for printing/saving the main protocol."""
        # Ensure PDF object is valid
        if not isinstance(pdf, FPDF):
             print("Error: Invalid PDF object provided to _populate_pdf.")
             return

        # Add fonts for UTF-8 support (like €)
        font_dir = resource_path('fonts')
        dejavu_sans_path = os.path.join(font_dir, "DejaVuSans.ttf")
        dejavu_sans_bold_path = os.path.join(font_dir, "DejaVuSans-Bold.ttf")
        pdf_font_family_name = "Helvetica" # Default fallback
        try:
            if os.path.exists(dejavu_sans_path) and os.path.exists(dejavu_sans_bold_path):
                pdf.add_font("DejaVuSans", "", dejavu_sans_path)
                pdf.add_font("DejaVuSans", "B", dejavu_sans_bold_path)
                pdf_font_family_name = "DejaVuSans"
            else:
                 print(f"Warning: DejaVuSans font files not found in {font_dir}. Using default Helvetica.")
        except RuntimeError as e:
            print(f"PDF Font Add Error: {e}. Using default Helvetica.")
            pdf_font_family_name = "Helvetica"
        except Exception as e:
             print(f"Unexpected error adding PDF font: {e}. Using default Helvetica.")
             pdf_font_family_name = "Helvetica"


        pdf.set_auto_page_break(True, margin=15) # Enable auto page breaks with margin
        pdf.add_page() # Start a new page

        # Get colors from settings for PDF styling
        colors_pdf = {
            'header_bg': hex_to_rgb(self.current_settings.get('header_bg', '#D0D0D0')),
            'header_fg': hex_to_rgb(self.current_settings.get('general_font_color', '#000000')),
            'sum_bg': hex_to_rgb(self.current_settings.get('sum_bg', '#E0E0E0')),
            'sum_fg': hex_to_rgb(self.current_settings.get('number_elements_fg_color', '#000000')),
            'data_fg': hex_to_rgb(self.current_settings.get('general_font_color', '#000000')),
            'number_data_fg': hex_to_rgb(self.current_settings.get('number_elements_fg_color', '#000000')),
            'overall_header_bg': hex_to_rgb(self.current_settings.get('overall_header_bg', '#FF9933')),
            'overall_header_fg': hex_to_rgb(self.current_settings.get('overall_header_fg', '#000000')),
            'notes_border_color': hex_to_rgb('#AAAAAA'), # Default border for notes section
        }

        # Helper function to draw a section title in PDF
        def draw_section_title(title_text, font_size=14):

            if pdf.get_y() > pdf.h - 40 : pdf.add_page() # Add page break if not enough space for title + some content
            pdf.set_font(pdf_font_family_name, "B", font_size) # Set font for title
            # Use overall header colors for section titles for consistency
            pdf.set_fill_color(*colors_pdf['overall_header_bg'])
            pdf.set_text_color(*colors_pdf['overall_header_fg'])
            pdf.cell(0, 10, title_text, border=1, new_x=XPos.LMARGIN, new_y=YPos.NEXT, align="C", fill=True) # Draw title cell
            pdf.ln(2) # Add some space after title
            pdf.set_text_color(*colors_pdf['data_fg']) # Reset text color to default data color

        # Helper function to draw a simple table in PDF
        def draw_simple_table(headers, data_rows_with_style_info, col_widths_proportions=None, default_col_aligns=None,
                              header_font_size=10, data_font_size=9):
            num_cols = len(headers)
            page_width = pdf.w - 2 * pdf.l_margin

            # Determine column widths based on proportions or equal distribution
            if col_widths_proportions and len(col_widths_proportions) == num_cols:
                col_widths = [page_width * p for p in col_widths_proportions]
            else:
                # If proportions are not provided or invalid, distribute width equally
                print("Warning: Invalid column width proportions provided for PDF table. Using equal width distribution.")
                col_widths = [(page_width / num_cols) for _ in range(num_cols)]

            # Determine column alignments
            final_col_aligns = default_col_aligns if default_col_aligns and len(default_col_aligns) == num_cols else ['L'] * num_cols

            # Draw table headers
            pdf.set_font(pdf_font_family_name, "B", header_font_size)
            pdf.set_fill_color(*colors_pdf['header_bg'])
            pdf.set_text_color(*colors_pdf['header_fg'])
            for i, header in enumerate(headers):
                pdf.cell(col_widths[i], 7, header, border=1, align='C', fill=True) # Header cells centered
            pdf.ln() # Move to next line

            # Draw data rows
            pdf.set_font(pdf_font_family_name, "", data_font_size)
            pdf.set_text_color(*colors_pdf['data_fg']) # Default data text color

            for row_cells, style_info in data_rows_with_style_info:
                # Check for page break before drawing a row
                if pdf.get_y() > pdf.h - 25 : # Leave space for a couple more lines + padding
                    pdf.add_page()
                    # Redraw headers on the new page
                    pdf.set_font(pdf_font_family_name, "B", header_font_size); pdf.set_fill_color(*colors_pdf['header_bg']); pdf.set_text_color(*colors_pdf['header_fg'])
                    for i_h, header_h in enumerate(headers): pdf.cell(col_widths[i_h], 7, header_h, border=1, align='C', fill=True)
                    pdf.ln()
                    pdf.set_font(pdf_font_family_name, "", data_font_size); pdf.set_text_color(*colors_pdf['data_fg']) # Reset font and color

                is_sum_styled = False; current_font_style = ""
                current_row_text_color = colors_pdf['data_fg']
                current_row_fill_color = (255, 255, 255) # Default fill color (white)

                if style_info:
                    if style_info.get('is_sum'):
                        is_sum_styled = True; current_font_style = "B"
                        current_row_text_color = colors_pdf['sum_fg']
                        current_row_fill_color = colors_pdf['sum_bg'] # Apply sum background color
                    elif 'style_hint' in style_info:
                        hint = style_info['style_hint']
                        # Check style hints that might indicate bold or different text color
                        if any(s in hint for s in ['sum_display', 'bold_display']):
                            current_font_style = "B"
                            current_row_text_color = colors_pdf['number_data_fg'] # Use number color for these
                        elif 'diff_display_auto' in hint:
                            # For difference displays, apply color coding based on value
                            try:
                                # Parse the value (assuming it's the last cell in the row for difference)
                                diff_val_str = str(row_cells[-1]).replace('€','').strip()
                                diff_val = self._parse_input_string(diff_val_str) or decimal.Decimal('0.00')
                                is_zero = abs(diff_val) <= decimal.Decimal('0.0001') # Use a small tolerance for comparisons

                                if is_zero:
                                    # Use PerfectBalance style color if defined, else green
                                    try: current_row_text_color = hex_to_rgb(self.current_settings.get('diff_positive_fg', '#008000')) # Use positive diff color for zero
                                    except: pass # Use default data_fg if hex fails
                                    # Optional: Apply a subtle background for perfect balance
                                    # try: perfect_balance_bg = hex_to_rgb('#E6FFEB')
                                    # except: pass
                                    # else: current_row_fill_color = perfect_balance_bg

                                elif diff_val < 0:
                                    # Use negative difference color (Red)
                                    try: current_row_text_color = hex_to_rgb(self.current_settings.get('diff_negative_fg', '#FF0000'))
                                    except: pass
                                else: # Value is positive
                                    # Use positive difference color (Green)
                                    try: current_row_text_color = hex_to_rgb(self.current_settings.get('diff_positive_fg', '#008000'))
                                    except: pass

                                current_font_style = "B" # Differences are usually bold

                            except Exception as e:
                                print(f"Error determining color for diff cell {row_cells[-1]}: {e}") # Log error, fallback to default color
                                current_row_text_color = colors_pdf['number_data_fg'] # Use number color as fallback for numeric diffs
                                current_font_style = "B"


                # Set font and colors for the current row before drawing cells
                pdf.set_font(pdf_font_family_name, current_font_style, data_font_size)
                pdf.set_text_color(*current_row_text_color)
                pdf.set_fill_color(*current_row_fill_color) # Set fill color (might be default white, sum_bg, or potential perfect_balance_bg)


                for i, cell_text_raw in enumerate(row_cells):
                    cell_text_str = str(cell_text_raw)

                    # Determine text color: number color for numeric columns, default for others
                    # Currently, row color is set once, but we could add cell-specific color logic here.
                    # For consistency with UI, number columns might use number_data_fg unless overridden by diff/sum color.
                    # For now, rely on the row's color set based on the style_info hint or sum status.

                    # Draw the cell
                    # Use `fill=True` if the row is styled with a background color (like sum_bg)
                    pdf.cell(col_widths[i], 6, cell_text_str, border=1, align=final_col_aligns[i], fill=is_sum_styled or (style_info and style_info.get('style_hint') == 'diff_display_auto'))

                pdf.ln() # Move to the next line

            pdf.ln(3) # Add a little extra space after the table
            pdf.set_fill_color(255,255,255) # Reset fill color to white
            pdf.set_text_color(*colors_pdf['data_fg']) # Reset text color to default data color

        # --- Overall Header ---
        pdf.set_font(pdf_font_family_name, "B", 16)
        pdf.set_fill_color(*colors_pdf['overall_header_bg'])
        pdf.set_text_color(*colors_pdf['overall_header_fg'])
        pdf.cell(0, 10, "Kassenprotokoll", border=1, new_x=XPos.LMARGIN, new_y=YPos.NEXT, align="C", fill=True)

        # --- Date ---
        pdf.set_font(pdf_font_family_name, "", 10)
        pdf.set_text_color(*colors_pdf['data_fg'])

        # Get current date formatted according to locale, fallback if needed.
        current_date_for_pdf = ""
        try:
             if locale_set and hasattr(locale, 'nl_langinfo') and locale.nl_langinfo(locale.D_FMT):
                 current_date_for_pdf = datetime.datetime.now().strftime(locale.nl_langinfo(locale.D_FMT))
             else: # Fallback if locale is not set or nl_langinfo is missing
                 current_date_for_pdf = datetime.datetime.now().strftime("%d.%m.%Y")
        except Exception as e:
             print(f"Error formatting date for PDF: {e}. Using basic format.")
             current_date_for_pdf = datetime.datetime.now().strftime("%Y-%m-%d") # Basic fallback


        pdf.cell(0, 7, f"Datum: {current_date_for_pdf}", new_x=XPos.LMARGIN, new_y=YPos.NEXT, align="C"); pdf.ln(5)

        # --- Shift Sections (Frühdienst and Spätdienst) ---
        # We need the *current state* of the variables for both shifts to populate the PDF.
        # The vars_dict (self.fruehdienst_vars, self.spaetdienst_vars) hold the current state.

        shifts_data_to_process = [("Frühdienst", self.fruehdienst_vars, "Frühdienst"), ("Spätdienst", self.spaetdienst_vars, "Spätdienst")]

        for shift_idx, (shift_display_name, vars_dict, shift_name_for_lookup) in enumerate(shifts_data_to_process):
            # Start a new page for the second shift (Spätdienst)
            if shift_idx > 0: pdf.add_page()

            # Draw the section title for the shift
            draw_section_title(f"{shift_display_name} Daten")

            # --- Dashboard/Kassenabschluss Overview Section ---
            pdf.set_font(pdf_font_family_name, "B", 11)
            pdf.cell(0, 8, "Dashboard Übersicht:", new_x=XPos.LMARGIN, new_y=YPos.NEXT, align="L")
            pdf.ln(1)

            # Define the order and labels for Kassenabschluss items in the PDF overview
            # Use the ordering from the settings for consistency
            all_reco_defs_from_settings = self.current_settings.get('kassenabschluss_zeilen_definitionen', [])
            dashboard_items_ordered_for_pdf = sorted([
                d for d in all_reco_defs_from_settings
                if d.get('key') in self.all_dashboard_item_keys and d.get('aktiv', True)
            ], key=lambda x: x.get('reihenfolge', 999))


            k_abschluss_vars_for_shift = self.kassenabschluss_wert_vars.get(shift_name_for_lookup, {}) # Get the KA vars for the current shift

            # Define column widths for the key-value list in the overview
            col1_width_overview = (pdf.w - 2 * pdf.l_margin) * 0.3 # Adjust width proportions for A4 portrait
            col2_width_overview = (pdf.w - 2 * pdf.l_margin) * 0.7 # Value column takes remaining width

            pdf.set_font(pdf_font_family_name, "", 9) # Font for overview items

            for reco_item_def in dashboard_items_ordered_for_pdf:
                k_key = reco_item_def.get('key')
                label_text = reco_item_def.get('label', k_key) # Get label from definition

                value_str = "N/A" # Default value display if data missing

                # Get the value from the Kassenabschluss StringVar for this key and shift
                if k_key and k_key in k_abschluss_vars_for_shift:
                    value_str = self._get_tk_var_value_safely(k_abschluss_vars_for_shift[k_key], "N/A")

                # Determine font style for the label based on style hint
                label_font_style = ""
                style_hint = reco_item_def.get('style')
                if style_hint in ['sum_display', 'diff_display_auto', 'bold_display']:
                     label_font_style = "B" # Use bold font for label


                pdf.set_font(pdf_font_family_name, label_font_style, 9) # Set font for the label cell
                pdf.cell(col1_width_overview, 6, label_text, border=0, align="L") # Draw label cell

                pdf.set_font(pdf_font_family_name, "", 9) # Set font for the value cell
                pdf.cell(col2_width_overview, 6, value_str, border=0, new_x=XPos.LMARGIN, new_y=YPos.NEXT, align="R") # Draw value cell

            pdf.ln(3) # Add space after the overview


            # --- Bargeldzählung Section for PDF ---
            pdf.set_font(pdf_font_family_name, "B", 11); pdf.cell(0, 8, "Bargeldzählung:", new_x=XPos.LMARGIN, new_y=YPos.NEXT, align="L"); pdf.ln(1)

            # Table headers and column properties for Cash section
            _PDF_CASH_HEADERS = ["Anzahl", "Scheine/Münzen", "Betrag (€)"] # Add currency symbol to header
            cash_col_props = [0.25, 0.45, 0.30]; cash_col_aligns = ['R', 'L', 'R'];

            cash_data_rows_styled = [] # List to hold rows (cell data, style info)

            # Get active cash denominations from the shift's vars_dict (reflects settings)
            active_cash_denoms = vars_dict.get('cash_denominations', [])

            # Get references to the necessary dictionaries in the shift's vars_dict
            cash_counts_sub_dict = vars_dict.get('cash_counts', {})
            cash_amounts_display_sub_dict = vars_dict.get('cash_amounts_display', {})

            # Iterate through active denominations to build data rows
            for denom_val in active_cash_denoms:
                denom_dec = decimal.Decimal(str(denom_val)) # Convert denomination value to Decimal

                # Format denomination label appropriately (€ vs integer value)
                denom_label = f"{int(denom_dec)} €" if denom_dec >= 1 else f"{locale.format_string('%.2f', denom_dec, grouping=False).replace('.', ',')} €"

                # Get the values from the Tkinter variables for this denomination
                count_tk_var = cash_counts_sub_dict.get(denom_val)
                amount_tk_var = cash_amounts_display_sub_dict.get(denom_val)

                # Get string values from Tkinter variables, with default fallbacks
                count_str_val = self._get_tk_var_value_safely(count_tk_var, "0")
                amount_str_val = self._get_tk_var_value_safely(amount_tk_var, "0,00 €")

                # Determine what to display in the "Anzahl" column ( '-' for coins < 5€, count for others)
                count_str_display = "-" if denom_val < 5.0 else count_str_val
                # The amount string should already be formatted currency from UI variables
                amount_str_display = amount_str_val

                  # Add the row data and no specific style info (default row style)
                cash_data_rows_styled.append(([count_str_display, denom_label, amount_str_display], None))

            # Add the total sum row for Bargeld
              # Get the total
            sum_tk_var = vars_dict.get('cash_sum_display')
            cash_sum_str = self._get_tk_var_value_safely(sum_tk_var, "0,00 €")

            # Add the sum row data and style info indicating it's a sum row
            cash_data_rows_styled.append((["", "Summe Bargeld:", cash_sum_str], {'is_sum': True}))

            # Draw the Cash table using the helper function
            draw_simple_table(_PDF_CASH_HEADERS, cash_data_rows_styled, cash_col_props, cash_col_aligns)


            # --- Briefmarkenbestand Section for PDF ---
            pdf.set_font(pdf_font_family_name, "B", 11); pdf.cell(0, 8, "Briefmarkenbestand:", new_x=XPos.LMARGIN, new_y=YPos.NEXT, align="L"); pdf.ln(1)

            # Table headers and column properties for Stamps section
            _PDF_STAMP_HEADERS = ["Anzahl", "Label", "Preis (€)", "Betrag (€)"]
            stamp_col_props = [0.15, 0.45, 0.20, 0.20]; stamp_col_aligns = ['R', 'L', 'R', 'R'];

            stamp_data_rows_styled = [] # List to hold rows (cell data, style info)

            # Get active stamp definitions from the shift's vars_dict (reflects settings)
            active_stamp_defs = vars_dict.get('stamp_definitions', [])

            # Get references to the necessary dictionaries in the shift's vars_dict
            stamp_counts_sub_dict = vars_dict.get('stamp_counts', {})
            stamp_price_input_sub_dict = vars_dict.get('stamp_price_input', {})
            stamp_amounts_display_sub_dict = vars_dict.get('stamp_amounts_display', {})

            # Iterate through active stamp definitions to build data rows
            for stamp_def in active_stamp_defs:
                price_key_float = float(stamp_def.get('price', 0.0)); label = stamp_def.get('label', f"{stamp_def.get('price', 0.0):.2f} €")
                if not isinstance(price_key_float, (int, float)) or price_key_float <= 0:
                    print(f"Warning: Invalid stamp definition price: {stamp_def}. Skipping.")
                    continue # Skip invalid definitions

                # Get the values from the Tkinter variables for this stamp definition
                count_tk_var = stamp_counts_sub_dict.get(price_key_float)
                price_tk_var = stamp_price_input_sub_dict.get(price_key_float)
                amount_tk_var = stamp_amounts_display_sub_dict.get(price_key_float)

                # Get string values from Tkinter variables, with default fallbacks
                count_str_display = self._get_tk_var_value_safely(count_tk_var, "0")
                price_str_display = self._get_tk_var_value_safely(price_tk_var, "0,00 €")
                amount_str_display = self._get_tk_var_value_safely(amount_tk_var, "0,00 €")

                # Add the row data and no specific style info (default row style)
                stamp_data_rows_styled.append(([count_str_display, label, price_str_display, amount_str_display], None))

            # Add the total sum row for Briefmarken
            # Get the total sum display string from the variable
            stamp_sum_tk_var = vars_dict.get('stamp_sum_display')
            stamp_sum_str = self._get_tk_var_value_safely(stamp_sum_tk_var, "0,00 €")

            # Add the sum row data and style info indicating it's a sum row
            stamp_data_rows_styled.append((["", "", "Summe Briefmarken:", stamp_sum_str], {'is_sum': True}))

            # Draw the Stamps table using the helper function
            draw_simple_table(_PDF_STAMP_HEADERS, stamp_data_rows_styled, stamp_col_props, stamp_col_aligns)


            # --- Kartenzahlungen Section for PDF ---
            # Get active card types from the shift's vars_dict (reflects settings)
            active_card_keys = vars_dict.get('card_type_keys', [])
            # Get the number of reception fields from settings
            num_reception_fields_pdf = self.current_settings.get('reception_fields_count', 3)

            # Table headers and column properties for Card sections (simple key-value list format)
            _PDF_CARD_TABLE_HEADERS = ["Posten", "Betrag (€)"]
            card_col_props = [0.65, 0.35]; card_col_aligns = ['L', 'R']

            # Get references to the necessary dictionaries in the shift's vars_dict
            card_data_main_dict = vars_dict.get('card_data', {})
            card_display_info_main_dict = vars_dict.get('card_display_info', {})


            # Iterate through active card keys to draw tables for each card type
            for card_key in active_card_keys:
                # Ensure card data exists for this key
                card_data_for_key = card_data_main_dict.get(card_key, {})
                if not card_data_for_key:
                    print(f"Warning: Card data missing for key '{card_key}' when populating PDF.")
                    continue # Skip if card data is missing

                # Get the display label for the card type
                card_label_display = card_display_info_main_dict.get(card_key, {}).get('label', card_key)

                # Draw the section title for this card type
                pdf.set_font(pdf_font_family_name, "B", 11); pdf.cell(0, 8, f"Kartenzahlungen - {card_label_display} CP:", new_x=XPos.LMARGIN, new_y=YPos.NEXT, align="L"); pdf.ln(1)

                card_table_data_styled = [] # List to hold rows (cell data, style info) for this card table

                 # Add rows specific to the shift type (Frühdienst or Spätdienst)
                if shift_name_for_lookup == "Frühdienst":
                    # Frühdienst Manual Total
                    manual_total_tk_var = card_data_for_key.get('manual_total_input')
                    manual_total_str = self._get_tk_var_value_safely(manual_total_tk_var, "0,00 €")
                    # Add row data and style info indicating it's a sum row (like in UI)
                    card_table_data_styled.append(([f"{card_label_display} Gesamt:", manual_total_str], {'is_sum': True}))
                
                elif shift_name_for_lookup == "Spätdienst":
                    # Spätdienst Specific Rows (Frühdienst Sum, Spätdienst Sum, Combined Sum)
                    fd_sum_tk_var = card_data_for_key.get('fruehdienst_sum_input'); sd_sum_tk_var = card_data_for_key.get('spaetdienst_sum_input'); combined_sum_tk_var = card_data_for_key.get('combined_sum_display')

                    # Get values with fallbacks
                    fd_sum_str = self._get_tk_var_value_safely(fd_sum_tk_var, "0,00 €")
                    sd_sum_str = self._get_tk_var_value_safely(sd_sum_tk_var, "0,00 €")
                    combined_sum_str = self._get_tk_var_value_safely(combined_sum_tk_var, "0,00 €")

                    # Add rows for FD Sum, SD Sum, and Combined Sum (styled as sum)
                    card_table_data_styled.extend([
                        ([f"{card_label_display} Frühdienst:", fd_sum_str], None), # Not a sum row technically, but part of the sums group
                        ([f"{card_label_display} Spätdienst:", sd_sum_str], None), # Not a sum row technically
                        (["Summe (FD+SD):", combined_sum_str], {'is_sum': True}) # This is the total sum
                    ])

                # Add rows for Reception fields (common for both shifts)
                for i_rec in range(1, num_reception_fields_pdf + 1):
                    rec_tk_var = card_data_for_key.get(f'reception{i_rec}');
                    rec_val_str = self._get_tk_var_value_safely(rec_tk_var, "0,00 €")
                    card_table_data_styled.append(([f"Rezeption {i_rec}:", rec_val_str], None))

                # Add rows for Abgebucht (Sum of Receptions) and Differenz (Calculated Difference)
                actual_debit_tk_var = card_data_for_key.get('actual_debit_input'); difference_tk_var = card_data_for_key.get('difference_display')

                # Get values with fallbacks
                actual_debit_str = self._get_tk_var_value_safely(actual_debit_tk_var, "0,00 €")
                difference_str = self._get_tk_var_value_safely(difference_tk_var, "0,00 €")

                # Add rows for Abgebucht (styled as sum) and Differenz (styled with diff hint)
                card_table_data_styled.extend((
                    [["Abgebucht (Summe Rezeptionen):", actual_debit_str], {'is_sum': True}], # Styled as sum
                    [["Differenz:", difference_str], {'style_hint': 'diff_display_auto'}] # Styled with diff hint for color coding
                ))

                # Draw the Card table for this card type
                draw_simple_table(_PDF_CARD_TABLE_HEADERS, card_table_data_styled, card_col_props, card_col_aligns)


            # --- Notizen Section for PDF ---
            pdf.set_font(pdf_font_family_name, "B", 11); pdf.cell(0, 8, f"Notizen {shift_display_name}:", new_x=XPos.LMARGIN, new_y=YPos.NEXT, align="L"); pdf.ln(1)

            notes_content = "" # Variable to hold the notes text

            # Try to get content from the Text widget first (if it exists and is mapped)
            notes_widget_candidate = vars_dict.get('notes_text_widget')
            if notes_widget_candidate and hasattr(notes_widget_candidate, 'winfo_exists') and notes_widget_candidate.winfo_exists() and notes_widget_candidate.winfo_ismapped() and hasattr(notes_widget_candidate, 'get'):
                notes_content = notes_widget_candidate.get("1.0", tk.END + "-1c").strip()

                has_custom_formatting_tags = False
                try:
                    all_defined_tags = notes_widget_candidate.tag_names()
                    for tag_name in all_defined_tags:
                         if tag_name.startswith("userfont_") and notes_widget_candidate.tag_ranges(tag_name):
                             has_custom_formatting_tags = True
                             break
                except tk.TclError:
                    has_custom_formatting_tags = False
                    print("Warning: TclError accessing notes widget tags for formatting check.")

                if has_custom_formatting_tags:
                    pdf.set_font(pdf_font_family_name, "", 7); pdf.set_text_color(128, 128, 128); # Grey, small font
                    pdf.cell(0, 4, "(Hinweis: Textformatierungen aus dem Notizfeld werden im PDF nicht übernommen)", border=0, new_x=XPos.LMARGIN, new_y=YPos.NEXT, align="L")
                    pdf.ln(1); pdf.set_text_color(*colors_pdf['data_fg']); pdf.set_font(pdf_font_family_name, "", 9); # Reset font/color

            elif isinstance(vars_dict.get('notes_initial_content'), str) and vars_dict.get('notes_initial_content'):
                 notes_content = vars_dict['notes_initial_content'].strip()

            pdf.set_font(pdf_font_family_name, "", 9) # Set font for notes content
            pdf.set_draw_color(*colors_pdf['notes_border_color']) # Set border color for the notes box

            if notes_content:
                pdf.multi_cell(0, 5, notes_content, border=1, align="L", new_x=XPos.LMARGIN, new_y=YPos.NEXT)
            else:
                pdf.cell(0, 7, "(Keine Notizen)", border=1, new_x=XPos.LMARGIN, new_y=YPos.NEXT, align="L")

            pdf.ln(3); pdf.set_draw_color(0,0,0)


