    def _load_urlaubsantraege_data(self):
        """Lädt die gespeicherten Urlaubsanträge aus der JSON-Datei."""
        if os.path.exists(self.urlaubsantraege_data_file):
            try:
                with open(self.urlaubsantraege_data_file, 'r', encoding='utf-8') as f:
                    self.urlaubsantraege_data_cache = json.load(f)
                    if not isinstance(self.urlaubsantraege_data_cache, list): self.urlaubsantraege_data_cache = []
            except (json.JSONDecodeError, IOError): self.urlaubsantraege_data_cache = []
        else:
            self.urlaubsantraege_data_cache = []

    def _save_urlaubsantraege_data(self):
        """Speichert den Cache der Urlaubsanträge in die JSON-Datei."""
        try:
            os.makedirs(os.path.dirname(self.urlaubsantraege_data_file), exist_ok=True)
            with open(self.urlaubsantraege_data_file, 'w', encoding='utf-8') as f:
                json.dump(self.urlaubsantraege_data_cache, f, indent=2, ensure_ascii=False)
        except Exception as e:
            print(f"Fehler beim Speichern der Urlaubsanträge: {e}")

