    def _load_and_display_urlaubsantraege(self):
        """Lädt die gespeicherten Anträge und zeigt sie in der Liste an."""
        if not hasattr(self, 'urlaubsantraege_tree') or not self.urlaubsantraege_tree.winfo_exists(): return
        for item in self.urlaubsantraege_tree.get_children(): self.urlaubsantraege_tree.delete(item)
        
        # Sortiert nach Mitarbeitername
        sorted_cache = sorted(self.urlaubsantraege_data_cache, key=lambda x: x.get('name', '').lower())

        for entry in sorted_cache:
            values = (entry.get('name',''), entry.get('abteilung',''), entry.get('erster_tag',''), entry.get('letzter_tag',''), str(entry.get('gesamtzahl','')))
            self.urlaubsantraege_tree.insert("", "end", values=values, iid=entry.get('id'))

    def _add_urlaubsantrag(self):
        """
        Öffnet den Dialog zum Hinzufügen eines neuen Urlaubsantrags.
        Diese korrigierte Version stellt sicher, dass jeder Antrag nur einmal hinzugefügt wird.
        """
        dialog = UrlaubsantragEntryDialog(self.master, self)
        new_data = dialog.show()

        if new_data:
            # 1. Der neue Datensatz wird NUR zur In-Memory-Liste hinzugefügt.
            self.urlaubsantraege_data_cache.append(new_data)
            
            # 2. Die komplette, aktualisierte Liste wird gespeichert.
            self._save_urlaubsantraege_data()
            
            # 3. Die Anzeige wird komplett neu aus der aktualisierten Liste aufgebaut.
            #    Diese Funktion leert zuerst die Tabelle und lädt sie dann neu.
            #    Es findet KEIN erneutes Laden aus der Datei statt.
            self._load_and_display_urlaubsantraege()


    def _edit_urlaubsantrag(self, event=None):
        """
        Öffnet den Dialog zum Bearbeiten eines ausgewählten Urlaubsantrags.
        Diese korrigierte Version ersetzt den alten Eintrag, anstatt einen neuen hinzuzufügen.
        """
        selected_ids = self.urlaubsantraege_tree.selection()
        if not selected_ids:
            return
        
        selected_id = selected_ids[0]
        
        # Findet den Index des zu bearbeitenden Eintrags in der Liste.
        entry_index = -1
        for i, entry in enumerate(self.urlaubsantraege_data_cache):
            if entry.get("id") == selected_id:
                entry_index = i
                break
        
        if entry_index == -1:
            messagebox.showerror("Fehler", "Ausgewählter Eintrag nicht in den Daten gefunden.", parent=self.master)
            return

        entry_to_edit = self.urlaubsantraege_data_cache[entry_index]
        
        dialog = UrlaubsantragEntryDialog(self.master, self, entry_data=entry_to_edit.copy())
        updated_data = dialog.show()
        
        if updated_data:
            # 1. HIER IST DIE KORREKTUR: Der alte Eintrag wird am exakten Index 
            #    durch den neuen ersetzt, anstatt einen weiteren hinzuzufügen.
            self.urlaubsantraege_data_cache[entry_index] = updated_data
            
            # 2. Die komplette, aktualisierte Liste wird gespeichert.
            self._save_urlaubsantraege_data()
            
            # 3. Die Anzeige wird neu aufgebaut, um die Änderung zu reflektieren.
            self._load_and_display_urlaubsantraege()

    def _delete_urlaubsantrag(self):
        selected_ids = self.urlaubsantraege_tree.selection()
        if not selected_ids: return
        
        if messagebox.askyesno("Löschen", f"{len(selected_ids)} Antrag/Anträge wirklich löschen?"):
            self.urlaubsantraege_data_cache = [e for e in self.urlaubsantraege_data_cache if e.get("id") not in selected_ids]
            self._save_urlaubsantraege_data()
            self._load_and_display_urlaubsantraege()
            SuccessToast(self.master, title="Erfolg", message=f"{len(selected_ids)} Antrag/Anträge gelöscht.", toast_type='success', colors=self.current_settings.get('toast_colors'))

    def _get_selected_urlaubsantrag_data(self):
        """Hilfsfunktion, um die Daten des ausgewählten Antrags zu holen."""
        selected_ids = self.urlaubsantraege_tree.selection()
        if not selected_ids:
            SuccessToast(self.master, title="Keine Auswahl", message="Bitte wählen Sie zuerst einen Antrag aus der Liste aus.", toast_type='warning', colors=self.current_settings.get('toast_colors'))
            return None
        return next((e for e in self.urlaubsantraege_data_cache if e.get("id") == selected_ids[0]), None)

    def _save_urlaubsantrag_pdf(self):
        antrag_data = self._get_selected_urlaubsantrag_data()
        if not antrag_data: return

        # --- KORREKTUR: Datumsformat im Dateinamen auf Deutsch geändert ---
        # Das Format wurde von '%Y-%m-%d' auf '%d.%m.%Y' geändert.
        save_path = filedialog.asksaveasfilename(
            defaultextension=".pdf", filetypes=[("PDF-Dateien", "*.pdf")], title="Urlaubsantrag als PDF speichern",
            initialfile=f"Urlaubsantrag_{antrag_data['name'].replace(' ', '_')}_{datetime.date.today().strftime('%d.%m.%Y')}.pdf"
        )
        # --- ENDE DER KORREKTUR ---
        
        if not save_path: return

        try:
            pdf = UrlaubsantragPDF(antrag_data, logo_path=_get_pdf_logo_path(self.current_settings, 'urlaubsantrag'))
            pdf.create_form()
            pdf.output(save_path)
            SuccessToast(self.master, title="Erfolg", message="Antrag als PDF gespeichert.", toast_type='success', colors=self.current_settings.get('toast_colors'))
        except Exception as e:
            messagebox.showerror("Fehler beim Speichern", f"Ein Fehler ist aufgetreten:\n{e}", parent=self.master)
    def _print_urlaubsantrag(self):
        """
        Erstellt eine temporäre PDF des ausgewählten Antrags und öffnet diese im
        Standard-PDF-Viewer, damit der Benutzer den Druckvorgang starten kann.
        """
        antrag_data = self._get_selected_urlaubsantrag_data()
        if not antrag_data:
            return

        temp_pdf_path = ""
        try:
            # Erstellt eine sichere temporäre Datei für das PDF
            with tempfile.NamedTemporaryFile(suffix=".pdf", delete=False) as temp_pdf_file:
                temp_pdf_path = temp_pdf_file.name

            pdf = UrlaubsantragPDF(antrag_data, logo_path=_get_pdf_logo_path(self.current_settings, 'urlaubsantrag'))
            pdf.create_form()
            pdf.output(temp_pdf_path)

            # Informiert den Benutzer klar und deutlich über den nächsten Schritt
            SuccessToast(self.master,
                         title="PDF wird geöffnet",
                         message="Das Dokument wird in Ihrem PDF-Programm geöffnet.",
                         toast_type='info',
                         colors=self.current_settings.get('toast_colors'),
                         duration=4000)

            # Öffnet die PDF-Datei zuverlässig im Standardprogramm des Betriebssystems
            if platform.system() == "Windows":
                os.startfile(temp_pdf_path)
            else:
                opener = "open" if platform.system() == "Darwin" else "xdg-open"
                subprocess.run([opener, temp_pdf_path], check=True)

            # Startet den robusten Aufräumprozess für die temporäre Datei im Hintergrund
            self._schedule_temp_file_cleanup(temp_pdf_path)

        except FileNotFoundError:
             messagebox.showerror("Fehler", "Kein Standard-PDF-Programm zum Öffnen der Vorschau gefunden.", parent=self.master)
             self._schedule_temp_file_cleanup(temp_pdf_path)
        except Exception as e:
            messagebox.showerror("Druckfehler", f"Ein Fehler ist beim Öffnen der Druckvorschau aufgetreten:\n{e}", parent=self.master)
            self._schedule_temp_file_cleanup(temp_pdf_path)





