    def _toggle_sidebar(self):
        """Schaltet die Sichtbarkeit der Sidebar um und passt das Layout an."""
        self.sidebar_visible = not self.sidebar_visible
        
        if self.sidebar_visible:
            # Sidebar anzeigen
            self.sidebar_frame.grid()
            self.content_frame.grid_configure(column=1, columnspan=1)
            if self.sidebar_toggle_button:
                self.sidebar_toggle_button.config(text="◀")
                ToolTip(self.sidebar_toggle_button, "Navigation ausblenden")
        else:
            # Sidebar ausblenden
            self.sidebar_frame.grid_remove()
            self.content_frame.grid_configure(column=0, columnspan=2)
            if self.sidebar_toggle_button:
                self.sidebar_toggle_button.config(text="▶")
                ToolTip(self.sidebar_toggle_button, "Navigation einblenden")
