    def _create_settings_spickzettel_tab_icons_section(self, parent_frame, temp_settings, dialog_vars, start_row=0):
        """Erstellt den Abschnitt für die Spickzettel Tab-Icons im Einstellungsdialog."""
        frame = ttk.LabelFrame(parent_frame, text="Spickzettel: Icons der Reiter (Tabs)", style='TLabelframe')
        frame.grid(row=start_row, column=0, columnspan=4, sticky='ew', padx=5, pady=10)
        frame.columnconfigure(1, weight=1)

        dialog_vars['spickzettel_tab_icon_vars'] = {}
        
        tab_keys_map = {
            'zimmer': 'Zimmerkategorien',
            'designs': 'Designs',
            'minibar': 'Minibar',
            'mwst': 'MwSt-Sätze'
        }
        
        # Sicherstellen, dass der Schlüssel in temp_settings existiert
        temp_icon_paths = temp_settings.setdefault('spickzettel_tab_icons', {})
        current_row = 0

        for key, label_text in tab_keys_map.items():
            ttk.Label(frame, text=f"Icon für '{label_text}':").grid(row=current_row, column=0, sticky='w', padx=5, pady=5)
            
            path_var = tk.StringVar(value=temp_icon_paths.get(key, ''))
            dialog_vars['spickzettel_tab_icon_vars'][key] = path_var
            
            path_entry = ttk.Entry(frame, textvariable=path_var, state='readonly')
            path_entry.grid(row=current_row, column=1, sticky='ew', padx=5)

            def create_browse_callback(k=key, v=path_var):
                def browse():
                    fpath = filedialog.askopenfilename(
                        title=f"Icon für '{label_text}' auswählen",
                        #filetypes=[("Bilddateien", "*.png *.gif *.jpg *.avif"), ("Alle Dateien", "*.*")],
                        
                        filetypes=[("Bilddateien", "*.png *.gif *.jpg *.avif"), ("Alle Dateien", "*.*")],

                        
                        parent=parent_frame.winfo_toplevel()
                    )
                    if fpath:
                        v.set(fpath)
                        temp_settings['spickzettel_tab_icons'][k] = fpath
                return browse
            
            def create_clear_callback(k=key, v=path_var):
                def clear():
                    v.set('')
                    temp_settings['spickzettel_tab_icons'][k] = ''
                return clear

            ttk.Button(frame, text="Durchsuchen...", command=create_browse_callback()).grid(row=current_row, column=2, padx=5)
            ttk.Button(frame, text="Entfernen", command=create_clear_callback()).grid(row=current_row, column=3, padx=5)
            current_row += 1

        return start_row + 1
    
    
    def _create_settings_sizes_section(self, parent_frame, temp_settings, dialog_vars, start_row=0):
        """Erstellt den Abschnitt für konfigurierbare Schriftgrößen und Breiten."""
        frame = ttk.LabelFrame(parent_frame, text="Konfigurierbare Größen (Schrift & Breite)", style='TLabelframe')
        frame.grid(row=start_row, column=0, columnspan=4, sticky='ew', padx=5, pady=10)
        
        dialog_vars['configurable_sizes_vars'] = {}
        
        size_configs = temp_settings.get('configurable_sizes', {})
        
        # Mapping der Schlüssel zu den Anzeigenamen
        labels_map = {
            'weckrufliste': "Weckrufliste",
            'taxibestellung': "Taxibestellung",
            'shuttle_service': "Shuttle-Service",
            'minibarliste': "Minibarliste", # <-- HIER IST DER FEHLENDE EINTRAG
            'trinkgeldliste': "Trinkgeldliste",
            'tagesabrechnung': "Tagesabrechnung",
            'dialog_buttons': "Dialog-Buttons"
        }
        
        current_row = 0
        # Die Reihenfolge der Anzeige wird hier festgelegt
        ordered_keys = ['weckrufliste', 'taxibestellung', 'shuttle_service', 'trinkgeldliste', 'minibarliste', 'tagesabrechnung', 'dialog_buttons']

        for key in ordered_keys:
            if key not in size_configs:
                continue

            config = size_configs[key]
            dialog_vars['configurable_sizes_vars'][key] = {}
            
            ttk.Label(frame, text=f"{labels_map[key]}:", font=("Segoe UI", 10, "bold")).grid(row=current_row, column=0, columnspan=4, sticky='w', padx=5, pady=(8,2))
            
            sub_frame = ttk.Frame(frame)
            sub_frame.grid(row=current_row + 1, column=0, columnspan=4, sticky='ew', padx=20)
            
            col_idx = 0
            for setting_key, setting_value in config.items():
                if 'font_size' in setting_key:
                    label_text = "Schriftgröße:"
                    from_, to = 8, 24
                elif 'entry_width' in setting_key:
                    label_text = "Eingabefeld-Breite:"
                    from_, to = 10, 50
                else:
                    continue

                ttk.Label(sub_frame, text=label_text).grid(row=0, column=col_idx, sticky='w', padx=(0, 5))
                
                var = tk.IntVar(value=setting_value)
                dialog_vars['configurable_sizes_vars'][key][setting_key] = var
                
                ttk.Spinbox(sub_frame, from_=from_, to=to, textvariable=var, width=7).grid(row=0, column=col_idx + 1, sticky='w', padx=(0, 15))
                
                var.trace_add('write', 
                    lambda n, i, m, k=key, sk=setting_key, v=var: 
                    temp_settings.setdefault('configurable_sizes', {}).setdefault(k, {}).update({sk: v.get()})
                )
                col_idx += 2
                
            current_row += 2

        return start_row + 1
    
    
