    def _create_settings_spickzettel_sidebar_section(self, parent_frame, temp_settings, dialog_vars, start_row=0):
        """Erstellt den Abschnitt für die Sidebar-Farben des Spickzettels."""
        frame = ttk.LabelFrame(parent_frame, text="Spickzettel: Sidebar-Design", style='TLabelframe')
        frame.grid(row=start_row, column=0, columnspan=4, sticky='ew', padx=5, pady=10)
        frame.columnconfigure(1, weight=1)

        dialog_vars['spickzettel_sidebar_colors'] = {}
        
        # Mapping der Farbschlüssel zu den Labels
        color_map = {
            'spickzettel_sidebar_color': "Hintergrundfarbe",
            'spickzettel_sidebar_hover_color': "Hover-Farbe (Mauszeiger)"
        }
        
        current_row = 0
        for key, label_text in color_map.items():
            ttk.Label(frame, text=f"{label_text}:").grid(row=current_row, column=0, sticky='w', padx=5, pady=3)
            
            initial_color = temp_settings.get(key, self.default_settings.get(key, '#FFFFFF'))
            color_var = tk.StringVar(value=initial_color)
            dialog_vars['spickzettel_sidebar_colors'][key] = color_var
            
            color_display = tk.Label(frame, textvariable=color_var, width=10, relief='solid', borderwidth=1, bg=initial_color)
            color_display.grid(row=current_row, column=1, sticky='w', padx=5)

            def create_pick_color_callback(k=key, v=color_var, swatch=color_display, lbl=label_text):
                def pick_color():
                    new_color = colorchooser.askcolor(title=f"Farbe für '{lbl}' wählen", initialcolor=v.get(), parent=parent_frame.winfo_toplevel())
                    if new_color and new_color[1]:
                        hex_color = new_color[1].upper()
                        v.set(hex_color)
                        swatch.config(bg=hex_color)
                        temp_settings[k] = hex_color
                return pick_color

            ttk.Button(frame, text="Farbe wählen...", command=create_pick_color_callback()).grid(row=current_row, column=2, padx=5, pady=2)
            current_row += 1

        return start_row + 1
