    def _create_settings_backup_section(self, parent_frame, temp_settings, dialog_vars, start_row=0):
        """Erstellt den Abschnitt für die Backup-Einstellungen im Einstellungsdialog."""
        frame = ttk.LabelFrame(parent_frame, text="Sicherung & Wiederherstellung", style='TLabelframe')
        frame.grid(row=start_row, column=0, columnspan=4, sticky='ew', padx=5, pady=10)
        frame.columnconfigure(1, weight=1)

        # Checkbox (Toggle-Switch) für automatische Backups
        dialog_vars['auto_backup_enabled_var'] = tk.BooleanVar(value=temp_settings.get('auto_backup_enabled', True))
        auto_backup_check = ttk.Checkbutton(
            frame, 
            text="Automatische Backups aktivieren", 
            variable=dialog_vars['auto_backup_enabled_var']
        )
        auto_backup_check.grid(row=0, column=0, columnspan=2, sticky='w', padx=5, pady=5)
        
        # Trace, um die Einstellung bei Änderung sofort zu aktualisieren
        dialog_vars['auto_backup_enabled_var'].trace_add(
            'write', 
            lambda n, i, m: temp_settings.update({'auto_backup_enabled': dialog_vars['auto_backup_enabled_var'].get()})
        )

        # Eingabefeld für das Backup-Intervall
        ttk.Label(frame, text="Sicherungsintervall (Stunden):").grid(row=1, column=0, sticky='w', padx=5, pady=3)
        dialog_vars['auto_backup_interval_var'] = tk.IntVar(value=temp_settings.get('auto_backup_interval_hours', 24))
        interval_spinbox = ttk.Spinbox(
            frame, 
            from_=1, 
            to=168, # Max. 1 Woche
            textvariable=dialog_vars['auto_backup_interval_var'], 
            width=8
        )
        interval_spinbox.grid(row=1, column=1, sticky='w', padx=5, pady=3)

        # Trace, um die Einstellung bei Änderung sofort zu aktualisieren
        dialog_vars['auto_backup_interval_var'].trace_add(
            'write', 
            lambda n, i, m: temp_settings.update({'auto_backup_interval_hours': dialog_vars['auto_backup_interval_var'].get()})
        )

        return start_row + 1
    
    
