    def _create_settings_shuttle_menu_tiles_section(self, parent_frame, temp_settings, dialog_vars, start_row=0):
        """Erstellt den Abschnitt zur Konfiguration der Shuttle-Menü-Kacheln (Hinfahrt/Rückfahrt)."""
        frame = ttk.LabelFrame(parent_frame, text="Shuttle-Service: Menü-Kacheln (Auswahl)", style='TLabelframe')
        frame.grid(row=start_row, column=0, columnspan=4, sticky='ew', padx=5, pady=10)
        frame.columnconfigure(1, weight=1)

        # Sicherstellen, dass die Konfigurationsstruktur existiert
        if 'shuttle_main_menu_button_configs' not in temp_settings:
            temp_settings['shuttle_main_menu_button_configs'] = self.default_settings['shuttle_main_menu_button_configs'].copy()
        
        configs = temp_settings['shuttle_main_menu_button_configs']
        
        # Initialisiere Variable-Dictionary für diesen Abschnitt
        dialog_vars['shuttle_menu_tiles_vars'] = {}
        
        tile_keys = ["Shuttle Hinfahrt", "Shuttle Rückfahrt"]
        current_row = 0

        for key in tile_keys:
            if key not in configs:
                continue

            cfg = configs[key]
            dialog_vars['shuttle_menu_tiles_vars'][key] = {}

            # Container für eine Kachel
            tile_frame = ttk.Frame(frame, padding=(0, 5))
            tile_frame.grid(row=current_row, column=0, columnspan=4, sticky='ew')
            tile_frame.columnconfigure(1, weight=1)

            ttk.Label(tile_frame, text=f"Kachel '{key}':", font=("Segoe UI", 9, "bold")).grid(row=0, column=0, columnspan=4, sticky='w', padx=5, pady=(5,2))

            # 1. Aktiv/Inaktiv
            is_active_var = tk.BooleanVar(value=cfg.get('is_active', True))
            dialog_vars['shuttle_menu_tiles_vars'][key]['is_active'] = is_active_var
            
            def update_active(k=key, v=is_active_var):
                temp_settings['shuttle_main_menu_button_configs'][k]['is_active'] = v.get()

            ttk.Checkbutton(tile_frame, text="Aktiv", variable=is_active_var, command=update_active).grid(row=1, column=0, sticky='w', padx=15)

            # 2. Label Text
            ttk.Label(tile_frame, text="Text:").grid(row=2, column=0, sticky='w', padx=15, pady=2)
            label_var = tk.StringVar(value=cfg.get('label', key))
            dialog_vars['shuttle_menu_tiles_vars'][key]['label'] = label_var
            ttk.Entry(tile_frame, textvariable=label_var).grid(row=2, column=1, columnspan=3, sticky='ew', padx=5)
            
            label_var.trace_add('write', lambda n, i, m, k=key, v=label_var: temp_settings['shuttle_main_menu_button_configs'][k].update({'label': v.get()}))

            # 3. Symbol (Standard)
            ttk.Label(tile_frame, text="Symbol (Standard):").grid(row=3, column=0, sticky='w', padx=15, pady=2)
            symbol_var = tk.StringVar(value=cfg.get('value', '') if cfg.get('type') == 'symbol' else '')
            dialog_vars['shuttle_menu_tiles_vars'][key]['value'] = symbol_var
            
            # Wir nutzen hier ein Entry, falls man ein Emoji manuell ändern will, 
            # aber hauptsächlich wird das Feld für den Bildpfad genutzt, wenn Type=Image ist.
            # Der Einfachheit halber trennen wir hier Bild und Symbol nicht strikt in der UI, 
            # sondern bieten einen Upload für das Bild an.

            # 4. Bildauswahl (Icon/Image)
            ttk.Label(tile_frame, text="Eigenes Bild:").grid(row=4, column=0, sticky='w', padx=15, pady=2)
            
            # Wir ermitteln den aktuellen Bildpfad, falls der Typ 'image' ist
            current_img_path = cfg.get('value', '') if cfg.get('type') == 'image' else ''
            img_path_var = tk.StringVar(value=current_img_path)
            dialog_vars['shuttle_menu_tiles_vars'][key]['img_path'] = img_path_var
            
            path_entry = ttk.Entry(tile_frame, textvariable=img_path_var, state='readonly')
            path_entry.grid(row=4, column=1, columnspan=2, sticky='ew', padx=5)

            def create_browse_cmd(k=key, v=img_path_var):
                def browse():
                    fpath = filedialog.askopenfilename(
                        title=f"Bild für {k} wählen",
                        filetypes=[("Bilder", "*.png *.jpg *.jpeg *.gif *.avif"), ("Alle", "*.*")],
                        parent=parent_frame.winfo_toplevel()
                    )
                    if fpath:
                        v.set(fpath)
                        # Setze Typ auf 'image' und Value auf Pfad
                        temp_settings['shuttle_main_menu_button_configs'][k]['type'] = 'image'
                        temp_settings['shuttle_main_menu_button_configs'][k]['value'] = fpath
                return browse

            def create_reset_cmd(k=key, v=img_path_var, default_sym='🚐'):
                def reset():
                    v.set('')
                    # Zurücksetzen auf Standard-Symbol
                    temp_settings['shuttle_main_menu_button_configs'][k]['type'] = 'symbol'
                    temp_settings['shuttle_main_menu_button_configs'][k]['value'] = default_sym
                return reset

            browse_btn = ttk.Button(tile_frame, text="...", width=3, command=create_browse_cmd())
            browse_btn.grid(row=4, column=3, sticky='w', padx=5)
            
            reset_btn = ttk.Button(tile_frame, text="X", width=3, command=create_reset_cmd())
            reset_btn.grid(row=4, column=4, sticky='w', padx=0)

            current_row += 1
            
            if current_row < len(tile_keys):
                ttk.Separator(frame, orient='horizontal').grid(row=current_row, column=0, columnspan=4, sticky='ew', pady=10)
                current_row += 1

        return start_row + 1
    
    
    def _create_settings_shuttle_backup_section(self, parent_frame, temp_settings, dialog_vars, start_row=0):
        """Erstellt den Abschnitt für die Shuttle-Backup-Einstellungen."""
        frame = ttk.LabelFrame(parent_frame, text="Sicherung & Wiederherstellung (Shuttle-Service)", style='TLabelframe')
        frame.grid(row=start_row, column=0, columnspan=4, sticky='ew', padx=5, pady=10)
        frame.columnconfigure(1, weight=1)

        dialog_vars['auto_backup_shuttle_enabled_var'] = tk.BooleanVar(value=temp_settings.get('auto_backup_shuttle_enabled', True))
        ttk.Checkbutton(
            frame,
            text="Automatische Backups für Shuttle-Service aktivieren",
            variable=dialog_vars['auto_backup_shuttle_enabled_var']
        ).grid(row=0, column=0, columnspan=2, sticky='w', padx=5, pady=5)
        
        dialog_vars['auto_backup_shuttle_enabled_var'].trace_add(
            'write',
            lambda n, i, m: temp_settings.update({'auto_backup_shuttle_enabled': dialog_vars['auto_backup_shuttle_enabled_var'].get()})
        )

        ttk.Label(frame, text="Sicherungsintervall (Stunden):").grid(row=1, column=0, sticky='w', padx=5, pady=3)
        dialog_vars['auto_backup_shuttle_interval_var'] = tk.IntVar(value=temp_settings.get('auto_backup_shuttle_interval_hours', 24))
        ttk.Spinbox(
            frame,
            from_=1,
            to=168,
            textvariable=dialog_vars['auto_backup_shuttle_interval_var'],
            width=8
        ).grid(row=1, column=1, sticky='w', padx=5, pady=3)

        dialog_vars['auto_backup_shuttle_interval_var'].trace_add(
            'write',
            lambda n, i, m: temp_settings.update({'auto_backup_shuttle_interval_hours': dialog_vars['auto_backup_shuttle_interval_var'].get()})
        )
        return start_row + 1
    
    
