    def _create_generic_button_config_section(self, parent_frame, temp_settings, dialog_vars, section_title, settings_key, button_order, start_row):
        """
        Erstellt einen generischen Konfigurationsabschnitt für eine Gruppe von Buttons
        mit Aktiv-Checkbox, Typ-Auswahl (Text/Bild) und Wert-Eingabe.
        (FINALE, KORRIGIERTE VERSION)
        """
        # Erstellt den Hauptrahmen für diesen Konfigurationsabschnitt
        if section_title:
            frame = ttk.LabelFrame(parent_frame, text=section_title, style='TLabelframe')
            frame.grid(row=start_row, column=0, columnspan=4, sticky='ew', padx=5, pady=10)
        else:
            frame = ttk.Frame(parent_frame)
            frame.grid(row=start_row, column=0, columnspan=4, sticky='ew', padx=5, pady=0)
        
        # Stellt sicher, dass das Haupt-Dictionary für die Dialogvariablen existiert
        if settings_key not in dialog_vars:
            dialog_vars[settings_key] = {}
        
        # Lädt die aktuellen Button-Konfigurationen aus den temporären Einstellungen
        button_configs = temp_settings.get(settings_key, {})
        current_row_in_frame = 0

        # Iteriert durch die Liste der zu konfigurierenden Buttons
        for key in button_order:
            if key not in button_configs:
                print(f"Warnung: Konfigurationsschlüssel '{key}' nicht in '{settings_key}' gefunden. Wird übersprungen.")
                continue
            
            dialog_vars[settings_key][key] = {}
            cfg = button_configs.get(key, {})
            
            # Erstellt einen eigenen Frame für die Konfiguration jedes einzelnen Buttons
            button_config_frame = ttk.Frame(frame, padding=(0, 5))
            button_config_frame.grid(row=current_row_in_frame, column=0, columnspan=4, sticky='ew')
            button_config_frame.columnconfigure(1, weight=1)

            # Bestimmt den Anzeigenamen für den Button im Einstellungsdialog
            base_label_map = {'List_Add': 'Hinzufügen', 'List_Edit': 'Bearbeiten', 'List_Delete': 'Löschen', 'List_Print': 'Drucken'}
            base_label = base_label_map.get(key, key.replace('_', ' '))
            ttk.Label(button_config_frame, text=f"Button '{base_label}':", font=("Segoe UI", 9, "bold")).grid(row=0, column=0, columnspan=4, sticky='w', padx=5, pady=5)

            # Checkbox zum Aktivieren/Deaktivieren des Buttons
            is_active_var = tk.BooleanVar(value=cfg.get('is_active', True))
            dialog_vars[settings_key][key]['is_active_var'] = is_active_var
            ttk.Checkbutton(button_config_frame, text="Aktiv", variable=is_active_var, command=lambda k=key, v=is_active_var, sk=settings_key: temp_settings.setdefault(sk, {}).setdefault(k, {}).update({'is_active': v.get()})).grid(row=1, column=0, sticky='w', padx=15)
            
            # Variable zur Speicherung des Typs (Text/Symbol oder Bild)
            type_var = tk.StringVar(value=cfg.get('type', 'symbol'))
            dialog_vars[settings_key][key]['type_var'] = type_var
            
            # Frame für die Radiobuttons zur Typ-Auswahl
            type_frame = ttk.Frame(button_config_frame)
            type_frame.grid(row=2, column=0, columnspan=3, sticky='w', padx=5, pady=2)
            
            # Widgets für die Text/Symbol-Eingabe
            symbol_label = ttk.Label(button_config_frame, text="Text/Symbol:")
            label_var = tk.StringVar(value=cfg.get('value', '') if cfg.get('type') == 'symbol' else '')
            dialog_vars[settings_key][key]['label_var'] = label_var
            symbol_entry = ttk.Entry(button_config_frame, textvariable=label_var)

            # Widgets für die Bild-Auswahl
            image_label = ttk.Label(button_config_frame, text="Bildpfad:")
            image_var = tk.StringVar(value=cfg.get('value', '') if cfg.get('type') == 'image' else '')
            dialog_vars[settings_key][key]['image_var'] = image_var
            image_path_display = ttk.Entry(button_config_frame, textvariable=image_var, state='readonly')

            # Funktion zum Öffnen des Dateidialogs
            def create_browse_callback(var):
                def browse_icon():
                    fpath = filedialog.askopenfilename(filetypes=[("Bilddateien", "*.png *.gif *.jpg *.jpeg *.ico"), ("Alle Dateien", "*.*")], parent=parent_frame.winfo_toplevel())
                    if fpath: var.set(fpath)
                return browse_icon
            
            browse_button = ttk.Button(button_config_frame, text="...", width=3, command=create_browse_callback(image_var))

            # Funktion zum Umschalten der Sichtbarkeit der Eingabefelder
            def create_toggle_visibility_callback(t_var, s_lbl, s_entry, i_lbl, i_path, i_btn):
                def toggle(*args):
                    if t_var.get() == 'symbol':
                        s_lbl.grid(row=3, column=0, sticky='w', padx=(15, 5), pady=2)
                        s_entry.grid(row=3, column=1, sticky='ew', padx=5, pady=2)
                        i_lbl.grid_remove(); i_path.grid_remove(); i_btn.grid_remove()
                    else: # image
                        s_lbl.grid_remove(); s_entry.grid_remove()
                        i_lbl.grid(row=3, column=0, sticky='w', padx=(15, 5), pady=2)
                        i_path.grid(row=3, column=1, sticky='ew', padx=5, pady=2)
                        i_btn.grid(row=3, column=2, sticky='w', padx=5, pady=2)
                return toggle
            
            toggle_visibility_func = create_toggle_visibility_callback(type_var, symbol_label, symbol_entry, image_label, image_path_display, browse_button)
            
            ttk.Radiobutton(type_frame, text="Text/Symbol", variable=type_var, value='symbol', command=toggle_visibility_func).pack(side='left', padx=(0, 10))
            ttk.Radiobutton(type_frame, text="Bild", variable=type_var, value='image', command=toggle_visibility_func).pack(side='left')
            
            toggle_visibility_func() # Setzt den initialen Zustand

            # Funktion, um Änderungen sofort in den temporären Einstellungen zu speichern
            def create_update_config_callback(k, t, txt, img, sk):
                def update_config(*args):
                    if sk not in temp_settings: temp_settings[sk] = {}
                    if k not in temp_settings[sk]: temp_settings[sk][k] = {}
                    cfg_ref = temp_settings[sk][k]
                    cfg_ref['type'] = t.get()
                    cfg_ref['value'] = txt.get() if t.get() == 'symbol' else img.get()
                return update_config

            update_callback = create_update_config_callback(key, type_var, label_var, image_var, settings_key)
            type_var.trace_add('write', update_callback)
            label_var.trace_add('write', update_callback)
            image_var.trace_add('write', update_callback)
            
            # Fügt eine Trennlinie zwischen den Konfigurationsblöcken hinzu
            if current_row_in_frame < len(button_order) - 1:
                ttk.Separator(frame, orient='horizontal').grid(row=current_row_in_frame + 1, column=0, columnspan=4, sticky='ew', pady=(10, 5))
            current_row_in_frame += 2
        
        return start_row + 1
    
    def _create_settings_mod_rundgang_colors_section(self, parent_frame, temp_settings, dialog_vars, start_row=0):
        """Farbkonfiguration für den MOD-Rundgang Bereich."""
        frame = ttk.LabelFrame(parent_frame, text="MOD-Rundgang: Farbdesign", style='TLabelframe')
        frame.grid(row=start_row, column=0, columnspan=4, sticky='ew', padx=5, pady=10)
        frame.columnconfigure(1, weight=1)

        key_labels = {
            'header_from':   'Header-Verlauf (Start)',
            'header_to':     'Header-Verlauf (Ende)',
            'actionbar_bg':  'Aktionsleiste Hintergrund',
            'progress_from': 'Fortschrittsbalken (Start)',
            'progress_to':   'Fortschrittsbalken (Ende)',
            'task_done_bg':  'Erledigte Aufgabe Hintergrund',
            'card_bg':       'Karten-Hintergrund',
            'page_bg':       'Seiten-Hintergrund',
            'shadow_color':  'Schatten-Farbe',
            'warning_fg':    'Warnungstext-Farbe',
        }

        if 'mod_rundgang_colors' not in dialog_vars:
            dialog_vars['mod_rundgang_colors'] = {}

        current_colors = temp_settings.get('mod_rundgang_colors',
                         self.default_settings.get('mod_rundgang_colors', {}))

        for row_i, (k, label_text) in enumerate(key_labels.items()):
            default_val = self.default_settings.get('mod_rundgang_colors', {}).get(k, '#FFFFFF')
            initial = current_colors.get(k, default_val)

            ttk.Label(frame, text=f"{label_text}:").grid(row=row_i, column=0, sticky='w', padx=5, pady=3)
            cv = tk.StringVar(value=initial)
            dialog_vars['mod_rundgang_colors'][k] = cv

            swatch = tk.Label(frame, textvariable=cv, width=12, relief='solid', borderwidth=1, bg=initial)
            swatch.grid(row=row_i, column=1, sticky='w', padx=5)

            def _pick(k=k, v=cv, sw=swatch):
                res = colorchooser.askcolor(title=f"Farbe für '{k}'", initialcolor=v.get(),
                                            parent=parent_frame.winfo_toplevel())
                if res and res[1]:
                    hex_c = res[1].upper()
                    v.set(hex_c)
                    sw.config(bg=hex_c)
                    temp_settings.setdefault('mod_rundgang_colors', {})[k] = hex_c

            ttk.Button(frame, text="Farbe wählen...", command=_pick).grid(row=row_i, column=2, padx=5, pady=2)

        return start_row + 1

