    def _configure_layover_button(self, button_widget, config_key, default_text):
        """
        Konfiguriert den 'Daten bearbeiten'-Button in der Layover-Ansicht.
        Priorisiert das vom Admin hochgeladene Icon.
        """
        custom_icon_path = self.current_settings.get('layover_icon_path', '')
        pil_available = 'Image' in globals() and 'ImageTk' in globals() and Image is not None

        # Priorität 1: Benutzerdefiniertes Icon aus den Einstellungen verwenden
        if custom_icon_path and os.path.exists(custom_icon_path) and pil_available:
            try:
                style_cfg = self.current_settings.get('list_views_button_style', {})
                icon_size = style_cfg.get('icon_size', 24)
                
                img = Image.open(custom_icon_path).resize((icon_size, icon_size), Image.Resampling.LANCZOS)
                photo = ImageTk.PhotoImage(img)
                
                if not hasattr(self, 'layover_button_images'):
                    self.layover_button_images = {}
                self.layover_button_images[config_key] = photo
                
                # WICHTIGE KORREKTUR: Die Referenz auf das Bild muss direkt am Widget
                # gespeichert werden, um zu verhindern, dass es vom Speicher entfernt wird.
                button_widget.image = photo
                
                button_widget.config(image=photo, text=f" {default_text}", compound='left')
                ToolTip(button_widget, default_text)
                return
            except Exception as e:
                print(f"Fehler beim Laden des benutzerdefinierten Layover-Icons: {e}")
        
        # Fallback: Generische Button-Konfiguration verwenden, wenn kein Icon gesetzt ist
        layover_configs = self.current_settings.get('layover_button_configs', {})
        self._configure_list_tab_button(
            button_widget, 
            config_key, 
            default_text, 
            button_config_source=layover_configs
        )
    # ^^^^^ HIER ENDET DER NEUE CODEBLOCK ^^^^^
