        icon_size_var.trace_add('write', lambda n,i,m: temp_settings['right_panel_button_style'].update({'icon_size': icon_size_var.get()}))

        # --- Innenabstand (ipady) ---
        ttk.Label(content_frame, text="Innenabstand (Vertikal, px):").grid(row=1, column=0, sticky='w', padx=5, pady=3)
        ipady_var = tk.IntVar(value=style_cfg.get('ipady', 2))
