    def _create_settings_namensliste_columns_section(self, parent_frame, temp_settings, dialog_vars, start_row=0):
        """Spaltenbreiten der Namensliste-Tabelle konfigurieren (Summe = 277 mm für A4-Querformat)."""
        TOTAL_WIDTH = 277
        COLUMNS = [
            ('name',        "Nachname, Vorname"),
            ('nationality', "Nationalität"),
            ('contact',     "E-Mail / Telefon"),
            ('car',         "PKW"),
            ('signature',   "Unterschrift"),
        ]
        DEFAULTS = self.default_settings.get('namensliste_col_widths', {})

        frame = ttk.LabelFrame(parent_frame, text="Namensliste: Spaltenbreiten (mm, Summe = 277 mm)", style='TLabelframe')
        frame.grid(row=start_row, column=0, columnspan=4, sticky='ew', padx=5, pady=8)
        frame.columnconfigure(1, weight=1)

        cfg = temp_settings.setdefault('namensliste_col_widths', dict(DEFAULTS))

        col_vars = {}
        total_var = tk.StringVar()

        def update_total(*_):
            try:
                s = sum(v.get() for v in col_vars.values())
                total_var.set(f"Summe: {s} mm")
                total_lbl.config(foreground='green' if s == TOTAL_WIDTH else 'red')
            except Exception:
                pass

        for i, (key, label) in enumerate(COLUMNS):
            ttk.Label(frame, text=f"{label}:", anchor='w', width=22).grid(
                row=i, column=0, sticky='w', padx=(8, 4), pady=3)
            var = tk.IntVar(value=cfg.get(key, DEFAULTS.get(key, 40)))
            col_vars[key] = var
            sp = ttk.Spinbox(frame, from_=10, to=200, textvariable=var, width=7)
            sp.grid(row=i, column=1, sticky='w', padx=4, pady=3)
            ttk.Label(frame, text="mm").grid(row=i, column=2, sticky='w')
            var.trace_add('write', lambda *_, k=key, v=var: (cfg.update({k: v.get()}), update_total()))

        total_lbl = ttk.Label(frame, textvariable=total_var, font=('', 10, 'bold'))
        total_lbl.grid(row=len(COLUMNS), column=0, columnspan=2, sticky='w', padx=8, pady=(6, 4))

        def reset_defaults():
            for key, var in col_vars.items():
                var.set(DEFAULTS.get(key, 40))
                cfg[key] = DEFAULTS.get(key, 40)
            update_total()

        ttk.Button(frame, text="Auf Standard zurücksetzen", command=reset_defaults).grid(
            row=len(COLUMNS), column=2, columnspan=2, sticky='e', padx=8, pady=(6, 4))

        dialog_vars['namensliste_col_width_vars'] = col_vars
        update_total()
        return start_row + 1

    def _create_settings_main_menu_buttons_section(self, parent_frame, temp_settings, dialog_vars, start_row=0):
        """Erstellt den Abschnitt zur Konfiguration der Hauptmenü-Kacheln (Tiles) im Einstellungsdialog."""
        main_menu_buttons_frame = ttk.LabelFrame(parent_frame, text="Hauptmenü-Kacheln (Tiles)", style='TLabelframe')
        main_menu_buttons_frame.grid(row=start_row, column=0, columnspan=4, sticky='ew', padx=5, pady=10)
        main_menu_buttons_frame.columnconfigure(1, weight=1) # Spalte für Eingabefelder dehnbar machen

        dialog_vars['main_menu_button_vars'] = {}
        
        button_order = ["AbrechnungFinanzen", "DienstplanungAufgaben", "WeckrufServices", "Vorlagen"]
        button_configs = temp_settings.get('main_menu_buttons', {})
        row_idx = 0

        for key in button_order:
            if key not in button_configs:
                continue
            
            dialog_vars['main_menu_button_vars'][key] = {}
            cfg = button_configs[key]

            # Ein Container-Frame für jede Kachel-Konfiguration, um die Elemente zu gruppieren
            button_config_frame = ttk.Frame(main_menu_buttons_frame, padding=(0, 5))
            button_config_frame.grid(row=row_idx, column=0, columnspan=4, sticky='ew')
            button_config_frame.columnconfigure(1, weight=1) # Spalte für Eingabefelder dehnbar machen

            # Haupt-Label für die Kachel
            ttk.Label(button_config_frame, text=f"Kachel '{cfg.get('label', key).replace(chr(10), ' ')}':", font=("Segoe UI", 9, "bold")).grid(row=0, column=0, columnspan=4, sticky='w', padx=5, pady=(5,2))

            # Checkbox zum Aktivieren/Deaktivieren
            is_active_var = tk.BooleanVar(value=cfg.get('is_active', True))
            dialog_vars['main_menu_button_vars'][key]['is_active_var'] = is_active_var
            ttk.Checkbutton(button_config_frame, text="Aktiv", variable=is_active_var, command=lambda k=key, v=is_active_var: temp_settings['main_menu_buttons'][k].update({'is_active': v.get()})).grid(row=1, column=0, sticky='w', padx=15)
            
            # Eingabefeld für den Label-Text
            ttk.Label(button_config_frame, text="Text:").grid(row=2, column=0, sticky='w', padx=15, pady=2)
            label_var = tk.StringVar(value=cfg.get('label', ''))
            dialog_vars['main_menu_button_vars'][key]['label_var'] = label_var
            ttk.Entry(button_config_frame, textvariable=label_var).grid(row=2, column=1, columnspan=3, sticky='ew', padx=5)
            label_var.trace_add('write', lambda n, i, m, k=key, v=label_var: temp_settings['main_menu_buttons'][k].update({'label': v.get()}))

            # Eingabefeld für das Sidebar-Symbol
            ttk.Label(button_config_frame, text="Symbol (Sidebar):").grid(row=3, column=0, sticky='w', padx=15, pady=2)
            sidebar_icon_var = tk.StringVar(value=cfg.get('sidebar_icon', '?'))
            dialog_vars['main_menu_button_vars'][key]['sidebar_icon_var'] = sidebar_icon_var
            ttk.Entry(button_config_frame, textvariable=sidebar_icon_var).grid(row=3, column=1, columnspan=3, sticky='ew', padx=5)
            sidebar_icon_var.trace_add('write', lambda n, i, m, k=key, v=sidebar_icon_var: temp_settings['main_menu_buttons'][k].update({'sidebar_icon': v.get()}))
            
            # Eingabefeld für das Dashboard-Icon (Bild) mit "Durchsuchen"-Button
            ttk.Label(button_config_frame, text="Bild (Kachel):").grid(row=4, column=0, sticky='w', padx=15, pady=2)
            dashboard_icon_var = tk.StringVar(value=cfg.get('dashboard_icon', ''))
            dialog_vars['main_menu_button_vars'][key]['dashboard_icon_var'] = dashboard_icon_var
            
            # Das Eingabefeld wird auf "readonly" gesetzt, um Fehleingaben zu vermeiden
            icon_path_entry = ttk.Entry(button_config_frame, textvariable=dashboard_icon_var, state='readonly')
            icon_path_entry.grid(row=4, column=1, columnspan=2, sticky='ew', padx=5)
            
            # Trace, um Änderungen am Pfad sofort in den temporären Einstellungen zu speichern
            dashboard_icon_var.trace_add('write', lambda n, i, m, k=key, v=dashboard_icon_var: temp_settings['main_menu_buttons'][k].update({'dashboard_icon': v.get()}))

            # Helper-Funktion, um den Dateidialog zu öffnen und die Variable zu aktualisieren
            def create_browse_callback(var_to_update):
                def browse():
                    fpath = filedialog.askopenfilename(
                        title="Icon für Kachel auswählen",
                        filetypes=[("Bilddateien", "*.png *.gif *.jpg *.avif"), ("Alle Dateien", "*.*")],
                        parent=parent_frame.winfo_toplevel()
                    )
                    if fpath:
                        var_to_update.set(fpath) # Der Trace wird hierdurch ausgelöst
                return browse
            
            ttk.Button(button_config_frame, text="...", width=3, command=create_browse_callback(dashboard_icon_var)).grid(row=4, column=3, sticky='w', padx=5)
            
            row_idx += 1
            
            # Trennlinie zwischen den Konfigurationsblöcken, außer beim letzten
            if row_idx < len(button_order):
                ttk.Separator(main_menu_buttons_frame, orient='horizontal').grid(row=row_idx, column=0, columnspan=4, sticky='ew', pady=8, padx=5)
                row_idx += 1

        return start_row + 1
    
