    def _create_settings_main_header_logo_section(self, parent_frame, temp_settings, dialog_vars, start_row=0):
        """Erstellt den Abschnitt für das anpassbare Logo im Haupt-Header. (UMBENANNT & KORRIGIERT)"""
        logo_frame = ttk.LabelFrame(parent_frame, text="Hauptmenü Logo (Kopfbereich)", style='TLabelframe')
        logo_frame.grid(row=start_row, column=0, columnspan=4, sticky='ew', padx=5, pady=10)
        logo_frame.columnconfigure(1, weight=1)

        # Vorschau-Label, das dem angeforderten Layout entspricht
        preview_label_container = ttk.Frame(logo_frame, relief='sunken', padding=5, width=150, height=100)
        preview_label_container.grid(row=0, column=1, padx=5, pady=5, sticky='w')
        preview_label_container.grid_propagate(False)
        preview_label = ttk.Label(preview_label_container)
        preview_label.pack(expand=True)
        
        ttk.Label(logo_frame, text="Vorschau:").grid(row=0, column=0, sticky='nw', padx=5, pady=5)

        # Pfad-Variable und Anzeige
        logo_path_var = tk.StringVar(value=temp_settings.get('header_logo_path', ''))
        dialog_vars['header_logo_path_var'] = logo_path_var
        
        path_display = ttk.Entry(logo_frame, textvariable=logo_path_var, state='readonly')
        path_display.grid(row=1, column=1, sticky='ew', padx=5, pady=5)
        ttk.Label(logo_frame, text="Datei auswählen:").grid(row=1, column=0, sticky='w', padx=5, pady=5)


        def update_preview(path):
            """Aktualisiert die Bildvorschau im Einstellungsdialog."""
            try:
                path_to_load = None
                if path and os.path.exists(path):
                    path_to_load = path
                else:
                    try:
                        default_path = resource_path("icons/bwp_logo.png")
                        if os.path.exists(default_path):
                            path_to_load = default_path
                    except Exception:
                        path_to_load = None

                if path_to_load:
                    img = Image.open(path_to_load)
                    img.thumbnail((128, 90)) # Vorschaugröße
                    photo = ImageTk.PhotoImage(img)
                    preview_label.config(image=photo, text="")
                    preview_label.image = photo
                else:
                    preview_label.config(image=None, text="Kein Logo")
                    preview_label.image = None
            except Exception as e:
                preview_label.config(image=None, text=f"Fehler:\n{e}")
                preview_label.image = None

        def browse_for_logo():
            fpath = filedialog.askopenfilename(
                title="Logo-Datei auswählen (PNG, JPG)",
                #filetypes=[("Bilddateien", "*.png *.jpg *.jpeg"), ("Alle Dateien", "*.*")],
                
                filetypes=[("Bilddateien", "*.png *.jpg *.jpeg *.avif"), ("Alle Dateien", "*.*")],

                
                parent=parent_frame.winfo_toplevel()
            )
            if fpath:
                logo_path_var.set(fpath)
                temp_settings['header_logo_path'] = fpath
                update_preview(fpath)
                
        def reset_to_default():
            logo_path_var.set('')
            temp_settings['header_logo_path'] = ''
            update_preview('')

        ttk.Label(logo_frame, text="Datei auswählen:").grid(row=1, column=0, sticky='w', padx=5, pady=5)
        ttk.Button(logo_frame, text="Durchsuchen...", command=browse_for_logo).grid(row=1, column=2, padx=5, pady=5)
        
        action_frame = ttk.Frame(logo_frame)
        action_frame.grid(row=2, column=1, sticky='w', pady=5)
        
        ttk.Button(action_frame, text="Auf Standard zurücksetzen", command=reset_to_default).pack(side='left', padx=5)

        update_preview(logo_path_var.get())

                # vvvvvvvvvvvvvvvvvvvvvvvv HIER BEGINNT DIE ERGÄNZUNG vvvvvvvvvvvvvvvvvvvvvvvv
        # Frame für die neuen Design-Einstellungen
        design_frame = ttk.Frame(logo_frame)
        design_frame.grid(row=3, column=0, columnspan=3, sticky='ew', pady=(10, 0), padx=5)
        design_frame.columnconfigure(1, weight=1)

        icon_cfg = temp_settings.setdefault('dashboard_header_icon_config', self.default_settings['dashboard_header_icon_config'].copy())
        
        # Icon-Größe
        ttk.Label(design_frame, text="Icon-Größe (px):").grid(row=0, column=0, sticky='w', pady=2)
        icon_size_var = tk.IntVar(value=icon_cfg.get('icon_size', 40))
        dialog_vars['header_icon_size_var'] = icon_size_var
        ttk.Spinbox(design_frame, from_=20, to=100, textvariable=icon_size_var, width=8).grid(row=0, column=1, sticky='e', padx=5)
        icon_size_var.trace_add('write', lambda n,i,m: temp_settings['dashboard_header_icon_config'].update({'icon_size': icon_size_var.get()}))

        # Innenabstand (padding)
        ttk.Label(design_frame, text="Innenabstand (Vertikal, px):").grid(row=1, column=0, sticky='w', pady=2)
        padding_var = tk.IntVar(value=icon_cfg.get('padding_vertical', 0))
        dialog_vars['header_icon_padding_var'] = padding_var
        ttk.Spinbox(design_frame, from_=0, to=50, textvariable=padding_var, width=8).grid(row=1, column=1, sticky='e', padx=5)
        padding_var.trace_add('write', lambda n,i,m: temp_settings['dashboard_header_icon_config'].update({'padding_vertical': padding_var.get()}))

        # Außenabstand (margin)
        ttk.Label(design_frame, text="Außenabstand (Vertikal, px):").grid(row=2, column=0, sticky='w', pady=2)
        margin_var = tk.IntVar(value=icon_cfg.get('margin_vertical', 0))
        dialog_vars['header_icon_margin_var'] = margin_var
        ttk.Spinbox(design_frame, from_=0, to=50, textvariable=margin_var, width=8).grid(row=2, column=1, sticky='e', padx=5)
        margin_var.trace_add('write', lambda n,i,m: temp_settings['dashboard_header_icon_config'].update({'margin_vertical': margin_var.get()}))
        # ^^^^^^^^^^^^^^^^^^^^^^^ HIER ENDET DIE ERGÄNZUNG ^^^^^^^^^^^^^^^^^^^^^^^
        
        return start_row + 1
            
            
    def _create_settings_shuttle_overlay_section(self, parent_frame, temp_settings, dialog_vars, start_row=0):
        """Erstellt den Abschnitt für die Konfiguration des 'Info-Fenster'-Buttons im Shuttle-Service."""
        frame = ttk.LabelFrame(parent_frame, text="Shuttle Service: Info-Fenster Button", style='TLabelframe')
        frame.grid(row=start_row, column=0, columnspan=4, sticky='ew', padx=5, pady=10)
        frame.columnconfigure(1, weight=1)

        settings_key = 'shuttle_button_configs'
        button_key = 'Shuttle_Overlay'
        
        # Sicherstellen, dass die Konfiguration existiert
        if button_key not in temp_settings.get(settings_key, {}):
            temp_settings.setdefault(settings_key, {})[button_key] = self.default_settings.get(settings_key, {}).get(button_key, {}).copy()

        cfg = temp_settings[settings_key][button_key]
        dialog_vars.setdefault(settings_key, {})[button_key] = {}

        # Vorschau-Label
        preview_label_container = ttk.Frame(frame, relief='sunken', padding=5, width=80, height=60)
        preview_label_container.grid(row=0, column=0, rowspan=3, padx=10, pady=5)
        preview_label_container.grid_propagate(False)
        preview_label = ttk.Label(preview_label_container, text="Vorschau")
        preview_label.pack(expand=True)

        def update_preview(path, text):
            try:
                if path and os.path.exists(path):
                    img = Image.open(path).resize((48, 48), Image.Resampling.LANCZOS)
                    photo = ImageTk.PhotoImage(img)
                    preview_label.config(image=photo, text="")
                    preview_label.image = photo
                else:
                    preview_label.config(image="", text=text, font=("Segoe UI Emoji", 14))
                    preview_label.image = None
            except Exception:
                preview_label.config(image="", text="Fehler")
                preview_label.image = None

        # UI-Elemente
        type_var = tk.StringVar(value=cfg.get('type', 'symbol'))
        label_var = tk.StringVar(value=cfg.get('value', '') if cfg.get('type') == 'symbol' else '👁️ Info-Fenster')
        image_var = tk.StringVar(value=cfg.get('value', '') if cfg.get('type') == 'image' else '')
        
        dialog_vars[settings_key][button_key]['type_var'] = type_var
        dialog_vars[settings_key][button_key]['label_var'] = label_var
        dialog_vars[settings_key][button_key]['image_var'] = image_var

        type_frame = ttk.Frame(frame); type_frame.grid(row=0, column=1, columnspan=3, sticky='w', padx=5)
        symbol_frame = ttk.Frame(frame); ttk.Label(symbol_frame, text="Text/Symbol:").pack(side='left', padx=(0, 5)); ttk.Entry(symbol_frame, textvariable=label_var).pack(side='left', fill='x', expand=True)
        image_frame = ttk.Frame(frame); ttk.Label(image_frame, text="Icon-Pfad:").pack(side='left', padx=(0, 5)); ttk.Label(image_frame, textvariable=image_var, relief='sunken', width=40).pack(side='left', fill='x', expand=True)
        browse_button = ttk.Button(image_frame, text="...", width=3, command=lambda: (fpath := filedialog.askopenfilename(filetypes=[("Bilder", "*.png *.gif *.jpg"), ("Alle", "*.*")]), image_var.set(fpath) if fpath else None))
        browse_button.pack(side='left', padx=2)

        def toggle_visibility(*args):
            selected_type = type_var.get()
            if selected_type == 'symbol':
                symbol_frame.grid(row=1, column=1, columnspan=3, sticky='ew', padx=5, pady=2); image_frame.grid_forget()
                update_preview(None, label_var.get())
            else:
                symbol_frame.grid_forget(); image_frame.grid(row=1, column=1, columnspan=3, sticky='ew', padx=5, pady=2)
                update_preview(image_var.get(), None)

        ttk.Radiobutton(type_frame, text="Text/Symbol", variable=type_var, value='symbol').pack(side='left')
        ttk.Radiobutton(type_frame, text="Bild", variable=type_var, value='image').pack(side='left', padx=(10, 0))
        
        def update_config(*args):
            cfg['type'] = type_var.get()
            cfg['value'] = label_var.get() if type_var.get() == 'symbol' else image_var.get()
            toggle_visibility()

        type_var.trace_add('write', update_config); label_var.trace_add('write', update_config); image_var.trace_add('write', update_config)
        toggle_visibility()

        return start_row + 1
    
    
    
