    def _create_settings_header_colors_section(self, parent_frame, temp_settings, dialog_vars, start_row=0):
        """Erstellt den Abschnitt für die anpassbaren Farben der Sektions-Überschriften."""
        header_colors_frame = ttk.LabelFrame(parent_frame, text="Farben der Sektions-Überschriften (Früh-/Spätdienst)", style='TLabelframe')
        header_colors_frame.grid(row=start_row, column=0, columnspan=4, sticky='ew', padx=5, pady=10)
        header_colors_frame.columnconfigure(1, weight=1)

        if 'section_header_colors' not in dialog_vars:
            dialog_vars['section_header_colors'] = {}
        
        # Mapping von internen Schlüsseln zu angezeigten Namen
        header_key_map = {
            'cash_section': "Bargeldzählung",
            'stamps_section': "Briefmarken",
            'cards_section': "Kartenzahlungen (alle)",
            'notes_section': "Notizen"
        }
        
        temp_header_colors = temp_settings.get('section_header_colors', {})
        # Robuster Zugriff auf die Standardeinstellungen
        default_header_colors = self.default_settings.get('section_header_colors', {})
        current_row = 0

        for key, label_text in header_key_map.items():
            # Sicherer Zugriff auf die Farben, falls Schlüssel fehlen
            default_color = default_header_colors.get(key, '#434C5E')
            initial_color = temp_header_colors.get(key, default_color)

            ttk.Label(header_colors_frame, text=f"{label_text}:").grid(row=current_row, column=0, sticky='w', padx=5, pady=3)

            color_var = tk.StringVar(value=initial_color)
            dialog_vars['section_header_colors'][key] = color_var
            
            color_display = tk.Label(header_colors_frame, textvariable=color_var, width=10, relief='solid', borderwidth=1, bg=initial_color)
            color_display.grid(row=current_row, column=1, sticky='w', padx=5)

            def pick_color_command(k=key, v=color_var, swatch=color_display):
                # Verwenden Sie toplevel(), um sicherzustellen, dass der Dialog über dem Einstellungsfenster liegt
                new_color_tuple = colorchooser.askcolor(title=f"Farbe für '{label_text}' wählen", initialcolor=v.get(), parent=parent_frame.winfo_toplevel())
                
                if new_color_tuple and new_color_tuple[1]:
                    hex_color = new_color_tuple[1].upper()
                    v.set(hex_color)
                    swatch.config(bg=hex_color)
                    
                    if 'section_header_colors' not in temp_settings:
                        temp_settings['section_header_colors'] = {}
                    temp_settings['section_header_colors'][k] = hex_color
            
            ttk.Button(header_colors_frame, text="Farbe wählen...", command=pick_color_command).grid(row=current_row, column=2, padx=5, pady=2)
            current_row += 1
            
        return start_row + 1
    
    
    def _create_settings_toast_colors_section(self, parent_frame, temp_settings, dialog_vars, start_row=0):
        """Erstellt den Abschnitt für die anpassbaren Farben der Benachrichtigungsfenster."""
        toast_colors_frame = ttk.LabelFrame(parent_frame, text="Benachrichtigungsfenster: Farben", style='TLabelframe')
        toast_colors_frame.grid(row=start_row, column=0, columnspan=4, sticky='ew', padx=5, pady=10)
        
        if 'toast_colors' not in dialog_vars:
            dialog_vars['toast_colors'] = {}

        toast_types = {
            'success': "Erfolg (Gelb)", 'warning': "Warnung (Orange/Rot)", 'error': "Fehler (Rot)",
            'info': "Information (Blau)", 'neutral': "Bestätigung (Grün)"
        }
        
        temp_toast_colors = temp_settings.get('toast_colors', {})
        current_row = 0

        for key, label_text in toast_types.items():
            ttk.Label(toast_colors_frame, text=f"{label_text}:").grid(row=current_row, column=0, sticky='w', padx=5, pady=3)
            
            color_config_frame = ttk.Frame(toast_colors_frame)
            color_config_frame.grid(row=current_row, column=1, columnspan=3, sticky='ew')

            color_attributes = [('bg', 'Hintergrund'), ('border', 'Rahmen'), ('title_fg', 'Titel'), ('message_fg', 'Text')]
            
            for i, (attr_key, attr_label) in enumerate(color_attributes):
                default_color = self.default_settings.get('toast_colors', {}).get(key, {}).get(attr_key, '#FFFFFF')
                initial_color = temp_toast_colors.get(key, {}).get(attr_key, default_color)

                color_var = tk.StringVar(value=initial_color)
                if key not in dialog_vars['toast_colors']: dialog_vars['toast_colors'][key] = {}
                dialog_vars['toast_colors'][key][attr_key] = color_var
                
                def pick_color(k=key, ak=attr_key, v=color_var, lbl=f"{label_text} - {attr_label}"):
                    new_color = colorchooser.askcolor(title=f"Farbe für '{lbl}'", initialcolor=v.get(), parent=parent_frame.winfo_toplevel())
                    if new_color and new_color[1]:
                        hex_color = new_color[1].upper()
                        v.set(hex_color)
                        if key not in temp_settings['toast_colors']: temp_settings['toast_colors'][key] = {}
                        temp_settings['toast_colors'][key][ak] = hex_color

                btn = ttk.Button(color_config_frame, text=attr_label, command=pick_color)
                btn.grid(row=0, column=i, padx=5, pady=2)

            current_row += 1
            
        return start_row + 1
    
        
    def _create_settings_logo_section(self, parent_frame, temp_settings, dialog_vars, start_row=0):
        """Erstellt den Abschnitt für das anpassbare Header-Logo im Einstellungsdialog."""
        logo_frame = ttk.LabelFrame(parent_frame, text="Hauptmenü Logo (Kopfbereich)", style='TLabelframe')
        logo_frame.grid(row=start_row, column=0, columnspan=4, sticky='ew', padx=5, pady=10)
        logo_frame.columnconfigure(1, weight=1)

        # Vorschau-Label
        ttk.Label(logo_frame, text="Vorschau:").grid(row=0, column=0, sticky='nw', padx=5, pady=5)
        preview_label = ttk.Label(logo_frame, relief='sunken', padding=5)
        preview_label.grid(row=0, column=1, padx=5, pady=5, sticky='w')
        
        # Pfad-Variable und Anzeige
        logo_path_var = tk.StringVar(value=temp_settings.get('header_logo_path', ''))
        dialog_vars['header_logo_path_var'] = logo_path_var
        
        path_display = ttk.Entry(logo_frame, textvariable=logo_path_var, state='readonly')
        path_display.grid(row=1, column=1, sticky='ew', padx=5, pady=5)

        def update_preview(path):
            try:
                if path and os.path.exists(path):
                    img = Image.open(path)
                    img.thumbnail((128, 128)) # Vorschaugröße
                    photo = ImageTk.PhotoImage(img)
                    preview_label.config(image=photo, text="")
                    preview_label.image = photo # Referenz behalten
                else:
                    # Standardlogo anzeigen, wenn kein Pfad oder ein ungültiger Pfad vorhanden ist
                    default_img_path = resource_path("icons/bwp_logo.png")
                    if os.path.exists(default_img_path):
                        default_img = Image.open(default_img_path)
                        default_img.thumbnail((128, 128))
                        photo = ImageTk.PhotoImage(default_img)
                        preview_label.config(image=photo, text="")
                        preview_label.image = photo
                    else:
                        preview_label.config(image=None, text="Standard nicht gefunden")
                        preview_label.image = None

            except Exception as e:
                preview_label.config(image=None, text=f"Fehler:\n{e}")
                preview_label.image = None

        def browse_for_logo():
            fpath = filedialog.askopenfilename(
                title="Logo-Datei auswählen (PNG, JPG)",
                filetypes=[("Bilddateien", "*.png *.jpg *.jpeg"), ("Alle Dateien", "*.*")],
                parent=parent_frame.winfo_toplevel()
            )
            if fpath:
                logo_path_var.set(fpath)
                temp_settings['header_logo_path'] = fpath
                update_preview(fpath)
                
        def reset_logo():
            logo_path_var.set('')
            temp_settings['header_logo_path'] = ''
            update_preview('')

        ttk.Label(logo_frame, text="Datei:").grid(row=1, column=0, sticky='w', padx=5, pady=5)
        ttk.Button(logo_frame, text="Durchsuchen...", command=browse_for_logo).grid(row=1, column=2, padx=5, pady=5)
        ttk.Button(logo_frame, text="Zurücksetzen", command=reset_logo).grid(row=2, column=1, sticky='w', padx=5, pady=5)

        update_preview(logo_path_var.get()) # Initiale Vorschau laden

        return start_row + 1


    
    
    def _create_settings_dashboard_header_section(self, parent_frame, temp_settings, dialog_vars, start_row=0):
        """Erstellt den Abschnitt für das anpassbare Icon im Dashboard-Header."""
        header_icon_frame = ttk.LabelFrame(parent_frame, text="Dashboard: Header-Icon", style='TLabelframe')
        header_icon_frame.grid(row=start_row, column=0, columnspan=4, sticky='ew', padx=5, pady=10)
        header_icon_frame.columnconfigure(1, weight=1)

        icon_path = temp_settings.get('dashboard_header_icon_path', '')
        
        ttk.Label(header_icon_frame, text="Icon-Bildpfad:").grid(row=0, column=0, sticky='w', padx=5, pady=5)
        
        header_icon_path_var = tk.StringVar(value=icon_path)
        dialog_vars['dashboard_header_icon_path_var'] = header_icon_path_var
        
        # --- KORREKTUR: Label durch Entry ersetzt ---
        path_entry = ttk.Entry(header_icon_frame, textvariable=header_icon_path_var)
        path_entry.grid(row=0, column=1, sticky='ew', padx=5, pady=5)
        
        # Trace hinzufügen, um manuelle Änderungen am Pfad zu speichern
        def update_path_from_entry(*args):
            temp_settings['dashboard_header_icon_path'] = header_icon_path_var.get()
        header_icon_path_var.trace_add('write', update_path_from_entry)

        def browse_header_icon():
            fpath = filedialog.askopenfilename(
                title="Dashboard Header-Icon auswählen",
                #filetypes=[("Bilddateien", "*.png *.jpg *.gif"), ("Alle Dateien", "*.*")],
                
                filetypes=[("Bilddateien", "*.png *.jpg *.gif *.avif"), ("Alle Dateien", "*.*")],

                
                parent=parent_frame.winfo_toplevel()
            )
            if fpath:
                header_icon_path_var.set(fpath)
                # Der Trace sorgt automatisch für die Speicherung in temp_settings

        browse_btn = ttk.Button(header_icon_frame, text="Bild auswählen...", command=browse_header_icon)
        browse_btn.grid(row=0, column=2, padx=5, pady=5)

        return start_row + 1
    
    
    def _create_settings_header_icon_section(self, parent_frame, temp_settings, dialog_vars, start_row=0):
        """Erstellt den Abschnitt für die Konfiguration des Icons in der Überschrift."""
        frame = ttk.LabelFrame(parent_frame, text="Überschriften-Icon (Hauptmenü)", style='TLabelframe')
        frame.grid(row=start_row, column=0, columnspan=4, sticky='ew', padx=5, pady=10)
        
        # Holen der aktuellen Konfiguration oder der Standardwerte
        icon_cfg = temp_settings.get('dashboard_header_icon_config', self.default_settings['dashboard_header_icon_config'].copy())
        
        # UI für Icon-Größe
        ttk.Label(frame, text="Icon-Größe (px):").grid(row=0, column=0, sticky='w', padx=5, pady=3)
        icon_size_var = tk.IntVar(value=icon_cfg.get('icon_size', 40))
        dialog_vars['header_icon_size_var'] = icon_size_var
        ttk.Spinbox(frame, from_=20, to=100, textvariable=icon_size_var, width=7).grid(row=0, column=1, sticky='w', padx=5)
        icon_size_var.trace_add('write', lambda n,i,m: temp_settings.setdefault('dashboard_header_icon_config', {}).update({'icon_size': icon_size_var.get()}))

        # UI für Innenabstand (Vertikal)
        ttk.Label(frame, text="Innenabstand (Vertikal, px):").grid(row=1, column=0, sticky='w', padx=5, pady=3)
        padding_var = tk.IntVar(value=icon_cfg.get('padding_vertical', 0))
        dialog_vars['header_icon_padding_var'] = padding_var
        ttk.Spinbox(frame, from_=0, to=50, textvariable=padding_var, width=7).grid(row=1, column=1, sticky='w', padx=5)
        padding_var.trace_add('write', lambda n,i,m: temp_settings.setdefault('dashboard_header_icon_config', {}).update({'padding_vertical': padding_var.get()}))

        # UI für Außenabstand (Vertikal)
        ttk.Label(frame, text="Außenabstand (Vertikal, px):").grid(row=2, column=0, sticky='w', padx=5, pady=3)
        margin_var = tk.IntVar(value=icon_cfg.get('margin_vertical', 0))
        dialog_vars['header_icon_margin_var'] = margin_var
        ttk.Spinbox(frame, from_=0, to=50, textvariable=margin_var, width=7).grid(row=2, column=1, sticky='w', padx=5)
        margin_var.trace_add('write', lambda n,i,m: temp_settings.setdefault('dashboard_header_icon_config', {}).update({'margin_vertical': margin_var.get()}))

        return start_row + 1
    
        
    def _rebuild_ui_after_settings_change(self):
        """
        Zerstört und erstellt die Haupt-UI-Komponenten neu. In dieser korrigierten Version
        wird am Ende kein show_page mehr aufgerufen, um doppeltes Laden zu verhindern.
        """
        # Der gesamte bestehende Code in dieser Methode bleibt unverändert...
        # ... (alle self._create..._page Aufrufe bleiben hier) ...
        self._create_shift_widgets(self.fruehdienst_frame, self.fruehdienst_vars, "Frühdienst", self.spaetdienst_vars)
        self._create_shift_widgets(self.spaetdienst_frame, self.spaetdienst_vars, "Spätdienst", self.fruehdienst_vars)
        self._configure_header_elements()
        self._update_all_calculations(called_by_button=False)
        
        
        
    def _open_settings_dialog(self, event=None):
        if not self.is_admin_mode:
            messagebox.showwarning("Einstellungen", "Admin-Zugriff erforderlich.")
            return

        settings_window = tk.Toplevel(self.master)
        settings_window.title("Programmeinstellungen")
        settings_window.transient(self.master)
        settings_window.grab_set()
        
        main_settings_frame = ttk.Frame(settings_window, padding=10)
        main_settings_frame.pack(fill='both', expand=True)
        main_settings_frame.rowconfigure(1, weight=1)
        main_settings_frame.columnconfigure(0, weight=1)

        temp_settings = json.loads(json.dumps(self.current_settings))
        dialog_vars = {}

        self.symbol_input_vars = {}
        self.ta_symbol_input_vars = {}
        self.shift_action_button_vars = {}
        self.dialog_button_vars = {}
        self.checklist_button_vars = {}
        self.weckrufliste_button_vars = {}
        self.taxibestellung_button_vars = {}
        self.shuttle_button_vars = {}

        def save_and_close_settings():
            old_backup_enabled_states = {
                'kassenprotokoll': self.current_settings.get('auto_backup_enabled', False),
                'trinkgeld': self.current_settings.get('auto_backup_trinkgeld_enabled', False),
                'minibar': self.current_settings.get('auto_backup_minibar_enabled', False),
                'shuttle': self.current_settings.get('auto_backup_shuttle_enabled', False),
                'tagesabrechnung': self.current_settings.get('auto_backup_tagesabrechnung_enabled', False),
                'weckruf': self.current_settings.get('auto_backup_weckruf_enabled', False),
            }

            path_changed = False
            if 'data_storage_path_var' in dialog_vars:
                new_path_from_dialog_str = dialog_vars['data_storage_path_var'].get()
                actual_path_for_settings = ""
                if "(Standard)" in new_path_from_dialog_str:
                    actual_path_for_settings = ""
                else:
                    actual_path_for_settings = new_path_from_dialog_str.strip()
                    if not os.path.isdir(actual_path_for_settings):
                        try:
                            os.makedirs(actual_path_for_settings, exist_ok=True)
                        except OSError as e_mkdir_custom:
                            messagebox.showerror("Fehler Speicherpfad", f"Konnte benutzerdefinierten Speicherpfad '{actual_path_for_settings}' nicht erstellen: {e_mkdir_custom}\nÄnderungen am Pfad werden nicht gespeichert.", parent=settings_window)
                            actual_path_for_settings = self.current_settings.get('data_storage_path', "")

                old_data_storage_path_setting = self.current_settings.get('data_storage_path', '')
                if actual_path_for_settings != old_data_storage_path_setting:
                    path_changed = True
                    app_path_config_file_default_loc = get_app_data_path(self.APP_PATH_CONFIG_FILENAME)
                    try:
                        with open(app_path_config_file_default_loc, 'w', encoding='utf-8') as f_app_cfg:
                            json.dump({"custom_data_path": actual_path_for_settings}, f_app_cfg, indent=2)
                    except IOError as e_io_app_cfg:
                        messagebox.showerror("Fehler", f"Konnte die Pfadkonfiguration nicht speichern: {e_io_app_cfg}\nÄnderung des Speicherorts wird möglicherweise nicht persistent.", parent=settings_window)
                        path_changed = False

                    if path_changed:
                        self.effective_data_root = self._determine_effective_data_root()
                        self.settings_file = os.path.join(self.effective_data_root, 'kassenprotokoll_settings.json')
                        self.history_file = os.path.join(self.effective_data_root, 'kassenprotokoll_history.json')
                        self.trinkgeld_data_file = os.path.join(self.effective_data_root, 'trinkgeld_data.json')
                        self.minibar_data_file = os.path.join(self.effective_data_root, 'minibar_data.json')
                temp_settings['data_storage_path'] = actual_path_for_settings
            
            if 'new_admin_password_var' in dialog_vars and dialog_vars['new_admin_password_var'].get():
                temp_settings['admin_password'] = dialog_vars['new_admin_password_var'].get()
            
            if 'dashboard_bg_path_var' in dialog_vars:
                temp_settings['dashboard_background_image_path'] = dialog_vars['dashboard_bg_path_var'].get()
            if 'dashboard_bg_alpha_var' in dialog_vars:
                temp_settings['dashboard_background_image_alpha'] = dialog_vars['dashboard_bg_alpha_var'].get()
            
            if 'dashboard_bg_scaling_mode_var' in dialog_vars:
                temp_settings['dashboard_background_scaling_mode'] = dialog_vars['dashboard_bg_scaling_mode_var'].get()

            if 'layover_design_vars' in dialog_vars:
                if 'layover_design_configs' not in temp_settings:
                    temp_settings['layover_design_configs'] = {}
                for key, var in dialog_vars['layover_design_vars'].items():
                    temp_settings['layover_design_configs'][key] = var.get()
            
            if 'offene_rechnungen_icon_path_var' in dialog_vars:
                temp_settings['offene_rechnungen_icon_path'] = dialog_vars['offene_rechnungen_icon_path_var'].get()

            if 'pdf_logo_path_vars' in dialog_vars:
                if 'pdf_logo_paths' not in temp_settings:
                    temp_settings['pdf_logo_paths'] = {}
                for key, var in dialog_vars['pdf_logo_path_vars'].items():
                    temp_settings['pdf_logo_paths'][key] = var.get()

            if 'window_width_var' in dialog_vars: temp_settings['window_width'] = dialog_vars['window_width_var'].get()
            if 'window_height_var' in dialog_vars: temp_settings['window_height'] = dialog_vars['window_height_var'].get()
            if 'tab_header_bold_var' in dialog_vars: temp_settings['tab_header_bold'] = dialog_vars['tab_header_bold_var'].get()
            #if 'selected_theme_var' in dialog_vars: temp_settings['selected_theme'] = dialog_vars['selected_theme_var'].get()

            
             # vvvvv HIER IST DIE KORREKTUR vvvvv
            if 'selected_theme_var' in dialog_vars:
                new_theme = dialog_vars['selected_theme_var'].get()
                temp_settings['selected_theme'] = new_theme
                
                # Wir versuchen, das Theme sofort "hart" anzuwenden
                try:
                    # Weg 1: Über die ThemedTk-Methode des Hauptfensters (bevorzugt)
                    if hasattr(self.master, "set_theme"):
                        self.master.set_theme(new_theme)
                    
                    # Weg 2: Direkt über den Style-Manager (als Fallback/Verstärkung)
                    self.style.theme_use(new_theme)
                    
                except Exception as e:
                    print(f"Warnung: Theme '{new_theme}' konnte nicht sofort angewendet werden: {e}")
            # ^^^^^ ENDE DER KORREKTUR ^^^^^
             

            font_size_map = {
                'general_font_size_var': 'general_font_size', 'number_font_size_var': 'number_font_size',
                'dashboard_input_field_font_size_var': 'dashboard_input_field_font_size', 'overall_header_font_size_var': 'overall_header_font_size'
            }
            for var_key, setting_key in font_size_map.items():
                if var_key in dialog_vars: temp_settings[setting_key] = dialog_vars[var_key].get()
                
            if 'color_vars' in dialog_vars:
                for key, var in dialog_vars['color_vars'].items():
                    if isinstance(var, tk.StringVar):
                        temp_settings[key] = var.get()
                    elif isinstance(var, dict) and key == 'tab_colors':
                        if 'tab_colors' not in temp_settings:
                            temp_settings['tab_colors'] = {}
                        for tab_key, tab_color_var in var.items():
                            if isinstance(tab_color_var, tk.StringVar):
                                temp_settings['tab_colors'][tab_key] = tab_color_var.get()
            
            if 'starting_float_value_var' in dialog_vars:
                parsed_val = self._parse_input_string(dialog_vars['starting_float_value_var'].get())
                if parsed_val is not None: temp_settings['starting_float_value'] = float(abs(parsed_val))
            if 'use_quantity_combobox_var' in dialog_vars: temp_settings['use_quantity_combobox'] = dialog_vars['use_quantity_combobox_var'].get()
            if 'quantity_combobox_max_value_var' in dialog_vars: temp_settings['quantity_combobox_max_value'] = dialog_vars['quantity_combobox_max_value_var'].get()

            if 'alarm_enabled_var' in dialog_vars: temp_settings['alarm_enabled'] = dialog_vars['alarm_enabled_var'].get()
            if 'alarm_sound_path_var' in dialog_vars: temp_settings['alarm_sound_path'] = dialog_vars['alarm_sound_path_var'].get()
            
            if 'hover_sound_enabled_var' in dialog_vars:
                temp_settings['hover_sound_enabled'] = dialog_vars['hover_sound_enabled_var'].get()
            if 'hover_sound_path_var' in dialog_vars:
                temp_settings['hover_sound_path'] = dialog_vars['hover_sound_path_var'].get()
            
            if 'smtp_vars' in dialog_vars:
                if 'smtp_settings' not in temp_settings: temp_settings['smtp_settings'] = {}
                for key, var in dialog_vars['smtp_vars'].items(): temp_settings['smtp_settings'][key] = var.get()
                try: temp_settings['smtp_settings']['port'] = int(temp_settings['smtp_settings']['port'])
                except (ValueError, TypeError): temp_settings['smtp_settings']['port'] = 587
            
            self.current_settings = temp_settings
            self._save_settings()
            canvas.unbind_all("<MouseWheel>")
            settings_window.destroy()

            self._apply_settings_to_styles()
            self._schedule_periodic_backup()

            if self.current_settings.get('auto_backup_enabled') and not old_backup_enabled_states['kassenprotokoll']:
                print("Führe initiales Backup für Kassenprotokoll aus...")
                self._perform_auto_backup()
            if self.current_settings.get('auto_backup_trinkgeld_enabled') and not old_backup_enabled_states['trinkgeld']:
                print("Führe initiales Backup für Trinkgeldliste aus...")
                self._perform_auto_backup_trinkgeld()
            if self.current_settings.get('auto_backup_minibar_enabled') and not old_backup_enabled_states['minibar']:
                print("Führe initiales Backup für Minibarliste aus...")
                self._perform_auto_backup_minibar()
            if self.current_settings.get('auto_backup_shuttle_enabled') and not old_backup_enabled_states['shuttle']:
                print("Führe initiales Backup für Shuttle-Service aus...")
                self._perform_auto_backup_shuttle()
            if self.current_settings.get('auto_backup_tagesabrechnung_enabled') and not old_backup_enabled_states['tagesabrechnung']:
                print("Führe initiales Backup für Tagesabrechnung aus...")
                self._perform_auto_backup_tagesabrechnung()
            if self.current_settings.get('auto_backup_weckruf_enabled') and not old_backup_enabled_states['weckruf']:
                print("Führe initiales Backup für Weckrufliste aus...")
                self._perform_auto_backup_weckruf()

            self._init_shift_vars(self.fruehdienst_vars, "Frühdienst")
            self._init_shift_vars(self.spaetdienst_vars, "Spätdienst")
            
            self._rebuild_ui_after_settings_change()

            if path_changed:
                messagebox.showinfo("Speicherort Geändert", "Der Datenspeicherort wurde geändert. Die Anwendung verwendet nun den neuen Pfad.\nBitte stellen Sie sicher, dass vorhandene Daten bei Bedarf manuell kopiert werden.", parent=self.master)

        def cancel_and_close_settings():
            if canvas.winfo_exists():
                canvas.unbind_all("<MouseWheel>")
            settings_window.destroy()

        # --- UI Aufbau ---
        button_frame_settings = ttk.Frame(main_settings_frame)
        button_frame_settings.grid(row=0, column=0, sticky='ew', pady=(0, 10))
        button_frame_settings.columnconfigure((0,1), weight=1)
        ttk.Button(button_frame_settings, text="Speichern & Schließen", command=save_and_close_settings).pack(side='left', fill='x', expand=True, padx=5, ipady=4)
        ttk.Button(button_frame_settings, text="Abbrechen", command=cancel_and_close_settings).pack(side='left', fill='x', expand=True, padx=5, ipady=4)
        
        canvas = tk.Canvas(main_settings_frame, borderwidth=0, highlightthickness=0)
        vsb = ttk.Scrollbar(main_settings_frame, orient="vertical", command=canvas.yview)
        canvas.configure(yscrollcommand=vsb.set)
        
        vsb.grid(row=1, column=1, sticky='ns')
        canvas.grid(row=1, column=0, sticky='nsew')

        settings_content_frame = ttk.Frame(canvas, padding=10)
        canvas_window_id = canvas.create_window((0,0), window=settings_content_frame, anchor="nw")

        def _on_frame_configure(event):
            canvas.configure(scrollregion=canvas.bbox("all"))
        def _on_canvas_configure(event):
            canvas.itemconfig(canvas_window_id, width=event.width)

        settings_content_frame.bind("<Configure>", _on_frame_configure)
        canvas.bind("<Configure>", _on_canvas_configure)

        def _on_mousewheel(event):
            if canvas.winfo_exists():
                canvas.yview_scroll(int(-1 * (event.delta / 120)), "units")
        canvas.bind_all("<MouseWheel>", _on_mousewheel)

        settings_notebook = ttk.Notebook(settings_content_frame)
        settings_notebook.pack(fill='both', expand=True)

        tab_general = ttk.Frame(settings_notebook, padding=10)
        tab_appearance = ttk.Frame(settings_notebook, padding=10)
        tab_content_logic = ttk.Frame(settings_notebook, padding=10)
        tab_pdf_logos = ttk.Frame(settings_notebook, padding=10)

        settings_notebook.add(tab_general, text="Allgemein")
        settings_notebook.add(tab_appearance, text="Darstellung")
        settings_notebook.add(tab_content_logic, text="Inhalte & Logik")
        settings_notebook.add(tab_pdf_logos, text="PDF-Logos")

        self._populate_general_settings_tab(tab_general, temp_settings, dialog_vars)
        self._populate_appearance_settings_tab(tab_appearance, temp_settings, dialog_vars)
        self._populate_content_logic_settings_tab(tab_content_logic, temp_settings, dialog_vars)
        self._populate_pdf_logos_settings_tab(tab_pdf_logos, temp_settings, dialog_vars)

        settings_window.protocol("WM_DELETE_WINDOW", cancel_and_close_settings)
        
        settings_window.resizable(True, True)
        settings_window.state('zoomed')
        settings_window.minsize(750, 650)

    def cancel_and_close_settings():
        settings_window.destroy()

        # --- UI Aufbau ---
        button_frame_settings = ttk.Frame(main_settings_frame)
        button_frame_settings.grid(row=0, column=0, sticky='ew', pady=(0, 10))
        button_frame_settings.columnconfigure((0,1), weight=1)
        ttk.Button(button_frame_settings, text="Speichern & Schließen", command=save_and_close_settings).pack(side='left', fill='x', expand=True, padx=5, ipady=4)
        ttk.Button(button_frame_settings, text="Abbrechen", command=cancel_and_close_settings).pack(side='left', fill='x', expand=True, padx=5, ipady=4)
        
        canvas = tk.Canvas(main_settings_frame, borderwidth=0, highlightthickness=0)
        vsb = ttk.Scrollbar(main_settings_frame, orient="vertical", command=canvas.yview)
        canvas.configure(yscrollcommand=vsb.set)
        
        vsb.grid(row=1, column=1, sticky='ns')
        canvas.grid(row=1, column=0, sticky='nsew')

        settings_content_frame = ttk.Frame(canvas, padding=10)
        canvas_window_id = canvas.create_window((0,0), window=settings_content_frame, anchor="nw")

        def _on_frame_configure(event):
            canvas.configure(scrollregion=canvas.bbox("all"))
        def _on_canvas_configure(event):
            canvas.itemconfig(canvas_window_id, width=event.width)

        settings_content_frame.bind("<Configure>", _on_frame_configure)
        canvas.bind("<Configure>", _on_canvas_configure)

        settings_notebook = ttk.Notebook(settings_content_frame)
        settings_notebook.pack(fill='both', expand=True)

        tab_general = ttk.Frame(settings_notebook, padding=10)
        tab_appearance = ttk.Frame(settings_notebook, padding=10)
        tab_content_logic = ttk.Frame(settings_notebook, padding=10)
        
        settings_notebook.add(tab_general, text="Allgemein")
        settings_notebook.add(tab_appearance, text="Darstellung")
        settings_notebook.add(tab_content_logic, text="Inhalte & Logik")
        
        # HIER ERFOLGEN DIE KORREKTEN AUFRUFE
        self._populate_general_settings_tab(tab_general, temp_settings, dialog_vars)
        self._populate_appearance_settings_tab(tab_appearance, temp_settings, dialog_vars)
        self._populate_content_logic_settings_tab(tab_content_logic, temp_settings, dialog_vars)

        settings_window.protocol("WM_DELETE_WINDOW", cancel_and_close_settings)
        
        settings_window.resizable(True, True)
        settings_window.state('zoomed')
        settings_window.minsize(750, 650)
    
    def _add_edit_minibar_item_dialog(self, parent_window, item=None, current_defs=None, list_name='minibar_items'):
        is_editing = item is not None
        title = "Minibar Artikel Bearbeiten" if is_editing else "Minibar Artikel Hinzufügen"
        
        new_name = simpledialog.askstring(title, "Artikelname:", parent=parent_window, initialvalue=item.get('name','') if item else '')
        if new_name is None or not new_name.strip():
            if new_name is not None: messagebox.showerror("Fehler", "Artikelname darf nicht leer sein.", parent=parent_window)
            return None
        new_name_stripped = new_name.strip()

        is_name_conflicting = False
        for def_item in (current_defs or []):
            if def_item.get('name', '').strip().lower() == new_name_stripped.lower():
                if not (is_editing and item and item.get('name', '').strip().lower() == new_name_stripped.lower()):
                    is_name_conflicting = True
                    break
        if is_name_conflicting:
            messagebox.showwarning("Duplikat", f"Ein Artikel mit dem Namen '{new_name_stripped}' existiert bereits.", parent=parent_window)
            return None

        new_price_str = simpledialog.askstring(title, "Preis (€):", parent=parent_window, initialvalue=str(item.get('price',0.0)).replace('.',',') if item else '0,00 €')
        if new_price_str is None: return None
        
        parsed_price = self._parse_input_string(new_price_str.replace("€","").strip())
        if parsed_price is None or parsed_price < 0:
            messagebox.showerror("Fehler", "Ungültiger Preis. Muss eine nicht-negative Zahl sein.", parent=parent_window)
            return None
            
        return {'name': new_name_stripped, 'price': float(parsed_price), 'is_active': item.get('is_active', True) if is_editing else True}

    def _add_edit_cash_denomination_dialog(self, parent_window, item=None, current_defs=None, list_name='cash_denominations'):
        is_editing = item is not None; title = "Stückelung bearbeiten" if is_editing else "Stückelung hinzufügen"
        initial_val_str = str(item.get('value', 0.0)).replace('.', ',') if item else '0,00'
        
        new_value_str = simpledialog.askstring(title, "Wert der Stückelung (€):", parent=parent_window, initialvalue=initial_val_str)
        if new_value_str is None: return None
        
        parsed_value = self._parse_input_string(new_value_str)
        if parsed_value is None or parsed_value <= 0:
            messagebox.showerror("Fehler", "Ungültiger Wert. Muss eine positive Zahl sein.", parent=parent_window)
            return None
        
        float_value = float(parsed_value)
        for def_item in (current_defs or []):
            if abs(def_item.get('value', -1.0) - float_value) < 0.001:
                 messagebox.showwarning("Duplikat", f"Eine Stückelung mit dem Wert '{new_value_str}' existiert bereits.", parent=parent_window)
                 return None
        
        return {'value': float_value, 'is_active': item.get('is_active', True) if is_editing else True}

    def _add_edit_stamp_dialog(self, parent_window, item=None, current_defs=None, list_name='stamp_definitions'):
        is_editing = item is not None; title = "Briefmarke bearbeiten" if is_editing else "Briefmarke hinzufügen"

        new_label = simpledialog.askstring(title, "Label (Bezeichnung):", parent=parent_window, initialvalue=item.get('label', '') if item else '')
        if new_label is None or not new_label.strip():
             if new_label is not None: messagebox.showerror("Fehler", "Label darf nicht leer sein.", parent=parent_window)
             return None
        new_label_stripped = new_label.strip()

        for def_item in (current_defs or []):
            if def_item.get('label', '').strip().lower() == new_label_stripped.lower():
                messagebox.showwarning("Duplikat", f"Ein Label mit dem Namen '{new_label_stripped}' existiert bereits.", parent=parent_window)
                return None
        
        new_price_str = simpledialog.askstring(title, "Preis (€):", parent=parent_window, initialvalue=str(item.get('price',0.0)).replace('.',',') if item else '0,00')
        if new_price_str is None: return None
        parsed_price = self._parse_input_string(new_price_str)
        if parsed_price is None or parsed_price <= 0:
            messagebox.showerror("Fehler", "Ungültiger Preis. Muss eine positive Zahl sein.", parent=parent_window)
            return None

        return {'label': new_label_stripped, 'price': float(parsed_price), 'is_active': item.get('is_active', True) if is_editing else True}

    def _add_edit_card_type_dialog(self, parent_window, item=None, current_defs=None, list_name='card_types'):
        is_editing = item is not None; title = "Kartentyp bearbeiten" if is_editing else "Kartentyp hinzufügen"
        
        new_key = simpledialog.askstring(title, "Schlüssel (Key, z.B. 'Mastercard', ohne Leerzeichen):", parent=parent_window, initialvalue=item.get('key', '') if item else '')
        if new_key is None or not new_key.strip() or " " in new_key:
            if new_key is not None: messagebox.showerror("Fehler", "Schlüssel darf nicht leer sein und keine Leerzeichen enthalten.", parent=parent_window)
            return None
        new_key_stripped = new_key.strip()

        for def_item in (current_defs or []):
            if def_item.get('key', '').strip().lower() == new_key_stripped.lower():
                messagebox.showwarning("Duplikat", f"Ein Kartentyp mit dem Schlüssel '{new_key_stripped}' existiert bereits.", parent=parent_window)
                return None

        new_label = simpledialog.askstring(title, "Anzeige-Label:", parent=parent_window, initialvalue=item.get('label', '') if item else new_key_stripped)
        if new_label is None or not new_label.strip():
            if new_label is not None: messagebox.showerror("Fehler", "Anzeige-Label darf nicht leer sein.", parent=parent_window)
            return None
        
        return {'key': new_key_stripped, 'label': new_label.strip(), 'is_active': item.get('is_active', True) if is_editing else True}

    def _extract_data_for_snapshot(self, vars_dict, shift_name_for_lookup):
        data = {}
        if 'cash_counts' in vars_dict: data['cash_counts'] = {str(k): v.get() for k, v in vars_dict['cash_counts'].items()}
        data['cash_amounts_display_manual'] = {}
        target_cash_amounts_display_dict = vars_dict.get('cash_amounts_display', {})
        for denom_key_float in vars_dict.get('cash_denominations', []):
            if denom_key_float < 5.0:
                coin_amount_str_var = target_cash_amounts_display_dict.get(denom_key_float)
                if isinstance(coin_amount_str_var, tk.StringVar): data['cash_amounts_display_manual'][str(denom_key_float)] = coin_amount_str_var.get()
                else: data['cash_amounts_display_manual'][str(denom_key_float)] = self._format_decimal_for_display(decimal.Decimal('0.00'))
        if 'cash_sum_display' in vars_dict and isinstance(vars_dict['cash_sum_display'], tk.StringVar): data['cash_sum_display'] = vars_dict['cash_sum_display'].get()
        else: data['cash_sum_display'] = self._format_decimal_for_display(decimal.Decimal('0.00'))
        if 'stamp_counts' in vars_dict: data['stamp_counts'] = {str(k): v.get() for k, v in vars_dict['stamp_counts'].items()}
        if 'stamp_price_input' in vars_dict: data['stamp_price_input'] = {str(k): v.get() for k, v in vars_dict['stamp_price_input'].items()}
        if 'stamp_sum_display' in vars_dict and isinstance(vars_dict['stamp_sum_display'], tk.StringVar): data['stamp_sum_display'] = vars_dict['stamp_sum_display'].get()
        else: data['stamp_sum_display'] = self._format_decimal_for_display(decimal.Decimal('0.00'))
        if 'card_data' in vars_dict:
            data['card_data'] = {}
            for card_key, card_details in vars_dict['card_data'].items():
                data['card_data'][card_key] = {}
                fields_to_save_per_card = ['manual_total_input', 'fruehdienst_sum_input', 'spaetdienst_sum_input']
                num_reception_fields = self.current_settings.get('reception_fields_count', 3)
                fields_to_save_per_card.extend([f'reception{i}' for i in range(1, num_reception_fields + 1)])
                for field_key in fields_to_save_per_card:
                     if field_key in card_details and isinstance(card_details[field_key], (tk.StringVar, tk.DoubleVar)):
                         data['card_data'][card_key][field_key] = card_details[field_key].get()
        if hasattr(self, 'kassenabschluss_wert_vars') and shift_name_for_lookup in self.kassenabschluss_wert_vars:
            data['kassenabschluss_werte'] = {}
            all_reco_defs_in_settings = self.current_settings.get('kassenabschluss_zeilen_definitionen', [])
            for k, v in self.kassenabschluss_wert_vars[shift_name_for_lookup].items():
                 if isinstance(v, tk.StringVar): data['kassenabschluss_werte'][k] = v.get()
        current_notes_content = ""
        if vars_dict.get('notes_text_widget') and vars_dict['notes_text_widget'].winfo_exists() and vars_dict['notes_text_widget'].winfo_ismapped():

            current_notes_content = vars_dict['notes_text_widget'].get("1.0", tk.END + "-1c").strip()
        elif 'notes_initial_content' in vars_dict:

            current_notes_content = vars_dict['notes_initial_content'].strip()
        data['notes_content'] = current_notes_content
        return data

    def _get_snapshot_summary_line(self, shift_data, shift_label):
        if not shift_data: return f"{shift_label}: ---"
        cash_sum = shift_data.get('cash_sum_display', "N/A"); k_abschluss_werte = shift_data.get('kassenabschluss_werte', {})
        summe_posten_key = 'SUMME_POSTEN'; umsatz_total_key = 'UMSATZ_TOTAL'; soll_key = 'SOLL'
        umsatz_frueh_key = 'UMSATZ_FRUEH'; umsatz_spaet_key = 'UMSATZ_SPAET'
        summe_posten_val = k_abschluss_werte.get(summe_posten_key, "N/A"); umsatz_total_val = k_abschluss_werte.get(umsatz_total_key, "N/A")
        soll_val = k_abschluss_werte.get(soll_key, "N/A"); umsatz_frueh_val = k_abschluss_werte.get(umsatz_frueh_key, "N/A")
        umsatz_spaet_val = k_abschluss_werte.get(umsatz_spaet_key, "N/A")
        cash_sum_brief = cash_sum.replace(" €", "").strip() if cash_sum != "N/A" else "N/A"
        summe_posten_brief = summe_posten_val.replace(" €", "").strip() if summe_posten_val != "N/A" else "N/A"
        umsatz_total_brief = umsatz_total_val.replace(" €", "").strip() if umsatz_total_val != "N/A" else "N/A"
        soll_brief = soll_val.replace(" €", "").strip() if soll_val != "N/A" else "N/A"
        umsatz_frueh_brief = umsatz_frueh_val.replace(" €", "").strip() if umsatz_frueh_val != "N/A" else "N/A"
        ums_spaet_brief = umsatz_spaet_val.replace(" €", "").strip() if umsatz_spaet_val != "N/A" else "N/A"
        return f"{shift_label}: Bargeld: {cash_sum_brief}, Soll: {soll_brief}, U.Früh: {umsatz_frueh_brief}, U.Spät: {ums_spaet_brief}, U.Total: {umsatz_total_brief}, ∑Posten: {summe_posten_brief}"

    def _apply_snapshot_to_vars(self, target_vars_dict, snapshot_shift_data, target_shift_name_for_vars_lookup):
        if not target_vars_dict: return
        def set_str_var_if_changed(tk_str_var, new_value_str):
            if not isinstance(tk_str_var, tk.StringVar): return False
            if tk_str_var.get() != new_value_str: tk_str_var.set(new_value_str); return True
            return False
        default_qty_str = str(self.current_settings.get('quantity_combobox_default_value', 0))
        zero_euro_display = self._format_decimal_for_display(decimal.Decimal('0.00'))
        effective_snapshot_data = snapshot_shift_data or {}
        snapshot_cash_counts = effective_snapshot_data.get('cash_counts', {})
        snapshot_cash_manual_amounts = effective_snapshot_data.get('cash_amounts_display_manual', {})
        for denom_float_key in target_vars_dict.get('cash_denominations', []):
            denom_str_key = str(denom_float_key)
            if denom_float_key >= 5.0:
                if denom_float_key in target_vars_dict.get('cash_counts', {}):
                    value_to_set = snapshot_cash_counts.get(denom_str_key, default_qty_str)
                    set_str_var_if_changed(target_vars_dict['cash_counts'][denom_float_key], str(value_to_set))
            else:
                if denom_float_key in target_vars_dict.get('cash_amounts_display', {}):
                    value_to_set = snapshot_cash_manual_amounts.get(denom_str_key, zero_euro_display)
                    set_str_var_if_changed(target_vars_dict['cash_amounts_display'][denom_float_key], str(value_to_set))
        snapshot_stamp_counts = effective_snapshot_data.get('stamp_counts', {})
        snapshot_stamp_prices_input = effective_snapshot_data.get('stamp_price_input', {})
        for stamp_def in target_vars_dict.get('stamp_definitions', []):
            price_key_float = float(stamp_def.get('price', 0.0)); price_key_str = str(price_key_float)
            if price_key_float in target_vars_dict.get('stamp_counts', {}):
                count_to_set = snapshot_stamp_counts.get(price_key_str, default_qty_str)
                set_str_var_if_changed(target_vars_dict['stamp_counts'][price_key_float], str(count_to_set))
            default_price_for_this_stamp_str = self._format_decimal_for_display(decimal.Decimal(str(stamp_def['price'])))
            price_input_str_to_set = snapshot_stamp_prices_input.get(price_key_str, default_price_for_this_stamp_str)
            if price_key_float in target_vars_dict.get('stamp_price_input', {}):
                 set_str_var_if_changed(target_vars_dict['stamp_price_input'][price_key_float], str(price_input_str_to_set))
            if 'stamp_price_value' in target_vars_dict and price_key_float in target_vars_dict['stamp_price_value']:
                 parsed_price_val_dec = self._parse_input_string(str(price_input_str_to_set).replace("€","").strip())
                 final_price_float = float(parsed_price_val_dec if parsed_price_val_dec is not None and parsed_price_val_dec > 0 else decimal.Decimal(str(stamp_def['price'])))
                 if target_vars_dict['stamp_price_value'][price_key_float].get() != final_price_float:
                    target_vars_dict['stamp_price_value'][price_key_float].set(final_price_float)
        snapshot_card_data_all_types = effective_snapshot_data.get('card_data', {})
        num_reception_fields_current = self.current_settings.get('reception_fields_count', 3)
        for card_key in target_vars_dict.get('card_type_keys', []):
            target_card_dict_for_key = target_vars_dict.get('card_data', {}).get(card_key, {})
            if not target_card_dict_for_key: continue
            snapshot_card_details_for_this_key = snapshot_card_data_all_types.get(card_key, {})
            for i in range(1, num_reception_fields_current + 1):
                field_name = f'reception{i}'
                if field_name in target_card_dict_for_key and isinstance(target_card_dict_for_key[field_name], tk.StringVar):
                    value_to_set = snapshot_card_details_for_this_key.get(field_name, zero_euro_display)
                    set_str_var_if_changed(target_card_dict_for_key[field_name], str(value_to_set))
            if target_shift_name_for_vars_lookup == "Frühdienst":
                if 'manual_total_input' in target_card_dict_for_key and isinstance(target_card_dict_for_key['manual_total_input'], tk.StringVar):
                    value_to_set = snapshot_card_details_for_this_key.get('manual_total_input', zero_euro_display)
                    set_str_var_if_changed(target_card_dict_for_key['manual_total_input'], str(value_to_set))
            elif target_shift_name_for_vars_lookup == "Spätdienst":
                if 'fruehdienst_sum_input' in target_card_dict_for_key and isinstance(target_card_dict_for_key['fruehdienst_sum_input'], tk.StringVar):
                    if 'fruehdienst_sum_input' in snapshot_card_details_for_this_key:
                         value_to_set = snapshot_card_details_for_this_key.get('fruehdienst_sum_input', zero_euro_display)
                         set_str_var_if_changed(target_card_dict_for_key['fruehdienst_sum_input'], str(value_to_set))
                if 'spaetdienst_sum_input' in target_card_dict_for_key and isinstance(target_card_dict_for_key['spaetdienst_sum_input'], tk.StringVar):
                    value_to_set = snapshot_card_details_for_this_key.get('spaetdienst_sum_input', zero_euro_display)
                    set_str_var_if_changed(target_card_dict_for_key['spaetdienst_sum_input'], str(value_to_set))
        snapshot_kassenabschluss_werte = effective_snapshot_data.get('kassenabschluss_werte', {})
        kassenabschluss_vars_for_shift = self.kassenabschluss_wert_vars.get(target_shift_name_for_vars_lookup, {})
        all_reco_defs_in_settings = self.current_settings.get('kassenabschluss_zeilen_definitionen', [])
        for item_def in all_reco_defs_in_settings:
            key_from_def = item_def.get('key')
            if key_from_def is None: continue
            target_var_instance = kassenabschluss_vars_for_shift.get(key_from_def)
            if target_var_instance and isinstance(target_var_instance, tk.StringVar):
                if item_def['typ'] in ['EINGABE', 'EINGABE_KERN']:
                    initial_val_from_settings_str = self._format_decimal_for_display(decimal.Decimal(str(item_def.get('initialwert_eingabe', 0.0))))
                    value_to_set = snapshot_kassenabschluss_werte.get(key_from_def, initial_val_from_settings_str)
                    set_str_var_if_changed(target_var_instance, str(value_to_set))
                elif item_def['key'] == 'SOLL' and item_def['typ'] == 'FESTWERT_AUS_EINSTELLUNG' and item_def.get('formel_string') == '_STARTING_FLOAT_VALUE':
                     value_to_set = snapshot_kassenabschluss_werte.get(key_from_def, self._format_decimal_for_display(decimal.Decimal(str(self.current_settings.get('starting_float_value', 0.0)))))
                     set_str_var_if_changed(target_var_instance, str(value_to_set))
                     num_val_key = f"{key_from_def}_numeric_value"
                     parsed_num_val = self._parse_input_string(value_to_set)
                     if num_val_key in target_vars_dict and isinstance(target_vars_dict[num_val_key], tk.DoubleVar) and parsed_num_val is not None:
                          target_vars_dict[num_val_key].set(float(parsed_num_val))
                elif key_from_def in snapshot_kassenabschluss_werte:
                    value_to_set = snapshot_kassenabschluss_werte[key_from_def]
                    set_str_var_if_changed(target_var_instance, str(value_to_set))
        notes_text_from_snapshot = effective_snapshot_data.get('notes_content', "")
        target_vars_dict['notes_initial_content'] = notes_text_from_snapshot

        notes_widget = target_vars_dict.get('notes_text_widget')
        if notes_widget and notes_widget.winfo_exists() and notes_widget.winfo_ismapped():

            current_content = notes_widget.get("1.0", tk.END + "-1c")
            if current_content != notes_text_from_snapshot:
                notes_widget.delete("1.0", tk.END)
                if notes_text_from_snapshot: notes_widget.insert("1.0", notes_text_from_snapshot)
                notes_widget.edit_modified(False)


    def _load_history_data(self):
        if os.path.exists(self.history_file):
            try:
                with open(self.history_file, 'r', encoding='utf-8') as f:
                    data = json.load(f)
                    if isinstance(data, list): return data
                    else: print(f"History file '{self.history_file}' contains invalid data format. Returning empty."); return []
            except (json.JSONDecodeError, IOError) as e: print(f"Error reading history file '{self.history_file}': {e}. Returning empty."); return []
            except Exception as e: print(f"Unexpected error loading history from '{self.history_file}': {e}. Returning empty."); return []
        return []
    
    
    
    
    
    
