    def _initialize_history_state(self):
        """Speichert den initialen Zustand nach dem Laden, um die Delta-Erkennung zu starten."""
        if self.is_shutting_down: return
        self.last_state_for_history = self._get_current_state_for_history()

    def _get_current_state_for_history(self):
        """Sammelt die aktuellen Werte der Felder, die für den Verlauf relevant sind."""
        state = {}
        # Die relevanten Werte (Soll, Umsätze, etc.) aus dem Dashboard werden als Quelle genutzt,
        # da sie den Gesamtstand der Anwendung widerspiegeln.
        for key, config in self.dashboard_item_configs.items():
            if "var" in config and hasattr(config["var"], 'get'):
                state[key] = config["var"].get()
        return state

    def _initiate_debounced_save(self):
        """Setzt den Timer für eine verzögerte Speicherung (10 Sek.) zurück und startet ihn neu."""
        if self.is_loading_data or self.is_shutting_down:
            return
        
        if self.history_debounce_job:
            self.master.after_cancel(self.history_debounce_job)
        
        self.history_debounce_job = self.master.after(10000, self._perform_debounced_save)

    def _perform_debounced_save(self):
        """Führt die Delta-Speicherung nach Ablauf des Timers durch, falls sich Werte geändert haben."""
        if self.is_loading_data or self.is_shutting_down:
            return
            
        self.history_debounce_job = None
        current_state = self._get_current_state_for_history()
        
        changes = {}
        # Vergleicht den aktuellen Zustand mit dem zuletzt gespeicherten
        for key, new_value in current_state.items():
            old_value = self.last_state_for_history.get(key)
            if old_value is not None and old_value != new_value:
                # Findet den lesbaren Namen für den internen Key
                label = key
                for item_def in self.current_settings.get('kassenabschluss_zeilen_definitionen', []):
                    if item_def.get('key') == key:
                        label = item_def.get('label', key).replace(':', '')
                        break
                changes[label] = f"{old_value} → {new_value}"

        if changes:
            self._save_current_state_to_history(save_type='delta', changes=changes)
            self.last_state_for_history = current_state







    
    
    

    def _save_current_state_to_history(self, save_type, changes=None):
        """Speichert einen Snapshot des aktuellen Zustands in der Verlaufsdatei mit zusätzlichen Metadaten."""
        if not hasattr(self, 'fruehdienst_vars') or not hasattr(self, 'spaetdienst_vars'):
            if self.master.winfo_exists():
                print("Verlaufspeicherung übersprungen: Schichtdaten nicht initialisiert.")
            return

        self._save_kassenprotokoll_data()

        history_data = self._load_history_data()
        
        try:
            fruehdienst_snapshot = self._extract_data_for_snapshot(self.fruehdienst_vars, "Frühdienst")
            spaetdienst_snapshot = self._extract_data_for_snapshot(self.spaetdienst_vars, "Spätdienst")
        except Exception as e_extract:
            print(f"Error extracting snapshot data: {e_extract}")
            return

        current_snapshot = {
            "timestamp": datetime.datetime.now().isoformat(),
            "type": save_type,
            "changes": changes,
            "fruehdienst_data": fruehdienst_snapshot,
            "spaetdienst_data": spaetdienst_snapshot
        }
        
        if save_type == 'manual':
            current_snapshot['highlight'] = True

        history_data.insert(0, current_snapshot)
        history_data = history_data[:self.max_history_entries]
        
        try:
            with open(self.history_file, 'w', encoding='utf-8') as f:
                json.dump(history_data, f, indent=2)
            self.last_saved_timestamp = current_snapshot["timestamp"]
            if hasattr(self, 'current_history_dialog_window') and self.current_history_dialog_window and self.current_history_dialog_window.winfo_exists():
                self._refresh_history_dialog()
        except Exception as e_save:
            print(f"Fehler beim Speichern der Verlaufsdatei: {e_save}")

    def _schedule_autosave(self):
        if self.autosave_after_id:
            try: self.master.after_cancel(self.autosave_after_id)
            except tk.TclError: pass
        
        try:
            self._save_current_state_to_history(save_type='autosave')

            
            # KORREKTUR: Prüft jetzt zusätzlich, ob die Instanz nicht None ist.
            if hasattr(self, 'layover_app_instance') and self.layover_app_instance: 
                self.layover_app_instance.save_data()
            
            self._save_trinkgeld_data() 
            self._save_minibar_data()
            self._save_tagesabrechnung_to_history()
            
            if self.offene_rechnungen_app_instance: 
                self.offene_rechnungen_app_instance.save_data(show_toast=False)
        except Exception as e:
            print("!!! FEHLER BEIM AUTOMATISCHEN SPEICHERN !!!")
            import traceback
            traceback.print_exc()

        if self.master.winfo_exists():
            self.autosave_after_id = self.master.after(self.autosave_interval_ms, self._schedule_autosave)

    def _restore_data_from_snapshot(self, snapshot_data, history_dialog_window):
        if messagebox.askyesno("Daten wiederherstellen", "Möchten Sie die Daten aus diesem Snapshot wirklich wiederherstellen?\nAktuelle, nicht gespeicherte Änderungen gehen verloren.", parent=history_dialog_window):
            try:
                if not snapshot_data:
                    SuccessToast(history_dialog_window,
                                 title="Fehler",
                                 message="Snapshot enthält keine Daten zum Wiederherstellen.",
                                 toast_type='error',
                                 colors=self.current_settings.get('toast_colors'))
                    return
                
                fruehdienst_snapshot_content = snapshot_data.get('fruehdienst_data', {})
                spaetdienst_snapshot_content = snapshot_data.get('spaetdienst_data', {})
                
                self._apply_snapshot_to_vars(self.fruehdienst_vars, fruehdienst_snapshot_content, "Frühdienst")
                self._apply_snapshot_to_vars(self.spaetdienst_vars, spaetdienst_snapshot_content, "Spätdienst")
                
                self._clear_widget_tracking_lists()
                if self.fruehdienst_frame.winfo_exists():
                     for widget in self.fruehdienst_frame.winfo_children(): widget.destroy()
                if self.spaetdienst_frame.winfo_exists():
                     for widget in self.spaetdienst_frame.winfo_children(): widget.destroy()
                     
                self._create_shift_widgets(self.fruehdienst_frame, self.fruehdienst_vars, "Frühdienst", self.spaetdienst_vars)
                self._create_shift_widgets(self.spaetdienst_frame, self.spaetdienst_vars, "Spätdienst", self.fruehdienst_vars)
                
                self._update_all_calculations(called_by_button=False)
                self._update_admin_editable_state()
                
                current_tab_idx = self.notebook.index(self.notebook.select()) if self.notebook.tabs() else 0
                if self.notebook.tabs() and 0 <= current_tab_idx < len(self.notebook.tabs()):
                    try: self.notebook.select(current_tab_idx)
                    except tk.TclError:
                        if self.notebook.tabs(): self.notebook.select(0)
                
                # ERSETZT: Alte messagebox.showinfo
                SuccessToast(self.master,
                             title="Wiederherstellung erfolgreich",
                             message="Die Daten wurden aus dem Verlauf wiederhergestellt.",
                             toast_type='success',
                             colors=self.current_settings.get('toast_colors'))
                
                history_dialog_window.destroy()
                
            except Exception as e:
                # ERSETZT: Alte messagebox.showerror
                SuccessToast(history_dialog_window,
                             title="Fehler bei Wiederherstellung",
                             message=f"Die Daten konnten nicht wiederhergestellt werden:\n{e}",
                             toast_type='error',
                             colors=self.current_settings.get('toast_colors'),
                             duration=5000)
                import traceback
                traceback.print_exc()
    def _are_all_fields_at_default_in_snapshot_section(self, section_data, shift_name_for_kassenabschluss_lookup):
        if not section_data:
            expected_top_keys = ['cash_counts', 'cash_amounts_display_manual', 'stamp_counts', 'card_data', 'kassenabschluss_werte', 'notes_content']
            if not section_data or not any(key in section_data for key in expected_top_keys): return True
        default_qty_str = str(self.current_settings.get('quantity_combobox_default_value', 0))
        zero_euro_display = self._format_decimal_for_display(decimal.Decimal('0.00'))
        if 'cash_counts' in section_data:
            active_cash_denoms_from_settings = [str(d['value']) for d in self.current_settings.get('cash_denominations', []) if d.get('is_active', True) and float(d.get('value', 0)) >= 5.0]
            for denom_str, count_val_str in section_data['cash_counts'].items():
                 if denom_str in active_cash_denoms_from_settings:
                      if str(count_val_str) != default_qty_str: return False
        if 'cash_amounts_display_manual' in section_data:
            active_cash_denoms_manual_from_settings = [str(d['value']) for d in self.current_settings.get('cash_denominations', []) if d.get('is_active', True) and float(d.get('value', 0)) < 5.0]
            for denom_str, amount_str in section_data['cash_amounts_display_manual'].items():
                 if denom_str in active_cash_denoms_manual_from_settings:
                     if amount_str != zero_euro_display: return False
        if 'stamp_counts' in section_data:
              active_stamp_prices_from_settings = [str(d['price']) for d in self.current_settings.get('stamp_definitions', []) if d.get('is_active', True) and d.get('price') is not None]
              for price_str, count_val_str in section_data['stamp_counts'].items():
                   if price_str in active_stamp_prices_from_settings:
                        if str(count_val_str) != default_qty_str: return False
        if 'card_data' in section_data:
            active_card_keys_from_settings = [ct['key'] for ct in self.current_settings.get('card_types', []) if ct.get('is_active', True) and ct.get('key')]
            num_reception_fields = self.current_settings.get('reception_fields_count', 3)
            for card_key, card_details in section_data['card_data'].items():
                if card_key in active_card_keys_from_settings:
                    for i in range(1, num_reception_fields + 1):
                        field_name = f'reception{i}'
                        if card_details.get(field_name, zero_euro_display) != zero_euro_display: return False
                    if shift_name_for_kassenabschluss_lookup == "Frühdienst":
                        if card_details.get('manual_total_input', zero_euro_display) != zero_euro_display: return False
                    elif shift_name_for_kassenabschluss_lookup == "Spätdienst":
                        if card_details.get('spaetdienst_sum_input', zero_euro_display) != zero_euro_display: return False
        if 'kassenabschluss_werte' in section_data:
            all_reco_defs_from_current_settings = self.current_settings.get('kassenabschluss_zeilen_definitionen', [])
            input_reco_defs_active = {d['key']: decimal.Decimal(str(d.get('initialwert_eingabe', 0.0))) for d in all_reco_defs_from_current_settings if d.get('aktiv') and d['typ'] in ['EINGABE', 'EINGABE_KERN'] and 'key' in d}
            for key_from_snapshot, value_from_snapshot_str in section_data['kassenabschluss_werte'].items():
                if key_from_snapshot in input_reco_defs_active:
                    initial_val_from_settings_decimal = input_reco_defs_active[key_from_snapshot]
                    snapshot_val_decimal = self._parse_input_string(str(value_from_snapshot_str))
                    if snapshot_val_decimal is not None and initial_val_from_settings_decimal.compare(snapshot_val_decimal) != decimal.Decimal('0'): return False
                    if snapshot_val_decimal is None and initial_val_from_settings_decimal.compare(decimal.Decimal('0')) != decimal.Decimal('0'): return False
                elif key_from_snapshot == 'SOLL':
                     soll_def = next((d for d in all_reco_defs_from_current_settings if d.get('key') == 'SOLL' and d.get('typ') == 'FESTWERT_AUS_EINSTELLUNG' and d.get('formel_string') == '_STARTING_FLOAT_VALUE'), None)
                     if soll_def:
                          current_starting_float_decimal = decimal.Decimal(str(self.current_settings.get('starting_float_value', 0.0)))
                          snapshot_val_decimal = self._parse_input_string(str(value_from_snapshot_str))
                          if snapshot_val_decimal is not None and current_starting_float_decimal.compare(snapshot_val_decimal) != decimal.Decimal('0'): return False
                          if snapshot_val_decimal is None and current_starting_float_decimal.compare(decimal.Decimal('0')) != decimal.Decimal('0'): return False
        if 'notes_content' in section_data and section_data['notes_content'].strip(): return False
        return True
    
        # HIER DEN NEUEN CODEBLOCK EINFÜGEN
    def _is_snapshot_posten_sum_zero(self, snapshot_data):
        """
        Prüft, ob die ΣPosten für beide Schichten in einem Verlaufsdatensatz null sind.
        Ein Datensatz wird als null betrachtet, wenn beide Schichten einen ΣPosten-Wert von null haben.
        """
        if not isinstance(snapshot_data, dict):
            return True # Behandelt ungültige Daten als leer

        fd_data = snapshot_data.get('fruehdienst_data', {})
        sd_data = snapshot_data.get('spaetdienst_data', {})

        def get_posten_value(shift_data):
            if not shift_data or not isinstance(shift_data, dict):
                return decimal.Decimal('0.0')
            
            kassenabschluss_werte = shift_data.get('kassenabschluss_werte', {})
            if not isinstance(kassenabschluss_werte, dict):
                return decimal.Decimal('0.0')

            summe_posten_str = kassenabschluss_werte.get('SUMME_POSTEN', '0,00 €')
            
            parsed_value = self._parse_input_string(summe_posten_str)
            return parsed_value if parsed_value is not None else decimal.Decimal('0.0')

        fd_posten = get_posten_value(fd_data)
        sd_posten = get_posten_value(sd_data)
        
        # Die Bedingung ist wahr, wenn BEIDE Postensummen null sind (mit kleiner Toleranz).
        if abs(fd_posten) < decimal.Decimal('0.01') and abs(sd_posten) < decimal.Decimal('0.01'):
            return True
        
        return False
    # ENDE DES NEUEN CODEBLOCKS
    
    def _is_snapshot_umsatz_total_zero(self, snapshot_data):
        """
        Prüft, ob der 'Umsatz Total' in einem Verlaufsdatensatz null ist.
        Da 'Umsatz Total' für beide Schichten berechnet wird, reicht die Prüfung einer Schicht.
        """
        if not isinstance(snapshot_data, dict):
            return True # Ungültige Daten als leer behandeln

        # Wir prüfen den Spätdienst, da dieser in der Regel die finalen Werte enthält.
        # Der Wert für 'Umsatz Total' ist in beiden Schichten identisch.
        shift_data = snapshot_data.get('spaetdienst_data', {})
        
        if not shift_data or not isinstance(shift_data, dict):
            # Wenn keine Spätdienst-Daten vorhanden sind, prüfen wir den Frühdienst als Fallback.
            shift_data = snapshot_data.get('fruehdienst_data', {})
            if not shift_data or not isinstance(shift_data, dict):
                return True # Keine Daten in beiden Schichten, also kein Umsatz.

        kassenabschluss_werte = shift_data.get('kassenabschluss_werte', {})
        if not isinstance(kassenabschluss_werte, dict):
            return True # Keine Kassenabschluss-Werte vorhanden.

        umsatz_total_str = kassenabschluss_werte.get('UMSATZ_TOTAL', '0,00 €')
        
        parsed_value = self._parse_input_string(umsatz_total_str)
        umsatz_total_val = parsed_value if parsed_value is not None else decimal.Decimal('0.0')

        # Rückgabe True, wenn der Umsatz Total (nahezu) null ist.
        return abs(umsatz_total_val) < decimal.Decimal('0.01')
    # ENDE DES NEUEN CODEBLOCKS
    

    def _delete_history_snapshots_revised(self, history_listbox, master_history_data_list_ref, current_displayable_list_ref, history_dialog_window):
        selected_indices_in_listbox = history_listbox.curselection()
        if not selected_indices_in_listbox: messagebox.showwarning("Auswahl", "Bitte mindestens einen Eintrag zum Löschen auswählen.", parent=history_dialog_window); return
        confirm_msg = "Ausgewählten Eintrag wirklich löschen?" if len(selected_indices_in_listbox) == 1 else f"{len(selected_indices_in_listbox)} ausgewählte Einträge wirklich löschen?"
        if messagebox.askyesno("Löschen bestätigen", confirm_msg, parent=history_dialog_window):
            snapshots_marked_for_deletion_by_timestamp = []
            for listbox_idx in selected_indices_in_listbox:
                try:
                    if 0 <= listbox_idx < len(current_displayable_list_ref):
                         snapshot_obj = current_displayable_list_ref[listbox_idx]
                         if 'timestamp' in snapshot_obj: snapshots_marked_for_deletion_by_timestamp.append(snapshot_obj['timestamp'])
                except IndexError: print(f"Warning: Listbox index {listbox_idx} out of range for current_displayable_list_ref."); continue
            if not snapshots_marked_for_deletion_by_timestamp: messagebox.showinfo("Information", "Keine gültigen Einträge zum Löschen ausgewählt.", parent=history_dialog_window); return
            num_actually_deleted_from_master = 0; new_master_history_data_kept = []
            
            for snapshot_in_master in list(master_history_data_list_ref):
                if snapshot_in_master.get('timestamp') in snapshots_marked_for_deletion_by_timestamp: num_actually_deleted_from_master += 1
                else: new_master_history_data_kept.append(snapshot_in_master)
            if num_actually_deleted_from_master > 0:
                master_history_data_list_ref.clear(); master_history_data_list_ref.extend(new_master_history_data_kept)
                try:
                    with open(self.history_file, 'w', encoding='utf-8') as f: json.dump(master_history_data_list_ref, f, indent=2)
                    current_displayable_list_ref.clear()
                    for snapshot in master_history_data_list_ref:
                         frueh_sums_default = self._are_all_fields_at_default_in_snapshot_section(snapshot.get('fruehdienst_data'), "Frühdienst")
                         spaet_sums_default = self._are_all_fields_at_default_in_snapshot_section(snapshot.get('spaetdienst_data'), "Spätdienst")
                         if not (frueh_sums_default and spaet_sums_default): current_displayable_list_ref.append(snapshot)
                    history_listbox.delete(0, tk.END)
                    for i, snapshot in enumerate(current_displayable_list_ref):
                        try: dt_obj = datetime.datetime.fromisoformat(snapshot['timestamp']); display_ts = dt_obj.strftime("%a, %d.%b %Y %H:%M:%S")
                        except (ValueError, KeyError): display_ts = f"Snapshot {i+1} (unbekanntes Datum)"
                        fd_data = snapshot.get('fruehdienst_data'); sd_data = snapshot.get('spaetdienst_data')
                        fd_summary_line = self._get_snapshot_summary_line(fd_data, "FD"); sd_summary_line = self._get_snapshot_summary_line(sd_data, "SD")
                        full_display_string = f"{display_ts} | {fd_summary_line} | {sd_summary_line}"
                        history_listbox.insert(tk.END, full_display_string)##############################
                    messagebox.showinfo("Erfolg", f"{num_actually_deleted_from_master} Eintrag/Einträge gelöscht.", parent=history_dialog_window)
                    if history_listbox.size() > 0:
                        new_selection_index = min(selected_indices_in_listbox[0], history_listbox.size() - 1); new_selection_index = max(0, new_selection_index)
                        history_listbox.selection_clear(0, tk.END); history_listbox.selection_set(new_selection_index); history_listbox.activate(new_selection_index); history_listbox.see(new_selection_index)
                    else: history_listbox.selection_clear(0, tk.END)
                    history_listbox.event_generate("<<ListboxSelect>>")
                except IOError as e: messagebox.showerror("Fehler", f"Fehler beim Speichern der Verlaufsdaten nach dem Löschen: {e}", parent=history_dialog_window)
                except Exception as e_general: messagebox.showerror("Fehler", f"Allgemeiner Fehler beim Aktualisieren der Verlaufsansicht: {e_general}", parent=history_dialog_window)
            else: messagebox.showinfo("Information", "Keine Einträge zum Löschen ausgewählt oder effektiv gelöscht.", parent=history_dialog_window)

    def _are_key_sums_at_default_in_snapshot_section(self, section_data):
        return self._are_all_fields_at_default_in_snapshot_section(section_data, "Frühdienst")


    def _open_history_dialog(self):
        """Öffnet den Verlaufsdialog und stellt die Einträge entsprechend ihres Typs dar."""
        all_history_data_from_file_master = self._load_history_data() 

        if not all_history_data_from_file_master: 
            messagebox.showinfo("Verlauf", "Keine Verlaufsdaten verfügbar.", parent=self.master); 
            return

        history_window = tk.Toplevel(self.master)
        history_window.title("Datenverlauf Wiederherstellen / Verwalten")
        history_window.transient(self.master)
        history_window.grab_set()
        history_window.geometry("750x450")

        # ... (Code für Listbox und Scrollbars bleibt wie im Original) ...
        listbox_frame = ttk.Frame(history_window, padding=10)
        listbox_frame.pack(fill='both', expand=True)
        scrollbar_y = ttk.Scrollbar(listbox_frame, orient=tk.VERTICAL)
        scrollbar_y.pack(side='right', fill='y')
        scrollbar_x = ttk.Scrollbar(listbox_frame, orient=tk.HORIZONTAL)
        scrollbar_x.pack(side='bottom', fill='x')
        history_listbox = tk.Listbox(listbox_frame, yscrollcommand=scrollbar_y.set, xscrollcommand=scrollbar_x.set, exportselection=False, font=(tkFont.nametofont("TkDefaultFont").actual()['family'], 10), selectmode=tk.EXTENDED)
        self.currently_displayed_history_in_dialog.clear()
        
        # Logik zum Filtern und Anzeigen der Einträge
        for i, snapshot in enumerate(all_history_data_from_file_master):
            self.currently_displayed_history_in_dialog.append(snapshot)
            try:
                dt_obj = datetime.datetime.fromisoformat(snapshot['timestamp'])
                display_ts = dt_obj.strftime("%d.%m.%y %H:%M:%S")
            except (ValueError, KeyError):
                display_ts = "Unbekannter Zeitpunkt"

            save_type = snapshot.get('type', 'legacy')
            display_string = f"{display_ts} - "
            
            if save_type == 'delta':
                changes = snapshot.get('changes', {})
                if changes:
                    # Zeigt nur die erste Änderung für eine kompakte Ansicht
                    first_change_key = next(iter(changes))
                    change_summary = f"Änderung: {first_change_key}"
                    if len(changes) > 1:
                        change_summary += f" (+{len(changes) - 1} weitere)"
                    display_string += change_summary
                else:
                    display_string += "Daten geändert"
            elif save_type == 'manual':
                display_string += "Manuelles Speichern durch Nutzer"
            elif save_type == 'backup':
                display_string += "Automatisches Backup"
            else: # Fallback für alte Einträge ohne Typ
                fd_summary = self._get_snapshot_summary_line(snapshot.get('fruehdienst_data'), "FD")
                display_string += f"Voller Datensatz ({fd_summary})"

            history_listbox.insert(tk.END, display_string)

            # Farbliche Markierung anwenden
            if snapshot.get('highlight') or save_type == 'manual':
                history_listbox.itemconfig(i, {'bg': '#cce5ff', 'fg': '#004085'}) # Blau
            elif save_type == 'backup':
                history_listbox.itemconfig(i, {'fg': 'grey'}) # Grau
            elif save_type == 'delta':
                history_listbox.itemconfig(i, {}) # Standardfarbe

        # ... (Rest der Methode für Buttons und Events bleibt wie im Original) ...
        history_listbox.pack(side='left', fill='both', expand=True)
        scrollbar_y.config(command=history_listbox.yview)
        scrollbar_x.config(command=history_listbox.xview)
        history_window.listbox_widget = history_listbox
        history_window.displayed_snapshots = self.currently_displayed_history_in_dialog
        button_frame = ttk.Frame(history_window, padding=(10, 5, 10, 10))
        button_frame.pack(fill='x')
        ipady = self.current_settings.get('dialog_button_ipady', 5)
        history_window.restore_button = ttk.Button(button_frame, style='TButton', command=lambda: self._restore_data_from_snapshot(self.currently_displayed_history_in_dialog[history_listbox.curselection()[0]], history_window) if history_listbox.curselection() and len(history_listbox.curselection()) == 1 else None)
        self._configure_dialog_button(history_window.restore_button, 'Dialog_Restore', 'Wiederherstellen')
        history_window.restore_button.config(state='disabled')
        history_window.restore_button.pack(side='left', padx=(0,5), expand=True, ipady=ipady)
        history_window.delete_button = ttk.Button(button_frame, style='TButton', command=lambda: self._delete_history_snapshots_revised(history_listbox, all_history_data_from_file_master, self.currently_displayed_history_in_dialog, history_window))
        self._configure_dialog_button(history_window.delete_button, 'Dialog_Delete', 'Löschen')
        history_window.delete_button.config(state='disabled')
        history_window.delete_button.pack(side='left', padx=5, expand=True, ipady=ipady)
        cancel_btn = ttk.Button(button_frame, command=history_window.destroy, style='TButton')
        self._configure_dialog_button(cancel_btn, 'Dialog_Cancel', 'Abbrechen')
        cancel_btn.pack(side='right', padx=(5,0), expand=True, ipady=ipady)
        def on_select(event_unused):
            selections = history_listbox.curselection()
            history_window.restore_button.config(state='normal' if len(selections) == 1 else 'disabled')
            history_window.delete_button.config(state='normal' if selections and self.is_admin_mode else 'disabled')
        history_listbox.bind('<<ListboxSelect>>', on_select)
        if history_listbox.size() > 0:
            history_listbox.selection_set(0)
            history_listbox.activate(0)
        self.master.after_idle(lambda: history_listbox.event_generate("<<ListboxSelect>>") if history_listbox.winfo_exists() else None)
        self.current_history_dialog_window = history_window 
        history_window.protocol("WM_DELETE_WINDOW", lambda: setattr(self, 'current_history_dialog_window', None) or history_window.destroy())
        self.master.wait_window(history_window)

    def _refresh_history_dialog(self):
        """Aktualisiert den Inhalt des bereits geöffneten Verlaufsfensters mit der korrekten Filterlogik."""
        history_window = self.current_history_dialog_window
        if not (history_window and history_window.winfo_exists()):
            return

        history_listbox = getattr(history_window, 'listbox_widget', None)
        displayed_list = getattr(history_window, 'displayed_snapshots', None)

        if not history_listbox or displayed_list is None:
            return

        # 1. Alte Inhalte leeren
        history_listbox.delete(0, tk.END)
        displayed_list.clear()
        
        # 2. Verlaufsdaten neu aus der Datei laden
        all_history_data = self._load_history_data()

        # 3. KORRIGIERTE FILTERUNG & BEFÜLLUNG
        latest_timestamp_in_list = ""
        if all_history_data:
            latest_timestamp_in_list = all_history_data[0].get('timestamp')
        
        timestamp_to_highlight = self.last_saved_timestamp or latest_timestamp_in_list
        
        for snapshot in all_history_data:
            # VERWENDET JETZT DIE KORREKTE FILTERLOGIK
            if self._is_snapshot_posten_sum_zero(snapshot) or self._is_snapshot_umsatz_total_zero(snapshot):
                continue  # Überspringe leere oder irrelevante Datensätze

            displayed_list.append(snapshot)
            
            try: 
                dt_obj = datetime.datetime.fromisoformat(snapshot['timestamp'])
                display_ts = dt_obj.strftime("%a, %d.%b %Y %H:%M:%S")
            except (ValueError, KeyError): 
                display_ts = "Snapshot (unbekanntes Datum)"

            fd_data = snapshot.get('fruehdienst_data')
            sd_data = snapshot.get('spaetdienst_data')
            fd_summary_line = self._get_snapshot_summary_line(fd_data, "FD")
            sd_summary_line = self._get_snapshot_summary_line(sd_data, "SD")
            
            full_display_string = f"{display_ts} | {fd_summary_line} | {sd_summary_line}"
            
            history_listbox.insert(tk.END, full_display_string)
            listbox_index = history_listbox.size() - 1

            if snapshot.get('timestamp') == timestamp_to_highlight:
                history_listbox.itemconfig(listbox_index, {'bg': 'yellow', 'fg': 'black', 'selectbackground': '#ffc107', 'selectforeground': 'black'})
            elif snapshot.get('highlight', False):
                history_listbox.itemconfig(listbox_index, {'bg': '#ffdddd'})

        # 4. Auswahl aktualisieren, um Button-Zustände zu erneuern
        if history_listbox.size() > 0:
            history_listbox.selection_set(0)
            history_listbox.event_generate("<<ListboxSelect>>")

    def _on_history_treeview_select(self, history_dialog_window_ref):
        if not history_dialog_window_ref or not history_dialog_window_ref.winfo_exists(): 
            print("Warning: History dialog window reference is invalid or window does not exist.")
            return

        listbox_to_trigger = None
        
        if hasattr(history_dialog_window_ref, 'winfo_children') and callable(history_dialog_window_ref.winfo_children):
            for child in history_dialog_window_ref.winfo_children(): 
                if isinstance(child, ttk.Frame) and hasattr(child, 'winfo_children') and callable(child.winfo_children): 
                     for sub_child in child.winfo_children():
                          if isinstance(sub_child, tk.Listbox): 
                               listbox_to_trigger = sub_child
                               break
                if listbox_to_trigger: break 

        if listbox_to_trigger and listbox_to_trigger.winfo_exists():
            listbox_to_trigger.event_generate("<<ListboxSelect>>")


