    def _extract_tagesabrechnung_data_for_snapshot(self):
        data = {
            'einnahmen_fo_frueh': self.ta_einnahmen_fo_frueh_var.get(),
            'einnahmen_fo_spaet': self.ta_einnahmen_fo_spaet_var.get(),
            'einnahmen_fo_nacht': self.ta_einnahmen_fo_nacht_var.get(),
            'einnahmen_fo_tip': self.ta_einnahmen_fo_tip_var.get(),
            'einnahmen_bar_haupt': self.ta_einnahmen_bar_haupt_var.get(),
            'einnahmen_bar_tip': self.ta_einnahmen_bar_tip_var.get(),
            'ausgaben_rows': [{'mitarbeiter': r['mitarbeiter'].get(), 'wofuer': r['wofuer'].get(), 'betrag': r['betrag'].get()} for r in self.ta_ausgaben_rows]
        }
        return data

    def _load_tagesabrechnung_history(self):
        if os.path.exists(self.tagesabrechnung_history_file):
            try:
                with open(self.tagesabrechnung_history_file, 'r', encoding='utf-8') as f:
                    data = json.load(f)
                    return data if isinstance(data, list) else []
            except (json.JSONDecodeError, IOError):
                return []
        return []
    
    
    def _load_latest_tagesabrechnung_from_history(self):
        """Lädt den neuesten Zustand der Tagesabrechnung aus der Verlaufsdatei beim Start."""
        history_data = self._load_tagesabrechnung_history()

        if not history_data:
            print("Info: Keine Verlaufsdaten für die Tagesabrechnung zum Laden gefunden.")
            return

        try:
            # Der neueste Eintrag ist immer der erste in der Liste
            latest_snapshot = history_data[0]
            
            # Sicherstellen, dass der Snapshot die erwarteten Daten enthält
            if 'data' in latest_snapshot:
                print("Lade letzten gespeicherten Zustand der Tagesabrechnung...")
                self._apply_tagesabrechnung_snapshot_to_vars(latest_snapshot)
            else:
                print("Warnung: Der neueste Tagesabrechnungs-Snapshot ist ungültig.")

        except (IndexError, KeyError, Exception) as e:
            print(f"Fehler beim Anwenden des letzten Tagesabrechnungs-Snapshots: {e}")
    

    def _save_tagesabrechnung_to_history(self):
        history_data = self._load_tagesabrechnung_history()
        current_snapshot = {
            "timestamp": datetime.datetime.now().isoformat(),
            "data": self._extract_tagesabrechnung_data_for_snapshot()
        }
        
        # Prüfen, ob der aktuelle Zustand identisch mit dem letzten gespeicherten ist
        if history_data:
            # KORREKTUR: Greifen Sie auf das erste Element der Liste zu (history_data[0]),
            # welches ein Wörterbuch ist, und wenden Sie .get() darauf an.
            latest_entry_data = history_data[0].get('data', {})
            if json.dumps(latest_entry_data, sort_keys=True) == json.dumps(current_snapshot['data'], sort_keys=True):
                return # Nicht speichern, wenn keine Änderungen vorliegen
        
        history_data.insert(0, current_snapshot)
        history_data = history_data[:self.max_history_entries]

        try:
            with open(self.tagesabrechnung_history_file, 'w', encoding='utf-8') as f:
                json.dump(history_data, f, indent=2)
        except IOError as e:
            print(f"Error saving Tagesabrechnung history: {e}")

    def _apply_tagesabrechnung_snapshot_to_vars(self, snapshot_data):
        data = snapshot_data.get('data', {})
        self.ta_einnahmen_fo_frueh_var.set(data.get('einnahmen_fo_frueh', "0,00 €"))
        self.ta_einnahmen_fo_spaet_var.set(data.get('einnahmen_fo_spaet', "0,00 €"))
        self.ta_einnahmen_fo_nacht_var.set(data.get('einnahmen_fo_nacht', "0,00 €"))
        self.ta_einnahmen_fo_tip_var.set(data.get('einnahmen_fo_tip', "0,00 €"))
        self.ta_einnahmen_bar_haupt_var.set(data.get('einnahmen_bar_haupt', "0,00 €"))
        self.ta_einnahmen_bar_tip_var.set(data.get('einnahmen_bar_tip', "0,00 €"))

        ausgaben_rows_data = data.get('ausgaben_rows', [])
        for i, row_data in enumerate(ausgaben_rows_data):
            if i < len(self.ta_ausgaben_rows):
                self.ta_ausgaben_rows[i]['mitarbeiter'].set(row_data.get('mitarbeiter', ''))
                self.ta_ausgaben_rows[i]['wofuer'].set(row_data.get('wofuer', ''))
                self.ta_ausgaben_rows[i]['betrag'].set(row_data.get('betrag', '0,00 €'))
        
        self._update_tagesabrechnung_calculations(show_feedback=False)
        self._update_tagesabrechnung_sum_colors()

    def _get_tagesabrechnung_snapshot_summary_line(self, ta_snapshot_data):
        if not ta_snapshot_data: return "Leerer Eintrag"
        
        einn_fo = self._parse_input_string(ta_snapshot_data.get('einnahmen_fo_summe', "0,00 €")) or decimal.Decimal(0)
        einn_bar = self._parse_input_string(ta_snapshot_data.get('einnahmen_bar_summe', "0,00 €")) or decimal.Decimal(0)
        ausg = self._parse_input_string(ta_snapshot_data.get('ausgaben_summe', "0,00 €")) or decimal.Decimal(0)

        fo_sum = sum(self._parse_input_string(v) or decimal.Decimal(0) for k, v in ta_snapshot_data.items() if k.startswith('einnahmen_fo_') and k != 'einnahmen_fo_summe')
        bar_sum = sum(self._parse_input_string(v) or decimal.Decimal(0) for k, v in ta_snapshot_data.items() if k.startswith('einnahmen_bar_') and k != 'einnahmen_bar_summe')
        ausgaben_sum = sum(self._parse_input_string(row.get('betrag')) or decimal.Decimal(0) for row in ta_snapshot_data.get('ausgaben_rows', []))
        
        return f"Einn. FO: {fo_sum:,.2f} | Einn. Bar: {bar_sum:,.2f} | Ausg.: {ausgaben_sum:,.2f}".replace('.', '#').replace(',', '.').replace('#', ',')
    def _restore_tagesabrechnung_from_snapshot(self, snapshot_data, history_dialog_window):
        if messagebox.askyesno("Daten wiederherstellen", "Möchten Sie die Daten der Tagesabrechnung aus diesem Snapshot wiederherstellen?", parent=history_dialog_window):
            self._apply_tagesabrechnung_snapshot_to_vars(snapshot_data)
            #messagebox.showinfo("Erfolg", "Daten der Tagesabrechnung erfolgreich wiederhergestellt.", parent=history_dialog_window)
            
            
            SuccessToast(self.master, 
             title="Erfolgreich gespeichert", 
             message="Daten der Tagesabrechnung erfolgreich wiederhergestellt.", 
             toast_type='neutral', 
             colors=self.current_settings.get('toast_colors'))
            
            
            history_dialog_window.destroy()

    def _delete_tagesabrechnung_history_snapshots(self, history_listbox, master_list, displayed_list, dialog_window):
        selected_indices = history_listbox.curselection()
        if not selected_indices: return
        
        if messagebox.askyesno("Löschen", f"{len(selected_indices)} Eintrag/Einträge wirklich löschen?", parent=dialog_window):
            timestamps_to_delete = {displayed_list[i]['timestamp'] for i in selected_indices}
            
            new_master_list = [snap for snap in master_list if snap.get('timestamp') not in timestamps_to_delete]
            
            master_list.clear()
            master_list.extend(new_master_list)

            try:
                with open(self.tagesabrechnung_history_file, 'w', encoding='utf-8') as f:
                    json.dump(master_list, f, indent=2)
                
                dialog_window.destroy()
                self._open_tagesabrechnung_history_dialog()
                messagebox.showinfo("Erfolg", "Ausgewählte Einträge wurden gelöscht.", parent=self.master)
            except Exception as e:
                messagebox.showerror("Fehler", f"Fehler beim Speichern der Verlaufsdatei: {e}", parent=dialog_window)
                
    
