    def _create_settings_spickzettel_home_button_section(self, parent_frame, temp_settings, dialog_vars, start_row=0):
        """Erstellt den Abschnitt für den anpassbaren Home-Button in der Spickzettel-Sidebar."""
        frame = ttk.LabelFrame(parent_frame, text="Spickzettel: Home-Button (Sidebar)", style='TLabelframe')
        frame.grid(row=start_row, column=0, columnspan=4, sticky='ew', padx=5, pady=10)
        frame.columnconfigure(1, weight=1)

        # Sicherstellen, dass die Konfiguration existiert
        cfg = temp_settings.setdefault('spickzettel_home_button', self.default_settings['spickzettel_home_button'].copy())
        
        dialog_vars['spickzettel_home_button'] = {}
        
        # --- Typ-Auswahl (Text/Symbol vs. Bild) ---
        ttk.Label(frame, text="Typ:").grid(row=0, column=0, sticky='w', padx=5, pady=3)
        type_var = tk.StringVar(value=cfg.get('type', 'text'))
        dialog_vars['spickzettel_home_button']['type_var'] = type_var
        
        type_frame = ttk.Frame(frame)
        type_frame.grid(row=0, column=1, columnspan=3, sticky='w')

        def update_type(): temp_settings['spickzettel_home_button']['type'] = type_var.get()
        
        ttk.Radiobutton(type_frame, text="Text/Symbol", variable=type_var, value='text', command=update_type).pack(side='left', padx=5)
        ttk.Radiobutton(type_frame, text="Bild", variable=type_var, value='image', command=update_type).pack(side='left', padx=5)

        # --- Eingabefelder ---
        ttk.Label(frame, text="Wert (Text oder Pfad):").grid(row=1, column=0, sticky='w', padx=5, pady=3)
        value_var = tk.StringVar(value=cfg.get('value', ''))
        dialog_vars['spickzettel_home_button']['value_var'] = value_var
        ttk.Entry(frame, textvariable=value_var).grid(row=1, column=1, sticky='ew', padx=5)
        value_var.trace_add('write', lambda n,i,m: temp_settings['spickzettel_home_button'].update({'value': value_var.get()}))

        def browse_image():
            fpath = filedialog.askopenfilename(filetypes=[("Bilder", "*.png *.gif *.jpg"), ("Alle", "*.*")], parent=parent_frame.winfo_toplevel())
            if fpath: value_var.set(fpath)
        
        ttk.Button(frame, text="...", command=browse_image, width=3).grid(row=1, column=2, padx=5)
        
        # --- Design-Einstellungen ---
        ttk.Label(frame, text="Icon-Größe (px):").grid(row=2, column=0, sticky='w', padx=5, pady=3)
        icon_size_var = tk.IntVar(value=cfg.get('icon_size', 18))
        dialog_vars['spickzettel_home_button']['icon_size_var'] = icon_size_var
        ttk.Spinbox(frame, from_=10, to=100, textvariable=icon_size_var, width=7).grid(row=2, column=1, sticky='w', padx=5)
        icon_size_var.trace_add('write', lambda n,i,m: temp_settings['spickzettel_home_button'].update({'icon_size': icon_size_var.get()}))

        ttk.Label(frame, text="Innen-Padding Y:").grid(row=3, column=0, sticky='w', padx=5, pady=3)
        ipady_var = tk.IntVar(value=cfg.get('ipady', 5))
        dialog_vars['spickzettel_home_button']['ipady_var'] = ipady_var
        ttk.Spinbox(frame, from_=0, to=20, textvariable=ipady_var, width=7).grid(row=3, column=1, sticky='w', padx=5)
        ipady_var.trace_add('write', lambda n,i,m: temp_settings['spickzettel_home_button'].update({'ipady': ipady_var.get()}))

        return start_row + 1
