    def _populate_general_settings_tab(self, parent_frame, temp_settings, dialog_vars):
        """Füllt den 'Allgemein'-Tab in den Einstellungen mit Widgets."""
        parent_frame.columnconfigure(1, weight=1)
        row_idx = 0

        # Data Storage Path
        ttk.Label(parent_frame, text="Datenspeicherort:").grid(row=row_idx, column=0, sticky='w', padx=5, pady=5)
        
        default_path = os.path.dirname(get_app_data_path("dummy.txt"))
        current_path_setting = temp_settings.get('data_storage_path', '')
        display_path = current_path_setting if current_path_setting else f"(Standard) {default_path}"
        
        dialog_vars['data_storage_path_var'] = tk.StringVar(value=display_path)
        path_display = ttk.Label(parent_frame, textvariable=dialog_vars['data_storage_path_var'], relief="sunken", wraplength=400)
        path_display.grid(row=row_idx, column=1, sticky='ew', padx=5, pady=5)

        def select_data_path():
            new_path = filedialog.askdirectory(title="Speicherort für Daten- und Einstellungsdateien auswählen", parent=parent_frame.winfo_toplevel())
            if new_path:
                dialog_vars['data_storage_path_var'].set(new_path)
        
        def reset_data_path():
            dialog_vars['data_storage_path_var'].set(f"(Standard) {default_path}")

