    def create_color_picker(parent, key, label_text, initial_color, is_tab_color=False, tab_key=None):
            #nonlocal color_row
            col = 0 if color_row % 2 == 0 else 2
            
            ttk.Label(parent, text=f"{label_text}:").grid(row=color_row // 2, column=col, sticky='w', padx=5, pady=2)
            color_var = tk.StringVar(value=initial_color)
            
            if is_tab_color:
                dialog_vars['color_vars'][f'tab_colors_{tab_key}'] = color_var
            else:
                dialog_vars['color_vars'][key] = color_var
            
            color_display = tk.Label(parent, textvariable=color_var, width=10, relief='solid', borderwidth=1, bg=initial_color)
            color_display.grid(row=color_row // 2, column=col + 1, sticky='w', padx=5)
            
            def pick_color():
                new_color = colorchooser.askcolor(title=f"Farbe für '{label_text}'", initialcolor=color_var.get(), parent=parent.winfo_toplevel())
                if new_color and new_color[1]:
                    hex_color = new_color[1].upper()
                    color_var.set(hex_color)
                    color_display.config(bg=hex_color)
            
            ttk.Button(parent, text="Wählen...", command=pick_color).grid(row=color_row // 2, column=col + 1, sticky='e', padx=(0,5))
            color_row += 1

            for key, label in color_options:
                create_color_picker(color_settings_frame, key, label, temp_settings.get(key, self.default_settings[key]))

            # Speziell für Tab-Farben
            for tab_name in temp_settings.get('tab_colors', {}):
                create_color_picker(color_settings_frame, None, f"Farbe für Tabs ({tab_name})", temp_settings['tab_colors'][tab_name], is_tab_color=True, tab_key=tab_name)
            
            row_idx += (len(color_options) + len(temp_settings.get('tab_colors', {})) + 1) // 2 + 1
            
            # Aufruf der neuen Methode für die Hauptmenü-Buttons
            self._create_settings_main_menu_buttons_section(parent_frame, temp_settings, dialog_vars, start_row=row_idx)
            row_idx += 1

            self._create_settings_home_button_section(parent_frame, temp_settings, dialog_vars, start_row=row_idx)

