    def _populate_pdf_logos_settings_tab(self, parent_frame, temp_settings, dialog_vars):
        """Füllt den 'PDF-Logos'-Tab: Für jedes PDF-Dokument kann ein eigenes Logo gewählt werden."""

        PDF_DOCUMENTS = [
            ('offene_rechnungen',   "Offene Rechnungen"),
            ('layover',             "Layover-Übersicht"),
            ('namensliste',         "Namensliste"),
            ('urlaubsantrag',       "Urlaubsantrag"),
            ('ueberstundenantrag',  "Überstundenantrag"),
            ('weckruf',             "Weckrufliste"),
            ('taxi',                "Taxibestellungen"),
            ('zimmerreservierung',  "Zimmerreservierung"),
            ('mod_rundgang',        "MOD-Rundgang"),
        ]

        # Scrollbarer Bereich
        canvas = tk.Canvas(parent_frame, borderwidth=0, highlightthickness=0)
        scrollbar = ttk.Scrollbar(parent_frame, orient="vertical", command=canvas.yview)
        scroll_frame = ttk.Frame(canvas)
        scroll_frame.bind("<Configure>", lambda e: canvas.configure(scrollregion=canvas.bbox("all")))
        canvas.create_window((0, 0), window=scroll_frame, anchor="nw")
        canvas.configure(yscrollcommand=scrollbar.set)
        canvas.pack(side="left", fill="both", expand=True)
        scrollbar.pack(side="right", fill="y")
        canvas.bind("<MouseWheel>", lambda e: canvas.yview_scroll(int(-1 * (e.delta / 120)), "units"))

        ttk.Label(scroll_frame, text="Wählen Sie für jedes PDF-Dokument ein eigenes Logo.\nLeere Auswahl verwendet das Standard-Logo.", justify='left').grid(
            row=0, column=0, columnspan=5, sticky='w', padx=10, pady=(8, 14))

        pdf_logo_paths = temp_settings.setdefault('pdf_logo_paths', {})
        dialog_vars['pdf_logo_path_vars'] = {}

        DEFAULT_LABEL = "(Standard-Logo)"
        PREVIEW_W, PREVIEW_H = 80, 55

        def make_row(row_idx, key, label):
            ttk.Label(scroll_frame, text=label, width=22, anchor='w').grid(
                row=row_idx, column=0, sticky='w', padx=(10, 4), pady=6)

            path_var = tk.StringVar(value=pdf_logo_paths.get(key, ''))
            dialog_vars['pdf_logo_path_vars'][key] = path_var

            # Pfad-Anzeige (readonly)
            display_var = tk.StringVar(value=path_var.get() or DEFAULT_LABEL)
            entry = ttk.Entry(scroll_frame, textvariable=display_var, state='readonly', width=38)
            entry.grid(row=row_idx, column=1, sticky='ew', padx=4, pady=6)

            # Vorschau-Container
            preview_container = ttk.Frame(scroll_frame, relief='sunken', width=PREVIEW_W + 4, height=PREVIEW_H + 4)
            preview_container.grid(row=row_idx, column=2, padx=4, pady=6)
            preview_container.grid_propagate(False)
            preview_lbl = ttk.Label(preview_container, text="—")
            preview_lbl.pack(expand=True)

            def refresh_preview(path, lbl=preview_lbl):
                try:
                    load_path = path if (path and os.path.exists(path)) else None
                    if not load_path:
                        try:
                            dp = resource_path("icons/bwp_logo.png")
                            if os.path.exists(dp):
                                load_path = dp
                        except Exception:
                            pass
                    if load_path:
                        img = Image.open(load_path)
                        img.thumbnail((PREVIEW_W, PREVIEW_H))
                        photo = ImageTk.PhotoImage(img)
                        lbl.config(image=photo, text="")
                        lbl.image = photo
                    else:
                        lbl.config(image='', text="Kein Logo")
                        lbl.image = None
                except Exception:
                    lbl.config(image='', text="Fehler")
                    lbl.image = None

            refresh_preview(path_var.get())

            def browse(k=key, pv=path_var, dv=display_var, rp=refresh_preview):
                fpath = filedialog.askopenfilename(
                    title=f"Logo für '{label}' auswählen",
                    filetypes=[("Bilddateien", "*.png *.jpg *.jpeg"), ("Alle Dateien", "*.*")],
                    parent=parent_frame.winfo_toplevel()
                )
                if fpath:
                    pv.set(fpath)
                    dv.set(fpath)
                    temp_settings.setdefault('pdf_logo_paths', {})[k] = fpath
                    rp(fpath)

            def reset(k=key, pv=path_var, dv=display_var, rp=refresh_preview):
                pv.set('')
                dv.set(DEFAULT_LABEL)
                temp_settings.setdefault('pdf_logo_paths', {})[k] = ''
                rp('')

            ttk.Button(scroll_frame, text="Durchsuchen...", command=browse, width=14).grid(
                row=row_idx, column=3, padx=4, pady=6)
            ttk.Button(scroll_frame, text="Standard", command=reset, width=10).grid(
                row=row_idx, column=4, padx=(0, 10), pady=6)

        scroll_frame.columnconfigure(1, weight=1)
        for i, (key, label) in enumerate(PDF_DOCUMENTS):
            make_row(i + 1, key, label)

    def _open_tagesabrechnung_history_dialog(self):
        history_data = self._load_tagesabrechnung_history()
        if not history_data:
            messagebox.showinfo("Verlauf", "Kein Verlauf für die Tagesabrechnung verfügbar.", parent=self.master)
            return

        history_window = tk.Toplevel(self.master)
        history_window.title("Verlauf der Tagesabrechnung")
        history_window.transient(self.master)
        history_window.grab_set()
        
        self.current_ta_history_dialog_window = history_window

        listbox_frame = ttk.Frame(history_window, padding=10)
        listbox_frame.pack(fill='both', expand=True)
        
        scrollbar_y = ttk.Scrollbar(listbox_frame, orient=tk.VERTICAL)
        scrollbar_y.pack(side='right', fill='y')
        listbox = tk.Listbox(listbox_frame, yscrollcommand=scrollbar_y.set, exportselection=False, selectmode=tk.EXTENDED)
        
        # vvvvv HIER BEGINNT DIE ANPASSUNG vvvvv
        for i, item in enumerate(history_data):
            ts = datetime.datetime.fromisoformat(item['timestamp']).strftime('%d.%m.%Y %H:%M:%S')
            
            data_to_summarize = item.get('data', {})
            fo_sum_summary = sum(self._parse_input_string(v) or decimal.Decimal(0) for k, v in data_to_summarize.items() if k.startswith('einnahmen_fo_') and k != 'einnahmen_fo_summe')
            bar_sum_summary = sum(self._parse_input_string(v) or decimal.Decimal(0) for k, v in data_to_summarize.items() if k.startswith('einnahmen_bar_') and k != 'einnahmen_bar_summe')
            ausgaben_sum_summary = sum(self._parse_input_string(row.get('betrag')) or decimal.Decimal(0) for row in data_to_summarize.get('ausgaben_rows', []))
            
            summary = f"Einn. FO: {fo_sum_summary:,.2f} | Einn. Bar: {bar_sum_summary:,.2f} | Ausg.: {ausgaben_sum_summary:,.2f}".replace('.', '#').replace(',', '.').replace('#', ',')
            listbox.insert(tk.END, f"{ts} - {summary}")

            # Prüft, ob der Eintrag als "final" markiert ist und färbt ihn gelb.
            if item.get('final', False):
                listbox.itemconfig(i, {'bg': 'yellow'})
        # ^^^^^ HIER ENDET DIE ANPASSUNG ^^^^^

        listbox.pack(side='left', fill='both', expand=True)
        scrollbar_y.config(command=listbox.yview)

        button_frame = ttk.Frame(history_window, padding=(10, 5, 10, 10))
        button_frame.pack(fill='x')
        
        ipady = self.current_settings.get('dialog_button_ipady', 5)
        
        restore_btn = ttk.Button(button_frame, style='TButton',
            command=lambda: self._restore_tagesabrechnung_from_snapshot(history_data[listbox.curselection()[0]], history_window) if listbox.curselection() else None)
        self._configure_dialog_button(restore_btn, 'Dialog_Restore', 'Wiederherstellen')
        restore_btn.config(state='disabled')
        restore_btn.pack(side='left', padx=(0,5), expand=True, ipady=ipady)
        
        # vvvvv HIER BEGINNT DIE ANPASSUNG vvvvv

        # Logik zum Markieren eines Eintrags als final
        def mark_as_final():
            selected_indices = listbox.curselection()
            if not selected_indices: return

            selected_idx = selected_indices[0]
            snapshot_to_mark = history_data[selected_idx]
            snapshot_to_mark['final'] = True  # Fügt das 'final'-Flag hinzu

            try:
                with open(self.tagesabrechnung_history_file, 'w', encoding='utf-8') as f:
                    json.dump(history_data, f, indent=2)
                
                listbox.itemconfig(selected_idx, {'bg': 'yellow'})
                SuccessToast(history_window, title="Markiert", message="Eintrag als final markiert.", toast_type='success', colors=self.current_settings.get('toast_colors'))
            except Exception as e:
                messagebox.showerror("Fehler", f"Fehler beim Speichern der Markierung:\n{e}", parent=history_window)

       # vvvvv HIER BEGINNT DIE ANPASSUNG vvvvv
        final_btn = ttk.Button(button_frame, style='TButton', command=mark_as_final)
        # Der Button wird nun über die zentrale Funktion konfiguriert, die Icons unterstützt.
        self._configure_dialog_button(final_btn, 'Dialog_Final', 'Final')
        final_btn.config(state='disabled')
        final_btn.pack(side='left', padx=5, expand=True, ipady=ipady)
        ToolTip(final_btn, "Markiert den ausgewählten Eintrag als final (gelb).")
        # ^^^^^ HIER ENDET DIE ANPASSUNG ^^^^^
        
        delete_btn = ttk.Button(button_frame, style='TButton',
            command=lambda: self._delete_tagesabrechnung_history_snapshots(listbox, history_data, history_data, history_window))
        self._configure_dialog_button(delete_btn, 'Dialog_Delete', 'Löschen')
        delete_btn.config(state='disabled')
        delete_btn.pack(side='left', padx=5, expand=True, ipady=ipady)
        
        cancel_btn = ttk.Button(button_frame, command=history_window.destroy, style='TButton')
        self._configure_dialog_button(cancel_btn, 'Dialog_Cancel', 'Abbrechen')
        cancel_btn.pack(side='right', padx=(5,0), expand=True, ipady=ipady)

        def on_select(event):
            selections = listbox.curselection()
            can_restore = len(selections) == 1
            can_delete = bool(selections) and self.is_admin_mode
            
            # vvvvv HIER BEGINNT DIE ANPASSUNG vvvvv
            can_mark_final = len(selections) == 1
            final_btn.config(state='normal' if can_mark_final else 'disabled')
            # ^^^^^ HIER ENDET DIE ANPASSUNG ^^^^^
            
            restore_btn.config(state='normal' if can_restore else 'disabled')
            delete_btn.config(state='normal' if can_delete else 'disabled')

        listbox.bind('<<ListboxSelect>>', on_select)
        if listbox.size() > 0:
            listbox.selection_set(0)
            on_select(None)
        
        history_window.protocol("WM_DELETE_WINDOW", lambda: setattr(self, 'current_ta_history_dialog_window', None) or history_window.destroy())
        self.master.wait_window(history_window)




        
