    def _create_settings_mod_checkliste_email_section(self, parent_frame, temp_settings, dialog_vars, start_row=0):
        """Erstellt den Abschnitt für E-Mail-Empfänger und CC der MOD-Checkliste."""
        settings_key = 'mod_checkliste_email_recipients'
        section_title = "MOD-Checkliste: E-Mail-Konfiguration"
        
        frame = ttk.LabelFrame(parent_frame, text=section_title, style='TLabelframe')
        frame.grid(row=start_row, column=0, columnspan=4, sticky='ew', padx=5, pady=10)
        frame.columnconfigure(0, weight=1)

        # 1. Liste der Empfänger (wie bisher)
        list_container = ttk.Frame(frame)
        list_container.pack(fill='x', padx=5, pady=5)
        
        # ... (Logik für die generische Liste wiederverwenden oder neu aufbauen) ...
        # Um Code zu sparen, rufen wir hier den generischen Builder für den Listen-Teil auf,
        # aber wir müssen ihn in einen Sub-Frame packen, damit wir das CC-Feld darunter setzen können.
        
        # Wir bauen die Liste hier manuell kurz nach, damit das Layout passt:
        list_frame = ttk.Frame(frame)
        list_frame.pack(fill='both', expand=True, padx=5)
        
        scrollbar = ttk.Scrollbar(list_frame, orient=tk.VERTICAL)
        listbox = tk.Listbox(list_frame, yscrollcommand=scrollbar.set, exportselection=False, height=3)
        scrollbar.config(command=listbox.yview)
        scrollbar.pack(side='right', fill='y')
        listbox.pack(side='left', fill='both', expand=True)

        temp_dict = temp_settings.get(settings_key, {}).copy()
        
        def populate():
            listbox.delete(0, tk.END)
            for k, v in sorted(temp_dict.items()): listbox.insert(tk.END, f"{k}: {v}")
        populate()

        def add_item():
            res = self._add_edit_email_recipient_dialog(frame.winfo_toplevel(), None)
            if res: temp_dict[res[0]] = res[1]; temp_settings[settings_key] = temp_dict; populate()

        def edit_item():
            sel = listbox.curselection()
            if not sel: return
            key = listbox.get(sel[0]).split(':', 1)[0]
            res = self._add_edit_email_recipient_dialog(frame.winfo_toplevel(), (key, temp_dict[key]))
            if res: 
                if res[0] != key: del temp_dict[key]
                temp_dict[res[0]] = res[1]; temp_settings[settings_key] = temp_dict; populate()

        def del_item():
            sel = listbox.curselection()
            if sel: 
                key = listbox.get(sel[0]).split(':', 1)[0]
                del temp_dict[key]; temp_settings[settings_key] = temp_dict; populate()

        btn_frame = ttk.Frame(frame)
        btn_frame.pack(fill='x', padx=5, pady=2)
        ttk.Button(btn_frame, text="+", width=3, command=add_item).pack(side='left')
        ttk.Button(btn_frame, text="✎", width=3, command=edit_item).pack(side='left')
        ttk.Button(btn_frame, text="-", width=3, command=del_item).pack(side='left')

        # --- HIER IST DER NEUE TEIL FÜR CC ---
        ttk.Separator(frame, orient='horizontal').pack(fill='x', padx=5, pady=10)
        
        cc_frame = ttk.Frame(frame)
        cc_frame.pack(fill='x', padx=5, pady=(0, 5))
        
        ttk.Label(cc_frame, text="CC Empfänger (optional):", font=("Segoe UI", 9, "bold")).pack(anchor='w')
        
        # Variable initialisieren
        cc_val = temp_settings.get('mod_checkliste_cc_email', '')
        dialog_vars['mod_checkliste_cc_var'] = tk.StringVar(value=cc_val)
        
        cc_entry = ttk.Entry(cc_frame, textvariable=dialog_vars['mod_checkliste_cc_var'])
        cc_entry.pack(fill='x', pady=2)
        
        # Trace um Änderung zu speichern
        dialog_vars['mod_checkliste_cc_var'].trace_add('write', 
            lambda n,i,m: temp_settings.update({'mod_checkliste_cc_email': dialog_vars['mod_checkliste_cc_var'].get()}))
        
        ttk.Label(cc_frame, text="(Mehrere Adressen mit Semikolon trennen)", font=("Segoe UI", 8), foreground="gray").pack(anchor='w')
        # -------------------------------------

        return start_row + 1

    def _add_edit_email_recipient_dialog(self, parent_window, item=None, current_defs=None, list_name=None):
        """Ein einfacher Dialog zum Hinzufügen/Bearbeiten eines Name-E-Mail-Paares."""
        is_editing = item is not None
        title = "Empfänger bearbeiten" if is_editing else "Neuen Empfänger hinzufügen"
        
        # Name abfragen (z.B. "Reservierung")
        name = simpledialog.askstring(title, "Angezeigter Name:", parent=parent_window, initialvalue=item[0] if item else "")
        if name is None or not name.strip():
            return None

        # E-Mail-Adresse abfragen
        email = simpledialog.askstring(title, "E-Mail-Adresse:", parent=parent_window, initialvalue=item[1] if item else "")
        if email is None or not email.strip():
            return None
        
        # Einfache E-Mail-Validierung
        if "@" not in email or "." not in email.split('@')[1]:
            messagebox.showerror("Fehler", "Bitte geben Sie eine gültige E-Mail-Adresse ein.", parent=parent_window)
            return None
            
        return (name.strip(), email.strip())
    
    
    
     # vvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvv
    # HIER IST DIE PERFEKTE STELLE ZUM EINFÜGEN IHRER NEUEN METHODE
    # vvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvv
    def _create_settings_kuerzel_management_section(self, parent_frame, temp_settings, start_row=0):
        """Erstellt den UI-Abschnitt zur Verwaltung der Kürzel-Listen in den Einstellungen."""
        main_frame = ttk.LabelFrame(parent_frame, text="Kürzel-Verwaltung", style='TLabelframe')
        main_frame.grid(row=start_row, column=0, columnspan=4, sticky='ew', padx=5, pady=10)
        main_frame.columnconfigure((0, 1), weight=1)

        def create_list_manager(parent, title, settings_key):
            """Interne Hilfsfunktion, um eine Listbox mit Verwaltungsbuttons zu erstellen."""
            parent.rowconfigure(1, weight=1)
            parent.columnconfigure(0, weight=1)

            ttk.Label(parent, text=title, font=("Segoe UI", 11, "bold")).grid(row=0, column=0, columnspan=2, sticky='w')

            listbox_frame = ttk.Frame(parent)
            listbox_frame.grid(row=1, column=0, columnspan=2, sticky='nsew', pady=(5,0))
            listbox_frame.rowconfigure(0, weight=1)
            listbox_frame.columnconfigure(0, weight=1)
            
            scrollbar = ttk.Scrollbar(listbox_frame, orient=tk.VERTICAL)
            listbox = tk.Listbox(listbox_frame, yscrollcommand=scrollbar.set, exportselection=False)
            scrollbar.config(command=listbox.yview)
            listbox.grid(row=0, column=0, sticky='nsew')
            scrollbar.grid(row=0, column=1, sticky='ns')

            temp_list = temp_settings.get(settings_key, []).copy()

            def populate():
                listbox.delete(0, tk.END)
                for item in sorted(temp_list, key=str.lower):
                    listbox.insert(tk.END, item)

            def add_item():
                new_val = simpledialog.askstring("Hinzufügen", f"Neues Kürzel für '{title}':", parent=parent.winfo_toplevel())
                if new_val and new_val.strip():
                    new_val_stripped = new_val.strip()
                    if new_val_stripped.upper() in [k.upper() for k in temp_list]:
                        messagebox.showwarning("Duplikat", "Dieses Kürzel existiert bereits.", parent=parent.winfo_toplevel())
                        return
                    temp_list.append(new_val_stripped)
                    temp_settings[settings_key] = temp_list
                    populate()

            def edit_item():
                selected_idx_tuple = listbox.curselection()
                if not selected_idx_tuple: return
                selected_idx = selected_idx_tuple[0]
                old_val = listbox.get(selected_idx)
                
                new_val = simpledialog.askstring("Bearbeiten", f"Kürzel '{old_val}' ändern:", parent=parent.winfo_toplevel(), initialvalue=old_val)
                if new_val and new_val.strip():
                    new_val_stripped = new_val.strip()
                    if new_val_stripped.upper() in [k.upper() for k in temp_list if k.upper() != old_val.upper()]:
                        messagebox.showwarning("Duplikat", "Dieses Kürzel existiert bereits.", parent=parent.winfo_toplevel())
                        return
                    temp_list[temp_list.index(old_val)] = new_val_stripped
                    temp_settings[settings_key] = temp_list
                    populate()

            def delete_item():
                selected_idx_tuple = listbox.curselection()
                if not selected_idx_tuple: return
                
                if messagebox.askyesno("Löschen", "Ausgewähltes Kürzel wirklich löschen?", parent=parent.winfo_toplevel()):
                    selected_idx = selected_idx_tuple[0]
                    val_to_delete = listbox.get(selected_idx)
                    temp_list.remove(val_to_delete)
                    temp_settings[settings_key] = temp_list
                    populate()
            
            populate()
            
            button_frame = ttk.Frame(parent)
            button_frame.grid(row=2, column=0, columnspan=2, sticky='ew', pady=(5,0))
            button_frame.columnconfigure((0,1,2), weight=1)

            ttk.Button(button_frame, text="Neu", command=add_item).grid(row=0, column=0, padx=2, sticky='ew')
            ttk.Button(button_frame, text="Bearbeiten", command=edit_item).grid(row=0, column=1, padx=2, sticky='ew')
            ttk.Button(button_frame, text="Löschen", command=delete_item).grid(row=0, column=2, padx=2, sticky='ew')

        # Manager für Trinkgeld-Kürzel
        trinkgeld_frame = ttk.Frame(main_frame)
        trinkgeld_frame.grid(row=0, column=0, sticky='nsew', padx=5, pady=5)
        create_list_manager(trinkgeld_frame, "Trinkgeld-Kürzel", 'trinkgeld_kuerzel_list')

        # Manager für Checklisten-Kürzel
        checkliste_frame = ttk.Frame(main_frame)
        checkliste_frame.grid(row=0, column=1, sticky='nsew', padx=5, pady=5)
        create_list_manager(checkliste_frame, "Checklisten-Kürzel", 'checkliste_kuerzel_list')

        return start_row + 1
    



    def _load_ueberstundenantrag_data(self):
        """Lädt die gespeicherten Überstundenanträge."""
        if os.path.exists(self.ueberstundenantrag_data_file):
            try:
                with open(self.ueberstundenantrag_data_file, 'r', encoding='utf-8') as f:
                    self.ueberstundenantrag_data_cache = json.load(f)
            except (json.JSONDecodeError, IOError):
                self.ueberstundenantrag_data_cache = []
        else:
            self.ueberstundenantrag_data_cache = []

    def _save_ueberstundenantrag_data(self):
        """Speichert die Überstundenanträge."""
        try:
            with open(self.ueberstundenantrag_data_file, 'w', encoding='utf-8') as f:
                json.dump(self.ueberstundenantrag_data_cache, f, indent=2, ensure_ascii=False)
        except Exception as e:
            print(f"Fehler beim Speichern der Überstundenanträge: {e}")

    def _create_ueberstundenantrag_page(self, parent_frame):
        """Erstellt die UI-Seite zur Verwaltung von Überstundenanträgen."""
        for widget in parent_frame.winfo_children(): widget.destroy()
        parent_frame.grid_rowconfigure(1, weight=1); parent_frame.grid_columnconfigure(0, weight=1)

        header = ttk.Frame(parent_frame, style='AppBackground.TFrame', height=60)
        header.grid(row=0, column=0, sticky='ew'); header.columnconfigure(1, weight=1)
        home_button = self._create_home_button(header)
        if home_button: home_button.grid(row=0, column=0, sticky='w', padx=10, pady=10)
        ttk.Label(header, text="Überstundenanträge Verwalten", font=("Segoe UI", 20, "bold")).grid(row=0, column=1, sticky='w', padx=20, pady=10)

        tree_frame = ttk.Frame(parent_frame, style='AppBackground.TFrame', padding=(15, 8))
        tree_frame.grid(row=1, column=0, sticky='nsew'); tree_frame.columnconfigure(0, weight=1); tree_frame.rowconfigure(0, weight=1)

        self.ueberstundenantrag_tree = ttk.Treeview(tree_frame, show="headings", style="Urlaubsantraege.Treeview")
        self.ueberstundenantrag_tree['columns'] = ("name", "abteilung", "erster_tag", "letzter_tag", "gesamtzahl")
        self.ueberstundenantrag_tree.heading("name", text="Mitarbeiter"); self.ueberstundenantrag_tree.column("name", width=250, anchor='w')
        self.ueberstundenantrag_tree.heading("abteilung", text="Abteilung"); self.ueberstundenantrag_tree.column("abteilung", width=180, anchor='w')
        self.ueberstundenantrag_tree.heading("erster_tag", text="Erster Tag"); self.ueberstundenantrag_tree.column("erster_tag", width=120, anchor='center')
        self.ueberstundenantrag_tree.heading("letzter_tag", text="Letzter Tag"); self.ueberstundenantrag_tree.column("letzter_tag", width=120, anchor='center')
        self.ueberstundenantrag_tree.heading("gesamtzahl", text="Tage"); self.ueberstundenantrag_tree.column("gesamtzahl", width=80, anchor='center')
        
        vsb = ttk.Scrollbar(tree_frame, orient="vertical", command=self.ueberstundenantrag_tree.yview); vsb.grid(row=0, column=1, sticky='ns'); self.ueberstundenantrag_tree.configure(yscrollcommand=vsb.set)
        self.ueberstundenantrag_tree.grid(row=0, column=0, sticky="nsew")
        self.ueberstundenantrag_tree.bind("<Double-1>", self._edit_ueberstundenantrag)
        self._setupTreeViewCellNavigation(self.ueberstundenantrag_tree, edit_command_func=self._edit_ueberstundenantrag)
        
        button_frame = ttk.Frame(parent_frame, style='AppBackground.TFrame', padding=(15, 8))
        button_frame.grid(row=2, column=0, sticky='ew')
        style_cfg = self.current_settings.get('list_views_button_style', {}); ipady = style_cfg.get('ipady', 5)

        button_configs = self.current_settings.get('ueberstundenantrag_button_configs', {})
        button_defs = [
            ('Ueberstundenantrag_Add', "Hinzufügen", self._add_ueberstundenantrag),
            ('Ueberstundenantrag_Edit', "Bearbeiten", self._edit_ueberstundenantrag),
            ('Ueberstundenantrag_Delete', "Löschen", self._delete_ueberstundenantrag),
            (None, None, None),
            ('Ueberstundenantrag_History', "Verlauf", self._open_ueberstundenantrag_history_dialog),
            ('Ueberstundenantrag_Print', "Drucken", self._print_ueberstundenantrag_pdf),
            ('Ueberstundenantrag_SavePDF', "Als PDF speichern", self._save_ueberstundenantrag_pdf)
        ]

        for key, text, cmd in button_defs:
            if key is None:
                ttk.Separator(button_frame, orient='vertical').pack(side="left", fill='y', padx=10, pady=4)
                continue
            btn = ttk.Button(button_frame, command=cmd)
            self._configure_list_tab_button(btn, key, text, button_config_source=button_configs)
            btn.pack(side="left", padx=4, ipady=ipady, fill='x', expand=True)
            
        self._load_and_display_ueberstundenantraege()

    def _load_and_display_ueberstundenantraege(self):
        """Lädt die gespeicherten Überstundenanträge und zeigt sie in der Liste an."""
        if not hasattr(self, 'ueberstundenantrag_tree') or not self.ueberstundenantrag_tree.winfo_exists(): 
            return
        
        # Leert die bestehende Ansicht
        self.ueberstundenantrag_tree.delete(*self.ueberstundenantrag_tree.get_children())
        
        # Sortiert die Daten alphabetisch nach dem Namen des Mitarbeiters
        sorted_cache = sorted(self.ueberstundenantrag_data_cache, key=lambda x: x.get('name', '').lower())

        # Befüllt die Tabelle mit den sortierten Daten
        for entry in sorted_cache:
            values = (
                entry.get('name', ''), 
                entry.get('abteilung', ''), 
                entry.get('erster_tag', ''), 
                entry.get('letzter_tag', ''), 
                str(entry.get('gesamtzahl', ''))
            )
            self.ueberstundenantrag_tree.insert("", "end", values=values, iid=entry.get('id'))

    # HIER ENDET DER NEUE CODEBLOCK

    def _add_ueberstundenantrag(self):
        dialog = UeberstundenantragEntryDialog(self.master, self)
        new_data = dialog.show()
        if new_data:
            self.ueberstundenantrag_data_cache.append(new_data)
            self._save_ueberstundenantrag_data()
            # vvvvv HIER IST DIE KORREKTUR vvvvv
            self._save_list_entry_to_history(new_data, "Hinzugefügt", "Überstundenantrag")
            # ^^^^^ ENDE DER KORREKTUR ^^^^^
            self._load_and_display_ueberstundenantraege()

    def _edit_ueberstundenantrag(self, event=None):
        selected_ids = self.ueberstundenantrag_tree.selection()
        if not selected_ids: return
        selected_id = selected_ids[0]
        entry_index = next((i for i, e in enumerate(self.ueberstundenantrag_data_cache) if e.get("id") == selected_id), -1)
        if entry_index == -1: return
        
        dialog = UeberstundenantragEntryDialog(self.master, self, self.ueberstundenantrag_data_cache[entry_index])
        updated_data = dialog.show()
        if updated_data:
            self.ueberstundenantrag_data_cache[entry_index] = updated_data
            self._save_ueberstundenantrag_data()
            # vvvvv HIER IST DIE KORREKTUR vvvvv
            self._save_list_entry_to_history(updated_data, "Bearbeitet", "Überstundenantrag")
            # ^^^^^ ENDE DER KORREKTUR ^^^^^
            self._load_and_display_ueberstundenantraege()

    def _delete_ueberstundenantrag(self):
        selected_ids = self.ueberstundenantrag_tree.selection()
        if not selected_ids: return
        if messagebox.askyesno("Löschen", f"{len(selected_ids)} Antrag/Anträge wirklich löschen?"):
            # vvvvv HIER IST DIE KORREKTUR vvvvv
            for item_id in selected_ids:
                entry_to_delete = next((e for e in self.ueberstundenantrag_data_cache if e.get("id") == item_id), None)
                if entry_to_delete:
                    self._save_list_entry_to_history(entry_to_delete, "Gelöscht", "Überstundenantrag")
            # ^^^^^ ENDE DER KORREKTUR ^^^^^

            self.ueberstundenantrag_data_cache = [e for e in self.ueberstundenantrag_data_cache if e.get("id") not in selected_ids]
            self._save_ueberstundenantrag_data()
            self._load_and_display_ueberstundenantraege()

    def _get_selected_ueberstundenantrag_data(self):
        selected_ids = self.ueberstundenantrag_tree.selection()
        if not selected_ids:
            SuccessToast(self.master, title="Keine Auswahl", message="Bitte einen Antrag auswählen.", toast_type='warning', colors=self.current_settings.get('toast_colors'))
            return None
        return next((e for e in self.ueberstundenantrag_data_cache if e.get("id") == selected_ids[0]), None)

    def _save_ueberstundenantrag_pdf(self):
        antrag_data = self._get_selected_ueberstundenantrag_data()
        if not antrag_data: return
        save_path = filedialog.asksaveasfilename(
            defaultextension=".pdf", filetypes=[("PDF-Dateien", "*.pdf")], title="Überstundenantrag als PDF speichern",
            initialfile=f"Ueberstundenantrag_{antrag_data['name'].replace(' ', '_')}_{datetime.date.today().strftime('%d.%m.%Y')}.pdf"
        )
        if not save_path: return
        try:
            pdf = UeberstundenantragPDF(antrag_data, logo_path=_get_pdf_logo_path(self.current_settings, 'ueberstundenantrag'))
            pdf.create_form()
            pdf.output(save_path)
        except Exception as e:
            messagebox.showerror("Fehler beim Speichern", f"Ein Fehler ist aufgetreten:\n{e}", parent=self.master)

    def _print_ueberstundenantrag_pdf(self):
        antrag_data = self._get_selected_ueberstundenantrag_data()
        if not antrag_data: return
        temp_pdf_path = ""
        try:
            with tempfile.NamedTemporaryFile(suffix=".pdf", delete=False) as temp_pdf_file:
                temp_pdf_path = temp_pdf_file.name
            pdf = UeberstundenantragPDF(antrag_data, logo_path=_get_pdf_logo_path(self.current_settings, 'ueberstundenantrag'))
            pdf.create_form()
            pdf.output(temp_pdf_path)
            self._open_file(temp_pdf_path)
            self._schedule_temp_file_cleanup(temp_pdf_path)
        except Exception as e:
            messagebox.showerror("Druckfehler", f"Fehler beim Öffnen der Druckvorschau:\n{e}", parent=self.master)
            if temp_pdf_path: self._schedule_temp_file_cleanup(temp_pdf_path)

    def _open_ueberstundenantrag_history_dialog(self):
        self._open_generic_list_history_dialog(
            "Überstundenanträge", self.ueberstundenantrag_history_file,
            self._get_ueberstundenantrag_history_summary_line,
            self._restore_ueberstundenantrag_from_history
        )

    def _get_ueberstundenantrag_history_summary_line(self, snapshot):
        data = snapshot.get('data', {})
        action = snapshot.get('action', 'Unbekannt')
        return f"[{action}] {data.get('name', 'N/A')} - {data.get('erster_tag', '')} bis {data.get('letzter_tag', '')}"

    def _restore_ueberstundenantrag_from_history(self, history_dialog):
        """Stellt einen Überstundenantrag aus dem Verlauf wieder her."""
        # Die Logik zum Extrahieren der Daten wird direkt hier implementiert.
        try:
            listbox = history_dialog.listbox_widget
            all_snapshots = history_dialog.displayed_snapshots
            selected_indices = listbox.curselection()

            if not selected_indices:
                messagebox.showwarning("Auswahl", "Bitte einen Eintrag zum Wiederherstellen auswählen.", parent=history_dialog)
                return
            
            if len(selected_indices) > 1:
                messagebox.showwarning("Mehrfachauswahl", "Bitte nur einen Eintrag auf einmal wiederherstellen.", parent=history_dialog)
                return
            
            # Holt den korrekten Snapshot basierend auf der Auswahl in der Listbox
            snapshot_data = all_snapshots[selected_indices[0]]
        except (AttributeError, IndexError) as e:
            messagebox.showerror("Fehler", f"Die Daten aus dem Verlaufsfenster konnten nicht gelesen werden: {e}", parent=history_dialog)
            return

        entry_to_restore = snapshot_data.get('data')
        if not entry_to_restore:
            messagebox.showerror("Fehler", "Keine Daten zum Wiederherstellen in diesem Eintrag.", parent=history_dialog)
            return

        if messagebox.askyesno("Wiederherstellen", "Diesen Antrag wiederherstellen? Ein eventuell vorhandener Eintrag mit derselben ID wird überschrieben.", parent=history_dialog):
            self.ueberstundenantrag_data_cache = [e for e in self.ueberstundenantrag_data_cache if e.get('id') != entry_to_restore.get('id')]
            self.ueberstundenantrag_data_cache.append(entry_to_restore)
            self._save_ueberstundenantrag_data()
            self._save_list_entry_to_history(entry_to_restore, "Wiederhergestellt", "Überstundenantrag")
            self._load_and_display_ueberstundenantraege()
            history_dialog.destroy()
            SuccessToast(self.master, title="Erfolg", message="Der Antrag wurde wiederhergestellt.", toast_type='success', colors=self.current_settings.get('toast_colors'))


