    def _create_tischreservierung_page(self, parent_frame):
        """ Instanziiert die TischreservierungApp, speichert Referenzen und registriert sie. """
        self.tischreservierung_app_instance = TischreservierungApp(parent_frame, app_ref=self)
        self.tischreservierung_tree_widget = self.tischreservierung_app_instance.tree
        self._setupTreeViewCellNavigation(self.tischreservierung_tree_widget, edit_command_func=self._edit_tischreservierung_entry)
        self.sub_app_instances.append(self.tischreservierung_app_instance)

    def _load_tischreservierung_data(self):
        """Lädt Tischreservierungen aus der JSON-Datei."""
        if os.path.exists(self.tischreservierung_data_file):
            try:
                with open(self.tischreservierung_data_file, 'r', encoding='utf-8') as f:
                    self.tischreservierung_data_cache = json.load(f)
            except (json.JSONDecodeError, IOError):
                self.tischreservierung_data_cache = []
        else:
            self.tischreservierung_data_cache = []

    def _save_tischreservierung_data(self):
        """Speichert Tischreservierungen in die JSON-Datei."""
        try:
            with open(self.tischreservierung_data_file, 'w', encoding='utf-8') as f:
                json.dump(self.tischreservierung_data_cache, f, indent=2, ensure_ascii=False)
        except Exception as e:
            print(f"Fehler beim Speichern der Tischreservierungen: {e}")

    def _load_and_display_tischreservierungen(self):
        """Lädt die Daten und aktualisiert die Treeview-Anzeige über eine direkte Referenz."""
        # Prüft, ob die Tabellen-Referenz existiert und das Widget sichtbar ist
        if not hasattr(self, 'tischreservierung_tree_widget') or not self.tischreservierung_tree_widget or not self.tischreservierung_tree_widget.winfo_exists():
            return

        tree = self.tischreservierung_tree_widget # Direkte Referenz verwenden
        tree.delete(*tree.get_children())
        
        sorted_cache = sorted(self.tischreservierung_data_cache, key=lambda x: (x.get('datum', ''), x.get('uhrzeit', '')))

        for entry in sorted_cache:
            values = (
                entry.get('datum', ''), entry.get('uhrzeit', ''), entry.get('name', ''),
                entry.get('personen', ''), entry.get('telefon', ''),
                entry.get('angenommen_von', ''), entry.get('besondere_wuensche', '')
            )
            tree.insert("", "end", values=values, iid=entry.get('id'))

    def _add_tischreservierung_entry(self):
        dialog = TischreservierungEntryDialog(self.master, self)
        new_data = dialog.show()  # Korrekter Aufruf mit .show()
        if new_data:
            self.tischreservierung_data_cache.append(new_data)
            self._save_tischreservierung_data()
            self._save_list_entry_to_history(new_data, "Hinzugefügt", "Tischreservierung")
            self._load_and_display_tischreservierungen()
    def _edit_tischreservierung_entry(self):
        if not hasattr(self, 'tischreservierung_app_instance'): return
        selected_ids = self.tischreservierung_app_instance.tree.selection()
        if not selected_ids:
            SuccessToast(self.master, title="Keine Auswahl", message="Bitte eine Reservierung zum Bearbeiten auswählen.", toast_type='warning', colors=self.current_settings.get('toast_colors'))
            return

        selected_id = selected_ids[0]
        entry_to_edit = next((e for e in self.tischreservierung_data_cache if e.get("id") == selected_id), None)
        if not entry_to_edit: return

        dialog = TischreservierungEntryDialog(self.master, self, entry_data=entry_to_edit)
        updated_data = dialog.show()
        if updated_data:
            entry_index = next((i for i, e in enumerate(self.tischreservierung_data_cache) if e.get("id") == selected_id), -1)
            if entry_index != -1:
                self.tischreservierung_data_cache[entry_index] = updated_data
                self._save_tischreservierung_data()
                self._save_list_entry_to_history(updated_data, "Bearbeitet", "Tischreservierung")
                self._load_and_display_tischreservierungen()

    def _delete_tischreservierung_entry(self):
        if not hasattr(self, 'tischreservierung_app_instance'): return
        selected_ids = self.tischreservierung_app_instance.tree.selection()
        if not selected_ids:
            SuccessToast(self.master, title="Keine Auswahl", message="Bitte mindestens eine Reservierung zum Löschen auswählen.", toast_type='warning', colors=self.current_settings.get('toast_colors'))
            return
        
        if messagebox.askyesno("Löschen", f"{len(selected_ids)} Reservierung(en) wirklich löschen?"):
            for item_id in selected_ids:
                entry_to_delete = next((e for e in self.tischreservierung_data_cache if e.get("id") == item_id), None)
                if entry_to_delete:
                    self._save_list_entry_to_history(entry_to_delete, "Gelöscht", "Tischreservierung")

            self.tischreservierung_data_cache = [e for e in self.tischreservierung_data_cache if e.get("id") not in selected_ids]
            self._save_tischreservierung_data()
            self._load_and_display_tischreservierungen()
            SuccessToast(self.master, title="Erfolg", message=f"{len(selected_ids)} Reservierung(en) gelöscht.", toast_type='success', colors=self.current_settings.get('toast_colors'))
    
    def _open_tischreservierung_history_dialog(self):
        self._open_generic_list_history_dialog(
            "Tischreservierungen",
            self.tischreservierung_history_file,
            self._get_tischreservierung_history_summary_line,
            self._restore_tischreservierung_from_history
        )

    def _get_tischreservierung_history_summary_line(self, snapshot):
        data = snapshot.get('data', {})
        action = snapshot.get('action', 'Unbekannt')
        return f"[{action}] {data.get('datum', '')} {data.get('uhrzeit', '')} - {data.get('name', 'N/A')} ({data.get('personen', '?')} Pers.)"

    def _restore_tischreservierung_from_history(self, history_dialog):
        """Stellt einen Tischreservierungs-Eintrag aus dem Verlauf wieder her."""
        # Die Logik zum Extrahieren der Daten wird direkt hier implementiert.
        try:
            listbox = history_dialog.listbox_widget
            all_snapshots = history_dialog.displayed_snapshots
            selected_indices = listbox.curselection()

            if not selected_indices:
                messagebox.showwarning("Auswahl", "Bitte einen Eintrag zum Wiederherstellen auswählen.", parent=history_dialog)
                return
            
            if len(selected_indices) > 1:
                messagebox.showwarning("Mehrfachauswahl", "Bitte nur einen Eintrag auf einmal wiederherstellen.", parent=history_dialog)
                return
            
            # Holt den korrekten Snapshot basierend auf der Auswahl in der Listbox
            snapshot_data = all_snapshots[selected_indices[0]]
        except (AttributeError, IndexError) as e:
            messagebox.showerror("Fehler", f"Die Daten aus dem Verlaufsfenster konnten nicht gelesen werden: {e}", parent=history_dialog)
            return

        entry_to_restore = snapshot_data.get('data')
        if not entry_to_restore:
            messagebox.showerror("Fehler", "Keine Daten zum Wiederherstellen in diesem Eintrag.", parent=history_dialog)
            return

        if messagebox.askyesno("Wiederherstellen", "Diesen Eintrag wiederherstellen? Ein eventuell vorhandener Eintrag mit derselben ID wird überschrieben.", parent=history_dialog):
            self.tischreservierung_data_cache = [e for e in self.tischreservierung_data_cache if e.get('id') != entry_to_restore.get('id')]
            self.tischreservierung_data_cache.append(entry_to_restore)
            self._save_tischreservierung_data()
            self._save_list_entry_to_history(entry_to_restore, "Wiederhergestellt", "Tischreservierung")
            self._load_and_display_tischreservierungen()
            history_dialog.destroy()
            SuccessToast(self.master, title="Erfolg", message="Eintrag wurde wiederhergestellt.", toast_type='success', colors=self.current_settings.get('toast_colors'))
            
    def _print_tischreservierung_pdf(self):
        """
        Erstellt eine temporäre PDF der ausgewählten Tischreservierung und öffnet sie
        im Standard-PDF-Viewer zum Drucken.
        """
        if not hasattr(self, 'tischreservierung_app_instance'): return
        
        selected_ids = self.tischreservierung_app_instance.tree.selection()
        if not selected_ids:
            SuccessToast(self.master, title="Keine Auswahl", message="Bitte eine Reservierung zum Drucken auswählen.", toast_type='warning', colors=self.current_settings.get('toast_colors'))
            return
        
        selected_id = selected_ids[0]
        entry_data = next((e for e in self.tischreservierung_data_cache if e.get("id") == selected_id), None)
        
        if not entry_data:
            messagebox.showerror("Fehler", "Ausgewählte Reservierung nicht gefunden.", parent=self.master)
            return

        temp_pdf_path = ""
        try:
            with tempfile.NamedTemporaryFile(suffix=".pdf", delete=False) as temp_pdf_file:
                temp_pdf_path = temp_pdf_file.name

            pdf = TischreservierungPDF(entry_data)
            pdf.create_form()
            pdf.output(temp_pdf_path)

            SuccessToast(self.master,
                         title="PDF wird geöffnet",
                         message="Das Dokument wird in Ihrem PDF-Programm zum Drucken geöffnet.",
                         toast_type='info',
                         colors=self.current_settings.get('toast_colors'),
                         duration=4000)

            self._open_file(temp_pdf_path)
            self._schedule_temp_file_cleanup(temp_pdf_path)

        except Exception as e:
            messagebox.showerror("Fehler beim Drucken", f"Ein Fehler ist aufgetreten:\n{e}", parent=self.master)
            if temp_pdf_path:
                self._schedule_temp_file_cleanup(temp_pdf_path)
                
                
      # Neue Methoden in der KassenprotokollApp-Klasse für die Anrufliste
    def _create_anrufliste_page(self, parent_frame):
        """ Erstellt die UI für die Verwaltungsseite der Anrufliste. """
        for widget in parent_frame.winfo_children():
            widget.destroy()

        parent_frame.grid_rowconfigure(1, weight=1)
        parent_frame.grid_columnconfigure(0, weight=1)

        # 1. Kopfzeile (Header)
        header = ttk.Frame(parent_frame, style='AppBackground.TFrame', height=60)
        header.grid(row=0, column=0, sticky='ew')
        header.columnconfigure(1, weight=1)
        
        home_button = self._create_home_button(header)
        if home_button:
            home_button.grid(row=0, column=0, sticky='w', padx=10, pady=10)
        
        ttk.Label(header, text="Anrufliste", font=("Segoe UI", 20, "bold")).grid(row=0, column=1, sticky='w', padx=20, pady=10)
        self._add_time_display_to_header(header, 2)

        # 2. Hauptinhaltsbereich (Content)
        content_frame = ttk.Frame(parent_frame, style='AppBackground.TFrame', padding=(15, 8))
        content_frame.grid(row=1, column=0, sticky='nsew')
        content_frame.columnconfigure(0, weight=1)
        content_frame.rowconfigure(0, weight=1)
        
        # 3. Treeview für die Anrufliste
        tree_frame = ttk.Frame(content_frame)
        tree_frame.grid(row=0, column=0, sticky="nsew")
        tree_frame.rowconfigure(0, weight=1)
        tree_frame.columnconfigure(0, weight=1)
        
        self.style.configure("Anrufliste.Treeview", rowheight=30, font=("Segoe UI", 12))
        self.style.configure("Anrufliste.Treeview.Heading", font=("Segoe UI", 14, "bold"))
        
        self.anrufliste_tree_widget = ttk.Treeview(tree_frame, show="headings", style="Anrufliste.Treeview")
        self.anrufliste_tree_widget['columns'] = ("angenommen_von", "datum", "uhrzeit", "anrufer", "firma", "telefonnummer", "fuer_abteilung", "nachricht", "rueckruf_info")
        
        cols = {
            "angenommen_von": "Angenommen", "datum": "Datum", "uhrzeit": "Uhrzeit", "anrufer": "Anrufer",
            "firma": "Firma", "telefonnummer": "Telefonnummer", "fuer_abteilung": "Für/Abt.",
            "nachricht": "Nachricht", "rueckruf_info": "Info/Rückruf"
        }
        for col_id, text in cols.items():
            self.anrufliste_tree_widget.heading(col_id, text=text)

        self.anrufliste_tree_widget.column("angenommen_von", width=120); self.anrufliste_tree_widget.column("datum", width=100); self.anrufliste_tree_widget.column("uhrzeit", width=80)
        self.anrufliste_tree_widget.column("anrufer", width=200); self.anrufliste_tree_widget.column("firma", width=180); self.anrufliste_tree_widget.column("telefonnummer", width=150)
        self.anrufliste_tree_widget.column("fuer_abteilung", width=120); self.anrufliste_tree_widget.column("nachricht", width=350); self.anrufliste_tree_widget.column("rueckruf_info", width=120)

        vsb = ttk.Scrollbar(tree_frame, orient="vertical", command=self.anrufliste_tree_widget.yview)
        vsb.grid(row=0, column=1, sticky='ns')
        self.anrufliste_tree_widget.configure(yscrollcommand=vsb.set)
        self.anrufliste_tree_widget.grid(row=0, column=0, sticky="nsew")
